	/** 
	 *      [A] 오퍼레이션명 :  YD야드 코드 조회
	 *
	 * 		@ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 *      @param JDTORecord rcvMsg
	 *      @return JDTORecord
	 *      @throws DAOException
	 *		
     */			
	public GridData getYdCode(GridData gdReq) throws DAOException {
		String mthdNm = "YD야드코드조회[CCoilJspSeEJB.getYdCode]< " + gdReq.getNavigateValue();
		String logId  = commUtils.getLogId();
 
		try {
			JDTORecordSet jsRst = coilDao.getYdCode(gdReq);
			GridData gdRtn = OperateGridData.cloneResponseGridData(gdReq);
			return commUtils.jdtoRecordToGridData(gdRtn, jsRst.toList(), gdReq);
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * GridData - 단순 조회
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return JDTORecordSet
	 * @throws DAOException
	 */
	public GridData getSelectData(GridData gdReq) throws DAOException {
		String mthdNm = "조회[CCoilJspSeEJB.getSelectData] < " + gdReq.getNavigateValue();
		String logId  = commUtils.getLogId();
		
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");			
			//Grid date 를 JDTORecord data 로 변환
			JDTORecord jrInParam   = CmUtil.genJDTORecord(gdReq);			
			JDTORecordSet jsOutSet = JDTORecordFactory.getInstance().createRecordSet("retTmp");			
			jsOutSet = commDao.select(jrInParam, jrInParam.getFieldString("QUERY_ID"), logId, mthdNm, "");
				
			//UI로 반환 할 Grid data 를 생성 
			//GridData gdRet = CmUtil.genGridData(gdReq, jrOutSet); -- old version
			GridData gdRtn = OperateGridData.cloneResponseGridData(gdReq);
			GridData gdRet = commUtils.jdtoRecordToGridData(gdRtn, jsOutSet.toList(), gdReq);
			
			commUtils.printLog(logId, mthdNm, "S-");			
			return gdRet;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	} 	

