	/**
	 * 오퍼레이션명 : 야드적치X값 변경
	 *
	 * 염용선 2019-10-29 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord (JDTORecord : YD_WBOOK_ID , MODIFIER)
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord updYdCoilRuleXCol(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "야드적치X값 변경[CCoilJspSeEJB.updYdCoilRuleXCol] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sModifier     = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydStkLyrXaXis = commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_RULE_XAXIS"));
			String sMsg    	     = "";
			
			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, sModifier );
			
			//리턴값
			
			if(ydStkLyrXaXis.length() == 0 ){
				commUtils.printLog(logId, "야드적치X값 상태이상", "SL");
			}
			
			//-------------------------------------------------------------
			// 기존 해당 적치열에 대한야드적치X값 상태 정보 조회
			//-------------------------------------------------------------
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_STK_COL_GP", commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			
			/*
			 * SELECT 
					YD_STK_COL_GP AS YD_STK_COL_GP
					,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS') AS REG_DDTT
					,REGISTER AS REGISTER
					,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS') AS MOD_DDTT
					,MODIFIER AS MODIFIER
					,DEL_YN AS DEL_YN
					,YD_GP AS YD_GP
					,YD_BAY_GP AS YD_BAY_GP
					,YD_EQP_GP	AS YD_EQP_GP
					,YD_STK_COL_NO AS YD_STK_COL_NO
					,YD_STK_COL_ACT_STAT AS YD_STK_COL_ACT_STAT
					,YD_STK_COL_RULE_XAXIS AS YD_STK_COL_RULE_XAXIS
					,YD_STK_COL_RULE_YAXIS AS YD_STK_COL_RULE_YAXIS
				    ,YD_STK_COL_RULE_ZAXIS AS YD_STK_COL_RULE_ZAXIS
					,YD_STK_COL_W AS YD_STK_COL_W
					,YD_STK_COL_L AS YD_STK_COL_L
					,YD_CAR_USE_GP AS YD_CAR_USE_GP
					,TRN_EQP_CD AS TRN_EQP_CD
					,CAR_NO AS CAR_NO
					,CARD_NO AS CARD_NO
					,WLOC_CD AS WLOC_CD
					,YD_PNT_CD AS YD_PNT_CD
					,YD_STK_COL_W_GP AS YD_STK_COL_W_GP
					,YD_STK_COL_H_MAX AS YD_STK_COL_H_MAX
					,YD_STK_COL_BED_L_TP AS YD_STK_COL_BED_L_TP
				    ,YD_COIL_OUTDIA_GRP_GP AS YD_COIL_OUTDIA_GRP_GP 
				    ,YD_STKBED_USG_CD
				    ,YD_STK_SKID_GP
				    ,YD_STK_COL_TOLOC_STAT
				FROM TB_YD_STKCOL
				WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
				AND DEL_YN ='N'
			 */
			JDTORecordSet jsStkCol = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkcol", logId, mthdNm, "야드적치X값 상태 데이터");
	    	if(jsStkCol.size() < 1){
			
				sMsg = "야드적치X값 상태 데이터가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			
	    	jsStkCol.first();
	    	JDTORecord jrStkCol = jsStkCol.getRecord();
			
			String ydStkLyrXaXis_DB = commUtils.trim(jrStkCol.getFieldString("YD_STK_COL_RULE_XAXIS"));
			//-------------------------------------------------------------
			// 야드적치단활성상태 정보 비교
			//-------------------------------------------------------------
			
			if(ydStkLyrXaXis_DB.equals(ydStkLyrXaXis)){
				sMsg = "야드적치X값 상태 변경 되지 않았습니다..";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
				
			}
			

			//-------------------------------------------------------------
			//  TB_YD_STKBED 적치 베드 정보의  UPDATE
			//-------------------------------------------------------------

			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_STK_COL_GP"	, commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			jrParam.setField("YD_STK_BED_XAXIS"	, ydStkLyrXaXis);
		
			/*
			 * UPDATE TB_YD_STKBED
			   SET YD_STK_BED_XAXIS  = :V_YD_STK_BED_XAXIS 
			       , MOD_DDTT  = SYSDATE
			       , MODIFIER  = :V_MODIFIER  
			 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
			 */
			int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkbedYdStrX", logId, mthdNm, "베드 야드적치단활성상태 변경");
			
			if(intRtnVal < 0 ){
				sMsg = "베드 야드적치X값 상태의 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}else if(intRtnVal == 0 ){
				sMsg = "베드 야드적치X값 상태정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			sMsg = "베드  야드적치X값 상태의 성공.";
			commUtils.printLog(logId, sMsg, "SL");

			//-------------------------------------------------------------
			//  TB_YD_STKLYR 적치 베드 정보의  UPDATE
			//-------------------------------------------------------------
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_STK_COL_GP"	, commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			jrParam.setField("YD_STK_LYR_XAXIS"	, ydStkLyrXaXis);
			
			/*
			 * UPDATE TB_YD_STKLYR            
				   SET YD_STK_LYR_XAXIS = :V_YD_STK_LYR_XAXIS
				       , MOD_DDTT = SYSDATE
				       , MODIFIER  = :V_MODIFIER  
				WHERE YD_STK_COL_GP  = :V_YD_STK_COL_GP 
			 */
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStklyrX", logId, mthdNm, "단 야드적치X값 상태의 UPDATE");
			
			if(intRtnVal < 0 ){
				sMsg = "단 야드적치X값 상태의 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;

			} else if(intRtnVal == 0 ){
				sMsg = "단 야드적치X값 상태 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			sMsg = "단 야드적치X값 상태의 성공.";
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}

	
	/**
	 * 오퍼레이션명 : 야드적치단활성상태 변경
	 *
	 * 염용선 2019-10-29  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord (JDTORecord : YD_WBOOK_ID , MODIFIER)
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord updYdCoilLyeActStatCol(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "야드적치단활성상태 변경[CCoilJspSeEJB.updYdCoilLyeActStatCol] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");
			String sModifier 		= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydStkColActStat 	= commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_ACT_STAT"));
			String sMsg     		= "";

			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, sModifier );
			
			if(ydStkColActStat.length() != 1 ){
				sMsg = "야드적치단활성상태  올바르지 않습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			//-------------------------------------------------------------
			// 기존 해당 적치열에대한야드적치단활성상태 정보 조회
			//-------------------------------------------------------------
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_ACT_STAT" , ydStkColActStat);
			jrParam.setField("YD_STK_COL_GP"	   , commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			
			/*
			 * SELECT 
					YD_STK_COL_GP AS YD_STK_COL_GP
					,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS') AS REG_DDTT
					,REGISTER AS REGISTER
					,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS') AS MOD_DDTT
					,MODIFIER AS MODIFIER
					,DEL_YN AS DEL_YN
					,YD_GP AS YD_GP
					,YD_BAY_GP AS YD_BAY_GP
					,YD_EQP_GP	AS YD_EQP_GP
					,YD_STK_COL_NO AS YD_STK_COL_NO
					,YD_STK_COL_ACT_STAT AS YD_STK_COL_ACT_STAT
					,YD_STK_COL_RULE_XAXIS AS YD_STK_COL_RULE_XAXIS
					,YD_STK_COL_RULE_YAXIS AS YD_STK_COL_RULE_YAXIS
				    ,YD_STK_COL_RULE_ZAXIS AS YD_STK_COL_RULE_ZAXIS
					,YD_STK_COL_W AS YD_STK_COL_W
					,YD_STK_COL_L AS YD_STK_COL_L
					,YD_CAR_USE_GP AS YD_CAR_USE_GP
					,TRN_EQP_CD AS TRN_EQP_CD
					,CAR_NO AS CAR_NO
					,CARD_NO AS CARD_NO
					,WLOC_CD AS WLOC_CD
					,YD_PNT_CD AS YD_PNT_CD
					,YD_STK_COL_W_GP AS YD_STK_COL_W_GP
					,YD_STK_COL_H_MAX AS YD_STK_COL_H_MAX
					,YD_STK_COL_BED_L_TP AS YD_STK_COL_BED_L_TP
				    ,YD_COIL_OUTDIA_GRP_GP AS YD_COIL_OUTDIA_GRP_GP 
				    ,YD_STKBED_USG_CD
				    ,YD_STK_SKID_GP
				    ,YD_STK_COL_TOLOC_STAT
				FROM TB_YD_STKCOL
				WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
				AND DEL_YN ='N'
			 */
			JDTORecordSet jsStkCol = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkcol", logId, mthdNm, "차량정지위치 정보");
	    	if(jsStkCol.size() < 1){
			
	    		sMsg = "야드적치단활성상태 데이터가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			
	    	jsStkCol.first();
	    	JDTORecord jrStkCol = jsStkCol.getRecord();
			
			String ydStkColActStat_DB = commUtils.trim(jrStkCol.getFieldString("YD_STK_COL_ACT_STAT"));
			//-------------------------------------------------------------
			// 야드적치단활성상태 정보 비교
			//-------------------------------------------------------------
			
			if(ydStkColActStat_DB.equals(ydStkColActStat)){
				sMsg = "야드적치단활성상태의 변경 되지 않았습니다..";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			

			//-------------------------------------------------------------
			//  TB_YD_STKBED 적치 베드 정보의  UPDATE
			//-------------------------------------------------------------

			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"		, commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			jrParam.setField("YD_STK_BED_ACT_STAT"	, ydStkColActStat);
		
			/*
			 * UPDATE TB_YD_STKBED
				      SET YD_STK_BED_ACT_STAT = :V_YD_STK_BED_ACT_STAT 
				       , MOD_DDTT  = SYSDATE
				       , MODIFIER  = :V_MODIFIER  
				 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
			 */
			int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkbedYdStrActStat", logId, mthdNm, "베드 야드적치단활성상태 변경");
			
			if(intRtnVal < 0 ){
				sMsg = "베드 야드적치단활성상태의 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}else if(intRtnVal == 0 ){
				sMsg = "베드 야드적치단활성상태 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");				
			}
			
			sMsg = "베드  야드적치단활성상태의 성공.";
			commUtils.printLog(logId, sMsg, "SL");

			//-------------------------------------------------------------
			//  TB_YD_STKLYR 적치 베드 정보의  UPDATE
			//  
			//-------------------------------------------------------------
			if("L".equals(ydStkColActStat)){
			   ydStkColActStat = "E";
			}
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"		, commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")));
			jrParam.setField("YD_STK_LYR_ACT_STAT"	, ydStkColActStat);
			
			/*
			 * UPDATE TB_YD_STKLYR            
				   SET YD_STK_LYR_ACT_STAT = :V_YD_STK_LYR_ACT_STAT 
				       , MOD_DDTT = SYSDATE
				       , MODIFIER  = :V_MODIFIER  
				WHERE YD_STK_COL_GP  = :V_YD_STK_COL_GP
			 */
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStklyrColActStat", logId, mthdNm, "단 야드적치단활성상태  변경");
			
			if(intRtnVal < 0 ){
				sMsg = "단 야드적치단활성상태의 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
				
			}else if(intRtnVal == 0 ){
				sMsg = "단 야드적치단활성상태 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			sMsg = "단 야드적치단활성상태의 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}

	/**
	 * 오퍼레이션명 : 저장집합코드변경
	 * 염용선 2019-10-29 
	 *  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord (JDTORecord : YD_WBOOK_ID , MODIFIER)
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord updYdStkbedStrGtrCd(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "저장집합코드변경[CCoilJspSeEJB.updYdStkbedStrGtrCd] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();			
		/*
		 * # 업무기준 
		 * 
		 * 체크사항
		 *  - 저장집합코드 정보가 6자리
		 *  - 변경정보에 ""이 아닌값
		 *  - 수정자 (없을경우 'updYdCoil')
		 * 
		 * 1. 기존 첫번째 베드에 있는 저장집합코드와  정보와 변경할 정보를 비교한다.
		 * 	1.1 기존정보와 변경정보가 다를경우에 처리한다.
		 *  
		 * 2. 변경정보로 해당 적치열에 포함된 적치베드 테이블을 UPDATE 한다. 
		 */
		
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");
			String sModifier 	= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydStkColGp 	= commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP"));
			String sMsg     	= "";

			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, sModifier );
			
			if(ydStkColGp.length() != 6 ){
				sMsg = "적치열정보가 올바르지 않습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			String ydStrGtrCd = commUtils.trim(rcvMsg.getFieldString("YD_STR_GTR_CD"));
			if("".equals(ydStrGtrCd)){
				sMsg = "저장집합코드 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			//-------------------------------------------------------------
			// 기존 해당 적치열에대한 외경군그룹 정보 조회
			//-------------------------------------------------------------
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP", ydStkColGp);
			jrParam.setField("YD_STK_BED_NO", "01");
						
			/*
			 * SELECT 
				 A.YD_STK_COL_GP AS YD_STK_COL_GP
				,A.YD_STK_BED_NO AS YD_STK_BED_NO
				,A.YD_STR_GTR_CD AS YD_STR_GTR_CD
				,A.REGISTER AS REGISTER
				,TO_CHAR(A.REG_DDTT, 'YYYYMMDDHH24MISS') AS REG_DDTT
				,A.MODIFIER AS MODIFIER
				,TO_CHAR(A.MOD_DDTT, 'YYYYMMDDHH24MISS') AS MOD_DDTT
				,A.DEL_YN AS DEL_YN
				,A.YD_STK_BED_TP AS YD_STK_BED_TP
				,A.YD_STK_BED_L_GP AS YD_STK_BED_L_GP
				,A.YD_STK_BED_W_GP AS YD_STK_BED_W_GP
				,A.YD_STK_BED_DIR_GP AS YD_STK_BED_DIR_GP
				,A.YD_STK_BED_ACT_STAT AS YD_STK_BED_ACT_STAT
				,A.YD_STK_BED_WHIO_STAT AS YD_STK_BED_WHIO_STAT
				,A.YD_STK_BED_USG_GP AS YD_STK_BED_USG_GP
				,A.YD_STK_BED_XAXIS AS YD_STK_BED_XAXIS
				,A.YD_STK_BED_YAXIS AS YD_STK_BED_YAXIS
				,A.YD_STK_BED_ZAXIS AS YD_STK_BED_ZAXIS
				,A.YD_STK_BED_LYR_MAX AS YD_STK_BED_LYR_MAX
				,A.YD_STK_BED_WT_MAX AS YD_STK_BED_WT_MAX
				,A.YD_STK_BED_H_MAX AS YD_STK_BED_H_MAX
				,A.YD_STK_BED_L_MAX AS YD_STK_BED_L_MAX
				,A.YD_STK_BED_W_MAX AS YD_STK_BED_W_MAX
				,A.YD_STK_BED_XAXIS_TOL AS YD_STK_BED_XAXIS_TOL
				,A.YD_STK_BED_YAXIS_TOL AS YD_STK_BED_YAXIS_TOL
				,A.YD_L_S_GRP_GP AS YD_L_S_GRP_GP
			    ,NVL(A.YD_COIL_OUTDIA_GRP_GP,B.YD_COIL_OUTDIA_GRP_GP) AS YD_COIL_OUTDIA_GRP_GP
			FROM TB_YD_STKBED A
			   , TB_YD_STKCOL B
			WHERE A.YD_STK_COL_GP=B.YD_STK_COL_GP
			  AND A.YD_STK_COL_GP = :V_YD_STK_COL_GP
			  AND A.YD_STK_BED_NO = :V_YD_STK_BED_NO 
			  AND A.DEL_YN ='N'
            */

			JDTORecordSet jsStkBed = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkcol", logId, mthdNm, "적치베드 데이터 정보");
	    	if(jsStkBed.size() < 1){
				sMsg = "적치베드 데이터가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			
	    	jsStkBed.first();
	    	JDTORecord jrStkBed = jsStkBed.getRecord();
			
			String ydStrGtrCdBefo = commUtils.trim(jrStkBed.getFieldString("YD_STR_GTR_CD"));
			
			//-------------------------------------------------------------
			//  적치 베드 정보의 저장집합코드 비교
			//-------------------------------------------------------------
			if(ydStrGtrCdBefo.equals(ydStrGtrCd)){
				sMsg = "저장집합코드 변경정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}

			//-------------------------------------------------------------
			// 적치 베드 정보의 저장집합코드 변경
			//-------------------------------------------------------------

			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP", ydStkColGp);
			jrParam.setField("YD_STR_GTR_CD", ydStrGtrCd);
			
			/*
			 * UPDATE TB_YD_STKBED
				      SET 
				          YD_STR_GTR_CD = :V_YD_STR_GTR_CD
				         ,MODIFIER      = :V_MODIFIER
				 WHERE YD_STK_COL_GP    = :V_YD_STK_COL_GP
			 */
			int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkbedYdStrGtrCd", logId, mthdNm, "적치베드 정보의 외경군그룹  변경");
			
			if(intRtnVal < 0 ){
				sMsg = " 적치베드 정보의 저장집합코드  UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}else if(intRtnVal == 0 ){
				sMsg = "적치베드 저장집합코드 의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			sMsg = "적치베드 저장집합코드 변경 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}
	
	

	/**
	 * 오퍼레이션명 : 폭구분(열정보) 변경
	 *
	 * 염용선 2019-10-29 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord (JDTORecord : YD_WBOOK_ID , MODIFIER)
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord updYdStkbedYdStkBedWGp(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "폭구분(열정보) 변경[CCoilJspSeEJB.updYdStkbedYdStkBedWGp] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();			
		/*
		 * # 업무기준 
		 * 
		 * 체크사항
		 *  - 적치열 정보가 6자리
		 *  - 변경정보에 ""이 아닌값
		 *  - 수정자 (없을경우 'updYdCoil')
		 * 
		 * 1. 기존 열 정보에 있는 외경군그룹 정보와 변경할 정보를 비교한다.
		 * 	1.1 기존정보와 변경정보가 다를경우에 처리한다.
		 *  
		 * 2. 변경정보로 적치열 테이블을 UPDATE 한다.
		 * 
		 * 3. 변경정보로 해당 적치열에 포함된 적치베드 테이블을 UPDATE 한다. 
		 */
		 
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");

			String sModifier  = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydStkColGp = commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP"));
			String sMsg       = "";

			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, sModifier );
			
			if(ydStkColGp.length() != 6 ){
				sMsg = "[" + ydStkColGp +"] 적치열정보가 올바르지 않습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
				
			}
			
			String ydStkbedYdStkBedWGp = commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_W_GP"));
			if("".equals(ydStkbedYdStkBedWGp)){
				sMsg = "폭그룹 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			//-------------------------------------------------------------
			// 기존 해당 적치열에대한 외경군그룹 정보 조회
			//-------------------------------------------------------------
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP", ydStkColGp);
			
			/*
			 * SELECT 
					YD_STK_COL_GP AS YD_STK_COL_GP
					,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS') AS REG_DDTT
					,REGISTER AS REGISTER
					,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS') AS MOD_DDTT
					,MODIFIER AS MODIFIER
					,DEL_YN AS DEL_YN
					,YD_GP AS YD_GP
					,YD_BAY_GP AS YD_BAY_GP
					,YD_EQP_GP	AS YD_EQP_GP
					,YD_STK_COL_NO AS YD_STK_COL_NO
					,YD_STK_COL_ACT_STAT AS YD_STK_COL_ACT_STAT
					,YD_STK_COL_RULE_XAXIS AS YD_STK_COL_RULE_XAXIS
					,YD_STK_COL_RULE_YAXIS AS YD_STK_COL_RULE_YAXIS
				    ,YD_STK_COL_RULE_ZAXIS AS YD_STK_COL_RULE_ZAXIS
					,YD_STK_COL_W AS YD_STK_COL_W
					,YD_STK_COL_L AS YD_STK_COL_L
					,YD_CAR_USE_GP AS YD_CAR_USE_GP
					,TRN_EQP_CD AS TRN_EQP_CD
					,CAR_NO AS CAR_NO
					,CARD_NO AS CARD_NO
					,WLOC_CD AS WLOC_CD
					,YD_PNT_CD AS YD_PNT_CD
					,YD_STK_COL_W_GP AS YD_STK_COL_W_GP
					,YD_STK_COL_H_MAX AS YD_STK_COL_H_MAX
					,YD_STK_COL_BED_L_TP AS YD_STK_COL_BED_L_TP
				    ,YD_COIL_OUTDIA_GRP_GP AS YD_COIL_OUTDIA_GRP_GP 
				    ,YD_STKBED_USG_CD
				    ,YD_STK_SKID_GP
				    ,YD_STK_COL_TOLOC_STAT
				FROM TB_YD_STKCOL
				WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
				AND DEL_YN ='N'
			 */
			JDTORecordSet jsStkCol = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkcol", logId, mthdNm, "차량정지위치 정보");
	    	if(jsStkCol.size() < 1){
				sMsg = "적치열정보 데이터가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			
	    	jsStkCol.first();
	    	JDTORecord jrStkCol = jsStkCol.getRecord();
			
			String ydStkbedYdStkBedWGpBefo = commUtils.trim(jrStkCol.getFieldString("YD_STK_COL_W_GP"));
			
			//-------------------------------------------------------------
			//  외경군그룹 정보 비교
			//-------------------------------------------------------------
			if(ydStkbedYdStkBedWGpBefo.equals(ydStkbedYdStkBedWGp)){
				sMsg = "폭그룹 의 변경정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
			}
			
			//-------------------------------------------------------------
			// 적치열 정보의 폭 그룹 UPDATE
			//-------------------------------------------------------------
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"	, ydStkColGp);
			jrParam.setField("YD_STK_COL_W_GP"  , ydStkbedYdStkBedWGp);
			
			/* 
			UPDATE TB_YD_STKCOL
			   SET 
			       YD_STK_COL_W_GP = :V_YD_STK_COL_W_GP
			     , MOD_DDTT        = SYSDATE
			     , MODIFIER        = :V_MODIFIER
			WHERE YD_STK_COL_GP    = :V_YD_STK_COL_GP
			*/
	    	int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkcol03", logId, mthdNm, "적치열 외경군 그룹의 변경");
			
			
			if(intRtnVal <0 ){
				sMsg = "적치열 정보의 외경군그룹 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
				
			} else if(intRtnVal == 0 ){
				sMsg = "적치열 외경군 그룹의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			
			sMsg = "적치열 폭 그룹의 변경 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			
			//-------------------------------------------------------------
			// 적치 베드 정보의 폭 그룹 UPDATE
			//-------------------------------------------------------------

			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"	, ydStkColGp);
			jrParam.setField("YD_STK_BED_W_GP", ydStkbedYdStkBedWGp);
			
			/*
			 * UPDATE TB_YD_STKBED
				   SET 
				      YD_STK_BED_W_GP = :V_YD_STK_BED_W_GP
				     ,MODIFIER        = :V_MODIFIER
				 WHERE YD_STK_COL_GP  = :V_YD_STK_COL_GP
			 */
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkbedYdStkBedWGp", logId, mthdNm, "적치베드 정보의 외경군그룹  변경");
			
			if(intRtnVal < 0 ){
				sMsg = "적치베드 정보의 외경군그룹 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
				
			}else if(intRtnVal == 0 ){
				sMsg = "적치베드 외경군 그룹의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
			}
			
			sMsg = "적치열 폭 그룹의 변경 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	
	/**
	 * 오퍼레이션명 : 외경군그룹(열정보) 변경
	 *
	 * 염용선 2019-10-29  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord (JDTORecord : YD_WBOOK_ID , MODIFIER)
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord updYdCoilOutdiaGrpGpCol(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "외경군그룹(열정보) 변경[CCoilJspSeEJB.updYdCoilOutdiaGrpGpCol] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();		
		/*
		 * # 업무기준 
		 * 
		 * 체크사항
		 *  - 적치열 정보가 6자리
		 *  - 변경정보에 ""이 아닌값
		 *  - 수정자 (없을경우 'updYdCoil')
		 * 
		 * 1. 기존 열 정보에 있는 외경군그룹 정보와 변경할 정보를 비교한다.
		 * 	1.1 기존정보와 변경정보가 다를경우에 처리한다.
		 *  
		 * 2. 변경정보로 적치열 테이블을 UPDATE 한다.
		 * 
		 * 3. 변경정보로 해당 적치열에 포함된 적치베드 테이블을 UPDATE 한다. 
		 */
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");
			String sModifier  = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydStkColGp = commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP"));
			String sMsg       = "";
			
			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, sModifier );

			if(ydStkColGp.length() != 6 ){
				sMsg = "적치열정보가 올바르지 않습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
				
			}
			
			String ydCoilOutdiaGp = commUtils.trim(rcvMsg.getFieldString("YD_COIL_OUTDIA_GRP_GP"));
			if("".equals(ydCoilOutdiaGp)){
				sMsg = "외경군그룹 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
				
			}
			
			//-------------------------------------------------------------
			// 기존 해당 적치열에대한 외경군그룹 정보 조회
			//-------------------------------------------------------------
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP", ydStkColGp);
			
			/*
			 * SELECT 
					YD_STK_COL_GP AS YD_STK_COL_GP
					,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS') AS REG_DDTT
					,REGISTER AS REGISTER
					,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS') AS MOD_DDTT
					,MODIFIER AS MODIFIER
					,DEL_YN AS DEL_YN
					,YD_GP AS YD_GP
					,YD_BAY_GP AS YD_BAY_GP
					,YD_EQP_GP	AS YD_EQP_GP
					,YD_STK_COL_NO AS YD_STK_COL_NO
					,YD_STK_COL_ACT_STAT AS YD_STK_COL_ACT_STAT
					,YD_STK_COL_RULE_XAXIS AS YD_STK_COL_RULE_XAXIS
					,YD_STK_COL_RULE_YAXIS AS YD_STK_COL_RULE_YAXIS
				    ,YD_STK_COL_RULE_ZAXIS AS YD_STK_COL_RULE_ZAXIS
					,YD_STK_COL_W AS YD_STK_COL_W
					,YD_STK_COL_L AS YD_STK_COL_L
					,YD_CAR_USE_GP AS YD_CAR_USE_GP
					,TRN_EQP_CD AS TRN_EQP_CD
					,CAR_NO AS CAR_NO
					,CARD_NO AS CARD_NO
					,WLOC_CD AS WLOC_CD
					,YD_PNT_CD AS YD_PNT_CD
					,YD_STK_COL_W_GP AS YD_STK_COL_W_GP
					,YD_STK_COL_H_MAX AS YD_STK_COL_H_MAX
					,YD_STK_COL_BED_L_TP AS YD_STK_COL_BED_L_TP
				    ,YD_COIL_OUTDIA_GRP_GP AS YD_COIL_OUTDIA_GRP_GP 
				    ,YD_STKBED_USG_CD
				    ,YD_STK_SKID_GP
				    ,YD_STK_COL_TOLOC_STAT
				FROM TB_YD_STKCOL
				WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
				AND DEL_YN ='N'
			 */
			JDTORecordSet jsStkCol = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkcol", logId, mthdNm, "적치열정보 정보");
	    	if(jsStkCol.size() < 1){
				sMsg = "적치열정보 데이터가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
			}
			
			
	    	jsStkCol.first();
	    	JDTORecord jrStkCol = jsStkCol.getRecord();
			
			String ydCoilOutdiaGpBefo = commUtils.trim(jrStkCol.getFieldString("YD_COIL_OUTDIA_GRP_GP"));
			//-------------------------------------------------------------
			//  외경군그룹 정보 비교
			//-------------------------------------------------------------
			
			if(ydCoilOutdiaGpBefo.equals(ydCoilOutdiaGp)){
				sMsg = "외경군 그룹의 변경정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;
				
			}
			
			//-------------------------------------------------------------
			// 적치열 정보의 외경군그룹 UPDATE
			//-------------------------------------------------------------
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"			, ydStkColGp);
			jrParam.setField("YD_COIL_OUTDIA_GRP_GP"	, ydCoilOutdiaGp);
			
			/* 
			UPDATE TB_YD_STKCOL
			   SET 
			       YD_COIL_OUTDIA_GRP_GP = :V_YD_COIL_OUTDIA_GRP_GP
			     , MOD_DDTT              = SYSDATE
			     , MODIFIER              = :V_MODIFIER
			WHERE YD_STK_COL_GP          = :V_YD_STK_COL_GP
			*/
	    	int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkcol02", logId, mthdNm, "적치열 외경군 그룹의 변경");
			
			if(intRtnVal <0 ){
				sMsg = "적치열 정보의 외경군그룹 UPDATE ERROR";
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
			} else if(intRtnVal == 0 ){
				sMsg = "적치열 외경군 그룹의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
			}
			
			
			sMsg = "적치열 외경군 그룹의 변경 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			
			
			//-------------------------------------------------------------
			// 적치 베드 정보의 외경군그룹 UPDATE
			//-------------------------------------------------------------

			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"			, ydStkColGp);
			jrParam.setField("YD_COIL_OUTDIA_GRP_GP"	, ydCoilOutdiaGp);
			/*

			UPDATE TB_YD_STKBED
			   SET 
			      YD_COIL_OUTDIA_GRP_GP = :V_YD_COIL_OUTDIA_GRP_GP
			     ,MOD_DDTT              = SYSDATE
			     ,MODIFIER              = :V_MODIFIER
			 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
			*/
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkbedYdCoilOutdiaGrpGp", logId, mthdNm, "적치베드 외경군 그룹의 변경");
			
			if(intRtnVal < 0 ){
				sMsg = "적치베드 정보의 외경군그룹 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	
			}else if(intRtnVal == 0 ){
				sMsg = "적치베드 외경군 그룹의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
					
			}
			
			sMsg = "적치열 외경군 그룹의 변경 성공.";
			commUtils.printLog(logId, sMsg, "SL");
			
			//-------------------------------------------------------------
			// 적치 베드 정보의 외경군그룹 UPDATE  --> TB_YD_STKLYR
			//-------------------------------------------------------------
			jrParam = commUtils.getParam(logId, mthdNm, sModifier );
			jrParam.setField("YD_STK_COL_GP"			, ydStkColGp);
			jrParam.setField("YD_COIL_OUTDIA_GRP_GP"	, ydCoilOutdiaGp);
			/*
             UPDATE TB_YD_STKLYR A
               SET YD_STK_LYR_ACT_STAT =DECODE(YD_STK_LYR_ACT_STAT,'N','N',
                                    (CASE --WHEN SUBSTR(YD_STK_COL_GP,2,1) IN ('A','B','C') THEN YD_STK_LYR_ACT_STAT                                    
                                    WHEN (SELECT YD_STK_SKID_GP FROM TB_YD_STKCOL C WHERE C.YD_STK_COL_GP=A.YD_STK_COL_GP)='F' THEN YD_STK_LYR_ACT_STAT
                                    WHEN YD_STK_BED_NO = '01' THEN 'E'
                                    WHEN (SELECT MAX(YD_STK_BED_NO) FROM TB_YD_STKLYR C WHERE C.YD_STK_COL_GP=A.YD_STK_COL_GP)>35 AND SUBSTR(YD_STK_COL_GP,2,1) IN ('D','E','F','H','G')
                                        THEN --H,G동 가변스키드
                                             (CASE 
                                        
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'A' AND MOD(TO_NUMBER(YD_STK_BED_NO),2) = 1 
                                                    AND NOT(YD_STK_BED_NO ='21' AND YD_STK_LYR_NO='002')  AND YD_STK_BED_NO<=21 THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'B' AND MOD(TO_NUMBER(YD_STK_BED_NO),3) = 1 
                                                    AND NOT(YD_STK_BED_NO ='31' AND YD_STK_LYR_NO='002')  AND YD_STK_BED_NO<=31  THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'C' AND MOD(TO_NUMBER(YD_STK_BED_NO),4) = 1 
                                                    AND NOT(YD_STK_BED_NO ='41' AND YD_STK_LYR_NO='002')  AND YD_STK_BED_NO<=41 THEN 'E' 
                                            ELSE 'C' END) 
                                    WHEN (SELECT MAX(YD_STK_BED_NO) FROM TB_YD_STKLYR C WHERE C.YD_STK_COL_GP=A.YD_STK_COL_GP)>35 AND SUBSTR(YD_STK_COL_GP,2,1) IN ('A','B','C')
                                        THEN --A,B,C동 가변스키드
                                             (CASE 
                                        
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'A' AND MOD(TO_NUMBER(YD_STK_BED_NO),2) = 1 
                                                    AND NOT(YD_STK_BED_NO ='41' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'B' AND MOD(TO_NUMBER(YD_STK_BED_NO),3) = 1 
                                                    AND NOT(YD_STK_BED_NO ='40' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'C' AND MOD(TO_NUMBER(YD_STK_BED_NO),4) = 1 
                                                    AND NOT(YD_STK_BED_NO ='41' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            ELSE 'C' END)         
                                            
                                            
                                       ELSE --가변사용 
                                           (CASE 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'A' AND MOD(TO_NUMBER(YD_STK_BED_NO),2) = 1 
                                                    AND NOT(YD_STK_BED_NO ='35' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'B' AND MOD(TO_NUMBER(YD_STK_BED_NO),3) = 1 
                                                    AND NOT(YD_STK_BED_NO ='34' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            WHEN :V_YD_COIL_OUTDIA_GRP_GP = 'C' AND MOD(TO_NUMBER(YD_STK_BED_NO),4) = 1 
                                                    AND NOT(YD_STK_BED_NO ='33' AND YD_STK_LYR_NO='002') THEN 'E' 
                                            ELSE 'C' END) 
                                           
                                      END)
                                    )
                , MODIFIER = :V_MODIFIER
 	            , MOD_DDTT = SYSDATE
             WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
			*/
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStklyrACT_STAT", logId, mthdNm, "적치베드 외경군 그룹의 변경");
			
			if(intRtnVal < 0 ){
				sMsg = "TB_YD_STKLYR 적치베드 정보의 외경군그룹 UPDATE ERROR";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				return jrRtn;	 
			}else if(intRtnVal == 0 ){
				sMsg = "TB_YD_STKLYR 적치베드 외경군 그룹의 변경 할 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
			}
			
			sMsg = "TB_YD_STKLYR 적치열 외경군 그룹의 변경 성공.";
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;	
		
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}			
	}


	/**
	 * 야드적치열정보 수정 
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdColStsSet(GridData gdReq) throws DAOException {
		String mthdNm = "야드적치열정보 수정[CCoilJspSeEJB.updCoilYdColStsSet]  < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();	
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");
			String sModifier	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			JDTORecord jrRtn    = commUtils.getParam(logId, mthdNm, sModifier);	
			JDTORecord jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {
						
				//설비 ID 및 수정항목 세팅 
				jrParam.setField("YD_STK_COL_GP"       , commUtils.nvl(commUtils.getValue(gdReq, "YD_STK_COL_GP"		    , i),    ""));
				jrParam.setField("YD_STK_COL_ACT_STAT" , commUtils.nvl(commUtils.getValue(gdReq, "YD_STK_COL_ACT_STAT"		, i),    ""));
				/*
				 * UPDATE TB_YD_STKCOL
					   SET        
					        MOD_DDTT = SYSDATE             
					       ,MODIFIER   = :V_MODIFIER         
					       ,YD_STK_COL_ACT_STAT = :V_YD_STK_COL_ACT_STAT
					   WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
				 */
				int iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkcol", logId, mthdNm, "야드적치열정보 수정");
				
				commUtils.printLog(logId, mthdNm, "intRtnVal=="+iRtnVal);				
			}	
			
			jrRtn.setField("RTN_CD" , "1");	
			jrRtn.setField("RTN_MSG", "정상적으로 처리되었습니다.");
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}	
	
