	/**
	 *   도착 실적 
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return String
	 * @throws DAOException
	 */
	public JDTORecord procTcarStsSetTcarC(GridData gdReq) throws DAOException {			
		String mthdNm = "대차스케줄관리--대차 도착 실적[CCoilJspSeEJB.procTcarStsSetTcarC]<" + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm ,"S+");
			
			String sModifier 	 = commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String ydLocGp 		 = commUtils.trim(gdReq.getParam("YD_LOC_GP")); // 야드구분
			String ydCarProgStat = commUtils.trim(commUtils.getValue(gdReq, "YD_CAR_PROG_STAT" , 0)); 
			String ydEqpId   	 = commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID", 0));
			String sCurrBayGp    = commUtils.nvl (commUtils.getValue(gdReq, "NEW_YD_CURR_BAY_GP" , 0),"");
			String sMsg    		 = "";
			String ydAimYdGp	 = "";

			if ("".equals(ydCarProgStat)){
				
				sMsg = "대차 도착 실적 호출 - 대차진행상태(YD_CAR_PROG_STAT)값이 존재하지 않습니다. ";
				commUtils.printLog(logId, sMsg ,"SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				
				return jrRtn;
				
			} else if ("1".equals(ydCarProgStat)){
				// 상차/공차 출발일경우 - 도착실적(공차) 
				ydAimYdGp = commUtils.nvl(commUtils.getValue(gdReq, "YD_CARLD_STOP_LOC", 0),"");

			} else if ("A".equals(ydCarProgStat)){

				// 영차 출발일경우 - 도착실적(영차)
				ydAimYdGp = commUtils.nvl(commUtils.getValue(gdReq, "YD_CARUD_STOP_LOC" , 0),"");

			} else {
				// 야드차량진행상태가 맞지 않습니다 
				sMsg = "대차 도착 실적 호출 - 대차진행상태(YD_CAR_PROG_STAT[" + commUtils.nvl(commUtils.getValue(gdReq, "YD_CAR_PROG_STAT", 0),"") + "])값이 맞지 않습니다. ";
				commUtils.printLog(logId, sMsg ,"SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				
				return jrRtn;
			}
			
			if ("".equals(ydLocGp)){
				//공장 야드 구분이 없습니다 
				sMsg = "대차 도착 실적 호출 - 공장 야드 구분이 없습니다 ";
				commUtils.printLog(logId, sMsg ,"SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);
				
				return jrRtn;
			}
			
			JDTORecord jrParam     = commUtils.getParam(logId, mthdNm, sModifier);	
			jrParam.setField("YD_EQP_ID"		, ydEqpId);
			jrParam.setField("YD_BAY_GP"		, sCurrBayGp);
			jrParam.setField("YD_MOVE_GP"		, "E");
			jrParam.setField("YD_TCAR_MOVE_DIR"	, "F");
			jrParam.setField("YD_TCAR_CURR_BAY"	, sCurrBayGp);
			jrParam.setField("YD_TCAR_AIM_BAY"	, ydAimYdGp);

			EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);					
			JDTORecord jrRtnRec = (JDTORecord)ejbConn.trx( "rcvY5YDL011" , new Class[] { JDTORecord.class }, new Object[] { jrParam });
	
			String rtnCd	 = commUtils.nvl(jrRtnRec.getFieldString("RTN_CD"), "0");
			String rtnMg	 = commUtils.nvl(jrRtnRec.getFieldString("RTN_MSG"), "");
			commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMg, "SL");
			if ("1".equals(rtnCd)) {
				jrRtn = commUtils.addSndData(jrRtn,jrRtnRec);
			} else {
				sMsg = "대차 출발 실적 호출 처리 실패";
				commUtils.printLog(logId, sMsg ,"SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, rtnMg);
				
				return jrRtn;	 		
			}
			
			commUtils.printLog(logId, mthdNm, "S-");
			sMsg = "대차 출발 실적 호출 완료.";
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sMsg);
			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	

