	/**
	 * 이적/이송 대상 대차상태 체크 
	 * @ejb.interface-method
	 * @param JDTORecord[]
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord getStkColTCarChk(JDTORecord rcvMsg) throws DAOException{
		String mthdNm = "이적/이송 대상 대차상태 체크 [CCoilJspSeEJB.getStkColTCarChk] < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();	
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();	//전문 Return
		
		try{
			
			commUtils.printLog(logId, mthdNm, "S+");
			String sModifier   = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydLocGp     = commUtils.nvl (rcvMsg.getFieldString("YD_LOC_GP"),"");
			String sFROM       = commUtils.nvl (rcvMsg.getFieldString("FROM_YD_STK_COL_GP"),"");
			String sTO         = commUtils.nvl (rcvMsg.getFieldString("TO_YD_STK_COL_GP"),"");
			String sTcar       = commUtils.nvl (rcvMsg.getFieldString("YD_WRK_PLAN_TCAR"),"");

			String ydEqpStat   = "";
			String ydCurrBayGp = "";
			String sFrombayGp  = sFROM.substring(1, 2);
			String sTobayGp    = sTO.substring(1, 2);
			
			commUtils.printLog(logId, "sFROM=="+sFROM, "SL");
			commUtils.printLog(logId, "sTO=="+sTO, "SL");
			commUtils.printLog(logId, "sTcar=="+sTcar, "SL");
			commUtils.printLog(logId, "ydLocGp=="+ydLocGp, "SL");
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			if (!sFrombayGp.equals(sTobayGp)) { // 같은 동일때는 대차가 필요 없음
					// **** 선택된 대차로 체크 ****
				
				jrParam.setField("YD_EQP_ID", sTcar);

				/*
				 * SELECT YD_EQP_ID        -- 설비ID
				      ,YD_GP            -- 야드구분
				      ,YD_BAY_GP        -- 동구분
				      ,YD_EQP_GP        -- 야드설비구분
				      ,YD_EQP_NO        -- 야드설비번호
				      ,YD_CURR_BAY_GP   -- 현재동 
				      ,YD_TCAR_WRK_ABLE_BAY1 ||DECODE(YD_TCAR_WRK_ABLE_BAY1,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY2 ||DECODE(YD_TCAR_WRK_ABLE_BAY2,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY3 ||DECODE(YD_TCAR_WRK_ABLE_BAY3,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY4 ||DECODE(YD_TCAR_WRK_ABLE_BAY4,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY5 ||DECODE(YD_TCAR_WRK_ABLE_BAY5,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY6 ||DECODE(YD_TCAR_WRK_ABLE_BAY6,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY7 ||DECODE(YD_TCAR_WRK_ABLE_BAY7,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY8 
					  AS YD_TCAR_WRK_ABLE_BAY
				  FROM USRYDA.TB_YD_EQP
				 WHERE YD_EQP_ID =:V_YD_EQP_ID
				   AND DEL_YN = 'N'
				 */
				JDTORecordSet jsYdEqp = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarInfo", logId, mthdNm, "대차상태 조회");
				
				if(jsYdEqp == null || jsYdEqp.size() < 1){
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, "대차상태 조회에 실패 하였습니다.");	
					return jrRtn;
					
				} else {
					jsYdEqp.first();
					JDTORecord jrYdEqp = jsYdEqp.getRecord(0);	
					commUtils.printLog(logId, ydLocGp+"=ydLocGp===recTmp YD_GP======="+jrYdEqp.getFieldString("YD_GP"), "SL");
					ydCurrBayGp = jrYdEqp.getFieldString("YD_CURR_BAY_GP");
					  ydEqpStat = jrYdEqp.getFieldString("YD_EQP_STAT");
					  
					//REQ202407592703 야드설비상태(B:고장, N:정상, R:복구, P:롤이송 등)   
					if("P".equals(ydEqpStat)||"B".equals(ydEqpStat)){
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, "현재 대차가 고장 또는 롤이송 중이라 사용 할 수 없습니다");	
						return jrRtn;
					}
					  
					
					if(!jrYdEqp.getFieldString("YD_GP").equals(ydLocGp)){ //현재 대차가 위치한 야드 체크  
						// 현재 야드에 없을시 에러리턴
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, "현재 야드에 대차가 존재 하지 않습니다.");	
						return jrRtn;
					}
					// 대차 이동구간 체크 
					int fn = jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sFrombayGp);
					int tn = jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sTobayGp);
					
					commUtils.printLog(logId, sFrombayGp, "SL");
					commUtils.printLog(logId, sTobayGp, "SL");
					commUtils.printLog(logId, jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY"), "SL");
					commUtils.printLog(logId, tn+"====tn==fn==="+fn, "SL");
					
					if( fn < 0 || tn < 0){
						// from동과 To동이 대차 이동구간에 포함 되지 않을 경우 error 
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, "설정된 대차 이동구간이 일치하지 않습니다.<br>이동가능구간 : "+jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY"));	
						return jrRtn;
					}
				}
			}

			jrRtn.setField("RTN_CD" 		, "1");	
			jrRtn.setField("RTN_MSG" 		, "이적/이송 대상 대차상태 체크");
			jrRtn.setField("YD_CURR_BAY_GP" , ydCurrBayGp);	
			commUtils.printLog(logId, mthdNm, "S-");
			
			return jrRtn;
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
		
		
	}

	
	/**
	 * 이적/이송 대상 폭구분 체크 
	 * * 작성자 : 염용선
	 * 작성일 : 2019.09.06
	 * @ejb.interface-method
	 * @param JDTORecord[]
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord getStkColWidthGp(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "이적/이송 대상 폭구분 체크[CCoilJspSeEJB.getStkColWidthGp] <" + rcvMsg.getResultMsg();;
		String logId  = rcvMsg.getResultCode();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();	//전문 Return
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");
			
			String  sModifier  = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String	sFROM      = commUtils.trim(rcvMsg.getFieldString("FROM_YD_STK_COL_GP"));
			String	sTO        = commUtils.trim(rcvMsg.getFieldString("TO_YD_STK_COL_GP"));
			String	sTcar      = commUtils.trim(rcvMsg.getFieldString("YD_WRK_PLAN_TCAR"));
			String	sFrombayGp = sFROM.substring(1, 2);
			String	sTobayGp   = sTO.substring(1, 2);
			String  ydEqpStat  = "";
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);

			JDTORecordSet jsYdEqp  = JDTORecordFactory.getInstance().createRecordSet("Temp");
				
			if (!sFrombayGp.equals(sTobayGp)) { // 같은 동일때는 대차가 필요 없음
				// **** 선택된 대차로 체크 ****
				jrParam.setField("YD_EQP_ID", sTcar);
	
				/*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarInf
				SELECT YD_EQP_ID        -- 설비ID
				     , YD_GP                -- 야드구분
				     , YD_LOC_GP        -- 야드구분
				     , YD_BAY_GP        -- 동구분
				     , YD_EQP_GP        -- 야드설비구분
				     , YD_EQP_NO        -- 야드설비번호
				     , YD_CURR_BAY_GP   -- 현재동 
				     , YD_TCAR_WRK_ABLE_BAY1 ||DECODE(YD_TCAR_WRK_ABLE_BAY1,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY2 ||DECODE(YD_TCAR_WRK_ABLE_BAY2,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY3 ||DECODE(YD_TCAR_WRK_ABLE_BAY3,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY4 ||DECODE(YD_TCAR_WRK_ABLE_BAY4,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY5 ||DECODE(YD_TCAR_WRK_ABLE_BAY5,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY6 ||DECODE(YD_TCAR_WRK_ABLE_BAY6,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY7 ||DECODE(YD_TCAR_WRK_ABLE_BAY7,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY8 
					  AS YD_TCAR_WRK_ABLE_BAY
				  FROM USRYDA.TB_YD_EQP
				 WHERE YD_EQP_ID =:V_YD_EQP_ID
				   AND DEL_YN = 'N'
				 */
				jsYdEqp = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarInfo", logId, mthdNm, "대차상태 조회");
				if (jsYdEqp == null || jsYdEqp.size() == 0) {
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, "대차상태 조회에 실패 하였습니다.");	
					return jrRtn;
				} else {
					jsYdEqp.first();
					JDTORecord jrYdEqp = jsYdEqp.getRecord(0);	
	
					ydEqpStat = jrYdEqp.getFieldString("YD_EQP_STAT");
					  
					//REQ202407592703 야드설비상태(B:고장, N:정상, R:복구, P:롤이송 등)   
					if("P".equals(ydEqpStat)||"B".equals(ydEqpStat)){
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, "현재 대차가 고장 또는 롤이송 중이라 사용 할 수 없습니다.");	
						return jrRtn;
					}
					
					if(!jrYdEqp.getFieldString("YD_GP").equals(sFROM.substring(0, 1))){ //현재 대차가 위치한 야드 체크  
						// 현재 야드에 없을시 에러리턴
						jrRtn.setField("RTN_CD" 	, "-1");	
						jrRtn.setField("RTN_MSG" 	, "현재 야드에 대차가 존재 하지 않습니다.");	
						return jrRtn;
					}
					// 대차 이동구간 체크 
					int fn = jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sFrombayGp);
					int tn = jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sTobayGp);
					if( fn < 0 || tn < 0){
						// from동과 To동이 대차 이동구간에 포함 되지 않을 경우 error 
						jrRtn.setField("RTN_CD" 	, "-2");	
						jrRtn.setField("RTN_MSG" 	, "설정된 대차 이동구간이 일치하지 않습니다.<br>이동가능구간 : "+jrYdEqp.getFieldString("YD_TCAR_WRK_ABLE_BAY"));	
						return jrRtn;
					}
				}
			}
				
			//////////////////////////////////////////////////////////////////////////////////////////////////////
			// 폭구분 체크 	
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("FROM_STK_COL_GP",		sFROM);
			jrParam.setField("TO_STK_COL_GP",		sTO);
			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStkColWidthGp 
			SELECT A.YD_STK_COL_GP
			     , A.YD_STK_COL_W_GP
			     , B.YD_STK_COL_GP 
			     , B.YD_STK_COL_W_GP 
			     , (CASE WHEN A.YD_COIL_OUTDIA_GRP_GP = B.YD_COIL_OUTDIA_GRP_GP THEN 1
			       ELSE 0 END) AS GRP_GP_CHK
			     , (CASE WHEN A.YD_STK_COL_W_GP = B.YD_STK_COL_W_GP OR A.YD_STK_COL_GP LIKE 'H%' THEN 1
			       ELSE 0 END) AS STAT_CHK
			  FROM (SELECT YD_STK_COL_GP
			             , YD_STK_COL_W_GP 
			             , YD_COIL_OUTDIA_GRP_GP
			          FROM TB_YD_STKCOL
			         WHERE YD_STK_COL_GP = :V_FROM_STK_COL_GP --'JD0801'
			       ) A
			      ,(SELECT YD_STK_COL_GP
			             , YD_STK_COL_W_GP 
			             , YD_COIL_OUTDIA_GRP_GP
			          FROM TB_YD_STKCOL
			         WHERE YD_STK_COL_GP = :V_TO_STK_COL_GP --'JD0101'
			       ) B
			 */
			JDTORecordSet jsWidthChk = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStkColWidthGp", logId, mthdNm, "폭구분 체크");
			if(jsWidthChk == null || jsWidthChk.size() < 1){				
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, "폭구분 조회에 실패 하였습니다.");	
				return jrRtn;
			}else{
				jsWidthChk.first();
				JDTORecord jrWidthChk = jsWidthChk.getRecord(0);

				commUtils.printLog(logId, "STAT_CHK:"+jrWidthChk.getFieldString("STAT_CHK"), "SL");
				if("0".equals(jrWidthChk.getFieldString("STAT_CHK"))){ // 이적불가
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, "폭구분이 일치하지 않아 이적이 불가 합니다.");	
					return jrRtn;
				}
			}
			
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, "");
			
			return jrRtn;
		}catch (Exception e){
			e.printStackTrace();
			throw new DAOException(getClass().getName() + e.getMessage(),e);
		}
		
		
	}
	
	
	

	/**
	 * 오퍼레이션명 : 작업예약으로 대차이동지시 Check [CoilTransEqpSchSeEJB]
	 *  염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg, rsWbooId
	 * @return intRtnVal
	 * @throws JDTOException
	 */
	public JDTORecord chkTCarMoveWrkBook(JDTORecord rcvMsg) throws JDTOException  {
	    String mthdNm = "대차이동지시 Check[CCoilJspSeEJB.chkTCarMoveWrkBook] < " + rcvMsg.getResultMsg();
	    String logId  = rcvMsg.getResultCode();
	    
		JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();		
		String sMsg         = "";
		
	    try {
	    	
	    	String ydWbookId = commUtils.trim(rcvMsg.getFieldString("YD_WBOOK_ID"));
	    	String sModifier = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));

	    	commUtils.printLog(logId, mthdNm, "S+");
	    	
	    	int intRtnVal 		= 0; 			
	    	
	    	//작업예약id로 작업예약Table를 조회한다.
	    	JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
	    	jrParam.setField("YD_WBOOK_ID", ydWbookId);
	    	
	    	/*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqpTCarStatCoil
	    	SELECT A.YD_GP 
	    	     , A.YD_EQP_ID  
	    	     , A.YD_CURR_BAY_GP   
	    	     , B.YD_BAY_GP
	    	     , B.YD_AIM_BAY_GP
	    	     , A.YD_EQP_STAT     --야드설비상태 
	    	     , A.YD_EQP_WRK_MODE --야드설비작업MODE   
	    	     , C.YD_CAR_PROG_STAT 
	    	     , C.YD_TCAR_SCH_ID 
	    	  FROM TB_YD_EQP A
	    	     , TB_YD_WRKBOOK B  
	    	     , (
	    	        SELECT * 
	    	          FROM
	    	          (     
	    	           SELECT A2.YD_GP
	    	                , A1.YD_EQP_ID
	    	                , A1.YD_TCAR_SCH_ID 
	    	                , A1.YD_CAR_PROG_STAT 
	    	                , (SELECT COUNT(*) 
	    	                     FROM TB_YD_WRKBOOK 
	    	                    WHERE YD_WBOOK_ID = A1.YD_CARLD_WRK_BOOK_ID 
	    	                      AND DEL_YN = 'N') WRKBOOK_CNT
	    	                FROM TB_YD_TCARSCH A1
	    	                   , TB_YD_EQP A2 
	    	               WHERE A1.YD_EQP_ID = A2.YD_EQP_ID
	    	                 AND A1.YD_CAR_PROG_STAT ='0' 
	    	                 AND A1.DEL_YN = 'N'  
	    	          ) WHERE WRKBOOK_CNT = '0'
	    	        ) C
	    	  WHERE 1=1
	    	    AND A.YD_EQP_ID LIKE 'JXTC'||'%'
	    	    AND A.YD_EQP_ID = C.YD_EQP_ID
	    	    AND A.YD_EQP_ID = B.YD_WRK_PLAN_TCAR 
	    	    AND A.YD_EQP_STAT <> 'B'
	    	    AND (  B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY1,'*') 
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY2,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY3,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY4,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY5,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY6,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY7,'*')
	    	        OR B.YD_BAY_GP = NVL(A.YD_TCAR_WRK_ABLE_BAY8,'*')
	    	        )
	    	    AND ( B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY1,'*') 
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY2,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY3,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY4,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY5,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY6,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY7,'*')
	    	        OR B.YD_AIM_BAY_GP  = NVL(A.YD_TCAR_WRK_ABLE_BAY8,'*')
	    	        )
	    	    AND A.YD_GP       = B.YD_GP
	    	    AND A.YD_GP       = C.YD_GP
	    	    AND B.YD_WBOOK_ID = :V_YD_WBOOK_ID
	    	    AND B.DEL_YN = 'N'
		   	*/
	    	JDTORecordSet jsYdEqp = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqpTCarStatCoil", logId, mthdNm, "작업예약id로 작업예약Table를 조회한다");
	    	sMsg="대차 상태 조회 후 리턴 하지 않고 계속 처리 진행";
			commUtils.printLog(logId, "YD_CAR_PROG_STAT: "+jsYdEqp.size()+"==TB_YD_TCARSCH========"+sMsg, "SL");
			if(jsYdEqp.size() <= 0) {
				jrRtn.setField("SND_FLAG" , "N");	
				jrRtn.setField("RTN_CD"   , "1");	
				return jrRtn;
				
			}

			jsYdEqp.absolute(1);
			JDTORecord jrYdEqp = JDTORecordFactory.getInstance().create();
			jrYdEqp.setRecord(jsYdEqp.getRecord());
	    	

	    	String ydTcarSchId	= commUtils.trim(jrYdEqp.getFieldString("YD_TCAR_SCH_ID"));	
	    	String ydGp			= commUtils.trim(jrYdEqp.getFieldString("YD_GP"));	
	    	String ydBayGp		= commUtils.trim(jrYdEqp.getFieldString("YD_BAY_GP"));	
	    	String ydCurrBayGp	= commUtils.trim(jrYdEqp.getFieldString("YD_CURR_BAY_GP"));	

//	    	jrParam = commUtils.getParam(logId, mthdNm, sModifier);
//	    	jrParam.setField("YD_TCAR_SCH_ID"      , ydTcarSchId);
//	    	jrParam.setField("YD_CARLD_WRK_BOOK_ID", ydWbookId);
//
//    		 /* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdTcarschWrkBookId
//    		  * UPDATE TB_YD_TCARSCH
//				   SET MODIFIER = :V_MODIFIER
//				     , MOD_DDTT = SYSDATE
//				     , YD_CARLD_WRK_BOOK_ID = :V_YD_CARLD_WRK_BOOK_ID
//				  WHERE YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
//    		  */
//    		intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdTcarschWrkBookId", logId, mthdNm, "대차스케줄 수정");
//			
//			if(intRtnVal <= 0) {
//				sMsg="대차스케줄 수정 실패";
//				commUtils.printLog(logId, sMsg, "SL");
//				jrRtn.setField("RTN_CD" , "0");	
//				jrRtn.setField("RTN_MSG", sMsg);	
//				return jrRtn;
//				
//			}
	    	
			
			sMsg="작업예약으로 대차이동지시 완료";
			commUtils.printLog(logId, sMsg  , "SL");
			jrRtn.setField("RTN_CD" 		 , "1");	
			jrRtn.setField("RTN_MSG"		 , sMsg);	
			jrRtn.setField("YD_TCAR_SCH_ID"  , ydTcarSchId);	
			jrRtn.setField("YD_GP" 		     , ydGp);	
			jrRtn.setField("YD_AIM_BAY_GP"   , ydBayGp);
			
			
			/**************************************
			 * 현위치와 목적동이 일치 하면 송신 하지 않는다
			 ***************************************/ 
			if (ydBayGp.equals(ydCurrBayGp)) {
				jrRtn.setField("SND_FLAG" 		, "N");	
			} else {
				jrRtn.setField("SND_FLAG" 		, "Y");	
			}
			
	    	
		}catch(Exception e){
			commUtils.printLog(logId, "작업예약으로 대차이동지시 Error :", "SL");
			jrRtn.setField("RTN_CD" , "0");	
			jrRtn.setField("RTN_MSG", sMsg);	
			return jrRtn;
		}
		
		commUtils.printLog(logId, mthdNm, "S-");
		return jrRtn;
	} 
	

	/**
	 * (작업)크레인 변경 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return Boolean
	 * @throws DAOException
	 */
	public JDTORecord wrkCrnChangeJ(GridData gdReq) throws DAOException {
    	String mthdNm = "(작업)크레인 변경[CCoilJspSeEJB.wrkCrnChange] < " + gdReq.getNavigateValue();
    	String logId  = gdReq.getIPAddress();
		
    	JDTORecord jrRtn = JDTORecordFactory.getInstance().create(); 
	 	
		try {

			commUtils.printLog(logId, mthdNm, "S+");

			String sLogMsg          = "";
	    	String ydGp				= "";
	    	String ydEqpId 			= ""; 
			String ydEqpStat 		= "";
	    	String ydSchCd   		= "";
	    	String sChgYdEqpStat    = "";
	    	String sChkWrkProgStat  = "W";
	    	String ydEqpAutoCrnMode = "";
	    	String ydEqpAutoCrnYN   = "";
	    	String ydWrkProgStat    = ""; 
	    	String szRtnValue 		= CConstant.RETN_CD_SUCCESS;
	    	String sModifier        = commUtils.trim(gdReq.getParam("YD_USER_ID"));
	    	
	    	int rowCnt = gdReq.getHeader("CHECK").getRowCount();
	    	
	    	String rtnCd  = "";
	    	String rtnMsg = "";
			
			for (int i = 0; i < rowCnt; i++ ) {
				ydEqpId 	  = commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID", i));
				ydWrkProgStat = commUtils.trim(commUtils.getValue(gdReq, "YD_WRK_PROG_STAT_CD", i));
				ydSchCd       = commUtils.trim(commUtils.getValue(gdReq, "YD_SCH_CD", i));
			}
			
			JDTORecord jrEqpInfo = commUtils.getParam(logId, mthdNm, sModifier);
			jrEqpInfo.setField("YD_EQP_ID" , ydEqpId);
			// 해당 설비 szChgCrn 로 설비 정보 조회
			/* 
			SELECT *
			  FROM TB_YD_EQP
			 WHERE YD_EQP_ID = :V_YD_EQP_ID
			   AND DEL_YN = 'N'
		     */
			JDTORecordSet jsEqpId = commDao.select(jrEqpInfo, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "야드설비작업MODE 조회");
			
			JDTORecord jrEqpId = JDTORecordFactory.getInstance().create();
			if (jsEqpId.size() > 0) {
				jsEqpId.first();
				jrEqpId = jsEqpId.getRecord();
				//설비 상태
				ydEqpStat 		 = commUtils.trim(jrEqpId.getFieldString("YD_EQP_STAT"));
				ydEqpAutoCrnMode = commUtils.trim(jrEqpId.getFieldString("YD_EQP_AUTO_CRN_MODE")); //AutoCrn 상태
				ydEqpAutoCrnYN   = commUtils.trim(jrEqpId.getFieldString("YD_EQP_WRK_MODE2")); //AutoCrn 여부
				
				if(CConstant.YD_EQP_STAT_UP_CMPL.equals(ydWrkProgStat)){
					szRtnValue = "크레인 ["+  ydEqpId +"]가 권상완료 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
					
				}else if(CConstant.YD_EQP_STAT_DN_WO.equals(ydWrkProgStat)){
					szRtnValue = "크레인 ["+  ydEqpId +"]가 권하지시 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
					
				}else if(CConstant.YD_EQP_STAT_DN_CMPL.equals(ydWrkProgStat)){
					szRtnValue = "크레인 ["+  ydEqpId +"]가 권하완료 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
				}else if ("A".equals(ydEqpAutoCrnYN) || "R".equals(ydEqpAutoCrnYN)) {
					if (!"W".equals(ydWrkProgStat) && !"S".equals(ydWrkProgStat) ) {
						if (!"4".equals(ydEqpAutoCrnMode) && !"B".equals(ydEqpStat) ) {
							szRtnValue = "무인크레인 [" + ydEqpId + "]이 일시정지이거나 고장상태가 아니면 상태를 변경 할 수 없습니다.";
							jrRtn.setField("RTN_CD" , "0");
							jrRtn.setField("RTN_MSG" , szRtnValue);
							return jrRtn;
						}
					}
				}
			}
			
			//변경 크레인을 가져 온다********************************************************
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_SCH_CD" , ydSchCd); 
			/*
			 * SELECT YD_SCH_CD
			     , DEL_YN
			     , YD_GP
			     , YD_BAY_GP
			     , YD_SCH_RNG_CD
			     , YD_SCH_WHIO_GP
			     , YD_SCH_DIV_GP
			     , YD_SCH_RULE_ACT_STAT
			     , YD_WRK_CRN
			     , YD_WRK_CRN_PRIOR
			     , YD_ALT_CRN_YN
			     , YD_ALT_CRN
			     , YD_ALT_CRN_PRIOR
			     , CD_CONTENTS
			     , YD_SCH_PROH_EXN
			  FROM TB_YD_SCHRULE
			 WHERE 1 = 1 
			   AND YD_GP    IN ('H','J')
			   AND YD_SCH_CD = :V_YD_SCH_CD
			   AND DEL_YN    = 'N'
			 */
			JDTORecordSet jsDataSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "변경 크레인을 조회");
			
			if (jsDataSch.size() < 1 ){
				//선택된 스케줄 기준데이터 정보에 해당 스케줄 정보가 없을경우
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, "선택된 스케줄 기준데이터 정보에 해당 스케줄 정보가 없음");	
				return jrRtn;				
			}
			
			
			// 데이터가 실제로 1건 존재함
			JDTORecord jrTemp = commUtils.getParam(logId, mthdNm, sModifier);
			for (int ii = 1; ii <= jsDataSch.size(); ii++) {
				jsDataSch.absolute(ii);
				jrTemp = jsDataSch.getRecord();					
				
			}
			
			String ydWrkCrn	= commUtils.trim(jrTemp.getFieldString("YD_WRK_CRN"));
			String ydAltCrn	= commUtils.trim(jrTemp.getFieldString("YD_ALT_CRN"));
			String sChgCrn  = "";
			
			int intWrkCrnPrior = jrTemp.getFieldInt("YD_WRK_CRN_PRIOR");
			int intAltCrnPrior = jrTemp.getFieldInt("YD_ALT_CRN_PRIOR");
			int intCrnPrior    = 0;
			
			// 1-1 크레인 ID를 비교하여 주작업 크레인인 경우는 대체작업 크레인과 순위를
		    //     그렇지 않은 경우는 주작업 크레인과 순위를 변경 크레인 정보와 순위를 SETTING 한다.
			if (ydEqpId.equals(ydWrkCrn)){
				sChgCrn 	= ydAltCrn;
				intCrnPrior = intAltCrnPrior;
				
			} else {
				sChgCrn 	= ydWrkCrn;
				intCrnPrior = intWrkCrnPrior;
				
			}
			//변경 크레인 설비상태 체크*********************************************************
			// 1-2 변경 할 크레인이 선택되어 있으면 설비 정보를 조회한 후 고장 또는 OFF-LINE 일 경우 변경 할 수 없다고 판단하고 RETURN 한다.
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_EQP_ID" , sChgCrn);
			
			//해당 설비  szChgCrn 로 설비 정보 조회 			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp
			SELECT *
			  FROM TB_YD_EQP
			 WHERE YD_EQP_ID = :V_YD_EQP_ID
			   AND DEL_YN = 'N'
		     */
			jsEqpId = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "해당 설비  szChgCrn 로 설비 정보 조회");
			
			if(jsEqpId.size() > 0 ){
				jsEqpId.first();
				jrEqpId = jsEqpId.getRecord();
				sChgYdEqpStat = commUtils.trim(jrEqpId.getFieldString("YD_EQP_STAT"));
				if(sChgYdEqpStat.equals(CConstant.YD_EQP_STAT_BREAK)){
					// 설비 상태가 고장일 경우 
					szRtnValue = "변경 설비["+ sChgCrn+"]가 고장 상태여서 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
				}
				
				if(commUtils.trim(jrEqpId.getFieldString("YD_EQP_WRK_MODE")).equals(CConstant.YD_EQP_WRK_MODE_OFF_LINE)){
					// 설비 상태가 OFF_LINE 일 경우 
					szRtnValue = "변경 설비["+ sChgCrn+"]가 OFF_LINE 이기때문에 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
				}
				
				//권하이후 부터 크레인 변경이 가능 합니다.
				if(sChgYdEqpStat.equals(CConstant.YD_EQP_STAT_DN_WO) || sChgYdEqpStat.equals(CConstant.YD_EQP_STAT_DN_CMPL)	){						
					szRtnValue = "변경 설비["+ sChgCrn+"]가 권하중인 상태라 변경 할 수 없습니다.";						
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;					
				}	
				
			} else {
				//해당 설비가 존재 하지 않습니다.
				
				szRtnValue = "해당 설비["+ sChgCrn+"]가 존재 하지 않습니다";
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, szRtnValue);	
				return jrRtn;
				
			}

			String ydWbookId  	  = "";
			String ydGp1          = "";
			String ydWrkProgStat2 = "";
			String ydCrnSchId1    = "";
			JDTORecord jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
			
			for(int x=0 ; x < rowCnt ;x++){
				
				ydGp1 = commUtils.trim(commUtils.getValue(gdReq, "YD_SCH_CD", x));
				ydGp  = ydGp1.substring(0 , 1);
				
				ydCrnSchId1  = commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID", x ));

				// 크레인스케줄 변경 가능 상태 체크 **************************************************
				jsDataSch = JDTORecordFactory.getInstance().createRecordSet("YD");				
				jrParam = commUtils.getParam(logId, mthdNm, "");
				jrParam.setField("YD_CRN_SCH_ID" , commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID", x )));
				/* 
				SELECT YD_EQP_ID                        AS YD_EQP_ID
				     , YD_CRN_SCH_ID                    AS YD_CRN_SCH_ID
				     , REGISTER                         AS REGISTER
				     , TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
				     , MODIFIER                         AS MODIFIER
				     , TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
				     , DEL_YN                           AS DEL_YN
				     , YD_WBOOK_ID                      AS YD_WBOOK_ID
				     , YD_EQP_ID                        AS YD_EQP_ID
				     , YD_GP                            AS YD_GP
				     , YD_BAY_GP                        AS YD_BAY_GP
				     , YD_SCH_CD                        AS YD_SCH_CD
				     :
				     , YD_DN_WR_YAXIS                   AS YD_DN_WR_YAXIS
				     , YD_DN_WR_YAXIS1                  AS YD_DN_WR_YAXIS1
				     , YD_DN_WR_YAXIS2                  AS YD_DN_WR_YAXIS2
				     , YD_DN_WR_ZAXIS                   AS YD_DN_WR_ZAXIS
				     , YD_UP_WRK_MODE2                  AS YD_UP_WRK_MODE2
				     , YD_DN_WRK_MODE2                  AS YD_DN_WRK_MODE2
				     , YD_L2_REQUEST_STAT               AS YD_L2_REQUEST_STAT
				     , UP_ROTATION_ANGLE                AS UP_ROTATION_ANGLE
				     , DOWN_ROTATION_ANGLE              AS DOWN_ROTATION_ANGLE
				     , (CASE WHEN YD_DN_WO_LOC LIKE 'JH%' 
				              AND YD_EQP_ID='JHCRH2'
				              AND SUBSTR(YD_DN_WO_LOC,3,2) BETWEEN '00' AND '99' 
				              AND SUBSTR(YD_DN_WO_LOC,7,2) ='01' 
				              AND YD_DN_WO_LAYER = '001' 
				              AND YD_TO_LOC_DCSN_MTD ='S'  --주작업인 경우
				            THEN 'Y' ELSE 'N' END)    AS HDONG_YN
				     , YD_WRK_PROG_STAT AS YD_WRK_PROG_STAT_CD
				  FROM TB_YD_CRNSCH
				 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
				 ORDER BY YD_CRN_SCH_ID
				*/ 
				jsDataSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnsch", logId, mthdNm, "크레인스케줄 변경 가능 상태 체크");
				
				if (jsDataSch.size() < 1) {
					// 스케줄 정보가 존재 하지 않을 경우
					szRtnValue = "스케줄 [ " + ydCrnSchId1 + "정보가 존재 하지 않습니다.";
					jrRtn.setField("RTN_CD"  , "0");
					jrRtn.setField("RTN_MSG" , szRtnValue);
					return jrRtn;
					
				}
				
				jsDataSch.first();
				jrTemp = commUtils.getParam(logId, mthdNm, sModifier);
				jrTemp = jsDataSch.getRecord();
				
				ydWbookId 	  = commUtils.trim(jrTemp.getFieldString("YD_WBOOK_ID")); // 작업예약 ID				
				ydWrkProgStat = commUtils.trim(jrTemp.getFieldString("YD_WRK_PROG_STAT")); // 설비 상태
				
				if("2".equals(ydWrkProgStat)){
					szRtnValue = "스케줄 ["+  ydCrnSchId1 +"]가 권상완료 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
					
				}else if("2".equals(ydWrkProgStat)){
					szRtnValue = "스케줄 ["+  ydCrnSchId1 +"]가 권하지시 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
				}else if("4".equals(ydWrkProgStat)){
					szRtnValue = "스케줄 ["+  ydCrnSchId1 +"]가 권하완료 상태에서는 상태를 변경 할 수 없습니다.";
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;
				}else if(ydWrkProgStat.equals(CConstant.YD_EQP_STAT_UP_WO)){
					sChkWrkProgStat = ydWrkProgStat;
				}
				//***************************************************************************
				
				

				//작업예약 수정*****************************************************************
				// 2. 선택된 크레인 스케줄 작업예약 ID에  대체 설비 ID 와 우선순위 를 UPDATE 한다.			
				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_WBOOK_ID"   , ydWbookId);
				jrParam.setField("YD_SCH_PRIOR"  , new Integer(intCrnPrior));
				/*
				 * UPDATE TB_YD_WRKBOOK
				   SET MODIFIER = :V_MODIFIER
				      ,MOD_DDTT = SYSDATE
				      ,YD_SCH_PRIOR = :V_YD_SCH_PRIOR      
				 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
				 */
				int intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01", logId, mthdNm, "작업 예약 정보 우선순위 변경");
				
				
				if (intGp <1){
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, "선택된 크레인 스케줄 작업예약 ID : "+ydWbookId+"에   우선순위 ("+intCrnPrior+") 를 UPDATE 중 ERROR");	
					return jrRtn;
				}
				//****************************************************************************
				
				
				
				// 3. 작업예약 ID 로 현재 편성된 스케줄 ID [] 를 구한다.				
				jsDataSch =  JDTORecordFactory.getInstance().createRecordSet("YD");

				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_WBOOK_ID"		, ydWbookId);
				jrParam.setField("YD_WRK_PROG_STAT"	, "W");
				
				// 기존쿼리는 W 이상태만 체크하였으나 지금은 1,W 상태를 조회한다.
				
				/*
				 SELECT * 
				  FROM TB_YD_CRNSCH
				 WHERE 1=1   
				   AND YD_WBOOK_ID = :V_YD_WBOOK_ID 
				   AND YD_WRK_PROG_STAT IN ( '1','W', :V_YD_WRK_PROG_STAT ) 
				   AND DEL_YN = 'N'
				   */
				jsDataSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId", logId, mthdNm, "작업예약 ID 로 현재 1,W 상태를 조회");
				
				if (jsDataSch.size() <1 ){					
					// 해당 작업 ID 에 편성된 스케줄 정보가 없을경우  
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, "해당작업 ID 에 편성된 스케줄 정보가 존재하지 않음");	
					return jrRtn;
				}					
				
				//크레인 스케줄 정보 변경
				jsDataSch.first();
				
				for(int i =0; i< jsDataSch.size(); i++){	
					// 4. 편성된 스케줄 ID [] 에  대체 크레인 설비 ID와 우선순위를 편성
										
					jrTemp = jsDataSch.getRecord(i);
					ydWrkProgStat = commUtils.trim(jrTemp.getFieldString("YD_WRK_PROG_STAT")); // 설비 상태
					
					//*************************************************************
					// Auto크레인 경우 작업지시 취소 필수요청 ( 유무인 동시 적용 )
					//크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅하기전 현재 선택 작업지시 취소 전문 발송
					//*************************************************************
					
					// 화면에 check된 스케쥴이 여러건일때 기존 선택된 스케쥴만 전송  
					sLogMsg = "크레인이 변경될 경우 기존크레인 작업취소 전문발송 szWrkProgStat=["+ydWrkProgStat+"]";
					commUtils.printLog(logId,sLogMsg, "SL");
					
					if("1".equals(ydWrkProgStat)){
						jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
						jrSndMsg.setField("JMS_TC_CD"         , "YDY5L004");
						jrSndMsg.setField("YD_CRN_SCH_ID"     , jrTemp.getField("YD_CRN_SCH_ID") ); 
						jrSndMsg.setField("YD_WRK_PROG_STAT"  , "W");
						jrSndMsg.setField("MSG_GP"            , "D");
									
						/************************************
						 * L2저장제원정보 전송 YDY5L004
						 ************************************/
						jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrSndMsg));
										}
					//현작업지시 취소 전문 발송 end
					//*************************************************************
					
					
					if(ydWrkProgStat.equals(CConstant.YD_EQP_STAT_UP_WO)){
						sChkWrkProgStat = ydWrkProgStat;
					}
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_CRN_SCH_ID"    , jrTemp.getField("YD_CRN_SCH_ID"));
					jrParam.setField("YD_EQP_ID"        , sChgCrn);					
					jrParam.setField("YD_SCH_PRIOR"     , new Integer(intCrnPrior));
					jrParam.setField("YD_WRK_PROG_STAT" , "W");
					jrParam.setField("YD_WORD_DT"       , "");
					
					// 5. 스케줄 테이블에 UPDATE 
					
					/*
					 * UPDATE TB_YD_CRNSCH
					   SET  MODIFIER = :V_MODIFIER
					      ,MOD_DDTT = SYSDATE
					      ,YD_EQP_ID = :V_YD_EQP_ID
					      ,YD_SCH_PRIOR = :V_YD_SCH_PRIOR
					      ,YD_WRK_PROG_STAT = :V_YD_WRK_PROG_STAT
					      ,YD_WORD_DT = :V_YD_WORD_DT
					 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID 
					 */
					intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01", logId, mthdNm, "스케줄 테이블에 UPDATE");
					
					if (intGp <1){
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, "스케줄 테이블에 UPDATE 중 ERROR");	
						return jrRtn;
					}
										
				}
				
			} //for 문
			//##############################################################################################
				
			commUtils.printParam("크레인 변경 작업1",jrRtn);
			// *************************************************************
			// 변경 크레인 상태가  대기인 경우 작업대기 상태로 세팅을 바꾸어준다.
			// *************************************************************
			
			// 변경 크레인의 상태가 대기 상태인 경우
			if ("W".equals(sChgYdEqpStat)) {

				sLogMsg = "선택된 크레인이 변경될 경우 크레인 변경될 크레인 상태를  선택상태로 변경한다.";
				commUtils.printLog(logId,sLogMsg, "SL");


				sLogMsg = "크레인 작업지시   : 야드구분[" + ydGp + "]"; // 야드구분은 스케줄 코드앞자리에서 발생되었다.
				commUtils.printLog(logId,sLogMsg, "SL");

				// JMS => EJB CALL 형식으로 수정요청
				jrSndMsg   = commUtils.getParam(logId, mthdNm, sModifier);
				jrSndMsg.setField("JMS_TC_CD"        , "Y5YDL007");
				jrSndMsg.setField("YD_EQP_ID"        , sChgCrn);
				jrSndMsg.setField("YD_WRK_PROG_STAT" , "W");
				jrSndMsg.setField("YD_SCH_CD"        , ydSchCd);
				

				EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
				JDTORecord jrRtnParam = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrSndMsg });
				
				rtnCd	= commUtils.nvl(jrRtnParam.getFieldString("RTN_CD"), "0");
				rtnMsg	= commUtils.nvl(jrRtnParam.getFieldString("RTN_MSG"), "");
				commUtils.printLog(logId, "rcvY5YDL007##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMsg, "SL");
				
				//내부송신
				jrRtn = commUtils.addSndData(jrRtn, jrRtnParam );
			}
			
			//*************************************************************
			//크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅을 바꾸어준다.
			//*************************************************************
			
			if ("W".equals(ydEqpStat) || "1".equals(ydEqpStat)){ 	
					
				sLogMsg = "크레인 변경 후 전 크레인 정보 설비상태는 작업대기 상태로 바꾸어준다." + sChkWrkProgStat + ",eqp:" + ydEqpStat;
				commUtils.printLog(logId,sLogMsg, "SL");

				// 변경 크레인 상태와 변경 전 설비 상태 비교
				if ("1".equals(sChkWrkProgStat) && "1".equals(ydEqpStat)) {
					ydWrkProgStat2 = "W";
				} else if ("W".equals(sChkWrkProgStat) && "1".equals(ydEqpStat)) {
					ydWrkProgStat2 = "1";
				} else if ("W".equals(sChkWrkProgStat) && "W".equals(ydEqpStat)) {
					ydWrkProgStat2 = "W";
				}

				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_EQP_ID"   , ydEqpId);
				jrParam.setField("YD_EQP_STAT" , ydWrkProgStat2);

				/*
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MODIFIER    = :V_MODIFIER
				     , MOD_DDTT    = SYSDATE
				 WHERE YD_EQP_ID   = :V_YD_EQP_ID
				*/
				int intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅을 바꾸어준다");
				
				if (intGp < 1) {
					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG" , "설비에 UPDATE 중 ERROR");
					return jrRtn;
				}

				if (("1".equals(sChkWrkProgStat) && "1".equals(ydEqpStat))
						|| ("W".equals(sChkWrkProgStat) && "W".equals(ydEqpStat))) {

					// 작업지시 요구
					jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrSndMsg.setField("JMS_TC_CD"        , "Y5YDL007");
					jrSndMsg.setField("YD_EQP_ID"        , ydEqpId);
					jrSndMsg.setField("YD_WRK_PROG_STAT" , ydWrkProgStat2);
					jrSndMsg.setField("YD_SCH_CD"        , ydSchCd);	
					

					EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
					JDTORecord jrRtnParam = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrSndMsg });
					
					rtnCd	= commUtils.nvl(jrRtnParam.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRtnParam.getFieldString("RTN_MSG"), "");
					commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMsg, "SL");
					
					
					//내부송신
					jrRtn = commUtils.addSndData(jrRtn, jrRtnParam );
				}
			}
			
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, "크레인 변경 작업 완료.");	
			commUtils.printLog(logId, mthdNm, "S-");
	 		return jrRtn ;
				
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
				throw new DAOException(commUtils.makeErrorLog("", "", e));
		}
	}
	
	/**
	 * 크레인 변경 
	 * LHJ
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return Boolean
	 * @throws DAOException
	 */
    public JDTORecord wrkCrnChangeJNew(GridData gdReq) throws DAOException {
    	String mthdNm = "크레인 변경[CCoilJspSeEJB.wrkCrnChangeJNew] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String ydWbookId  = ""; //야드작업예약ID
			String ydEqpId    = ""; 
			String ydCrnSchId = "";
			String ydSchCd    = "";
			
			String ydAltCrnYn    = ""; //대체크레인 여부
			String ydAltCrn      = ""; //대체크레인
			String ydAltCrnPrior = ""; //대체크레인 순위
			String ydAltCrnStat  = ""; //대체크레인 상태
			
			String ydWrkProgStat = "";

			String sModifier  = commUtils.trim(gdReq.getParam("YD_USER_ID"));

			String rtnCd  = "";
	    	String rtnMsg = "";
	    	
			JDTORecord jrRtn = JDTORecordFactory.getInstance().create();;
			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);

			//처리완료한 야드작업예약ID
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();

			for (int ii = 0; ii < rowCnt; ii++) {
				/**********************************************************
				* 1. 작업예약ID Check
				**********************************************************/
				ydEqpId  	= commUtils.trim(gdReq.getHeader("YD_EQP_ID"    ).getValue(ii)); 
			    ydWbookId  	= commUtils.trim(gdReq.getHeader("YD_WBOOK_ID"  ).getValue(ii)); //야드작업예약ID
			    ydCrnSchId 	= commUtils.trim(gdReq.getHeader("YD_CRN_SCH_ID").getValue(ii)); //크레인스케줄ID
			    
			    jrParam.setField("YD_EQP_ID"		, ydEqpId   );
			    jrParam.setField("YD_CRN_SCH_ID" 	, ydCrnSchId);
				jrParam.setField("YD_WBOOK_ID" 		, ydWbookId );
			    	
			    /***************************************************
				 * 크레인스케줄 상태조회 
				 **************************************************/
				jrParam.setField("YD_CRN_SCH_ID", ydCrnSchId);		
				
				/*
				 SELECT YD_EQP_ID                                 AS YD_EQP_ID
					      ,YD_CRN_SCH_ID                          AS YD_CRN_SCH_ID
					      ,YD_WBOOK_ID                            AS YD_WBOOK_ID
					     ...
					      ,YD_UP_WRK_MODE2                    AS YD_UP_WRK_MODE2
					      ,YD_DN_WRK_MODE2                    AS YD_DN_WRK_MODE2
					      ,YD_L2_REQUEST_STAT                 AS YD_L2_REQUEST_STAT
					      ,UP_ROTATION_ANGLE                  AS UP_ROTATION_ANGLE
					      ,DOWN_ROTATION_ANGLE                AS DOWN_ROTATION_ANGLE
					      ,(CASE WHEN  YD_DN_WO_LOC LIKE 'HH%' 
					                AND YD_EQP_ID='HHCRH2'
					                AND SUBSTR(YD_DN_WO_LOC,3,2) BETWEEN '00' AND '99' 
					                AND SUBSTR(YD_DN_WO_LOC,7,2)='01' 
					                AND YD_DN_WO_LAYER='001' 
					                AND YD_TO_LOC_DCSN_MTD='S'  --주작업인 경우
					                THEN 'Y' ELSE 'N' END) AS HDONG_YN
					     , YD_WRK_PROG_STAT                   AS YD_WRK_PROG_STAT_CD
					  FROM TB_YD_CRNSCH
					 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
					 ORDER BY YD_CRN_SCH_ID
				 */
				JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnsch", logId, mthdNm, "기존 To 위치 정보 와 변경 To 위치 정보");
				if (jsCrnSch.size() <= 0 ){
					rtnMsg = "스케줄크레인스케줄ID["+ydCrnSchId+"] 조회실패";            		
            		commUtils.printLog(logId, rtnMsg, "SL");
            		continue;
				}
		    			
				ydWrkProgStat = jsCrnSch.getRecord(0).getFieldString("YD_WRK_PROG_STAT");
				ydSchCd       = jsCrnSch.getRecord(0).getFieldString("YD_SCH_CD"       );
				
				if (!"W".equals(ydWrkProgStat)) {
					rtnMsg = "크레인작업상태["+ydWrkProgStat+"] 크레인 변경 실패 - W(대기) 상태만 크레인변경 가능";            		
            		commUtils.printLog(logId, rtnMsg, "SL");
					continue;
				}
				
				/***************************************************
				 * 대체크레인 상태 조회 
				 **************************************************/
				jrParam.setField("YD_SCH_CD" , ydSchCd); 
				/*
				 * SELECT YD_SCH_CD
				     , DEL_YN
				     , YD_GP
				     , YD_BAY_GP
				     , YD_SCH_RNG_CD
				     , YD_SCH_WHIO_GP
				     , YD_SCH_DIV_GP
				     , YD_SCH_RULE_ACT_STAT
				     , YD_WRK_CRN
				     , YD_WRK_CRN_PRIOR
				     , YD_ALT_CRN_YN
				     , YD_ALT_CRN
				     , YD_ALT_CRN_PRIOR
				     , CD_CONTENTS
				     , YD_SCH_PROH_EXN
				  FROM TB_YD_SCHRULE
				 WHERE 1 = 1 
				   AND YD_GP    IN ('H','J')
				   AND YD_SCH_CD = :V_YD_SCH_CD
				   AND DEL_YN    = 'N'
				 */
				JDTORecordSet jsSchRule = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "변경 크레인을 조회");
				
				if (jsSchRule.size() <= 0) {
					rtnMsg = "스케줄코드["+ydSchCd+"] 조회실패";            		
            		commUtils.printLog(logId, rtnMsg, "SL");
            		continue;
				}
				//작업크레인이 사용불가이면 대체크레인의 상태를 체크한다.
					
				ydAltCrnYn    = jsSchRule.getRecord(0).getFieldString("YD_ALT_CRN_YN"   );
				ydAltCrn      = jsSchRule.getRecord(0).getFieldString("YD_ALT_CRN"      );
				ydAltCrnPrior = jsSchRule.getRecord(0).getFieldString("YD_ALT_CRN_PRIOR");
				
				//대체크레인의 유무 체크
				if (!"Y".equals(ydAltCrnYn)) {
					rtnMsg = "대체크레인유무(" + ydAltCrnYn + "), 대체크레인이 없습니다.";
					commUtils.printLog(logId, rtnMsg, "SL");
					continue;
				}
				
				if (ydEqpId.equals(ydAltCrn)) {
					rtnMsg = "현재 크레인과 대체크레인이 동일합니다.";
					commUtils.printLog(logId, rtnMsg, "SL");
					continue;
				}
				
				/*************************************
				 * 대체 크레인 정보 조회
				 **************************************/
				jrParam.setField("YD_EQP_ID", ydAltCrn);
				/*
				SELECT *
				  FROM TB_YD_EQP
				 WHERE YD_EQP_ID = :V_YD_EQP_ID
				   AND DEL_YN = 'N'
			    */
				JDTORecordSet jsAltEqp = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "변경대상 크레인 정보 조회");
				if (jsAltEqp.size() <= 0) {

					rtnMsg = "변경대상 크레인["+ ydEqpId +"] 설비정보 조회 실패";
					commUtils.printLog(logId, rtnMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", rtnMsg);
					commUtils.printLog(logId, mthdNm, "SL");
					continue;
				}

				ydAltCrnStat = commUtils.trim(jsAltEqp.getRecord(0).getFieldString("YD_EQP_STAT")); //대체크레인 상태
				
				//대체크레인 사용여부
				if ("B".equals(ydAltCrnStat)) {
					rtnMsg = "대체크레인[" + ydAltCrn + "]이 사용 불가 상태입니다.";
					commUtils.printLog(logId, rtnMsg, "SL");
					continue;
				} else {
					//대체크레인이 사용가능하면 설비사양 파라미터에 대체크레인의 설비ID를 세팅한다.
					ydEqpId = ydAltCrn;
				}
				
				/*******************************************
				 * W상태의 크레인스케줄 대체크레인으로 변경
				 ******************************************/
				jrParam.setField("YD_CRN_SCH_ID"    , ydCrnSchId);
				jrParam.setField("YD_EQP_ID"        , ydEqpId   );					
				jrParam.setField("YD_SCH_PRIOR"     , new Integer(ydAltCrnPrior));
				jrParam.setField("YD_WRK_PROG_STAT" , "W");
				jrParam.setField("YD_WORD_DT"       , "");
				
				/*
				UPDATE TB_YD_CRNSCH
				   SET MODIFIER  = :V_MODIFIER
				     , MOD_DDTT  = SYSDATE
				     , YD_EQP_ID = :V_YD_EQP_ID
				     , YD_SCH_PRIOR     = :V_YD_SCH_PRIOR
				     , YD_WRK_PROG_STAT = :V_YD_WRK_PROG_STAT
				     , YD_WORD_DT       = :V_YD_WORD_DT
				 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID 
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01", logId, mthdNm, "스케줄 테이블에 UPDATE");
				
				/***********************************************
				 * 변경된 크레인의 작업상태 W이면 명령선택 기동 
				 ***********************************************/
				if ("W".equals(ydAltCrnStat)) {
					JDTORecord jrYdMsg = JDTORecordFactory.getInstance().create();
					jrYdMsg.setResultCode(logId);	//Log ID
					jrYdMsg.setResultMsg(mthdNm);	//Log Method Name
					jrYdMsg.setField("JMS_TC_CD"        , "Y5YDL007");
					jrYdMsg.setField("YD_EQP_ID"        , ydEqpId);

					EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
					JDTORecord jrRtnParam = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrYdMsg });
					
					rtnCd	= commUtils.nvl(jrRtnParam.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRtnParam.getFieldString("RTN_MSG"), "");
					
					//내부송신
					jrRtn = commUtils.addSndData(jrRtn, jrRtnParam );
				}
			} //end for

			commUtils.printLog(logId, mthdNm, "S-");
			jrRtn.setField("RTN_CD" , "1");	
			jrRtn.setField("RTN_MSG", "크레인변경 작업완료");
			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}	
    	
    	

	/**
	 * (작업)크레인 변경 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return Boolean
	 * @throws DAOException
	 */
	public JDTORecord wrkCrnChangeH(GridData gdReq) throws DAOException {
    	String mthdNm = "(작업)크레인 변경[CCoilJspSeEJB.wrkCrnChangeH] < " + gdReq.getNavigateValue();
    	String logId  = gdReq.getIPAddress();
		
    	JDTORecord jrRtn = JDTORecordFactory.getInstance().create(); 
	 	
		try{

			commUtils.printLog(logId, mthdNm, "S+");
			
    		String sAPP040_YN = coilDao.ApplyYn(logId, mthdNm, "APP040", "J", "*");
			commUtils.printLog(logId,  "==========[[[ APP040 소재 신크레인변경 : "+ sAPP040_YN +" ]]]============", "SL");
			if( "Y".equals(sAPP040_YN) ) {

				jrRtn = wrkCrnChangeHNew(gdReq);
				commUtils.printLog(logId, mthdNm, "S-");

				return jrRtn;
			}
		
			String sModifier		= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String sMsg				= "";
	    	String ydGp				= "";
	    	String ydEqpId			= ""; 
			String ydEqpStat		= "";
	    	String ydSchCd			= "";
	    	String sChgYdEqpStat	= "";
	    	String sChkWrkProgStat	= "W";
	    	String ydEqpAutoCrnMode	= "";
	    	String ydEqpAutoCrnYN	= "";
	    	String ydWrkProgStat	= ""; 
	    	
	    	int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++ ){
				ydEqpId 	  = commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID", i));
				ydWrkProgStat = commUtils.trim(commUtils.getValue(gdReq, "YD_WRK_PROG_STAT_CD", i));
				ydSchCd       = commUtils.trim(commUtils.getValue(gdReq, "YD_SCH_CD", i));
				commUtils.printLog(logId, ydEqpId, "S----ydEqpId");
				commUtils.printLog(logId, ydWrkProgStat, "S----ydWrkProgStat");
				commUtils.printLog(logId, ydSchCd, "S----ydSchCd");
			}
			
			JDTORecord jrEqpInfo = commUtils.getParam(logId, mthdNm, sModifier);
			jrEqpInfo.setField("YD_EQP_ID" , ydEqpId);
			// 해당 설비 szChgCrn 로 설비 정보 조회
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp 
			SELECT *
			  FROM TB_YD_EQP
			 WHERE YD_EQP_ID = :V_YD_EQP_ID
			   AND DEL_YN = 'N'
		     */
			JDTORecordSet jsEqpId = commDao.select(jrEqpInfo, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "야드설비작업MODE 조회");
			
			JDTORecord jrEqpId = JDTORecordFactory.getInstance().create();
			if (jsEqpId.size() > 0) {
				jsEqpId.first();
				jrEqpId = jsEqpId.getRecord();
				//설비 상태
				ydEqpStat 		 = commUtils.trim(jrEqpId.getFieldString("YD_EQP_STAT"));
				ydEqpAutoCrnMode = commUtils.trim(jrEqpId.getFieldString("YD_EQP_AUTO_CRN_MODE")); //AutoCrn 상태
				ydEqpAutoCrnYN   = commUtils.trim(jrEqpId.getFieldString("YD_EQP_WRK_MODE2")); //AutoCrn 여부
				
				if(CConstant.YD_EQP_STAT_UP_CMPL.equals(ydWrkProgStat)){
					
					sMsg = "크레인 ["+ ydEqpId +"]가 권상완료 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
					
				}else if(CConstant.YD_EQP_STAT_DN_WO.equals(ydWrkProgStat)){
					
					sMsg = "크레인 ["+ ydEqpId +"]가 권하지시 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
					
				}else if(CConstant.YD_EQP_STAT_DN_CMPL.equals(ydWrkProgStat)){
					
					sMsg = "크레인 ["+ ydEqpId +"]가 권하완료 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
					// Auto크레인시에 일시정지(4) 상태만 가능
				}else if ("A".equals(ydEqpAutoCrnYN) || "R".equals(ydEqpAutoCrnYN)) {
					if (!"W".equals(ydWrkProgStat) && !"S".equals(ydWrkProgStat) ) {
						if (!"4".equals(ydEqpAutoCrnMode) && !"B".equals(ydEqpStat) ) {
							
							sMsg = "무인크레인 ["+ ydEqpId +"]이 일시정지이거나 고장상태가 아니면 상태를 변경 할 수 없습니다.";
							commUtils.printLog(logId, sMsg, "SL");

							jrRtn.setField("RTN_CD" , "0");
							jrRtn.setField("RTN_MSG" , sMsg);
							return jrRtn;
						}
					}
				}
			}
			
			//변경 크레인을 가져 온다********************************************************
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_SCH_CD" , ydSchCd); 
			/*
			 * SELECT YD_SCH_CD
			     , DEL_YN
			     , YD_GP
			     , YD_BAY_GP
			     , YD_SCH_RNG_CD
			     , YD_SCH_WHIO_GP
			     , YD_SCH_DIV_GP
			     , YD_SCH_RULE_ACT_STAT
			     , YD_WRK_CRN
			     , YD_WRK_CRN_PRIOR
			     , YD_ALT_CRN_YN
			     , YD_ALT_CRN
			     , YD_ALT_CRN_PRIOR
			     , CD_CONTENTS
			     , YD_SCH_PROH_EXN
			  FROM TB_YD_SCHRULE
			 WHERE 1 = 1 
			   AND YD_GP    IN ('H','J')
			   AND YD_SCH_CD = :V_YD_SCH_CD
			   AND DEL_YN    = 'N'
			 */
			JDTORecordSet jsDataSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "변경 크레인을 조회");
			
			if (jsDataSch.size() < 1 ){
				//선택된 스케줄 기준데이터 정보에 해당 스케줄 정보가 없을경우
				
				sMsg = "선택된 스케줄 기준데이터 정보에 해당 스케줄 정보가 없음";
				commUtils.printLog(logId, sMsg, "SL");

				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);	
				return jrRtn;				
			}
			
			
			// 데이터가 실제로 1건 존재함
			JDTORecord jrTemp = commUtils.getParam(logId, mthdNm, sModifier);
			for (int ii = 1; ii <= jsDataSch.size(); ii++) {
				jsDataSch.absolute(ii);
				jrTemp = jsDataSch.getRecord();					
				
			}
			
			String ydWrkCrn	= commUtils.trim(jrTemp.getFieldString("YD_WRK_CRN"));
			String ydAltCrn	= commUtils.trim(jrTemp.getFieldString("YD_ALT_CRN"));
			String sChgCrn  = "";
			
			int intWrkCrnPrior = jrTemp.getFieldInt("YD_WRK_CRN_PRIOR");
			int intAltCrnPrior = jrTemp.getFieldInt("YD_ALT_CRN_PRIOR");
			int intCrnPrior    = 0;
			
			// 1-1 크레인 ID를 비교하여 주작업 크레인인 경우는 대체작업 크레인과 순위를
		    //     그렇지 않은 경우는 주작업 크레인과 순위를 변경 크레인 정보와 순위를 SETTING 한다.
			if (ydEqpId.equals(ydWrkCrn)){
				sChgCrn 	= ydAltCrn;
				intCrnPrior = intAltCrnPrior;
				
			} else {
				sChgCrn 	= ydWrkCrn;
				intCrnPrior = intWrkCrnPrior;
				
			}
			//변경 크레인 설비상태 체크*********************************************************
			// 1-2 변경 할 크레인이 선택되어 있으면 설비 정보를 조회한 후 고장 또는 OFF-LINE 일 경우 변경 할 수 없다고 판단하고 RETURN 한다.
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_EQP_ID" , sChgCrn);
			
			//해당 설비  szChgCrn 로 설비 정보 조회 			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp 
			SELECT *
			  FROM TB_YD_EQP
			 WHERE YD_EQP_ID = :V_YD_EQP_ID
			   AND DEL_YN = 'N'
		     */
			JDTORecordSet jsEqpId2 = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "해당 설비  szChgCrn 로 설비 정보 조회");
			
			if(jsEqpId2.size() > 0 ){
				jsEqpId2.first();
				jrEqpId = jsEqpId2.getRecord();
				sChgYdEqpStat = commUtils.trim(jrEqpId.getFieldString("YD_EQP_STAT"));
				
				ydEqpAutoCrnMode = commUtils.trim(jrEqpId.getFieldString("YD_EQP_AUTO_CRN_MODE")); //AutoCrn 상태
				ydEqpAutoCrnYN   = commUtils.trim(jrEqpId.getFieldString("YD_EQP_WRK_MODE2")); //AutoCrn 여부
				
				if(CConstant.YD_EQP_STAT_BREAK.equals(sChgYdEqpStat)){
					
					// 설비 상태가 고장일 경우 
					sMsg = "변경 설비["+ sChgCrn +"]가 고장 상태여서 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
				}
				
				if(CConstant.YD_EQP_WRK_MODE_OFF_LINE.equals(commUtils.trim(jrEqpId.getFieldString("YD_EQP_WRK_MODE")))){
					// 설비 상태가 OFF_LINE 일 경우
					sMsg = "변경 설비["+ sChgCrn +"]가 OFF_LINE 이기때문에 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
					
				}
				/*
				// Auto크레인시에 일시정지(4) 상태만 가능
				else if ("A".equals(ydEqpAutoCrnYN) || "R".equals(ydEqpAutoCrnYN)) {
					if (!"4".equals(ydEqpAutoCrnMode) && !"B".equals(ydEqpStat) ) {
						
						sMsg = "변경 무인크레인 ["+ ydEqpId +"]이 일시정지이거나 고장상태가 아니면 상태를 변경 할 수 없습니다.";
						commUtils.printLog(logId, sMsg, "SL");
	
						jrRtn.setField("RTN_CD" , "0");
						jrRtn.setField("RTN_MSG" , sMsg);
						return jrRtn;
					}
				}
				*/
				
				/*
				//권하이후 부터 크레인 변경이 가능 합니다.
				if(sChgYdEqpStat.equals(CConstant.YD_EQP_STAT_DN_WO) || sChgYdEqpStat.equals(CConstant.YD_EQP_STAT_DN_CMPL)	){						
					szRtnValue = "변경 설비["+ sChgCrn+"]가 권하중인 상태라 변경 할 수 없습니다.";						
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, szRtnValue);	
					return jrRtn;					
				}
				*/	
				
			} else {
				
				//해당 설비가 존재 하지 않습니다.
				sMsg = "해당 설비["+ sChgCrn+"]가 존재 하지 않습니다";
				commUtils.printLog(logId, sMsg, "SL");

				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sMsg);	
				return jrRtn;
			}

			String ydWbookId  	  = "";
			String ydGp1          = "";
			String ydWrkProgStat2 = "";
			String ydCrnSchId1    = "";
			JDTORecord jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
			
			for(int x=0 ; x < rowCnt ;x++){
				
				ydGp1 = commUtils.trim(commUtils.getValue(gdReq, "YD_SCH_CD", x));
				ydGp  = ydGp1.substring(0 , 1);
				
				//sModifier 	 = commUtils.trim(commUtils.getValue(gdReq, "MODIFIER", x));
				ydCrnSchId1  = commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID", x ));

				// 크레인스케줄 변경 가능 상태 체크 **************************************************
				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_CRN_SCH_ID" , commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID", x )));
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnsch 
				SELECT YD_EQP_ID                        AS YD_EQP_ID
				     , YD_CRN_SCH_ID                    AS YD_CRN_SCH_ID
				     , REGISTER                         AS REGISTER
				     , TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
				     , MODIFIER                         AS MODIFIER
				     , TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
				     , DEL_YN                           AS DEL_YN
				     , YD_WBOOK_ID                      AS YD_WBOOK_ID
				     , YD_EQP_ID                        AS YD_EQP_ID
				     , YD_GP                            AS YD_GP
				     , YD_BAY_GP                        AS YD_BAY_GP
				     , YD_SCH_CD                        AS YD_SCH_CD
				     :
				     , YD_DN_WR_YAXIS                   AS YD_DN_WR_YAXIS
				     , YD_DN_WR_YAXIS1                  AS YD_DN_WR_YAXIS1
				     , YD_DN_WR_YAXIS2                  AS YD_DN_WR_YAXIS2
				     , YD_DN_WR_ZAXIS                   AS YD_DN_WR_ZAXIS
				     , YD_UP_WRK_MODE2                  AS YD_UP_WRK_MODE2
				     , YD_DN_WRK_MODE2                  AS YD_DN_WRK_MODE2
				     , YD_L2_REQUEST_STAT               AS YD_L2_REQUEST_STAT
				     , UP_ROTATION_ANGLE                AS UP_ROTATION_ANGLE
				     , DOWN_ROTATION_ANGLE              AS DOWN_ROTATION_ANGLE
				     , (CASE WHEN YD_DN_WO_LOC LIKE 'JH%' 
				              AND YD_EQP_ID='JHCRH2'
				              AND SUBSTR(YD_DN_WO_LOC,3,2) BETWEEN '00' AND '99' 
				              AND SUBSTR(YD_DN_WO_LOC,7,2) ='01' 
				              AND YD_DN_WO_LAYER = '001' 
				              AND YD_TO_LOC_DCSN_MTD ='S'  --주작업인 경우
				            THEN 'Y' ELSE 'N' END)    AS HDONG_YN
				     , YD_WRK_PROG_STAT AS YD_WRK_PROG_STAT_CD
				  FROM TB_YD_CRNSCH
				 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
				 
				*/ 
				JDTORecordSet jsYdCrnsch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnsch", logId, mthdNm, "크레인스케줄 변경 가능 상태 체크");
				
				if (jsYdCrnsch.size() < 1) {
					// 스케줄 정보가 존재 하지 않을 경우
					sMsg = "크레인스케줄ID [ "+ ydCrnSchId1 +"정보가 존재 하지 않습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD"  , "0");
					jrRtn.setField("RTN_MSG" , sMsg);
					return jrRtn;
					
				}
				
				jsYdCrnsch.first();
				jrTemp = commUtils.getParam(logId, mthdNm, sModifier);
				jrTemp = jsYdCrnsch.getRecord();
				
				ydWbookId 	  = commUtils.trim(jrTemp.getFieldString("YD_WBOOK_ID")); // 작업예약 ID				
				ydWrkProgStat = commUtils.trim(jrTemp.getFieldString("YD_WRK_PROG_STAT")); // 설비 상태
				
				if("2".equals(ydWrkProgStat)){
					
					sMsg = "크레인스케줄ID ["+ ydCrnSchId1 +"]가 권상완료 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
					
				}else if("2".equals(ydWrkProgStat)){
					
					sMsg = "크레인스케줄ID ["+ ydCrnSchId1 +"]가 권하지시 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
				}else if("4".equals(ydWrkProgStat)){
					
					sMsg = "크레인스케줄ID ["+ ydCrnSchId1 +"]가 권하완료 상태에서는 상태를 변경 할 수 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
				}else if(ydWrkProgStat.equals(CConstant.YD_EQP_STAT_UP_WO)){
					sChkWrkProgStat = ydWrkProgStat;
				}
				//***************************************************************************
				
				

				//작업예약 수정*****************************************************************
				// 2. 선택된 크레인 스케줄 작업예약 ID에  대체 설비 ID 와 우선순위 를 UPDATE 한다.			
				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_WBOOK_ID"   , ydWbookId);
				jrParam.setField("YD_SCH_PRIOR"  , new Integer(intCrnPrior));
				jrParam.setField("MODIFIER"      , sModifier);
				jrParam.setField("YD_SCH_CD"     , ydSchCd); 
				/*
				 * UPDATE TB_YD_WRKBOOK
				   SET MODIFIER = :V_MODIFIER
				      ,MOD_DDTT = SYSDATE
				      ,YD_SCH_PRIOR = :V_YD_SCH_PRIOR      
				 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
				 */
				int intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01", logId, mthdNm, "작업 예약 정보 우선순위 변경");
				
				
				if (intGp <1){
					sMsg = "선택된 크레인 스케줄 작업예약 ID : "+ydWbookId+"에  우선순위 ("+intCrnPrior+") 를 UPDATE 중 ERROR";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
				}
				//****************************************************************************
				
				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_WBOOK_ID"		, ydWbookId);
				jrParam.setField("YD_WRK_PROG_STAT"	, "W");
				jrParam.setField("YD_SCH_CD"        , ydSchCd); 
				// 기존쿼리는 W 이상태만 체크하였으나 지금은 1,W 상태를 조회한다.
				/*
				 SELECT * 
				  FROM TB_YD_CRNSCH
				 WHERE 1=1   
				   AND YD_WBOOK_ID = :V_YD_WBOOK_ID 
				   AND YD_WRK_PROG_STAT IN ( '1','W', :V_YD_WRK_PROG_STAT ) 
				   AND DEL_YN = 'N'
				   */
				JDTORecordSet jsYdCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId", logId, mthdNm, "작업예약 ID 로 현재 1,W 상태를 조회");
				
				if (jsYdCrnSch.size() <1 ){					
					// 해당 작업 ID 에 편성된 스케줄 정보가 없을경우 
					sMsg = "현재 크레인 상태가 변경 할 수 있는 크레인이 없습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, sMsg);	
					return jrRtn;
				}					
				
				//크레인 스케줄 정보 변경
				for(int i =0; i< jsYdCrnSch.size(); i++){	
					// 4. 편성된 스케줄 ID [] 에  대체 크레인 설비 ID와 우선순위를 편성
										
					jrTemp = jsYdCrnSch.getRecord(i);
					ydWrkProgStat = commUtils.trim(jrTemp.getFieldString("YD_WRK_PROG_STAT")); // 설비 상태
					
					//*************************************************************
					// Auto크레인 경우 작업지시 취소 필수요청 ( 유무인 동시 적용 )
					//크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅하기전 현재 선택 작업지시 취소 전문 발송
					//*************************************************************
					
					// 화면에 check된 스케쥴이 여러건일때 기존 선택된 스케쥴만 전송  
					sMsg = "크레인이 변경될 경우 기존크레인 작업취소 전문발송 szWrkProgStat=["+ydWrkProgStat+"]";
					commUtils.printLog(logId,sMsg, "SL");
					
					if("1".equals(ydWrkProgStat)){
						jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
						jrSndMsg.setField("JMS_TC_CD"         , "YDY5L004");
						jrSndMsg.setField("YD_CRN_SCH_ID"     , jrTemp.getField("YD_CRN_SCH_ID") ); 
						jrSndMsg.setField("YD_WRK_PROG_STAT"  , "W");
						jrSndMsg.setField("MSG_GP"            , "D");
									
						/************************************
						 * L2저장제원정보 전송 YDY5L004
						 ************************************/
						jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrSndMsg));
										}
					//현작업지시 취소 전문 발송 end
					//*************************************************************
					
					
					if(CConstant.YD_EQP_STAT_UP_WO.equals(ydWrkProgStat)){
						sChkWrkProgStat = ydWrkProgStat;
					}
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_CRN_SCH_ID"    , jrTemp.getField("YD_CRN_SCH_ID"));
					jrParam.setField("YD_EQP_ID"        , sChgCrn);					
					jrParam.setField("YD_SCH_PRIOR"     , new Integer(intCrnPrior));
					jrParam.setField("YD_WRK_PROG_STAT" , "W");
					jrParam.setField("YD_WORD_DT"       , "");
					
					// 5. 스케줄 테이블에 UPDATE 
					/*
					 * UPDATE TB_YD_CRNSCH
					   SET  MODIFIER = :V_MODIFIER
					      ,MOD_DDTT = SYSDATE
					      ,YD_EQP_ID = :V_YD_EQP_ID
					      ,YD_SCH_PRIOR = :V_YD_SCH_PRIOR
					      ,YD_WRK_PROG_STAT = :V_YD_WRK_PROG_STAT
					      ,YD_WORD_DT = :V_YD_WORD_DT
					 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID 
					 */
					intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01", logId, mthdNm, "스케줄 테이블에 UPDATE");
					
					if (intGp <1){
						sMsg = "스케줄 테이블에 UPDATE 중 ERROR";
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, sMsg);	
						return jrRtn;
					}
				}
			} 
			//##############################################################################################
				
			// *************************************************************
			// 변경 크레인 상태가  대기인 경우 작업대기 상태로 세팅을 바꾸어준다.
			// *************************************************************
			
			// 변경 크레인의 상태가 대기 상태인 경우
			commUtils.printLog(logId, "변경크레인 YD_EQP_STAT["+ sChgYdEqpStat +"]", "SL");
			if ("W".equals(sChgYdEqpStat)) {

				sMsg = "선택된 크레인이 변경될 경우 크레인 변경될 크레인 상태를  선택상태로 변경한다.";
				commUtils.printLog(logId,sMsg, "SL");

				sMsg = "크레인 작업지시  : 야드구분["+ ydGp +"]"; // 야드구분은 스케줄 코드앞자리에서 발생되었다.
				commUtils.printLog(logId,sMsg, "SL");

				// JMS => EJB CALL 형식으로 수정요청
				jrSndMsg   = commUtils.getParam(logId, mthdNm, sModifier);
				jrSndMsg.setField("JMS_TC_CD"        , "Y5YDL007");
				jrSndMsg.setField("YD_EQP_ID"        , sChgCrn);
				jrSndMsg.setField("YD_WRK_PROG_STAT" , "W");
				jrSndMsg.setField("YD_SCH_CD"        , ydSchCd);
				

				EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
				JDTORecord jrRtnParam = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrSndMsg });
				String rtnCd	= commUtils.nvl(jrRtnParam.getFieldString("RTN_CD"), "0");
				String rtnMg	= commUtils.nvl(jrRtnParam.getFieldString("RTN_MSG"), "");
				commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMg, "SL");
				
				//내부송신
				jrRtn = commUtils.addSndData(jrRtn, jrRtnParam );
			}
			
			//*************************************************************
			//크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅을 바꾸어준다.
			//*************************************************************
			
			if ("W".equals(ydEqpStat) || "1".equals(ydEqpStat)){ 	
					
				sMsg = "크레인 변경 후 전 크레인 정보 설비상태는 작업대기 상태로 바꾸어준다."+ sChkWrkProgStat +",eqp:"+ ydEqpStat;
				commUtils.printLog(logId,sMsg, "SL");

				// 변경 크레인 상태와 변경 전 설비 상태 비교
				if ("1".equals(sChkWrkProgStat) && "W".equals(ydEqpStat)) {
					ydWrkProgStat2 = "W";
				} else if ("W".equals(sChkWrkProgStat) && "1".equals(ydEqpStat)) {
					ydWrkProgStat2 = "1";
				} else if ("W".equals(sChkWrkProgStat) && "W".equals(ydEqpStat)) {
					ydWrkProgStat2 = "W";
				}

				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_EQP_ID"   , ydEqpId);
				jrParam.setField("YD_EQP_STAT" , ydWrkProgStat2);

				/*
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MODIFIER    = :V_MODIFIER
				     , MOD_DDTT    = SYSDATE
				 WHERE YD_EQP_ID   = :V_YD_EQP_ID
				*/
				int intGp = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "크레인 변경 후 원 크레인 정보는 작업대기 상태로 세팅을 바꾸어준다");
				
				if (intGp < 1) {
					
					sMsg = "설비에 UPDATE 중 ERROR";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

				if (("1".equals(sChkWrkProgStat) && "1".equals(ydEqpStat))
						|| ("W".equals(sChkWrkProgStat) && "W".equals(ydEqpStat))) {

					// 작업지시 요구
					jrSndMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrSndMsg.setField("JMS_TC_CD"        , "Y5YDL007");
					jrSndMsg.setField("YD_EQP_ID"        , ydEqpId);
					jrSndMsg.setField("YD_WRK_PROG_STAT" , ydWrkProgStat2);
					jrSndMsg.setField("YD_SCH_CD"        , ydSchCd);	
					

					EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
					JDTORecord jrRtnParam = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrSndMsg });
					
					String rtnCd	= commUtils.nvl(jrRtnParam.getFieldString("RTN_CD"), "0");
					String rtnMg	= commUtils.nvl(jrRtnParam.getFieldString("RTN_MSG"), "");
					commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMg, "SL");
					
					//내부송신
					jrRtn = commUtils.addSndData(jrRtn, jrRtnParam );
				}
			}
			
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, "크레인 변경 작업 완료.");	
			commUtils.printLog(logId, mthdNm, "S-");
	 		return jrRtn;
				
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
				throw new DAOException(commUtils.makeErrorLog("", "", e));
		}
	}
	
	/**
	 * 소재 크레인스케쥴현황조회-크레인변경
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord wrkCrnChangeHNew(GridData gdReq) throws DAOException {
    	String mthdNm = "소재 크레인스케쥴현황조회-크레인변경[CCoilJspSeEJB.wrkCrnChangeHNew] < " + gdReq.getNavigateValue();
    	String logId  = gdReq.getIPAddress();

    	JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();

		try{
			commUtils.printLog(logId, mthdNm, "S+");

	    	JDTORecord jrYdMsg	= JDTORecordFactory.getInstance().create();
			String sModifier	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String sMsg			= "";

	    	int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			String[] arrYdWbookId = new String[rowCnt];

			for (int i = 0; i < rowCnt; i++ ){
				String ydCrnSchId	= commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID"	, i));
				String ydEqpId2		= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID"		, i));
				String ydWbookId	= commUtils.trim(commUtils.getValue(gdReq, "YD_WBOOK_ID"	, i));

				sMsg = (i+1) +".YD_EQP_ID["+ ydEqpId2 +"] YD_WBOOK_ID["+ ydWbookId +"] YD_CRN_SCH_ID["+ ydCrnSchId +"]";
				commUtils.printLog(logId, sMsg, "SL");

				if (commUtils.chkExist(arrYdWbookId, ydWbookId)) {
					sMsg = (i+1) +".이전 동일작업예약ID["+ ydWbookId +"] SKIP";
					commUtils.printLog(logId, sMsg, "SL");
					continue;
				}
				arrYdWbookId[i] = ydWbookId;

				JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_CRN_SCH_ID", ydCrnSchId);
            	/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp
            	SELECT A.YD_CRN_SCH_ID
            	     , A.YD_WBOOK_ID
            	     , A.YD_WRK_PROG_STAT
            	     , A.YD_DN_WO_LOC
            	     , A.YD_SCH_CD
            	     , A.YD_EQP_ID
            	     , B.YD_EQP_STAT           -- 설비상태
            	     , B.YD_EQP_AUTO_CRN_MODE  -- 1:On-Line, 2:Off-Line, 4:일시정지, 5:비상정지
            	     , B.YD_EQP_WRK_MODE2      -- A:무인, R:리모컨, M:유인
            	     , B.YD_EQP_WRK_MODE
            	  FROM TB_YD_CRNSCH A
            	     , TB_YD_EQP    B
            	 WHERE A.YD_EQP_ID = B.YD_EQP_ID
            	   AND A.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
            	*/
            	JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp", logId, mthdNm, "크레인스케쥴 조회");

				if (jsCrnSch.size() < 1) {
					// 스케줄 정보가 존재 하지 않을 경우
					sMsg = "크레인스케줄ID [ "+ ydCrnSchId +"] 정보가 존재 하지 않습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);

					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jsCrnSch.first();
				JDTORecord jrCrnSch = jsCrnSch.getRecord();

            	String ydEqpId			= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_ID"));
				String ydSchCd			= commUtils.trim(jrCrnSch.getFieldString("YD_SCH_CD"));
				String ydWrkProgStat	= commUtils.trim(jrCrnSch.getFieldString("YD_WRK_PROG_STAT"));
				String ydEqpWrkMode2	= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_WRK_MODE2"));		// A:무인, R:리모컨, M:유인
				String ydEqpAutoCrnMode	= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_AUTO_CRN_MODE"));	// 1:On-Line, 2:Off-Line, 4:일시정지, 5:비상정지

				commUtils.printLog(logId, "스케쥴설비코드["+ ydEqpId +"] 화면설비코드["+ ydEqpId2 +"]", "SL");
				if( !ydEqpId.equals(ydEqpId2) ) {

					sMsg = "설비정보가 다릅니다. 재조회 후 [크레인변경] 하십시요.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 1. 권상 전 작업상태 체크
				 *********************************************/
				if (!"W".equals(ydWrkProgStat) &&!"S".equals(ydWrkProgStat) &&!"1".equals(ydWrkProgStat)) {

					sMsg = "스케쥴 취소를 할 수 없는 상태 입니다.";

					if( "2".equals(ydWrkProgStat) ) {
						sMsg = "권하지시 상태는 크레인변경 할 수 없습니다.";
					}
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 2. 무인크레인 체크
				 *********************************************/
				if( "A".equals(ydEqpWrkMode2) || "R".equals(ydEqpWrkMode2) ) {
					if( "1".equals(ydWrkProgStat) && !"4".equals(ydEqpAutoCrnMode) && !"5".equals(ydEqpAutoCrnMode) ) {

						sMsg = "무인크레인["+ ydEqpId +"]이 일시정지이거나 고장상태가 아니면 크레인변경을 할 수 없습니다.";
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD" , "0");
						jrRtn.setField("RTN_MSG", sMsg);
						commUtils.printLog(logId, mthdNm, "S-");
						return jrRtn;
					}
				}

				/*********************************************
				 * 3. 대체크레인 정보 조회
				 *********************************************/
				jrParam.setField("YD_SCH_CD", ydSchCd);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule
				SELECT YD_SCH_CD
				     , DEL_YN
				     , YD_GP
				     , YD_BAY_GP
				     , YD_SCH_RNG_CD
				     , YD_SCH_WHIO_GP
				     , YD_SCH_DIV_GP
				     , YD_SCH_RULE_ACT_STAT
				     , YD_WRK_CRN
				     , YD_WRK_CRN_PRIOR
				     , YD_ALT_CRN_YN
				     , YD_ALT_CRN
				     , YD_ALT_CRN_PRIOR
				     , CD_CONTENTS
				     , YD_SCH_PROH_EXN
				  FROM TB_YD_SCHRULE
				 WHERE 1 = 1
				   AND YD_GP    IN ('H','J')
				   AND YD_SCH_CD = :V_YD_SCH_CD
				   AND DEL_YN    = 'N'
				*/
				JDTORecordSet jsSchRule = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "대체크레인 정보조회");
				if( jsSchRule.size() < 1 ) {

					sMsg = "스케쥴 정보조회 실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jsSchRule.first();
				JDTORecord jrSchRule = jsSchRule.getRecord();

				String ydWrkCrn		= commUtils.trim(jrSchRule.getFieldString("YD_WRK_CRN"));		// 작업크레인
				String ydWrkCrnPrior= commUtils.trim(jrSchRule.getFieldString("YD_WRK_CRN_PRIOR"));	// 스케쥴 우선순위
				String ydAltCrnYn	= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN_YN"));	// 대체크레인 유무
				String ydAltCrn		= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN"));		// 대체크레인
				String ydAltCrnPrior= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN_PRIOR"));	// 대체크레인 스케쥴 우선순위

				if( !"Y".equals(ydAltCrnYn) ) {

					sMsg = "대체크레인 유무가 ["+ ydAltCrnYn +"]으로 설정되어 있어 변경실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				if( "".equals(ydAltCrn) ) {

					sMsg = "대체크레인이 설정되어 있지 않습니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 4. 크레인변경 대상 조회
				 *********************************************/
				String sChgCrn		= "";
				String sChgPrior	= "";

				if( ydEqpId.equals(ydWrkCrn) ) {
					sChgCrn		= ydAltCrn;
					sChgPrior	= ydAltCrnPrior;
				} else {
					sChgCrn		= ydWrkCrn;
					sChgPrior	= ydWrkCrnPrior;
				}

				jrParam.setField("YD_EQP_ID", sChgCrn);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp
				SELECT *
				  FROM TB_YD_EQP
				 WHERE YD_EQP_ID = :V_YD_EQP_ID
				   AND DEL_YN = 'N'
			    */
				JDTORecordSet jsChgCrn = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "변경대상 크레인 정보 조회");
				if( jsChgCrn.size() < 1 ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 설비정보 조회 실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				String sChgEqpStat = commUtils.trim(jsChgCrn.getRecord(0).getFieldString("YD_EQP_STAT"));
				if( "B".equals(sChgEqpStat) ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 설비상태가 고장입니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				String sChgEqpWrkMode = commUtils.trim(jsChgCrn.getRecord(0).getFieldString("YD_EQP_WRK_MODE"));
				if( "2".equals(sChgEqpWrkMode) ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 운전모드가 OFF-LINE 입니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 5. 권상지시 상태면 작업크레인 스케쥴 취소 전문 송신
				 *********************************************/
				if( "1".equals(ydWrkProgStat) ) {
					jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrYdMsg.setField("YD_CRN_SCH_ID"	, ydCrnSchId );
					jrYdMsg.setField("MSG_GP"			, "D");

					/************************************
					 * 크레인작업지시(YDY5L004) 취소 송신
					 ************************************/
					jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrYdMsg));
				}

				/*********************************************
				 * 6. 작업예약  우선순위 변경
				 *********************************************/
				jrParam.setField("YD_WBOOK_ID"	, ydWbookId);
				jrParam.setField("YD_SCH_PRIOR"	, sChgPrior);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01
				UPDATE TB_YD_WRKBOOK
				   SET MODIFIER = :V_MODIFIER
				     , MOD_DDTT = SYSDATE
				     , YD_SCH_PRIOR = :V_YD_SCH_PRIOR
				 WHERE YD_WBOOK_ID  = :V_YD_WBOOK_ID
				*/
				int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01", logId, mthdNm, "작업 예약 정보 우선순위 변경");
				if( intRtnVal < 1 ) {
					sMsg = "작업예약ID["+ ydWbookId +"] 우선순위 UPDATE ERROR!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 7. 크레인스케쥴 변경크레인 UPDATE
				 *********************************************/
				jrParam.setField("YD_WRK_PROG_STAT", "W");
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId
				SELECT *
				  FROM TB_YD_CRNSCH
				 WHERE 1=1
				   AND YD_WBOOK_ID = :V_YD_WBOOK_ID
				   AND YD_WRK_PROG_STAT IN ( '1','W', :V_YD_WRK_PROG_STAT )
				   AND DEL_YN = 'N'
				*/
				JDTORecordSet jsCrnSchByWbookId = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId", logId, mthdNm, "작업예약 크레인스케쥴 조회");
				for(int x=0; x<jsCrnSchByWbookId.size(); x++) {
					JDTORecord jrCrnSchByWbookId = jsCrnSchByWbookId.getRecord(x);

					String sDelYn	= commUtils.trim(jrCrnSchByWbookId.getFieldString("DEL_YN"));
					ydCrnSchId		= commUtils.trim(jrCrnSchByWbookId.getFieldString("YD_CRN_SCH_ID"));

					sMsg = "  "+ (x+1) +".크레인스케쥴ID["+ ydCrnSchId +"] DEL_YN["+ sDelYn +"]";
					commUtils.printLog(logId, sMsg, "SL");

					if( "Y".equals(sDelYn) ) continue;

					jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
					jrParam.setField("YD_EQP_ID"		, sChgCrn);
					jrParam.setField("YD_SCH_PRIOR"		, sChgPrior);
					jrParam.setField("YD_WRK_PROG_STAT"	, "W");
					jrParam.setField("YD_WORD_DT"		, "");
					/*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01
					UPDATE TB_YD_CRNSCH
					   SET MODIFIER         = :V_MODIFIER
					     , MOD_DDTT         = SYSDATE
					     , YD_EQP_ID        = :V_YD_EQP_ID
					     , YD_SCH_PRIOR     = :V_YD_SCH_PRIOR
					     , YD_WRK_PROG_STAT = :V_YD_WRK_PROG_STAT
					     , YD_WORD_DT       = :V_YD_WORD_DT
					 WHERE YD_CRN_SCH_ID    = :V_YD_CRN_SCH_ID
					*/
					intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01", logId, mthdNm, "크레인스케쥴 UPDATE");
					if( intRtnVal < 1 ) {
						sMsg = "크레인스케쥴 크레인변경 UPDATE ERROR!";
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD" , "0");
						jrRtn.setField("RTN_MSG", sMsg);
						commUtils.printLog(logId, mthdNm, "S-");
						return jrRtn;
					}
				}

				/*********************************************
				 * 8. 변경 전 크레인 상태 [대기]로 UPDATE
				 *********************************************/
				jrParam.setField("YD_EQP_ID"	, ydEqpId);
				jrParam.setField("YD_EQP_STAT"	, "W");
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MODIFIER    = :V_MODIFIER
				     , MOD_DDTT    = SYSDATE
				WHERE YD_EQP_ID    = :V_YD_EQP_ID
				*/
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "변경 전 크레인의 상태 UPDATE");
				if( intRtnVal < 1 ) {
					sMsg = "변경 전 크레인의 상태 UPDATE ERROR!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 9. 변경 전 크레인 명령선택기동(Y5YDL007) 호출
				 *********************************************/
				jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
				jrYdMsg.setField("JMS_TC_CD"		, "Y5YDL007"); // JMSTC코드
				jrYdMsg.setField("YD_EQP_ID"		, ydEqpId	); // 야드설비ID
				jrYdMsg.setField("YD_WRK_PROG_STAT"	, "W"		); // 야드작업진행상태

				jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);

				sMsg = "변경 전 크레인 명령선택기동(Y5YDL007) QUEUE 저장.";
				commUtils.printLog(logId, sMsg, "SL");

				sMsg = "변경대상크레인["+ sChgCrn +"] 설비상태["+ sChgEqpStat +"]";
				commUtils.printLog(logId, sMsg, "SL");

				/*******************************************************
				 * 10. 변경대상 크레인 작업대기[W] 명령선택기동(Y5YDL007) 호출
				 *******************************************************/
				if( "W".equals(sChgEqpStat) ) {
					jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrYdMsg.setField("JMS_TC_CD"		, "Y5YDL007"); // JMSTC코드
					jrYdMsg.setField("YD_EQP_ID"		, sChgCrn	); // 야드설비ID
					jrYdMsg.setField("YD_WRK_PROG_STAT"	, "W"		); // 야드작업진행상태

					jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);

					sMsg = "변경대상 크레인 명령선택기동(Y5YDL007) QUEUE 저장.";
					commUtils.printLog(logId, sMsg, "SL");
				}
			}

			jrRtn.setField("RTN_CD" , "1");
			jrRtn.setField("RTN_MSG", "크레인 변경 작업 완료.");

			commUtils.printLog(logId, mthdNm, "S-");
	 		return jrRtn;

		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

	/**
	 * 소재 크레인스케쥴현황조회-크레인변경
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord cvCrnChangeHNew(GridData gdReq) throws DAOException {
    	String mthdNm = "소재 크레인스케쥴현황조회-수입크레인변경[CCoilJspSeEJB.cvCrnChangeHNew] < " + gdReq.getNavigateValue();
    	String logId  = gdReq.getIPAddress();

    	JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();

		try{
			commUtils.printLog(logId, mthdNm, "S+");

	    	JDTORecord jrYdMsg	= JDTORecordFactory.getInstance().create();
			String sModifier	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String ydEqpId   	= commUtils.trim(gdReq.getParam("YD_EQP_ID_SELECT")); // 화면에서 선택한 크레인
			String sMsg			= "";
			/*
			 * AT0000_ 수입작업 크레인 변경 적용여부  YYS 202202
			 * */
			String sAPP005_YN = coilDao.ApplyYn(logId, mthdNm, "APP001", "J", "005");			    
			if("N".equals(sAPP005_YN)){
				jrRtn.setField("RTN_CD" , "0");
				jrRtn.setField("RTN_MSG", "개발진행중입니다.");
				return jrRtn;
			}
			
	    	int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			String[] arrYdWbookId = new String[rowCnt];

			for (int i = 0; i < rowCnt; i++ ){
				String ydCrnSchId	= commUtils.trim(commUtils.getValue(gdReq, "YD_CRN_SCH_ID"	, i));
				String ydEqpId2		= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID"		, i));
				String ydWbookId	= commUtils.trim(commUtils.getValue(gdReq, "YD_WBOOK_ID"	, i));

				sMsg = (i+1) +".YD_EQP_ID["+ ydEqpId2 +"] YD_WBOOK_ID["+ ydWbookId +"] YD_CRN_SCH_ID["+ ydCrnSchId +"]";
				commUtils.printLog(logId, sMsg, "SL");

				if (commUtils.chkExist(arrYdWbookId, ydWbookId)) {
					sMsg = (i+1) +".이전 동일작업예약ID["+ ydWbookId +"] SKIP";
					commUtils.printLog(logId, sMsg, "SL");
					continue;
				}
				arrYdWbookId[i] = ydWbookId;

				JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_CRN_SCH_ID", ydCrnSchId);
            	/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp
            	SELECT A.YD_CRN_SCH_ID
            	     , A.YD_WBOOK_ID
            	     , A.YD_WRK_PROG_STAT
            	     , A.YD_DN_WO_LOC
            	     , A.YD_SCH_CD
            	     , A.YD_EQP_ID
            	     , B.YD_EQP_STAT           -- 설비상태
            	     , B.YD_EQP_AUTO_CRN_MODE  -- 1:On-Line, 2:Off-Line, 4:일시정지, 5:비상정지
            	     , B.YD_EQP_WRK_MODE2      -- A:무인, R:리모컨, M:유인
            	     , B.YD_EQP_WRK_MODE
            	  FROM TB_YD_CRNSCH A
            	     , TB_YD_EQP    B
            	 WHERE A.YD_EQP_ID = B.YD_EQP_ID
            	   AND A.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
            	*/
            	JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp", logId, mthdNm, "크레인스케쥴 조회");

				if (jsCrnSch.size() < 1) {
					// 스케줄 정보가 존재 하지 않을 경우
					sMsg = "크레인스케줄ID [ "+ ydCrnSchId +"] 정보가 존재 하지 않습니다.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);

					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jsCrnSch.first();
				JDTORecord jrCrnSch = jsCrnSch.getRecord();

            	//String ydEqpId			= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_ID"));
				String ydSchCd			= commUtils.trim(jrCrnSch.getFieldString("YD_SCH_CD"));
				String ydWrkProgStat	= commUtils.trim(jrCrnSch.getFieldString("YD_WRK_PROG_STAT"));
				String ydEqpWrkMode2	= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_WRK_MODE2"));		// A:무인, R:리모컨, M:유인
				String ydEqpAutoCrnMode	= commUtils.trim(jrCrnSch.getFieldString("YD_EQP_AUTO_CRN_MODE"));	// 1:On-Line, 2:Off-Line, 4:일시정지, 5:비상정지

				commUtils.printLog(logId, "스케쥴설비코드["+ ydEqpId +"] 화면설비코드["+ ydEqpId2 +"]", "SL");
				if( ydEqpId.equals(ydEqpId2) ) {

					sMsg = "선택한 설비정보와 기존 설비정보가 동일합니다. 재선택 후 [수입 크레인변경] 하십시요.";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 1. 권상 전 작업상태 체크
				 *********************************************/
				if (!"W".equals(ydWrkProgStat) &&!"S".equals(ydWrkProgStat) &&!"1".equals(ydWrkProgStat)) {

					sMsg = "스케쥴 취소를 할 수 없는 상태 입니다.";

					if( "2".equals(ydWrkProgStat) ) {
						sMsg = "권하지시 상태는 크레인변경 할 수 없습니다.";
					}
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 2. 무인크레인 체크
				 *********************************************/
				if( "A".equals(ydEqpWrkMode2) || "R".equals(ydEqpWrkMode2) ) {
					if( "1".equals(ydWrkProgStat) && !"4".equals(ydEqpAutoCrnMode) && !"5".equals(ydEqpAutoCrnMode) ) {

						sMsg = "무인크레인["+ ydEqpId +"]이 일시정지이거나 고장상태가 아니면 크레인변경을 할 수 없습니다.";
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD" , "0");
						jrRtn.setField("RTN_MSG", sMsg);
						commUtils.printLog(logId, mthdNm, "S-");
						return jrRtn;
					}
				}

				/*********************************************
				 * 3. 대체크레인 정보 조회
				 *********************************************/
				jrParam.setField("YD_SCH_CD", ydSchCd);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule
				SELECT YD_SCH_CD
				     , DEL_YN
				     , YD_GP
				     , YD_BAY_GP
				     , YD_SCH_RNG_CD
				     , YD_SCH_WHIO_GP
				     , YD_SCH_DIV_GP
				     , YD_SCH_RULE_ACT_STAT
				     , YD_WRK_CRN
				     , YD_WRK_CRN_PRIOR
				     , YD_ALT_CRN_YN
				     , YD_ALT_CRN
				     , YD_ALT_CRN_PRIOR
				     , CD_CONTENTS
				     , YD_SCH_PROH_EXN
				  FROM TB_YD_SCHRULE
				 WHERE 1 = 1
				   AND YD_GP    IN ('H','J')
				   AND YD_SCH_CD = :V_YD_SCH_CD
				   AND DEL_YN    = 'N'
				*/
				JDTORecordSet jsSchRule = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "대체크레인 정보조회");
				if( jsSchRule.size() < 1 ) {

					sMsg = "스케쥴 정보조회 실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jsSchRule.first();
				JDTORecord jrSchRule = jsSchRule.getRecord();

				String ydWrkCrn		= commUtils.trim(jrSchRule.getFieldString("YD_WRK_CRN"));		// 작업크레인
				String ydWrkCrnPrior= commUtils.trim(jrSchRule.getFieldString("YD_WRK_CRN_PRIOR"));	// 스케쥴 우선순위
				String ydAltCrnYn	= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN_YN"));	// 대체크레인 유무
				String ydAltCrn		= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN"));		// 대체크레인
				String ydAltCrnPrior= commUtils.trim(jrSchRule.getFieldString("YD_ALT_CRN_PRIOR"));	// 대체크레인 스케쥴 우선순위

				if( !"Y".equals(ydAltCrnYn) ) {

					sMsg = "대체크레인 유무가 ["+ ydAltCrnYn +"]으로 설정되어 있어 변경실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				if( "".equals(ydAltCrn) ) {

					sMsg = "대체크레인이 설정되어 있지 않습니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 4. 크레인변경 대상 조회
				 *********************************************/
				String sChgCrn		= ydEqpId ;
				String sChgPrior	= ydWrkCrnPrior;

				/*if( ydEqpId.equals(ydWrkCrn) ) {
					sChgCrn		= ydAltCrn;
					sChgPrior	= ydAltCrnPrior;
				} else {
					sChgCrn		= ydWrkCrn;
					sChgPrior	= ydWrkCrnPrior;
				}*/

				jrParam.setField("YD_EQP_ID", sChgCrn);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp
				SELECT *
				  FROM TB_YD_EQP
				 WHERE YD_EQP_ID = :V_YD_EQP_ID
				   AND DEL_YN = 'N'
			    */
				JDTORecordSet jsChgCrn = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdEqp", logId, mthdNm, "변경대상 크레인 정보 조회");
				if( jsChgCrn.size() < 1 ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 설비정보 조회 실패!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				String sChgEqpStat = commUtils.trim(jsChgCrn.getRecord(0).getFieldString("YD_EQP_STAT"));
				if( "B".equals(sChgEqpStat) ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 설비상태가 고장입니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				String sChgEqpWrkMode = commUtils.trim(jsChgCrn.getRecord(0).getFieldString("YD_EQP_WRK_MODE"));
				if( "2".equals(sChgEqpWrkMode) ) {

					sMsg = "변경대상 크레인["+ sChgCrn +"] 운전모드가 OFF-LINE 입니다!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 5. 권상지시 상태면 작업크레인 스케쥴 취소 전문 송신
				 *********************************************/
				if( "1".equals(ydWrkProgStat) ) {
					jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrYdMsg.setField("YD_CRN_SCH_ID"	, ydCrnSchId );
					jrYdMsg.setField("MSG_GP"			, "D");

					/************************************
					 * 크레인작업지시(YDY5L004) 취소 송신
					 ************************************/
					jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrYdMsg));
				}

				/*********************************************
				 * 6. 작업예약  우선순위 변경
				 *********************************************/
				jrParam.setField("YD_WBOOK_ID"	, ydWbookId);
				jrParam.setField("YD_SCH_PRIOR"	, sChgPrior);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01
				UPDATE TB_YD_WRKBOOK
				   SET MODIFIER = :V_MODIFIER
				     , MOD_DDTT = SYSDATE
				     , YD_SCH_PRIOR = :V_YD_SCH_PRIOR
				 WHERE YD_WBOOK_ID  = :V_YD_WBOOK_ID
				*/
//				int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdWrkbook01", logId, mthdNm, "작업 예약 정보 우선순위 변경");
//				if( intRtnVal < 1 ) {
//					sMsg = "작업예약ID["+ ydWbookId +"] 우선순위 UPDATE ERROR!";
//					commUtils.printLog(logId, sMsg, "SL");
//
//					jrRtn.setField("RTN_CD" , "0");
//					jrRtn.setField("RTN_MSG", sMsg);
//					commUtils.printLog(logId, mthdNm, "S-");
//					return jrRtn;
//				}

				/*********************************************
				 * 7. 크레인스케쥴 변경크레인 UPDATE
				 *********************************************/
				jrParam.setField("YD_WRK_PROG_STAT", "W");
				int intRtnVal = 0;
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId
				SELECT *
				  FROM TB_YD_CRNSCH
				 WHERE 1=1
				   AND YD_WBOOK_ID = :V_YD_WBOOK_ID
				   AND YD_WRK_PROG_STAT IN ( '1','W', :V_YD_WRK_PROG_STAT )
				   AND DEL_YN = 'N'
				*/
				JDTORecordSet jsCrnSchByWbookId = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschYdStockYdCrnSchByWBookId", logId, mthdNm, "작업예약 크레인스케쥴 조회");
				for(int x=0; x<jsCrnSchByWbookId.size(); x++) {
					JDTORecord jrCrnSchByWbookId = jsCrnSchByWbookId.getRecord(x);

					String sDelYn	= commUtils.trim(jrCrnSchByWbookId.getFieldString("DEL_YN"));
					ydCrnSchId		= commUtils.trim(jrCrnSchByWbookId.getFieldString("YD_CRN_SCH_ID"));

					sMsg = "  "+ (x+1) +".크레인스케쥴ID["+ ydCrnSchId +"] DEL_YN["+ sDelYn +"]";
					commUtils.printLog(logId, sMsg, "SL");

					if( "Y".equals(sDelYn) ) continue;

					jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
					jrParam.setField("YD_EQP_ID"		, sChgCrn);
					jrParam.setField("YD_SCH_PRIOR"		, sChgPrior);
					jrParam.setField("YD_WRK_PROG_STAT"	, "W");
					jrParam.setField("YD_WORD_DT"		, "");
					/*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01
					UPDATE TB_YD_CRNSCH
					   SET MODIFIER         = :V_MODIFIER
					     , MOD_DDTT         = SYSDATE
					     , YD_EQP_ID        = :V_YD_EQP_ID
					     , YD_SCH_PRIOR     = :V_YD_SCH_PRIOR
					     , YD_WRK_PROG_STAT = :V_YD_WRK_PROG_STAT
					     , YD_WORD_DT       = :V_YD_WORD_DT
					 WHERE YD_CRN_SCH_ID    = :V_YD_CRN_SCH_ID
					*/
					intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch01", logId, mthdNm, "크레인스케쥴 UPDATE");
					if( intRtnVal < 1 ) {
						sMsg = "크레인스케쥴 크레인변경 UPDATE ERROR!";
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD" , "0");
						jrRtn.setField("RTN_MSG", sMsg);
						commUtils.printLog(logId, mthdNm, "S-");
						return jrRtn;
					}
				}

				/*********************************************
				 * 8. 변경 전 크레인 상태 [대기]로 UPDATE
				 *********************************************/
				jrParam.setField("YD_EQP_ID"	, ydEqpId2);
				jrParam.setField("YD_EQP_STAT"	, "W");
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MODIFIER    = :V_MODIFIER
				     , MOD_DDTT    = SYSDATE
				WHERE YD_EQP_ID    = :V_YD_EQP_ID
				*/
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "변경 전 크레인의 상태 UPDATE");
				if( intRtnVal < 1 ) {
					sMsg = "변경 전 크레인의 상태 UPDATE ERROR!";
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD" , "0");
					jrRtn.setField("RTN_MSG", sMsg);
					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************************
				 * 9. 변경 전 크레인 명령선택기동(Y5YDL007) 호출
				 *********************************************/
				jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
				jrYdMsg.setField("JMS_TC_CD"		, "Y5YDL007"); // JMSTC코드
				jrYdMsg.setField("YD_EQP_ID"		, ydEqpId2	); // 야드설비ID
				jrYdMsg.setField("YD_WRK_PROG_STAT"	, "W"		); // 야드작업진행상태

				jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);

				sMsg = "변경 전 크레인 명령선택기동(Y5YDL007) QUEUE 저장.";
				commUtils.printLog(logId, sMsg, "SL");

				sMsg = "변경대상크레인["+ sChgCrn +"] 설비상태["+ sChgEqpStat +"]";
				commUtils.printLog(logId, sMsg, "SL");

				/*******************************************************
				 * 10. 변경 후 대상 크레인 작업대기[W] 명령선택기동(Y5YDL007) 호출
				 *******************************************************/
				if( "W".equals(sChgEqpStat) ) {
					jrYdMsg = commUtils.getParam(logId, mthdNm, sModifier);
					jrYdMsg.setField("JMS_TC_CD"		, "Y5YDL007"); // JMSTC코드
					jrYdMsg.setField("YD_EQP_ID"		, sChgCrn	); // 야드설비ID
					jrYdMsg.setField("YD_WRK_PROG_STAT"	, "W"		); // 야드작업진행상태

					jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);

					sMsg = "변경대상 크레인 명령선택기동(Y5YDL007) QUEUE 저장.";
					commUtils.printLog(logId, sMsg, "SL");
				}
			}

			jrRtn.setField("RTN_CD" , "1");
			jrRtn.setField("RTN_MSG", "크레인 변경 작업 완료.");

			commUtils.printLog(logId, mthdNm, "S-");
	 		return jrRtn;

		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

	
	/**
	 * 오퍼레이션명 : 스케쥴 재전송 (크레인작업관리 화면-소재)
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord reSendSchCoilYdCrnWorkMgtH(GridData gdReq)throws JDTOException  {
		String mthdNm = "스케쥴 재전송 (크레인작업관리 화면[소재])[CCoilJspSeEJB.reSendSchCoilYdCrnWorkMgtH] < " + gdReq.getNavigateValue();    	
		String logId  = gdReq.getIPAddress();
		
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");
			JDTORecord jrRtn   = JDTORecordFactory.getInstance().create(); 
			
			String sModifier = commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String sLogMsg   = "";
			String sYdSchId  = "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int Loopi = 0; Loopi < rowCnt; Loopi++) {
				sYdSchId = commUtils.nvl(commUtils.getValue(gdReq, "YD_CRN_SCH_ID", Loopi),"");
			}	
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_CRN_SCH_ID",sYdSchId);		
			
			/*
			 SELECT YD_EQP_ID                                 AS YD_EQP_ID
				      ,YD_CRN_SCH_ID                          AS YD_CRN_SCH_ID
				      ,REGISTER                               AS REGISTER
				      ,TO_CHAR(REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
				      ,MODIFIER                               AS MODIFIER
				      ,TO_CHAR(MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
				      ,DEL_YN                                 AS DEL_YN
				      ,YD_WBOOK_ID                            AS YD_WBOOK_ID
				      ,YD_EQP_ID                              AS YD_EQP_ID
				      ,YD_GP                                  AS YD_GP
				      ,YD_BAY_GP                              AS YD_BAY_GP
				      ,YD_SCH_CD                              AS YD_SCH_CD
				      ,YD_SCH_ST_GP                           AS YD_SCH_ST_GP
				      ,YD_SCH_REQ_GP                          AS YD_SCH_REQ_GP
				      ,YD_SCH_PRIOR                           AS YD_SCH_PRIOR
				      ,YD_EQP_WRK_STAT                        AS YD_EQP_WRK_STAT
				      ,YD_WRK_PROG_STAT                       AS YD_WRK_PROG_STAT
				      ,TO_CHAR(YD_WBOOK_DT, 'YYYYMMDDHH24MISS') AS YD_WBOOK_DT
				      ,TO_CHAR(YD_SCH_DT, 'YYYYMMDDHH24MISS')   AS YD_SCH_DT
				      ,TO_CHAR(YD_WORD_DT, 'YYYYMMDDHH24MISS')  AS YD_WORD_DT
				      ,TO_CHAR(YD_UP_CMPL_DT, 'YYYYMMDDHH24MISS') AS YD_UP_CMPL_DT
				      ,TO_CHAR(YD_DN_CMPL_DT, 'YYYYMMDDHH24MISS') AS YD_DN_CMPL_DT
				      ,YD_WRK_HDS_DD                      AS YD_WRK_HDS_DD
				      ,YD_WRK_DUTY                        AS YD_WRK_DUTY
				      ,YD_WRK_PARTY                       AS YD_WRK_PARTY
				      ,YD_MAIN_WRK_MTL_SH                 AS YD_MAIN_WRK_MTL_SH
				      ,YD_AID_WRK_MTL_SH                  AS YD_AID_WRK_MTL_SH
				      ,YD_AID_WRK_UPDN_GP                 AS YD_AID_WRK_UPDN_GP
				      ,YD_TO_LOC_DCSN_MTD                 AS YD_TO_LOC_DCSN_MTD
				      ,YD_TO_LOC_GUIDE                    AS YD_TO_LOC_GUIDE
				      ,YD_EQP_WRK_SH                      AS YD_EQP_WRK_SH
				      ,YD_EQP_WRK_WT                      AS YD_EQP_WRK_WT
				      ,YD_EQP_WRK_T                       AS YD_EQP_WRK_T
				      ,YD_EQP_WRK_MAX_W                   AS YD_EQP_WRK_MAX_W
				      ,YD_EQP_WRK_MAX_L                   AS YD_EQP_WRK_MAX_L
				      ,YD_CRN_SB_CTL_H                    AS YD_CRN_SB_CTL_H
				      ,YD_CRN_GRAB_USE_RULE_ID            AS YD_CRN_GRAB_USE_RULE_ID
				      ,YD_UP_WO_LOC                       AS YD_UP_WO_LOC
				      ,YD_UP_WO_LAYER                     AS YD_UP_WO_LAYER
			        	:
				      ,YD_L2_REQUEST_STAT                 AS YD_L2_REQUEST_STAT
				      ,UP_ROTATION_ANGLE                  AS UP_ROTATION_ANGLE
				      ,DOWN_ROTATION_ANGLE                AS DOWN_ROTATION_ANGLE
				      ,(CASE WHEN  YD_DN_WO_LOC LIKE 'HH%' 
				                AND YD_EQP_ID='HHCRH2'
				                AND SUBSTR(YD_DN_WO_LOC,3,2) BETWEEN '00' AND '99' 
				                AND SUBSTR(YD_DN_WO_LOC,7,2)='01' 
				                AND YD_DN_WO_LAYER='001' 
				                AND YD_TO_LOC_DCSN_MTD='S'  --주작업인 경우
				                THEN 'Y' ELSE 'N' END) AS HDONG_YN
				     , YD_WRK_PROG_STAT                   AS YD_WRK_PROG_STAT_CD
				  FROM TB_YD_CRNSCH
				 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
				 ORDER BY YD_CRN_SCH_ID */
			JDTORecordSet jsYdCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnsch", logId, mthdNm, "기존 To 위치 정보 와 변경 To 위치 정보");
			
			if(jsYdCrnSch.size() < 0 ) {
				sLogMsg = "[JSP Session] " +  "스케쥴 재전송 (크레인작업관리 화면) 해당 크레인스케줄 ID  정보: ["+ sYdSchId +" ]조회시 ERROR발생";            		
        		commUtils.printLog(logId, sLogMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sLogMsg);	
				return jrRtn;
			}else if(jsYdCrnSch.size() == 0 || jsYdCrnSch == null){
				sLogMsg = "[JSP Session] " +  "스케쥴 재전송 (크레인작업관리 화면)해당 스케줄크레인스케줄 ID  정보: ["+ sYdSchId + "] 가 존재하지않습니다";            		
				commUtils.printLog(logId, sLogMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sLogMsg);	
				return jrRtn;
        		
			}
			
			jsYdCrnSch.first();
			
			JDTORecord jrYdCrnSch = jsYdCrnSch.getRecord();
			
			commUtils.printLog(logId, "크레인 작업재료 조회", "SL");
			
			/*
			  * SELECT YD_CRN_SCH_ID  AS YD_CRN_SCH_ID
				      ,A.STL_NO  AS STL_NO
				      , (SELECT X.BUY_SLAB_NO
				         FROM TB_QM_BUYSLABINFO X
				        WHERE X.MSLAB_NO = A.STL_NO) AS GU_SALB_NO
				        
				      ,A.REGISTER  AS REGISTER
				      ,TO_CHAR(A.REG_DDTT, 'YYYYMMDDHH24MISS')  AS REG_DDTT
				      ,TO_CHAR(A.MOD_DDTT, 'YYYYMMDDHH24MISS')  AS MOD_DDTT
				      ,A.MODIFIER  AS MODIFIER
				      ,A.DEL_YN  AS DEL_YN
				      ,A.YD_AID_WRK_YN  AS YD_AID_WRK_YN
				      ,A.YD_STK_LYR_NO  AS YD_STK_LYR_NO
				      ,A.YD_STK_LOT_TP  AS YD_STK_LOT_TP
				      ,A.YD_STK_LOT_CD  AS YD_STK_LOT_CD
				      ,A.HCR_GP  AS HCR_GP
				      ,A.STL_PROG_CD  AS STL_PROG_CD
				      ,A.YD_MTL_ITEM  AS YD_MTL_ITEM
				      ,A.YD_ROUTE_GP  AS YD_ROUTE_GP
				      ,B.YD_MTL_T 
				      ,B.YD_MTL_W
				      ,B.YD_MTL_L
				      ,B.YD_MTL_WT
				      ,B.DEMANDER_CD
				      ,B.ORD_NO || '-' || B.ORD_DTL AS ORD
				      ,B.YD_AIM_RT_GP
				  FROM TB_YD_CRNWRKMTL A
				      ,TB_YD_STOCK B
				 WHERE A.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
				   AND (A.DEL_YN <> 'Y' OR A.DEL_YN IS NULL)
				   AND A.STL_NO = B.STL_NO
				 ORDER BY YD_STK_LYR_NO DESC
			  */
			JDTORecordSet jsYdCrnSchMtl = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnwrkmtlID", logId, mthdNm, "작업재료 정보조회");
			
			
			sLogMsg = "스케쥴 재전송 (크레인작업관리 화면) 크레인 작업재료 조회 리턴값 :[ "+  jsYdCrnSchMtl.size() +" ]";
			commUtils.printLog(logId, sLogMsg, "SL");
			
			if (jsYdCrnSchMtl.size() == 0) {
				sLogMsg =  "스케쥴 재전송 (크레인작업관리 화면) 해당 스케줄에 해당되는 크레인 작업 재료가 없습니다.";
				commUtils.printLog(logId, sLogMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sLogMsg);	
				return jrRtn;
			} else if (jsYdCrnSchMtl.size() < 0){
				
				sLogMsg = "스케쥴 재전송 (크레인작업관리 화면)해당 스케줄에 해당되는 재료 조회시 ERROR";
				commUtils.printLog(logId, sLogMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, sLogMsg);	
				return jrRtn;
			}
			
			//크레인 스케줄의 값을 다시 재전송한다. 
        	
			String ydCrnSchId	   = commUtils.nvl(jrYdCrnSch.getFieldString("YD_CRN_SCH_ID"), "");
			String ydWrkProgStatL2 = commUtils.nvl(jrYdCrnSch.getFieldString("YD_L2_REQUEST_STAT"), "");
			
			JDTORecord jrInPara = commUtils.getParam(logId, mthdNm, sModifier);
    		//작업지시 전문 전송 data setup
			jrInPara.setField("JMS_TC_CD"			, "YDY5L004");
			jrInPara.setField("YD_CRN_SCH_ID"		, ydCrnSchId);
			jrInPara.setField("YD_WRK_PROG_STAT"	, ydWrkProgStatL2);
			jrInPara.setField("YD_SCH_CD"			, commUtils.nvl(jrYdCrnSch.getFieldString("YD_SCH_CD"), ""));
			jrInPara.setField("YD_GP"				, commUtils.nvl(jrYdCrnSch.getFieldString("YD_GP"), ""));
			jrInPara.setField("MSG_GP"				, "R");
        	jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrInPara));
        	
        	sLogMsg = "[스케쥴 재전송 (크레인작업관리 화면)] ["+ydWrkProgStatL2+"]인 스케줄["+ydWrkProgStatL2+"]을 재전송";
			
			commUtils.printLog(logId, mthdNm, "S-");
			jrRtn.setField("RTN_CD" 	, "1");	
			jrRtn.setField("RTN_MSG" 	, sLogMsg);	
			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}	
	

