	/**
	 * 지포장 보급 등록
	 * 강정선  2019.09.18
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdSendGF(GridData gdReq) throws DAOException {
		String mthdNm	= "지포장 보급관리 - 보급등록[CCoilJspSeEJB.updCoilYdSendGF] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {	
			commUtils.printLog(logId, mthdNm, "S+");

			String sMsg				= "";
			String rtnCd			= "";
			String rtnMsg			= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam   	= null;
			String sFirstAimBayGp 	= "";
			String sFirstSchCd 		= "";
			String sFirstWbookId 	= "";


			String sYdGp = commUtils.trim(gdReq.getParam("YD_GP"));
			if ( "".equals(sYdGp)) {
				sMsg = "YD_GP(야드구분) Error";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			
			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i<rowCnt; i++) {
				String sStkColGp = commUtils.getValue(gdReq, "YD_STK_COL_GP", i); 
				
				// 논리번지에서 동 체크
				if (sStkColGp.length() < 3) {
					throw new Exception("저장위치 Error");
				}
				String sStkBayGp = sStkColGp.substring(1, 2);
				
				if (!"B".equals(sStkBayGp) &&						
					!"C".equals(sStkBayGp) &&
					!"E".equals(sStkBayGp) &&
					!"H".equals(sStkBayGp) ) {
					
					sMsg = "B,C,E,H동 이외의 동은 동간이적후 지포장을 선택해 주시기 바랍니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
				}
 
				String sSchCd = sYdGp + sStkBayGp + "GF01UH";  //지포장 SCH_CD

				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("YD_USER_ID"));
				jrParam.setField("STL_SH"				, "1"											);  
				jrParam.setField("STL_NO1"				, commUtils.getValue(gdReq, "STL_NO", i)		);
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1"											);
				jrParam.setField("YD_USER_ID"			, gdReq.getParam("YD_USER_ID")					);  
				jrParam.setField("YD_AIM_BAY_GP"		, commUtils.getValue(gdReq, "YD_AIM_BAY_GP"	, i)); 
				jrParam.setField("YD_AIM_YD_GP"			, sYdGp											);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "S"											);
				jrParam.setField("TO_YD_STK_BED_NO"		, ""											);
				jrParam.setField("YD_SCH_CD"			, sSchCd										);
				
				EJBConnector ejbConn1 = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn1.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });				
				
				rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0"	);
				rtnMsg		= commUtils.trim(jrWrkBook.getFieldString("RTN_MSG")	);
				sSchCd		= commUtils.trim(jrWrkBook.getFieldString("YD_SCH_CD")	);

				if (!("1".equals(rtnCd))) {
					commUtils.printLog(logId, rtnMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", rtnMsg);
					return jrRtn;
					
				} else {
					if ("".equals(sFirstWbookId)) { 
						
						sFirstWbookId  = commUtils.trim(jrWrkBook.getFieldString("YD_WBOOK_ID"));
						sFirstSchCd    = sSchCd;
						sFirstAimBayGp = sStkBayGp;
					}
				} 	
				sMsg = "스케줄 코드 : ["+ sFirstSchCd +"]";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			if (!"".equals(sFirstWbookId)) {

				// 지포장장 To위치 가능 여부 체크 start
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("YD_USER_ID"));
			    jrParam.setField("YD_BAY_GP", sFirstAimBayGp);

			    /*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdLocByGFplace
			    SELECT *
			      FROM (
			            SELECT A.YD_STK_COL_GP
			                 , A.YD_STK_BED_NO
			                 , A.YD_STK_LYR_NO
			                 , CASE WHEN SUBSTR(A.YD_STK_COL_GP, 2, 1) IN('B','C')
			                         AND SUBSTR(A.YD_STK_COL_GP, 3, 2) BETWEEN '01' AND '40'
			                   THEN 2
			                   ELSE 1
			                   END AS FROM_LOC
			              FROM USRYDA.TB_YD_STKLYR     A ,
			                   USRYDA.TB_YD_SCHRULE    B ,
			                   USRYDA.TB_YD_LOCSRCHRNG C 
			             WHERE B.YD_SCH_CD = C.YD_SCH_CD
			               AND A.DEL_YN                 = 'N'
			               AND B.DEL_YN                 = 'N'
			               AND C.DEL_YN                 = 'N'
			               AND A.YD_STK_LYR_ACT_STAT    = 'E'
			               AND A.STL_NO              IS NULL
			               AND B.CD_CONTENTS         LIKE '%지포장%'
			               AND A.YD_STK_COL_GP       LIKE '%GF%'
			               AND B.YD_SCH_CD           LIKE 'J%'
			               AND A.YD_STK_COL_GP       LIKE 'J'|| :V_YD_BAY_GP ||'%'  --> 입력 값 (야드 동)
			             GROUP BY A.YD_STK_COL_GP, A.YD_STK_BED_NO, A.YD_STK_LYR_NO
			         ) X
			    */     
			    JDTORecordSet jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdLocByGFplace", logId, mthdNm, "지포장적치여부");
			    
			    if (jsResult.size() == 0) {
					sMsg = "지포장장 적재 불가능. 지포장장을 비워주시기 바랍니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

			    // 지포장 스케줄기동 여부 체크 start
			    jrParam  = commUtils.getParam(logId, mthdNm, gdReq.getParam("YD_USER_ID"));
			    jrParam.setField("YD_BAY_GP", sFirstAimBayGp);
			    
			    /*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdLocByGFExSCH
			    SELECT YD_CRN_SCH_ID
			      FROM TB_YD_CRNSCH
			     WHERE DEL_YN       = 'N'
			       AND YD_GP        = 'J'
			       AND YD_BAY_GP    = :V_YD_BAY_GP
			       AND YD_SCH_CD LIKE '%GF01UH'
				*/
			    jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdLocByGFExSCH", logId, mthdNm, "지포장보급스케쥴여부");
			    
			    if (jsResult.size() > 0) {
					sMsg = "지포장 보급 스케줄이 존재하므로 작업예약만 등록합니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "1");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}	
			    
				
				JDTORecord jrParam2 = commUtils.getParam(logId, mthdNm, gdReq.getParam("YD_USER_ID"));
				jrParam2.setField("YD_SCH_CD"		, sFirstSchCd); 
				jrParam2.setField("YD_WBOOK_ID"	, sFirstWbookId); 
				
				JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrParam2);
				rtnCd	= commUtils.trim(jrRunSch.getFieldString("RTN_CD"));
				rtnMsg	= commUtils.trim(jrRunSch.getFieldString("RTN_MSG"));

				if (!("1".equals(rtnCd))) {
					commUtils.printLog(logId, rtnMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", rtnMsg);
					return jrRtn;
				}
				jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
			}
			
			sMsg = "지포장 보급등록을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");
			
			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}
	
