						jrInRec.setField("STL_NO" 	    	, sTagStlNo);	
						jrInRec.setField("YD_SCH_CD" 	    , commUtils.getValue(gdReq, "YD_SCH_CD", i));	
						jrInRec.setField("YD_STK_COL_GP" 	, commUtils.getValue(gdReq, "TO_YD_STK_COL_GP", i));	
						jrInRec.setField("YD_STK_BED_NO" 	, commUtils.getValue(gdReq, "TO_YD_STK_BED_NO", i));	
						jrInRec.setField("YD_STK_LYR_NO" 	, "001");	
							
						EJBConnector ejbConn = new EJBConnector("default", "CCoilSchSeEJB", this);
