	/**
	 * 소재코일야드 메뉴얼 작업지시 편성-일품단위 이적 등록 [소재]
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return GridData
	 * @throws DAOException
	 * @throws JDTOException
	 */
	public JDTORecord updMtlUnitMvstkRegH(GridData gdReq) throws DAOException {
		String mthdNm = "일품단위 이적 등록 [소재][CCoilJspSeEJB.updMtlUnitMvstkRegH]  < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");
			
			String sTCar     	 = commUtils.trim(gdReq.getParam("T_CAR"));
            String sFrYdStkPos   = commUtils.trim(gdReq.getParam("FROM_YD_STK_POS"));
            String sToYdStkPos   = commUtils.trim(gdReq.getParam("TO_YD_STK_POS"));
			String sModifier 	 = commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String sydEqpId  =  commUtils.trim(gdReq.getParam("YD_EQP_ID"));
			
            String sToYdStkBedNo = commUtils.getValue(gdReq, "TO_YD_STK_COL_GP", 0) + commUtils.getValue(gdReq, "TO_YD_STK_BED_NO", 0);
            String sToAimBayGp   = commUtils.getValue(gdReq, "YD_AIM_BAY_GP", 0);
            
            commUtils.printLog(logId, "FROM_YD_STK_POS=="+sFrYdStkPos.substring(1, 2), "SL");
            commUtils.printLog(logId, "TO_YD_STK_POS  =="+sToYdStkPos.substring(1, 2), "SL");
            commUtils.printLog(logId, "FROM_YD_STK_POS=="+sFrYdStkPos, "SL");
            commUtils.printLog(logId, "TO_YD_STK_POS  =="+sToYdStkPos, "SL");

			
			String ydGp			= "";
			String ydAimBayGp	= "";
			String ydTcarSchId  = "";
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("FROM_YD_STK_COL_GP", sFrYdStkPos.substring(0, 6));
			jrParam.setField("TO_YD_STK_COL_GP"  , sToYdStkPos.substring(0, 6));
			jrParam.setField("YD_WRK_PLAN_TCAR"  , sTCar);
			
            JDTORecord jrWidthChk = (JDTORecord)this.getStkColWidthGp(jrParam);
			String rtnCd  = commUtils.nvl(jrWidthChk.getFieldString("RTN_CD"), "0");
			String rtnMsg = commUtils.nvl(jrWidthChk.getFieldString("RTN_MSG"), "");
			
			if (!"1".equals(rtnCd)) {
				jrRtn.setField("RTN_CD"  , "0");	
				jrRtn.setField("RTN_MSG" , rtnMsg);	
				
				return jrRtn;	
			}
			
			commUtils.printLog(logId, sToYdStkBedNo+"==updMtlUnitMvstkReg==================================================================", "S+");
			
			// 메뉴얼 코일 작업지시 편성체크
			JDTORecord jrRtn1 = (JDTORecord)this.updMtlUnitMvstkReg(gdReq);
			
			rtnCd	= commUtils.nvl(jrRtn1.getFieldString("RTN_CD"), "0");
			rtnMsg	= commUtils.nvl(jrRtn1.getFieldString("RTN_MSG"), "");
			if (!("1".equals(rtnCd))) {
				jrRtn.setField("RTN_CD"  , "0");	
				jrRtn.setField("RTN_MSG" , rtnMsg);	
				
				return jrRtn;	
			} else {
				jrRtn.setField("RTN_MSG" , rtnMsg);						
			} 	
			
			jrRtn1.setField("TO_YD_STK_BED_NO"  , sToYdStkBedNo); //LOC_GUIDE 값 생성
			jrRtn1.setField("YD_AIM_BAY_GP"     , sToAimBayGp); //목적동
			jrRtn1.setField("YD_AIM_YD_GP"      , "H");
			jrRtn1.setField("MODIFIER"			, sModifier);
			jrRtn1.setField("YD_EQP_ID"			, sydEqpId);
			
			commUtils.printLog(logId, sToYdStkBedNo+"==jrRtn1==================================================================", "S+");
			commUtils.printParam(logId, jrRtn1); 
			if("".equals(sToYdStkBedNo)){
				jrRtn.setField("RTN_CD"  , "0");	
				jrRtn.setField("RTN_MSG" , "LOC_GUIDE 값 이상.");	
				
				return jrRtn;
			}
            //작업예약등록				
			
			EJBConnector ejbConn1 = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
			JDTORecord jrRtn3 = (JDTORecord)ejbConn1.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrRtn1 });
			
			rtnCd	         = commUtils.nvl(jrRtn3.getFieldString("RTN_CD")     , "0");
			rtnMsg	         = commUtils.nvl(jrRtn3.getFieldString("RTN_MSG")    , "");
			
			String ydWbookId = commUtils.nvl(jrRtn3.getFieldString("YD_WBOOK_ID"), ""); //"201903141521019029";//
			String ydSchCd	 = commUtils.nvl(jrRtn3.getFieldString("YD_SCH_CD")  , "");
			if (!("1".equals(rtnCd))) {
				jrRtn.setField("RTN_CD"  , "0");	
				jrRtn.setField("RTN_MSG" , rtnMsg);	
				return jrRtn;	

			} else {				
			
				jrRtn.setField("RTN_MSG"			, rtnMsg+ " <br> 정상적으로 작업예약까지 등록했습니다.");	
			
			} 	
			commUtils.printLog(logId, "스케줄 코드 :"+ ydSchCd.substring(2, 4), "SL");
			commUtils.printLog(logId, "ydSchCd substring(2, 4)==="+ydSchCd.substring(2, 4), "SL");
			
			String sSndFlag 	= "N";
			if("TC".equals(ydSchCd.substring(2, 4))) {
			// 설비 check 하여 
             //대차작업 송신 여부		
				JDTORecord jrInRec1 = commUtils.getParam(logId, mthdNm, sModifier);
				jrInRec1.setField("YD_WBOOK_ID" , ydWbookId);

				JDTORecord jrRtn2 = (JDTORecord)this.chkTCarMoveWrkBook(jrInRec1);
				
				rtnCd		= commUtils.nvl(jrRtn2.getFieldString("RTN_CD")        , "0");
				rtnMsg		= commUtils.nvl(jrRtn2.getFieldString("RTN_MSG")       , "");
				ydGp		= commUtils.nvl(jrRtn2.getFieldString("YD_GP")         , "");
				ydTcarSchId = commUtils.nvl(jrRtn2.getFieldString("YD_TCAR_SCH_ID"), "");
				ydAimBayGp	= commUtils.nvl(jrRtn2.getFieldString("YD_AIM_BAY_GP") , "");
				sSndFlag	= commUtils.nvl(jrRtn2.getFieldString("SND_FLAG")      , "");
				
				if( "0".equals(rtnCd)) {
					jrRtn.setField("RTN_CD" 			, "0");	
					jrRtn.setField("RTN_MSG"			, rtnMsg);	
					
					return jrRtn;	
				} else {	
					if( "Y".equals(sSndFlag)) {
						
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_EQP_ID"   , sTCar); //야드설비ID(대차)
						jrParam.setField("YD_TO_BAY"   , ydAimBayGp      ); //야드동구분(상차동)
						jrParam.setField("YD_WBOOK_ID" , ydWbookId);

						jrRtn = this.procTcarSchLevWo(jrParam);	
					}
				}	
				
			} else {
	//스케쥴등록	
				//to위치 가이드가 대차인 경우 기동 안함
				if (!sToYdStkBedNo.substring(2, 4).equals("TC")) {
					
					JDTORecord jrParam2 = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam2.setField("YD_SCH_CD"		, ydSchCd); 
					jrParam2.setField("YD_WBOOK_ID"  	, ydWbookId); 
					
					JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrParam2);
					
					rtnCd	= commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
					if (!("1".equals(rtnCd))) {
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG"	, rtnMsg);	
						
						return jrRtn;	
					} else {	
						jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						jrRtn.setField("RTN_MSG"	, rtnMsg+ " <br> 스케쥴까지 등록했습니다.");	
					}
				}	
			}			
			jrRtn.setField("RTN_CD" , "1");	

			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;
			
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 코일야드 크레인 상태 설정(고장/정상)
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdCrnStsSetCrnStat(GridData gdReq) throws DAOException {
	    String mthdNm = "코일야드 크레인 상태 설정(고장/정상)[CCoilJspSeEJB.updCoilYdCrnStsSetCrnStat] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			
			//저장위치 좌표설정화면 BED 수정
            int rowCnt = gdReq.getHeader("CHECK").getRowCount();
            String sModifier   = commUtils.trim(gdReq.getParam("YD_USER_ID"));
            JDTORecord jrRtn 	= commUtils.getParam(logId, mthdNm, sModifier);
			for (int i = 0; i < rowCnt; i++) {	
				
				//입출입  상태
				JDTORecord jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_EQP_ID"	, commUtils.getValue(gdReq ,"YD_EQP_ID" , i));
				jrParam.setField("YD_EQP_STAT"	, commUtils.getValue(gdReq ,"YD_EQP_STAT" , i));
						
				/*
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MODIFIER    = :V_MODIFIER
				     , MOD_DDTT    = SYSDATE
				 WHERE YD_EQP_ID   = :V_YD_EQP_ID
				*/
				int intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "코일야드 크레인 상태 설정(고장/정상)");
				
				if(intRtnVal < 1){
					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, "코일야드 크레인 상태 설정(고장/정상)중 ERROR.");				
					
					return jrRtn;
				}
			}	
			jrRtn.setField("RTN_CD"		, "1");
			jrRtn.setField("RTN_MSG"	, "정상 처리 되었습니다.");				
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}	
	


