	/**
	 * 크레인 작업 구분 지정
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord crnWrkGPartSet(GridData gdReq) throws DAOException {
    	String mthdNm = "크레인 작업 구분 지정[CCoilJspSeEJB.crnWrkGPartSet] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();

    	String sLogMsg = null;
		
		try{
			commUtils.printLog(logId, mthdNm, "S+");
			JDTORecord jrRtn = commUtils.getParam(logId, mthdNm, "");
			JDTORecord jrParam = null;
			sLogMsg = "[크레인 작업 구분 지정 ]시작";
			commUtils.printLog(logId, sLogMsg, "SL");
			String sModifier   = commUtils.trim(gdReq.getParam("YD_USER_ID"));
				
				
			//1. 크레인 스케줄에서  현재 선택된 스케줄과 , 주설비 크레인으로 선택된 정보이외의
		    // 정보를 전부 스케줄정보를 구한다
			jrParam = commUtils.getParam(logId, mthdNm, "");
			jrParam.setField("YD_EQP_ID", commUtils.getValue(gdReq ,"YD_EQP_ID" , 0));
			jrParam.setField("YD_SCH_CD", commUtils.getValue(gdReq ,"WRK_YD_SCH_CD" , 0));
			
			/*
			 * SELECT YD_SCH_CD
				  FROM TB_YD_SCHRULE
				 WHERE 1=1
				   AND YD_WRK_CRN   = :V_YD_WRK_CRN
				   AND YD_SCH_CD NOT IN  :V_YD_SCH_CD
			 */
			JDTORecordSet jsData = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getSchRuleBySchCdEqpId", logId, mthdNm, " 스케줄정보 조회");
			
			if(jsData.size() < 1){
				//ERR : 변경할 스케줄 정보가 없습니다.
				jrRtn.setField("RTN_CD" 		, "0");	
				jrRtn.setField("RTN_MSG"		, "변경할 스케줄 정보가 없습니다.");	
				return jrRtn;
			}
				
		
			JDTORecord jrTemp = commUtils.getParam(logId, mthdNm, "");
			for (int ii = 1; ii <= jsData.size(); ii++) {
				jsData.absolute(ii);
			
				jrTemp = jsData.getRecord();
				
				jrParam.setField("YD_SCH_CD", jrTemp.getField("YD_SCH_CD"));
				//Y : 기동금지 , N : 기동가능
				jrParam.setField("YD_SCH_PROH_EXN", "Y"); 
				jrParam.setField("MODIFIER"       , sModifier); //수정자				
				/*
				 * UPDATE TB_YD_SCHRULE
				      SET MODIFIER = :V_MODIFIER
				         ,MOD_DDTT = SYSDATE
				         ,YD_SCH_PROH_EXN = :V_YD_SCH_PROH_EXN
				  WHERE YD_SCH_CD = :V_YD_SCH_CD
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdSchrule", logId, mthdNm, "스케줄 정보에 모두 스케줄 금지상태로 세팅한다");
				
			}
			
			
			jrRtn.setField("RTN_CD"  , "1");	
			jrRtn.setField("RTN_MSG" , "크레인 작업 구분 정보변경 완료.");
			return jrRtn;
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

	
	
