			jrParam.setField("YD_WRK_PROG_STAT"    , "2");
			jrParam.setField("YD_SCH_CD"           , commUtils.getValue(gdReq ,"YD_SCH_CD" , 0));
			jrParam.setField("YD_CRN_SCH_ID"       , commUtils.getValue(gdReq ,"YD_CRN_SCH_ID" , 0));
