	/**
	 * 저장위치변경관리 (YD저장위치수정)
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updYDStrlocModMgt1(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "저장위치 변경에서 작업 취소-스케쥴 취소[CCoilJspSeEJB.updYDStrlocModMgt1]  < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		int   intRtnVal     = 0;
	
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");
			
			String frYdStkColGp	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_STK_COL_GP")), ""); 
			String frYdStkBedNo	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_STK_BED_NO")), ""); 
			String frYdStkLyrNo	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_STK_LYR_NO")), ""); 
			String ydUserId		= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_USER_ID")), ""); 
			String sStlNo		= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("STL_NO")), ""); 
			String ydAimRtGp	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_AIM_RT_GP")), ""); 
			String ydAimYdGp	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_AIM_YD_GP")), ""); 
			String ydAimBayGp	= commUtils.nvl(commUtils.trim(rcvMsg.getFieldString("YD_AIM_BAY_GP")), ""); 

			JDTORecord    jrRtn      = JDTORecordFactory.getInstance().create();
			JDTORecord    jrInParam  = commUtils.getParam(logId, mthdNm, ydUserId);
			jrInParam.setField("YD_STK_COL_GP"	, frYdStkColGp);	// 야드적치열구분
			jrInParam.setField("YD_STK_BED_NO"	, frYdStkBedNo);	// 야드적치배드
			jrInParam.setField("YD_STK_LYR_NO"	, frYdStkLyrNo);	// 야드단
			jrInParam.setField("MODIFIER"		, ydUserId);	// 수정자
			jrInParam.setField("STL_NO"		    , sStlNo);	// 코일번호
			jrInParam.setField("YD_AIM_YD_GP"	, ydAimYdGp);	// 목표야드
			jrInParam.setField("YD_AIM_BAY_GP"  , ydAimBayGp);	// 목적동
			jrInParam.setField("YD_AIM_RT_GP"	, ydAimRtGp);	// 목표행선
			
			/*
			UPDATE TB_YD_STOCK
			   SET YD_STK_COL_GP    = :V_YD_STK_COL_GP  -- 야드적치열구분
			      ,YD_STK_BED_NO    = :V_YD_STK_BED_NO  -- 야드적치배드
			      ,YD_CURR_STR_LOC  =  SUBSTR(:V_YD_STK_COL_GP,2,5)||SUBSTR(:V_YD_STK_LYR_NO,3,1)||:V_YD_STK_BED_NO
			      ,MODIFIER         = :V_MODIFIER       -- 수정자
			      ,MOD_DDTT         = SYSDATE           -- 수정일
				  ,YD_AIM_YD_GP		= NVL(:V_YD_AIM_YD_GP,YD_AIM_YD_GP)
				  ,YD_AIM_BAY_GP 	= NVL(:V_YD_AIM_BAY_GP,YD_AIM_BAY_GP)
				  ,YD_AIM_RT_GP     = NVL(:V_YD_AIM_RT_GP,YD_AIM_RT_GP)
			 WHERE STL_NO           = :V_STL_NO 
		*/	 
			intRtnVal = commDao.update(jrInParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updStrlocModMgtStock", logId, mthdNm, "저장위치 변경에서 작업 취소-스케쥴 취소");
			
			if(intRtnVal != 1){
				jrRtn.setField("RTN_CD" 	, "0");	
				jrRtn.setField("RTN_MSG" 	, "야드저장품 정보 수정에 실패 하였습니다");	
				return jrRtn;

			}
			
			commUtils.printLog(logId, mthdNm, "S-");
			// 정상 처리 후
			jrRtn.setField("SND_COMM_FLAG" 	, "N");	
			jrRtn.setField("RTN_CD" 		, "1");	
			jrRtn.setField("RTN_MSG" 		, "야드저장품 정보 수정 하였습니다");	
			
			return jrRtn;
			
			
		}catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}		



