	    		/**************************************************
	    		 * 1-4. 작업예약 등록 완료. 
	    		 *      준비 스케쥴 삭제
	    		 **************************************************/
				sMsg = "상차LOT편성[작업자지정] : 준비스케줄["+ ydPrepSchId +"] 삭제 시작";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
		    	jrParam.setField("YD_PREP_SCH_ID"	, ydPrepSchId);
