	    		/**************************************************
	    		 * 2-1. 신규작업예약 등록
	    		 **************************************************/
	    		jrParam	= commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
	    		jrParam.setField("YD_SCH_CD"	, ydSchCd);
	    		jrParam.setField("YD_CAR_USE_GP", ydCarUseGp);
	    		jrParam.setField("TRN_EQP_CD"	, sTrnEqpCd);
	    		jrParam.setField("YD_AIM_YD_GP"	, ydAimYdGp);
	    		jrParam.setField("YD_AIM_BAY_GP", ydAimBayGp);
	    		jrParam.setField("STL_SH"		, "1"); // 재료매수 필수값
	    		
				EJBConnector ejbConn	= new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkResult	= (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				rtnCd = commUtils.trim(jrWrkResult.getFieldString("RTN_CD"));
				
