	/**
	 * 차량작업관리 - 대기장도착
	 * 야드관리 > 2열연 코일야드[신] > 출하이송관리 > 차량작업관리
	 * 강정선 2019.11.05
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procStandByYdArrive(GridData gdReq) throws DAOException {
		String mthdNm	= "대기장도착[CCoilJspSeEJB.procStandByYdArrive] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String rtnCd			= "";
			String sMsg				= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();

			//PIDEV
//			String sApplyYnPI = ydPICommDAO.ApplyYnPI("", mthdNm, "APPPI0", "J", "*");			
			
			/****************************************************
			 * procDMYDR061 대기장도착 실적 호출
			 ****************************************************/
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {
				jrParam.setField("YD_GP"			, commUtils.getValue(gdReq, "YD_GP", i));			// 야드구분
				jrParam.setField("CMBN_CARLD_YN"	, commUtils.getValue(gdReq, "CMBN_CARLD_YN", i));	// 조합상차유무(시작:S, 종료:E, 단일상차:N)
				jrParam.setField("WORK_GP"			, commUtils.getValue(gdReq, "WORK_GP", i));			// 작업구분
				jrParam.setField("TEL_NO"			, commUtils.getValue(gdReq, "TEL_NO", i));			// 전화번호
				jrParam.setField("TRANS_ORD_DT"		, commUtils.getValue(gdReq, "TRANS_ORD_DT", i));	// 운송지시일자
				jrParam.setField("TRANS_ORD_SEQNO"	, commUtils.getValue(gdReq, "TRANS_ORD_SEQNO", i));	// 운송지시순번
				jrParam.setField("CAR_NO"			, commUtils.getValue(gdReq, "CAR_NO", i));			// 차량번호
				jrParam.setField("CARD_NO"			, commUtils.getValue(gdReq, "CARD_NO", i));			// 카드번호
				jrParam.setField("WAIT_ARR_DDTT"	, commUtils.getDateTime14());						// 대기장도착시간 yyyyMMddHHmmss ## 기존 null 값
				jrParam.setField("WAIT_ARR_GP"		, "B");												// * 대기장도착구분  - B:BACKUP , S:SMARTPHONE ## 기존 null 값
				jrParam.setField("CAR_KIND"			, "TR");	 										// * TR 추가 ## 기존 null 값
				jrParam.setField("DRIVER_NAME"		, commUtils.getValue(gdReq, "DRIVER_NAME", i));

				EJBConnector ejbConn = null;
				JDTORecord jrArrived = null;
				
				// PIDEV
//				if("Y".equals(sApplyYnPI)) {
					ejbConn = new EJBConnector("default", "YdCoilL3RcvPISeEJB", this);
					jrArrived = (JDTORecord)ejbConn.trx("procM10LMYDJ_DMYDR061", new Class[] { JDTORecord.class }, new Object[] { jrParam });					
//				} else {
//					ejbConn = new EJBConnector("default", "CCoilL3RcvSeEJB", this);
//					jrArrived = (JDTORecord)ejbConn.trx("rcvDMYDR061", new Class[] { JDTORecord.class }, new Object[] { jrParam });					
//				}
				
				// 입동지시 전문 Return
				jrRtn = commUtils.addSndData(jrRtn, jrArrived);
				
				// 현재 Method 마이그레이션 작업이 되지 않아 Return 값이 없을수 있으므로 NVL 처리함
				rtnCd = commUtils.nvl(jrArrived.getFieldString("RTN_CD"), "1" );
				
				if( !"1".equals(rtnCd) ) {
					
					sMsg = "대기장도착실적 실행 실패! <br>" + commUtils.trim(jrArrived.getFieldString("RTN_MSG"));
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}
			
			sMsg = "대기장도착을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 차량작업관리 - 출발처리
	 * 야드관리 > 2열연 코일야드[신] > 출하이송관리 > 차량작업관리
	 * 강정선 2019.11.05
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 * 기존 : updCarStart 차량출발처리 (C열연 공통)
	 */
	public JDTORecord procCarStart(GridData gdReq) throws DAOException {
		String mthdNm = "출발처리[CCoilJspSeEJB.procCarStart] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			// procDMYDR040
			int intRtnVal			= 0;
			String rtnCd			= "";
			String sMsg				= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= null;
			JDTORecordSet jsYdCarSch= null;
			String ydCarSchId		= "";
			String sPI_YD 			= "";
			String sPI_YD1 			= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {
				
				//--------------------------------------------//
				// 차량스케쥴 조회
				//--------------------------------------------//
				ydCarSchId = commUtils.getValue(gdReq, "YD_CAR_SCH_ID", i);
				
				// PIDEV_S :병행가동용:PI_YD
				sPI_YD = commUtils.nvl(gdReq.getParam("PI_YD"), "*");
				sPI_YD1 = commUtils.nvl(gdReq.getParam("PI_YD1"), "*");				
				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_CAR_SCH_ID", ydCarSchId);
				
				// PIDEV_S :병행가동용:PI_YD
				jrParam.setField("PI_YD", sPI_YD);
				jrParam.setField("PI_YD1", sPI_YD1);
				
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarsch */
				/*
				SELECT YD_CAR_SCH_ID                                   AS YD_CAR_SCH_ID
				     , REGISTER                                        AS REGISTER
				     , TO_CHAR(REG_DDTT,'YYYYMMDDHH24MISS')            AS REG_DDTT
				     , MODIFIER                                        AS MODIFIER
				     , TO_CHAR(MOD_DDTT,'YYYYMMDDHH24MISS')            AS MOD_DDTT
				     , DEL_YN                                          AS DEL_YN
				     , YD_EQP_ID                                       AS YD_EQP_ID
				     , YD_CAR_USE_GP                                   AS YD_CAR_USE_GP
				     , CAR_NO                                          AS CAR_NO
				     , TRN_EQP_CD                                      AS TRN_EQP_CD
				     , CAR_KIND                                        AS CAR_KIND
				     , TRANS_EQUIPMENT_TYPE                            AS TRANS_EQUIPMENT_TYPE
				     , YD_EQP_WRK_STAT                                 AS YD_EQP_WRK_STAT
				     , YD_WRK_PROG_STAT                                AS YD_WRK_PROG_STAT
				     , NVL(YD_EQP_WRK_SH,'0')                          AS YD_EQP_WRK_SH
				     , YD_EQP_WRK_WT                                   AS YD_EQP_WRK_WT
				     , YD_STK_BED_TP                                   AS YD_STK_BED_TP
				     , SPOS_WLOC_CD                                    AS SPOS_WLOC_CD
				     , (CASE WHEN ARR_WLOC_CD IS NULL
				               THEN (SELECT (SELECT D.ARR_WLOC_CD
				                               FROM TB_PT_STLFRTOMOVE D
				                              WHERE D.TRANSWORD_SEQNO = (SELECT MAX(TRANSWORD_SEQNO)
				                                                           FROM TB_PT_STLFRTOMOVE K
				                                                          WHERE D.STL_NO=K.STL_NO
				                                                            AND ROWNUM <= 1)
				                                AND B.STL_NO =D.STL_NO
				                            ) AS ARR_WLOC_CD
				                       FROM  TB_YD_STKLYR B
				                      WHERE A.YD_CARLD_STOP_LOC = B.YD_STK_COL_GP
				                        AND ROWNUM <= 1 )
				               ELSE ARR_WLOC_CD END
				       )                                               AS ARR_WLOC_CD
				     , YD_CARLD_LEV_LOC                                AS YD_CARLD_LEV_LOC
				     , TO_CHAR(YD_CARLD_LEV_DT   ,'YYYYMMDDHH24MISS')  AS YD_CARLD_LEV_DT
				     , TO_CHAR(YD_CARLD_PNT_WO_DT,'YYYYMMDDHH24MISS')  AS YD_CARLD_PNT_WO_DT
				     , YD_PNT_CD1                                      AS YD_PNT_CD1
				     , YD_PNT_CD2                                      AS YD_PNT_CD2
				     , YD_CARLD_WRK_BOOK_ID                            AS YD_CARLD_WRK_BOOK_ID
				     , YD_CARLD_SCH_REQ_GP                             AS YD_CARLD_SCH_REQ_GP
				     , YD_CARLD_STOP_LOC                               AS YD_CARLD_STOP_LOC
				     , TO_CHAR(YD_CARLD_ARR_DT ,'YYYYMMDDHH24MISS')    AS YD_CARLD_ARR_DT
				     , TO_CHAR(YD_CARLD_ST_DT  ,'YYYYMMDDHH24MISS')    AS YD_CARLD_ST_DT
				     , TO_CHAR(YD_CARLD_CMPL_DT,'YYYYMMDDHH24MISS')    AS YD_CARLD_CMPL_DT
				     , YD_CARLD_WRK_ACT_GP                             AS YD_CARLD_WRK_ACT_GP
				     , TO_CHAR(YD_CARLD_CHK_DT   ,'YYYYMMDDHH24MISS')  AS YD_CARLD_CHK_DT
				     , TO_CHAR(YD_CARUD_LEV_DT   ,'YYYYMMDDHH24MISS')  AS YD_CARUD_LEV_DT
				     , TO_CHAR(YD_CARUD_PNT_WO_DT,'YYYYMMDDHH24MISS')  AS YD_CARUD_PNT_WO_DT
				     , YD_PNT_CD3                                      AS YD_PNT_CD3
				     , YD_PNT_CD4                                      AS YD_PNT_CD4
				     , YD_CARUD_WRK_BOOK_ID                            AS YD_CARUD_WRK_BOOK_ID
				     , YD_CARUD_STOP_LOC                               AS YD_CARUD_STOP_LOC
				     , YD_CARUD_SCH_REQ_GP                             AS YD_CARUD_SCH_REQ_GP
				     , TO_CHAR(YD_CARUD_ARR_DT ,'YYYYMMDDHH24MISS')    AS YD_CARUD_ARR_DT
				     , TO_CHAR(YD_CARUD_CHK_DT ,'YYYYMMDDHH24MISS')    AS YD_CARUD_CHK_DT
				     , TO_CHAR(YD_CARUD_ST_DT  ,'YYYYMMDDHH24MISS')    AS YD_CARUD_ST_DT
				     , TO_CHAR(YD_CARUD_CMPL_DT,'YYYYMMDDHH24MISS')    AS YD_CARUD_CMPL_DT
				     , YD_CARUD_WRK_ACT_GP                             AS YD_CARUD_WRK_ACT_GP
				     , YD_TRN_WRK_DELY_CD                              AS YD_TRN_WRK_DELY_CD
				     , CARD_NO                                         AS CARD_NO
				     , YD_CAR_PROG_STAT                                AS YD_CAR_PROG_STAT
				     , FRTOMOVE_PLANT_GP                               AS FRTOMOVE_PLANT_GP
				     , PROC_TO                                         AS PROC_TO
				     , RENTPROC_CD                                     AS RENTPROC_CD
				     , YD_FRTOMOVE_YD_GP                               AS YD_FRTOMOVE_YD_GP
				     , YD_FRTOMOVE_BAY_GP                              AS YD_FRTOMOVE_BAY_GP
				     , URGENT_FRTOMOVE_WORD_GP                         AS URGENT_FRTOMOVE_WORD_GP
				     , DEST_TEL_NO                                     AS DEST_TEL_NO
				     , YD_DLVRDD_RULE_DD                               AS YD_DLVRDD_RULE_DD
				     , SHIPASSIGN_WORD_DATE                            AS SHIPASSIGN_WORD_DATE
				     , SHIPASSIGN_WORD_SEQNO                           AS SHIPASSIGN_WORD_SEQNO
				     , SHIP_CD                                         AS SHIP_CD
				     , SHIP_NAME                                       AS SHIP_NAME
				     , RSHP_HOLD_NO                                    AS RSHP_HOLD_NO
				     , BERTH_NO                                        AS BERTH_NO
				     , SAILNO                                          AS SAILNO
				     , YD_CAR_WRK_GP                                   AS YD_CAR_WRK_GP
				     , TRANS_ORD_DATE                                  AS TRANS_ORD_DATE
				     , TRANS_ORD_SEQNO                                 AS TRANS_ORD_SEQNO
				     , YD_BAYIN_WO_SEQ                                 AS YD_BAYIN_WO_SEQ
				     , YD_CAR_RCPT_CHK_YN                              AS YD_CAR_RCPT_CHK_YN
				     , YD_CAR_ISSUE_CHK_YN                             AS YD_CAR_ISSUE_CHK_YN
				     , YD_CAR_RCPT_CHECKER                             AS YD_CAR_RCPT_CHECKER
				     , YD_CAR_ISSUE_CHECKER                            AS YD_CAR_ISSUE_CHECKER
				     , SUBSTR(YD_CARLD_STOP_LOC,1,1)                   AS YD_GP
				     , (SELECT COUNT(*)
				          FROM TB_YD_CRNSCH
				         WHERE YD_WBOOK_ID = YD_CARLD_WRK_BOOK_ID
				           AND DEL_YN = 'N'
				       )                                               AS YD_CRN_SCH_ID
				  FROM TB_YD_CARSCH A
				 WHERE YD_CAR_SCH_ID = :V_YD_CAR_SCH_ID
				*/
				jsYdCarSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarsch", logId, mthdNm, "차량스케쥴검색");
				intRtnVal = jsYdCarSch.size();

				if( intRtnVal < 1 ) {
					
					sMsg = "차량스케쥴 조회 실패!";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				/****************************************************
				 * 차량출발처리 호출(DMYDR040)
				 * return : 
				 *    차량도착위치에대한 입동대기차량들중에서 가장빠른 입동순서를 가진
				 *    차량을 입동지시하는 차량입동지시요구 모듈을 호출한다.
				 ****************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("CARD_NO"			, jsYdCarSch.getRecord(0).getFieldString("CARD_NO"));
				jrParam.setField("CAR_NO"			, jsYdCarSch.getRecord(0).getFieldString("CAR_NO"));
				jrParam.setField("SPOS_WLOC_CD"		, jsYdCarSch.getRecord(0).getFieldString("SPOS_WLOC_CD"));
				jrParam.setField("SPOS_YD_PNT_CD"	, jsYdCarSch.getRecord(0).getFieldString("YD_PNT_CD1"));
				jrParam.setField("TRANS_ORD_DT"		, jsYdCarSch.getRecord(0).getFieldString("TRANS_ORD_DATE"));
				jrParam.setField("TRANS_ORD_SEQNO"	, jsYdCarSch.getRecord(0).getFieldString("TRANS_ORD_SEQNO"));

				EJBConnector ejbConn = new EJBConnector("default", "CCoilCarMvSeEJB", this);
				JDTORecord jrCarStart = (JDTORecord)ejbConn.trx("procOutCarLevWr", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				rtnCd = commUtils.nvl(jrCarStart.getFieldString("RTN_CD"), "1");
				
				if( !"1".equals(rtnCd) ) {
					
					sMsg = "차량출발처리 모듈 호출에 실패하였습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				jrRtn = commUtils.addSndData(jrRtn, jrCarStart);
			}
			
			sMsg = "차량출발을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	

	/**
	 * 제품 반품/회송작업 등록 - 하차작업등록
	 * 이현진
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord regCarUdWrk(GridData gdReq) throws DAOException {
		String mthdNm	= "하차작업등록[CCoilJspSeEJB.regCarUdWrk] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= null;

			String userid			= commUtils.trim(gdReq.getParam("userid"));
			String sCarNo			= gdReq.getParam("CAR_NO").toUpperCase();
			String sRetnWkGp		= gdReq.getParam("RETN_WK_GP");  //1:반품, 2:회송, 3:부분하차 , 4:소재반품
			String ydCarPntCd		= gdReq.getParam("YD_CARPNT_CD");
			String sTelNo			= commUtils.nvl(gdReq.getParam("TEL_NO"), "00000000000");
			String sCardNo			= commUtils.nvl(gdReq.getParam("CARD_NO"), "").toUpperCase();
			String ydCarSchId		= "";
			
			String sRetnTrgtYn = ""; //반품회송대상 여부 (Y : 대상)
			
			//--------------------------------------------------//
			// CHECK : 등록된 차량스케쥴의 코일번호 여부
			//--------------------------------------------------//
			JDTORecordSet jsCarSch = JDTORecordFactory.getInstance().createRecordSet("retTmp");
			String sStlNo = "";
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			for (int i = 0; i < rowCnt; i++) {
				
				sStlNo	    = commUtils.trim(gdReq.getHeader("STL_NO"      ).getValue(i));
				sRetnTrgtYn = commUtils.trim(gdReq.getHeader("RETN_TRGT_YN").getValue(i));
				
				jrParam  = commUtils.getParam(logId, mthdNm, userid);
				jrParam.setField("STL_NO", sStlNo);
				jrParam.setField("CAR_NO", sCarNo);

				/*
				SELECT A.YD_CAR_SCH_ID
				  FROM TB_YD_CARSCH A
				     , TB_YD_CARFTMVMTL B
				 WHERE A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
				   AND A.YD_CAR_PROG_STAT NOT IN ('5', 'E')
				   AND B.STL_NO   = :V_STL_NO
				   AND (A.CAR_NO  = :V_CAR_NO OR A.TRN_EQP_CD = :V_CAR_NO)
				   AND A.DEL_YN   = 'N'
				   AND B.DEL_YN   = 'N'
				*/
				jsCarSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarYdCarMtlDEL_YN", logId, mthdNm, "차량스케쥴재료검색");
				if( jsCarSch.size() > 0 ) {
					
					sMsg = "["+ sStlNo +"] 코일번호는 차량스케쥴["+ jsCarSch.getRecord(0).getFieldString("YD_CAR_SCH_ID") +"]에 등록되어 있습니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}
			
			//CARD_NO가 NULL인경우 차량번호 뒤에 4자리로 셋팅
			if ("".equals(sCardNo) && sCarNo.length() >= 4) {
				sCardNo = sCarNo.substring(sCarNo.length()-4, sCarNo.length());
			}
			
			//--------------------------------------------------//
			// 차량번호 GT(TT카) && 부분하차(3) 은 [차량초기화] 호출
			//--------------------------------------------------//
			String sCarKind = "";
			if (sCarNo.startsWith("GT")) {
				sCarKind = "TT";
			} else {
				sCarKind = "TR";
			}
			
			/* **************************************************************************
			 * 하차위치(YD_CARPNT_CD)로 WLOC_CD, YD_PNT_CD, 저장위치(YD_STK_COL_GP) 검색
			 * *************************************************************************/
			jrParam  = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CARPNT_CD", ydCarPntCd);

			/*
			SELECT YD_STK_COL_GP
			     , WLOC_CD
			     , YD_PNT_CD
			  FROM TB_YD_CARPOINT A
			 WHERE YD_CARPNT_CD LIKE :V_YD_CARPNT_CD
			*/
			JDTORecordSet jsCarPoint = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarPoint", logId, mthdNm, "차량포인트 조회");
			if( jsCarPoint.size() < 1 ) {
				sMsg = "차량포인트 조회실패! ["+ ydCarPntCd +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			
			String sWlocCd		= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("WLOC_CD"      ));
			String ydPntCd		= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("YD_PNT_CD"    ));
			String ydStkColGp	= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("YD_STK_COL_GP"));
			
			
			/* **************************************************************************
			 * 운송지시일자, 순번 생성  (999001 처럼 앞에  999를 붙인다.)
			 * *************************************************************************/
			/*
			SELECT A.TRANS_ORD_DATE
			     , A.TRANS_ORD_SEQNO + 1 AS TRANS_ORD_SEQNO
			  FROM(
			        SELECT TO_CHAR(SYSDATE,'YYYYMMDD')       AS TRANS_ORD_DATE
			             , NVL(MAX(TRANS_ORD_SEQNO), 999000) AS TRANS_ORD_SEQNO
			          FROM TB_YD_CARSCH
			         WHERE TRANS_ORD_DATE = TO_CHAR(SYSDATE,'YYYYMMDD')
			           AND TRANS_ORD_SEQNO >  999000
			      ) A
			*/
			jsCarSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRetnTransOrdNo", logId, mthdNm, "운송일자,순번 생성");
			if( jsCarSch.size() < 1 ) {
				sMsg = "운송지시일자/순번 생성 Error!";
				commUtils.printLog(logId, sMsg, "SL");

				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			
			String sTransOrdDate  = commUtils.trim(jsCarSch.getRecord(0).getFieldString("TRANS_ORD_DATE" ));
			String sTransOrdSeqNo = commUtils.trim(jsCarSch.getRecord(0).getFieldString("TRANS_ORD_SEQNO"));

			/***************************************
			 * 1. 저장위치 수정 TB_YD_STOCK
			 ***************************************/
			jrParam 				= commUtils.getParam(logId, mthdNm, userid);
			String[] sAimRtGp	= new String[1];
			String ydAimRtGp	= "";
			String sStlProgCd	= "";
			String ydStkBedNo	= ""; // 차상위치코드
			String sMsgContents	= ""; // 반납메세지
			String sCoilWt		= ""; // 코일중량(kg)
			String sCoilOutdia  = ""; // 외경
			
			JDTORecord jrStockData  = commUtils.getParam(logId, mthdNm, userid);
			jrStockData.setField("TRANS_ORD_DATE"	, sTransOrdDate);  // 운송지시일자 
			jrStockData.setField("TRANS_ORD_SEQNO"	, sTransOrdSeqNo); // 운송지시순번
			jrStockData.setField("CARD_NO"			, sCardNo);        // 차량번호 끝4자리
			jrStockData.setField("CAR_NO"			, sCarNo);         // 차량번호
			jrStockData.setField("STL_APPEAR_GP"	, "Y");            // 재료외형 : Y(제품)
			
			for (int i = 0; i < rowCnt; i++ ) {
				sStlNo		 = commUtils.getValue(gdReq, "STL_NO", i); 
				ydStkBedNo	 = commUtils.getValue(gdReq, "YD_STK_BED_NO", i); 
				sCoilWt		 = commUtils.getValue(gdReq, "COIL_WT", i);
				sCoilOutdia	 = commUtils.getValue(gdReq, "COIL_OUTDIA", i);
				sMsgContents = commUtils.getValue(gdReq, "MSG_CONTENTS", i); 
				sRetnTrgtYn  = commUtils.getValue(gdReq, "RETN_TRGT_YN", i);

				// 2열연 코일 저장품 등록
				if (!coilDao.stockProcCom(logId, mthdNm, sStlNo,  1)) {
					// 실패해도 진행
					commUtils.printLog(logId, "stockProcCom 호출 실패! return false", "SL");
				}
				
				jrParam.setField("STL_NO", sStlNo);
				// 목표행선구분
				sAimRtGp = coilDao.getYdAimRtGp("C", jrParam);
				sStlProgCd = sAimRtGp[1];
				
				// 재료진도코드
				ydAimRtGp = "A1";
				if ("4".equals(sRetnWkGp)) {
					// RETN_WK_GP : 4(소재반품)
					ydAimRtGp = "B3";
				}
				
				jrStockData.setField("STL_NO"			, sStlNo);
				jrStockData.setField("YD_CAR_UPP_LOC_CD", ydStkBedNo );
				jrStockData.setField("YD_AIM_RT_GP"		, ydAimRtGp);
				jrStockData.setField("STL_PROG_CD"		, sStlProgCd);
				jrStockData.setField("MSG_CONTENTS"		, sMsgContents);
				jrStockData.setField("SNDBK_REGISTER"	, userid);
				jrStockData.setField("YD_MTL_WT"		, sCoilWt);
				jrStockData.setField("COIL_OUTDIA"		, sCoilOutdia);
				jrStockData.setField("DEL_YN"           , "Y".equals(sRetnTrgtYn) ? "N" : "Y");
				/*
				UPDATE TB_YD_STOCK
				   SET YD_CAR_UPP_LOC_CD = :V_YD_CAR_UPP_LOC_CD
				     , YD_AIM_RT_GP      = :V_YD_AIM_RT_GP
				     , STL_PROG_CD       = :V_STL_PROG_CD
				     , YD_ABMTL_REM      = :V_MSG_CONTENTS
				     , SNDBK_REGISTER    = :V_SNDBK_REGISTER
				     , YD_MTL_WT         = NVL(:V_YD_MTL_WT, YD_MTL_WT)
				     , COIL_OUTDIA       = NVL(:V_COIL_OUTDIA, COIL_OUTDIA)
				     , TRANS_ORD_DATE    = :V_TRANS_ORD_DATE
				     , TRANS_ORD_SEQNO   = :V_TRANS_ORD_SEQNO
				     , CARD_NO           = :V_CARD_NO
				     , CAR_NO            = :V_CAR_NO
				     , STL_APPEAR_GP     = :V_STL_APPEAR_GP
				     , DEL_YN            = :V_DEL_YN
				     , MODIFIER          = :V_MODIFIER
				     , MOD_DDTT          = SYSDATE
				 WHERE STL_NO = :V_STL_NO
				*/
				commDao.update(jrStockData, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockReg", logId, mthdNm, "TB_YD_STOCK 수정");
			}
			
			/*******************************
			 * 2. 차량스케쥴 생성 
			 *******************************/
			ydCarSchId = coilDao.getSeqId(logId, mthdNm, "CarSch");
			
			jrParam = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CAR_SCH_ID"		, ydCarSchId);
			jrParam.setField("YD_EQP_WRK_STAT"		, "L");
			jrParam.setField("YD_EQP_ID"			, "XXPT02"); // 출하차량에 대한 기본 설비ID
			jrParam.setField("YD_CAR_USE_GP"		, "G");      // 출하차량
			jrParam.setField("CAR_KIND"				, sCarKind);
			jrParam.setField("ARR_WLOC_CD"			, sWlocCd);
			jrParam.setField("SPOS_WLOC_CD"			, sWlocCd);
			jrParam.setField("YD_PNT_CD3"			, ydPntCd);
			jrParam.setField("CAR_NO"				, sCarNo);
			jrParam.setField("CARD_NO"				, sCardNo);
			jrParam.setField("TRANS_ORD_DATE"		, sTransOrdDate);
			jrParam.setField("TRANS_ORD_SEQNO"		, sTransOrdSeqNo);
			jrParam.setField("YD_CARUD_STOP_LOC"	, ydStkColGp);
			jrParam.setField("YD_BAYIN_WO_SEQ"		, "9");      // 입동지시순번 Default 값
			jrParam.setField("YD_CAR_PROG_STAT"		, "A");      // 하차출발
			jrParam.setField("TEL_NO"				, sTelNo);
			jrParam.setField("YD_CAR_WRK_GP"		, sRetnWkGp);
			
			/*
			INSERT INTO TB_YD_CARSCH
			(
			      YD_CAR_SCH_ID
			    , YD_EQP_WRK_STAT
			    , YD_EQP_ID
			    , YD_CAR_USE_GP
			    , CAR_KIND
			    , ARR_WLOC_CD
			    , SPOS_WLOC_CD
			    , TRANS_EQUIPMENT_TYPE
			    , YD_PNT_CD3
			    , CAR_NO
			    , CARD_NO
			    , YD_CARUD_LEV_DT
			    , TRANS_ORD_DATE
			    , TRANS_ORD_SEQNO
			    , YD_CARUD_STOP_LOC
			    , YD_BAYIN_WO_SEQ
			    , YD_CAR_PROG_STAT
			    , IF_SEQ_NO
			    , TEL_NO
			    , YD_CAR_WRK_GP
			    , REGISTER
			    , MODIFIER
			)
			VALUES
			(
			      :V_YD_CAR_SCH_ID
			    , :V_YD_EQP_WRK_STAT
			    , :V_YD_EQP_ID
			    , :V_YD_CAR_USE_GP
			    , :V_CAR_KIND
			    , :V_ARR_WLOC_CD
			    , :V_SPOS_WLOC_CD
			    , :V_TRANS_EQUIPMENT_TYPE
			    , :V_YD_PNT_CD3
			    , :V_CAR_NO
			    , :V_CARD_NO
			    , SYSDATE
			    , :V_TRANS_ORD_DATE
			    , :V_TRANS_ORD_SEQNO
			    , :V_YD_CARUD_STOP_LOC
			    , :V_YD_BAYIN_WO_SEQ
			    , :V_YD_CAR_PROG_STAT
			    , :V_IF_SEQ_NO
			    , :V_TEL_NO
			    , :V_YD_CAR_WRK_GP
			    , :V_MODIFIER
			    , :V_MODIFIER
			)
			*/
			intRtnVal = commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insYdCarsch01", logId, mthdNm, "차량스케쥴 생성");
			if( intRtnVal < 1 ) {
				sMsg = "차량스케쥴 생성 시 오류발생. YD_CAR_SCH_ID["+ ydCarSchId +"], intRtnVal["+ intRtnVal +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			commUtils.printLog(logId, "차량스케쥴 생성완료. YD_CAR_SCH_ID["+ ydCarSchId +"]", "SL");
			
			/**********************************************************
			 * 3. 차량스케쥴 재료 생성 & 저장품제원 전문 QUEUE 저장(YDY5L002)
			 **********************************************************/
			jrParam = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CAR_SCH_ID", ydCarSchId);
			
			for( int i = 0; i < rowCnt; i++ ) {
				sStlNo		= commUtils.trim(gdReq.getHeader("STL_NO"       ).getValue(i));
				ydStkBedNo	= commUtils.trim(gdReq.getHeader("YD_STK_BED_NO").getValue(i));
				sRetnTrgtYn = commUtils.trim(gdReq.getHeader("RETN_TRGT_YN" ).getValue(i));
				
				if ("".equals(sStlNo)) {
					break;
				}
				
				jrParam.setField("STL_NO"		, sStlNo);
				jrParam.setField("YD_STK_BED_NO", ydStkBedNo);
				jrParam.setField("YD_STK_LYR_NO", "001");
				jrParam.setField("DEL_YN"       , "Y".equals(sRetnTrgtYn) ? "N" : "Y");
				/*
				INSERT INTO TB_YD_CARFTMVMTL(
				       YD_CAR_SCH_ID
				     , STL_NO
				     , REGISTER
				     , REG_DDTT
				     , MODIFIER
				     , MOD_DDTT
				     , DEL_YN
				     , YD_CAR_UPP_LOC_CD
				     , YD_STK_BED_NO
				     , YD_STK_LYR_NO
				     , HCR_GP
				     , STL_PROG_CD
				     , YD_MTL_ITEM
				     , YD_ROUTE_GP
				) VALUES ( 
				       :V_YD_CAR_SCH_ID
				     , :V_STL_NO
				     , :V_MODIFIER
				     , SYSDATE
				     , :V_MODIFIER
				     , SYSDATE
				     , 'N'
				     , :V_YD_CAR_UPP_LOC_CD
				     , :V_YD_STK_BED_NO
				     , :V_YD_STK_LYR_NO
				     , :V_HCR_GP
				     , :V_STL_PROG_CD
				     , :V_YD_MTL_ITEM
				     , :V_YD_ROUTE_GP     
				)
				*/
				commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilL3RcvSeEJB.insCarSchmtl", logId, mthdNm, "차량스케쥴 재료 생성");
				
				if ("Y".equals(sRetnTrgtYn)){
					/**********************************************************
					* 저장품제원정보(YDY5L002) QUEUE 저장
					**********************************************************/
					JDTORecord sndL2Msg = JDTORecordFactory.getInstance().create();
					sndL2Msg.setField("JMS_TC_CD"      , "YDY5L002");
					sndL2Msg.setField("YD_INFO_SYNC_CD", "5");	//1:동,2:SPAN,3:열,4:BED,5:지정저장품,A:생산실적,B:차량입고,C:행선변경,D:생산종료(삭제)
					sndL2Msg.setField("STL_NO"         , sStlNo);
					
					jrRtn = commUtils.addSndData(jrRtn ,coilDao.getMsgL2("YDY5L002", sndL2Msg));
					commUtils.printLog(logId, "저장품제원 코일번호["+ sStlNo +"] 전문 송신 QUEUE 저장 완료.", "SL");
				}
			}

			/**********************************************************
			 * 4. YDYDJ553 출하차량 입동지시 요구 (기존 YDYDJ662). 도착처리
			 **********************************************************/
/*			JDTORecord jrSndTc = JDTORecordFactory.getInstance().create();
			jrSndTc.setField("JMS_TC_CD"	, "YDYDJ553");
			jrSndTc.setField("YD_CARPNT_CD"	, ydCarPntCd);
			jrSndTc.setField("YD_CAR_SCH_ID", ydCarSchId);
			jrSndTc.setField("CAR_NO"		, sCarNo);
			jrSndTc.setField("CARD_NO"		, sCardNo);
			jrSndTc.setField("CAR_KIND"		, sCarKind);
			jrSndTc.setField("CHK_YN"		, "N");
			
			jrRtn = commUtils.addSndData(jrRtn, jrSndTc);	
			*/
			JDTORecord jrYdMsg = commUtils.getParam(logId, mthdNm, userid);	
			jrYdMsg.setField("JMS_TC_CD"			, "YDYDJ553");          //차량입동지시 요구 기존:YDYDJ662
			jrYdMsg.setField("JMS_TC_CREATE_DDTT"	, commUtils.getDateTime14()); //JMSTC생성일시
			jrYdMsg.setField("YD_CARPNT_CD"		    , ydCarPntCd);
			jrYdMsg.setField("YD_CAR_SCH_ID"		, ydCarSchId );
			jrYdMsg.setField("CHK_YN"		        , "N"        );
			
			EJBConnector ejbConn = new EJBConnector("default", "CCoilCarMvSeEJB", this);
			JDTORecord jrRst = (JDTORecord)ejbConn.trx("rcvYDYDJ553", new Class[] { JDTORecord.class }, new Object[] { jrYdMsg });
			
			jrRtn = commUtils.addSndData(jrRtn, jrRst);
			

			sMsg = "차량스케쥴["+ ydCarSchId +"], 입동포인트["+ ydCarPntCd +"] 출하차량입동지시요구(YDYDJ553) 내부전문 QUEUE 저장완료.";
			commUtils.printLog(logId, sMsg, "SL");

			sMsg = "하차작업등록을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	

	/**
	 * 소재 반품/부분하차 등록 - 하차작업등록
	 * 염용선 2023 03 17
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord regCarUdWrkH(GridData gdReq) throws DAOException {
		String mthdNm	= "소재 하차작업등록[CCoilJspSeEJB.regCarUdWrkH] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= null;

			String userid			= commUtils.trim(gdReq.getParam("userid"));
			String sCarNo			= gdReq.getParam("CAR_NO").toUpperCase();
			String sRetnWkGp		= gdReq.getParam("RETN_WK_GP");  //1:반품, 2:회송, 3:부분하차 , 4:소재반품
			String ydCarPntCd		= gdReq.getParam("YD_CARPNT_CD");
			String sTelNo			= commUtils.nvl(gdReq.getParam("TEL_NO"), "00000000000");
			String sCardNo			= commUtils.nvl(gdReq.getParam("CARD_NO"), "").toUpperCase();
			String ydCarSchId		= "";
			
			String sRetnTrgtYn = ""; //반품회송대상 여부 (Y : 대상)
			
			//--------------------------------------------------//
			// CHECK : 등록된 차량스케쥴의 코일번호 여부
			//--------------------------------------------------//
			JDTORecordSet jsCarSch = JDTORecordFactory.getInstance().createRecordSet("retTmp");
			String sStlNo = "";
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			for (int i = 0; i < rowCnt; i++) {
				
				sStlNo	    = commUtils.trim(gdReq.getHeader("STL_NO"      ).getValue(i));
				sRetnTrgtYn = commUtils.trim(gdReq.getHeader("RETN_TRGT_YN").getValue(i));
				
				jrParam  = commUtils.getParam(logId, mthdNm, userid);
				jrParam.setField("STL_NO", sStlNo);
				jrParam.setField("CAR_NO", sCarNo);

				/*
				SELECT A.YD_CAR_SCH_ID
				  FROM TB_YD_CARSCH A
				     , TB_YD_CARFTMVMTL B
				 WHERE A.YD_CAR_SCH_ID = B.YD_CAR_SCH_ID
				   AND A.YD_CAR_PROG_STAT NOT IN ('5', 'E')
				   AND B.STL_NO   = :V_STL_NO
				   AND (A.CAR_NO  = :V_CAR_NO OR A.TRN_EQP_CD = :V_CAR_NO)
				   AND A.DEL_YN   = 'N'
				   AND B.DEL_YN   = 'N'
				*/
				jsCarSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarYdCarMtlDEL_YN", logId, mthdNm, "차량스케쥴재료검색");
				if( jsCarSch.size() > 0 ) {
					
					sMsg = "["+ sStlNo +"] 코일번호는 차량스케쥴["+ jsCarSch.getRecord(0).getFieldString("YD_CAR_SCH_ID") +"]에 등록되어 있습니다.";
					commUtils.printLog(logId, sMsg, "SL");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}
			
			//CARD_NO가 NULL인경우 차량번호 뒤에 4자리로 셋팅
			if ("".equals(sCardNo) && sCarNo.length() >= 4) {
				sCardNo = sCarNo.substring(sCarNo.length()-4, sCarNo.length());
			}
			
			//--------------------------------------------------//
			// 차량번호 GT(TT카) && 부분하차(3) 은 [차량초기화] 호출
			//--------------------------------------------------//
			String sCarKind = "";
			if (sCarNo.startsWith("GT")) {
				sCarKind = "TT";
			} else {
				sCarKind = "TR";
			}
			
			/* **************************************************************************
			 * 하차위치(YD_CARPNT_CD)로 WLOC_CD, YD_PNT_CD, 저장위치(YD_STK_COL_GP) 검색
			 * *************************************************************************/
			jrParam  = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CARPNT_CD", ydCarPntCd);

			/*
			SELECT YD_STK_COL_GP
			     , WLOC_CD
			     , YD_PNT_CD
			  FROM TB_YD_CARPOINT A
			 WHERE YD_CARPNT_CD LIKE :V_YD_CARPNT_CD
			*/
			JDTORecordSet jsCarPoint = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCarPoint", logId, mthdNm, "차량포인트 조회");
			if( jsCarPoint.size() < 1 ) {
				sMsg = "차량포인트 조회실패! ["+ ydCarPntCd +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			
			String sWlocCd		= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("WLOC_CD"      ));
			String ydPntCd		= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("YD_PNT_CD"    ));
			String ydStkColGp	= commUtils.trim(jsCarPoint.getRecord(0).getFieldString("YD_STK_COL_GP"));
			
			
			/* **************************************************************************
			 * 운송지시일자, 순번 생성  (999001 처럼 앞에  999를 붙인다.)
			 * *************************************************************************/
			/*
			SELECT A.TRANS_ORD_DATE
			     , A.TRANS_ORD_SEQNO + 1 AS TRANS_ORD_SEQNO
			  FROM(
			        SELECT TO_CHAR(SYSDATE,'YYYYMMDD')       AS TRANS_ORD_DATE
			             , NVL(MAX(TRANS_ORD_SEQNO), 999000) AS TRANS_ORD_SEQNO
			          FROM TB_YD_CARSCH
			         WHERE TRANS_ORD_DATE = TO_CHAR(SYSDATE,'YYYYMMDD')
			           AND TRANS_ORD_SEQNO >  999000
			      ) A
			*/
			jsCarSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRetnTransOrdNo", logId, mthdNm, "운송일자,순번 생성");
			if( jsCarSch.size() < 1 ) {
				sMsg = "운송지시일자/순번 생성 Error!";
				commUtils.printLog(logId, sMsg, "SL");

				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			
			String sTransOrdDate  = commUtils.trim(jsCarSch.getRecord(0).getFieldString("TRANS_ORD_DATE" ));
			String sTransOrdSeqNo = commUtils.trim(jsCarSch.getRecord(0).getFieldString("TRANS_ORD_SEQNO"));

			/***************************************
			 * 1. 저장위치 수정 TB_YD_STOCK
			 ***************************************/
			jrParam 				= commUtils.getParam(logId, mthdNm, userid);
			String[] sAimRtGp	= new String[1];
			String ydAimRtGp	= "";
			String sStlProgCd	= "";
			String ydStkBedNo	= ""; // 차상위치코드
			String sMsgContents	= ""; // 반납메세지
			String sCoilWt		= ""; // 코일중량(kg)
			String sCoilOutdia  = ""; // 외경
			
			JDTORecord jrStockData  = commUtils.getParam(logId, mthdNm, userid);
			jrStockData.setField("TRANS_ORD_DATE"	, sTransOrdDate);  // 운송지시일자 
			jrStockData.setField("TRANS_ORD_SEQNO"	, sTransOrdSeqNo); // 운송지시순번
			jrStockData.setField("CARD_NO"			, sCardNo);        // 차량번호 끝4자리
			jrStockData.setField("CAR_NO"			, sCarNo);         // 차량번호
			jrStockData.setField("STL_APPEAR_GP"	, "Y");            // 재료외형 : Y(제품)
			
			for (int i = 0; i < rowCnt; i++ ) {
				sStlNo		 = commUtils.getValue(gdReq, "STL_NO", i); 
				ydStkBedNo	 = commUtils.getValue(gdReq, "YD_STK_BED_NO", i); 
				sCoilWt		 = commUtils.getValue(gdReq, "COIL_WT", i);
				sCoilOutdia	 = commUtils.getValue(gdReq, "COIL_OUTDIA", i);
				sMsgContents = commUtils.getValue(gdReq, "MSG_CONTENTS", i); 
				sRetnTrgtYn  = commUtils.getValue(gdReq, "RETN_TRGT_YN", i);

				// 2열연 코일 저장품 등록
				if (!coilDao.stockProcCom(logId, mthdNm, sStlNo,  1)) {
					// 실패해도 진행
					commUtils.printLog(logId, "stockProcCom 호출 실패! return false", "SL");
				}
				
				jrParam.setField("STL_NO", sStlNo);
				// 목표행선구분
				sAimRtGp = coilDao.getYdAimRtGp("C", jrParam);
				sStlProgCd = sAimRtGp[1];
				
				// 재료진도코드
				ydAimRtGp = "A1";
				if ("4".equals(sRetnWkGp)) {
					// RETN_WK_GP : 4(소재반품)
					ydAimRtGp = "B3";
				}
				
				jrStockData.setField("STL_NO"			, sStlNo);
				jrStockData.setField("YD_CAR_UPP_LOC_CD", ydStkBedNo );
				jrStockData.setField("YD_AIM_RT_GP"		, ydAimRtGp);
				jrStockData.setField("STL_PROG_CD"		, sStlProgCd);
				jrStockData.setField("MSG_CONTENTS"		, sMsgContents);
				jrStockData.setField("SNDBK_REGISTER"	, userid);
				jrStockData.setField("YD_MTL_WT"		, sCoilWt);
				jrStockData.setField("SNDBK_GP"		    , sRetnWkGp); //반납구분
				jrStockData.setField("COIL_OUTDIA"		, sCoilOutdia);
				jrStockData.setField("DEL_YN"           , "Y".equals(sRetnTrgtYn) ? "N" : "Y");
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockRegH 
				UPDATE TB_YD_STOCK
				   SET YD_CAR_UPP_LOC_CD = :V_YD_CAR_UPP_LOC_CD
				     , YD_ABMTL_REM      = :V_MSG_CONTENTS
				     , SNDBK_REGISTER    = :V_SNDBK_REGISTER
				     , CAR_NO            = :V_CAR_NO
				     , MODIFIER         = :V_MODIFIER
				     , SNDBK_GP          = '1'
				     , SNDBK_RSN_CD      = :V_SNDBK_GP
				     , SNDBK_REG_DDTT    = SYSDATE
				     , MOD_DDTT          = SYSDATE
				 WHERE STL_NO = :V_STL_NO
				*/
				commDao.update(jrStockData, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockRegH", logId, mthdNm, "TB_YD_STOCK 수정");
			}
			
			/*******************************
			 * 2. 차량스케쥴 생성 
			 *******************************/
			ydCarSchId = coilDao.getSeqId(logId, mthdNm, "CarSch");
			
			jrParam = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CAR_SCH_ID"		, ydCarSchId);
			jrParam.setField("YD_EQP_WRK_STAT"		, "L");
			jrParam.setField("YD_EQP_ID"			, "XXPT02"); // 출하차량에 대한 기본 설비ID
			jrParam.setField("YD_CAR_USE_GP"		, "G");      // 출하차량
			jrParam.setField("CAR_KIND"				, sCarKind);
			jrParam.setField("ARR_WLOC_CD"			, sWlocCd);
			jrParam.setField("SPOS_WLOC_CD"			, sWlocCd);
			jrParam.setField("YD_PNT_CD3"			, ydPntCd);
			jrParam.setField("CAR_NO"				, sCarNo);
			jrParam.setField("CARD_NO"				, sCardNo);
			jrParam.setField("TRANS_ORD_DATE"		, sTransOrdDate);
			jrParam.setField("TRANS_ORD_SEQNO"		, sTransOrdSeqNo);
			jrParam.setField("YD_CARUD_STOP_LOC"	, ydStkColGp);
			// RETN_WK_GP : 3(부분하차)인 경우 1순위, 그외 Default 9
			if ("3".equals(sRetnWkGp)) {
				jrParam.setField("YD_BAYIN_WO_SEQ"	, "1");
			} else {
				jrParam.setField("YD_BAYIN_WO_SEQ"		, "9");      // 입동지시순번 Default 값
			}
			jrParam.setField("YD_CAR_PROG_STAT"		, "A");      // 하차출발
			//jrParam.setField("YD_CAR_PROG_STAT"     , "B" ); //하차도착
			jrParam.setField("TEL_NO"				, sTelNo);
			jrParam.setField("YD_CAR_WRK_GP"		, sRetnWkGp);
			
			/*
			INSERT INTO TB_YD_CARSCH
			(
			      YD_CAR_SCH_ID
			    , YD_EQP_WRK_STAT
			    , YD_EQP_ID
			    , YD_CAR_USE_GP
			    , CAR_KIND
			    , ARR_WLOC_CD
			    , SPOS_WLOC_CD
			    , TRANS_EQUIPMENT_TYPE
			    , YD_PNT_CD3
			    , CAR_NO
			    , CARD_NO
			    , YD_CARUD_LEV_DT
			    , TRANS_ORD_DATE
			    , TRANS_ORD_SEQNO
			    , YD_CARUD_STOP_LOC
			    , YD_BAYIN_WO_SEQ
			    , YD_CAR_PROG_STAT
			    , IF_SEQ_NO
			    , TEL_NO
			    , YD_CAR_WRK_GP
			    , REGISTER
			    , MODIFIER
			)
			VALUES
			(
			      :V_YD_CAR_SCH_ID
			    , :V_YD_EQP_WRK_STAT
			    , :V_YD_EQP_ID
			    , :V_YD_CAR_USE_GP
			    , :V_CAR_KIND
			    , :V_ARR_WLOC_CD
			    , :V_SPOS_WLOC_CD
			    , :V_TRANS_EQUIPMENT_TYPE
			    , :V_YD_PNT_CD3
			    , :V_CAR_NO
			    , :V_CARD_NO
			    , SYSDATE
			    , :V_TRANS_ORD_DATE
			    , :V_TRANS_ORD_SEQNO
			    , :V_YD_CARUD_STOP_LOC
			    , :V_YD_BAYIN_WO_SEQ
			    , :V_YD_CAR_PROG_STAT
			    , :V_IF_SEQ_NO
			    , :V_TEL_NO
			    , :V_YD_CAR_WRK_GP
			    , :V_MODIFIER
			    , :V_MODIFIER
			)
			*/
			intRtnVal = commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insYdCarsch01", logId, mthdNm, "차량스케쥴 생성");
			if( intRtnVal < 1 ) {
				sMsg = "차량스케쥴 생성 시 오류발생. YD_CAR_SCH_ID["+ ydCarSchId +"], intRtnVal["+ intRtnVal +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			commUtils.printLog(logId, "차량스케쥴 생성완료. YD_CAR_SCH_ID["+ ydCarSchId +"]", "SL");
			
			/**********************************************************
			 * 3. 차량스케쥴 재료 생성 & 저장품제원 전문 QUEUE 저장(YDY5L002)
			 **********************************************************/
			jrParam = commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("YD_CAR_SCH_ID", ydCarSchId);
			
			for( int i = 0; i < rowCnt; i++ ) {
				sStlNo		= commUtils.trim(gdReq.getHeader("STL_NO"       ).getValue(i));
				ydStkBedNo	= commUtils.trim(gdReq.getHeader("YD_STK_BED_NO").getValue(i));
				sRetnTrgtYn = commUtils.trim(gdReq.getHeader("RETN_TRGT_YN" ).getValue(i));
				
				if ("".equals(sStlNo)) {
					break;
				}
				
				jrParam.setField("STL_NO"		, sStlNo);
				jrParam.setField("YD_STK_BED_NO", ydStkBedNo);
				jrParam.setField("YD_STK_LYR_NO", "001");
				jrParam.setField("DEL_YN"       , "Y".equals(sRetnTrgtYn) ? "N" : "Y");
				/*
				INSERT INTO TB_YD_CARFTMVMTL(
				       YD_CAR_SCH_ID
				     , STL_NO
				     , REGISTER
				     , REG_DDTT
				     , MODIFIER
				     , MOD_DDTT
				     , DEL_YN
				     , YD_CAR_UPP_LOC_CD
				     , YD_STK_BED_NO
				     , YD_STK_LYR_NO
				     , HCR_GP
				     , STL_PROG_CD
				     , YD_MTL_ITEM
				     , YD_ROUTE_GP
				) VALUES ( 
				       :V_YD_CAR_SCH_ID
				     , :V_STL_NO
				     , :V_MODIFIER
				     , SYSDATE
				     , :V_MODIFIER
				     , SYSDATE
				     , 'N'
				     , :V_YD_CAR_UPP_LOC_CD
				     , :V_YD_STK_BED_NO
				     , :V_YD_STK_LYR_NO
				     , :V_HCR_GP
				     , :V_STL_PROG_CD
				     , :V_YD_MTL_ITEM
				     , :V_YD_ROUTE_GP     
				)
				*/
				commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilL3RcvSeEJB.insCarSchmtl", logId, mthdNm, "차량스케쥴 재료 생성");
				
				if ("Y".equals(sRetnTrgtYn)){
					/**********************************************************
					* 저장품제원정보(YDY5L002) QUEUE 저장
					**********************************************************/
					JDTORecord sndL2Msg = JDTORecordFactory.getInstance().create();
					sndL2Msg.setField("JMS_TC_CD"      , "YDY5L002");
					sndL2Msg.setField("YD_INFO_SYNC_CD", "5");	//1:동,2:SPAN,3:열,4:BED,5:지정저장품,A:생산실적,B:차량입고,C:행선변경,D:생산종료(삭제)
					sndL2Msg.setField("STL_NO"         , sStlNo);
					
					jrRtn = commUtils.addSndData(jrRtn ,coilDao.getMsgL2("YDY5L002", sndL2Msg));
					commUtils.printLog(logId, "저장품제원 코일번호["+ sStlNo +"] 전문 송신 QUEUE 저장 완료.", "SL");
				}
			}

			/***************************************
			 * APP001-J-026 적용 시
			 * 부분하차(RETN_WK_GP=3)인 경우 하차 포인트 입동차량 정보 클리어
			 ***************************************/
			commUtils.printLog(logId, "CICD 2026.04.10 부분하차시 입동차량 자동 삭제", "SL");
			String sAPP001_026_YN = coilDao.ApplyYn(logId, mthdNm, "APP001", "J", "026");
			if ("Y".equals(sAPP001_026_YN) && "3".equals(sRetnWkGp)) {
				JDTORecord jrCarPnt = commUtils.getParam(logId, mthdNm, userid);
				jrCarPnt.setField("YD_STK_COL_GP", ydStkColGp);
				// 1. 현재 입동차량 조회
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarPointByYdStkColGpWithVhcl
				SELECT * 
				FROM TB_YD_CARPOINT 
				WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP 
				AND DEL_YN = 'N' 
				AND (TRN_EQP_CD IS NOT NULL OR CAR_NO IS NOT NULL)
				*/
				commUtils.printLog(logId, "부분하차-포인트[" + ydStkColGp + "] 입동차량 조회 시작.", "SL");
				JDTORecordSet jsCarPntCur = commDao.select(jrCarPnt,"com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarPointByYdStkColGpWithVhcl",logId, mthdNm, "부분하차-입동차량 조회");
				if (jsCarPntCur.size() > 0) {
					String sCurTrnEqpCd = commUtils.trim(jsCarPntCur.getRecord(0).getFieldString("TRN_EQP_CD"));
					String sCurCarNo    = commUtils.trim(jsCarPntCur.getRecord(0).getFieldString("CAR_NO"));
						commUtils.printLog(logId, "부분하차-입동차량 클리어 시작. 포인트[" + ydStkColGp + "] TRN_EQP_CD[" + sCurTrnEqpCd + "] CAR_NO[" + sCurCarNo + "]", "SL");
						jrCarPnt.setField("TRN_EQP_CD",          "");
						jrCarPnt.setField("CAR_NO",               "");
						jrCarPnt.setField("CARD_NO",              "");
						jrCarPnt.setField("YD_STK_COL_ACT_STAT", "C");
						// 2. TB_YD_CARPOINT 클리어
						/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCarPointClearByYdStkColGp
						UPDATE TB_YD_CARPOINT
						   SET TRN_EQP_CD          = :V_TRN_EQP_CD
						     , CAR_NO              = :V_CAR_NO
						     , CARD_NO             = :V_CARD_NO
						     , YD_STK_COL_ACT_STAT = :V_YD_STK_COL_ACT_STAT
						     , MODIFIER            = :V_MODIFIER
						     , MOD_DDTT            = SYSDATE
						 WHERE YD_STK_COL_GP       = :V_YD_STK_COL_GP
						   AND DEL_YN              = 'N'
						*/
						commDao.update(jrCarPnt,"com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCarPointClearByYdStkColGp",	logId, mthdNm, "부분하차-TB_YD_CARPOINT 클리어");
						// 3. TB_YD_STKCOL 클리어
				    	/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkColGpCarPointClear
				    	UPDATE TB_YD_STKCOL
				    	   SET TRN_EQP_CD          = :V_TRN_EQP_CD
				    	     , CAR_NO              = :V_CAR_NO
				    	     , CARD_NO             = :V_CARD_NO
				    	     , MODIFIER            = :V_MODIFIER
				    	     , MOD_DDTT            = SYSDATE
				    	     , YD_STK_COL_ACT_STAT = :V_YD_STK_COL_ACT_STAT
				    	 WHERE YD_STK_COL_GP       = :V_YD_STK_COL_GP
				    	   AND DEL_YN              = 'N'
						*/
						commDao.update(jrCarPnt,"com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkColGpCarPointClear",logId, mthdNm, "부분하차-TB_YD_STKCOL 클리어");
						// 4. 출하차량인 경우 TB_YD_CARSCH PROG_STAT 리셋 (YD_BAYIN_WO_SEQ 변경 없음)
						if (!"".equals(sCurCarNo) && "".equals(sCurTrnEqpCd)) { // 출하차량인 경우만 PROG_STAT 리셋
							JDTORecord jrCarSch = commUtils.getParam(logId, mthdNm, userid);
							jrCarSch.setField("CAR_NO", sCurCarNo);
							/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarSchProgStatResetByCarNo
							UPDATE TB_YD_CARSCH
							   SET YD_CAR_PROG_STAT = CASE
							                           WHEN YD_CAR_PROG_STAT IN ('2','3','4','5') THEN '1' -- 상차대기
							                           WHEN YD_CAR_PROG_STAT IN ('B','C','D','E') THEN 'A' -- 하차대기
							                           ELSE YD_CAR_PROG_STAT
							                         END
							     , MODIFIER         = :V_MODIFIER
							     , MOD_DDTT         = SYSDATE
							 WHERE DEL_YN  = 'N'
							   AND CAR_NO  = :V_CAR_NO
							   AND YD_CAR_PROG_STAT NOT IN ('1','A')
							*/
							commDao.update(jrCarSch,"com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarSchProgStatResetByCarNo",logId, mthdNm, "부분하차-TB_YD_CARSCH PROG_STAT 리셋");
						}
						commUtils.printLog(logId, "부분하차-입동차량 클리어 완료.", "SL");
				} else {
					commUtils.printLog(logId, "부분하차-포인트[" + ydStkColGp + "] 입동차량 없음. 클리어 불필요.", "SL");
				}
			}

			/**********************************************************
			 * 4. YDYDJ553 출하차량 입동지시 요구 (기존 YDYDJ662). 도착처리
			 **********************************************************/
/*			JDTORecord jrSndTc = JDTORecordFactory.getInstance().create();
			jrSndTc.setField("JMS_TC_CD"	, "YDYDJ553");
			jrSndTc.setField("YD_CARPNT_CD"	, ydCarPntCd);
			jrSndTc.setField("YD_CAR_SCH_ID", ydCarSchId);
			jrSndTc.setField("CAR_NO"		, sCarNo);
			jrSndTc.setField("CARD_NO"		, sCardNo);
			jrSndTc.setField("CAR_KIND"		, sCarKind);
			jrSndTc.setField("CHK_YN"		, "N");
			
			jrRtn = commUtils.addSndData(jrRtn, jrSndTc);	
			*/
			JDTORecord jrYdMsg = commUtils.getParam(logId, mthdNm, userid);	
			jrYdMsg.setField("JMS_TC_CD"			, "YDYDJ553");          //차량입동지시 요구 기존:YDYDJ662
			jrYdMsg.setField("JMS_TC_CREATE_DDTT"	, commUtils.getDateTime14()); //JMSTC생성일시
			jrYdMsg.setField("YD_CARPNT_CD"		    , ydCarPntCd);
			jrYdMsg.setField("YD_CAR_SCH_ID"		, ydCarSchId );
			jrYdMsg.setField("CHK_YN"		        , "Y"        ); //소재반납은 입동제한 하나로 감
			
			EJBConnector ejbConn = new EJBConnector("default", "CCoilCarMvSeEJB", this);
			JDTORecord jrRst = (JDTORecord)ejbConn.trx("rcvYDYDJ553", new Class[] { JDTORecord.class }, new Object[] { jrYdMsg });
			
			jrRtn = commUtils.addSndData(jrRtn, jrRst);
			

			sMsg = "차량스케쥴["+ ydCarSchId +"], 입동포인트["+ ydCarPntCd +"] 출하차량입동지시요구(YDYDJ553) 내부전문 QUEUE 저장완료.";
			commUtils.printLog(logId, sMsg, "SL");

			sMsg = "하차작업등록을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 오퍼레이션명 : 스케줄 삭제 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return
	 * @throws JDTOException
	 */
	public JDTORecord trtCrnSchCncl(JDTORecord rcvMsg) throws JDTOException  {
		String mthdNm = "크레인스케줄 삭제[CCoilJspSeEJB.trtCrnSchCncl] <" + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();		
		
		try {
			
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);
			
			JDTORecord jrRtn 	= JDTORecordFactory.getInstance().create();
			String rtnCd 	    = "";   //
			String rtnMsg 	    = "";   //
			String sMsg			= "";
			String sModifier  		= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));  //수정자			
			String ydCrnSchId 		= commUtils.trim(rcvMsg.getFieldString("YD_CRN_SCH_ID"));
			String sIsLastSelected  = commUtils.trim(rcvMsg.getFieldString("IS_LAST_SELECTED"));  // 마지막 1건만 명령선택
			
			String ydL2ReturnFlag	= commUtils.nvl (rcvMsg.getFieldString("YD_L2_RETURN_FLAG" ),"N");  // rcvY5YDL015 수신시 'Y'
			
			/*********************************************
			 *  기본 ERROR CHECK
			 *********************************************/			
			
			if ("".equals(ydCrnSchId)) {				
				rtnMsg = "스케줄 취소 처리 실패, YD_CRN_SCH_ID값이 없음";
				commUtils.printLog(logId, rtnMsg, "SL");
				jrRtn.setField("RTN_CD" , "0");	
				jrRtn.setField("RTN_MSG", rtnMsg);	
				return jrRtn;
			}			
			
			//파라미터 레코드 setting
			JDTORecord jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_CRN_SCH_ID", ydCrnSchId);
			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp 
        	SELECT A.YD_CRN_SCH_ID
        	     , A.YD_WBOOK_ID
        	     , A.YD_WRK_PROG_STAT
        	     , A.YD_DN_WO_LOC
        	     , A.YD_SCH_CD
        	     , A.YD_EQP_ID
        	     , B.YD_EQP_STAT           -- 설비상태
        	     , B.YD_EQP_AUTO_CRN_MODE  -- 1:On-Line, 2:Off-Line, 4:일시정지, 5:비상정지
        	     , B.YD_EQP_WRK_MODE2      -- A:무인, R:리모컨, M:유인
        	     , B.YD_EQP_WRK_MODE
        	     , B.YD_LOC_GP
        	  FROM TB_YD_CRNSCH A
        	     , TB_YD_EQP    B 
        	 WHERE A.YD_EQP_ID = B.YD_EQP_ID
        	   AND A.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
        	*/   
        	
			JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqp", logId, mthdNm, "크레인상태정보");
        	
        	if (jsCrnSch.size() <= 0 ) {
        		rtnMsg = "크레인 작업 지시 설비 번호 이상";
				jrRtn.setField("RTN_CD"  , "0");	
				jrRtn.setField("RTN_MSG" , rtnMsg);	
				return jrRtn;
        	}
        	
        	jsCrnSch.first();
        	JDTORecord jrCrnSch    = jsCrnSch.getRecord();
        	String ydEqpId         = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_ID"));  
        	String ydEqpStat       = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_STAT"));  
        	String sEqpAutoCrnYN   = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_WRK_MODE2")); 
        	String sEqpAutoCrnMode = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_AUTO_CRN_MODE"));
        	String ydWrkProgStat   = commUtils.trim(jrCrnSch.getFieldString("YD_WRK_PROG_STAT")); 
        	String ydDnWoLoc       = commUtils.trim(jrCrnSch.getFieldString("YD_DN_WO_LOC")); 
        	String ydSchCd         = commUtils.trim(jrCrnSch.getFieldString("YD_SCH_CD")); 
        	String ydEqpWrkMode    = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_WRK_MODE")); 
        	String ydLocGp         = commUtils.trim(jrCrnSch.getFieldString("YD_LOC_GP"));
			
        	if("2".equals(ydWrkProgStat) || "3".equals(ydWrkProgStat) || "4".equals(ydWrkProgStat)){
				rtnMsg = "크레인 작업이 완료되지 않았습니다!!";
				jrRtn.setField("RTN_CD" , "0");	
				jrRtn.setField("RTN_MSG", rtnMsg);	
				return jrRtn;
			}
        	
        	boolean bAutoCrnWk     = false;
			if ("A".equals(sEqpAutoCrnYN)) {// A:무인
				bAutoCrnWk = true; 
			}
			
			// 위치검색실패인 경우 유인으로 처리
			if ("XX010101".equals(ydDnWoLoc)) {
				bAutoCrnWk = false;
			} 
			
			//W:명령선택대기 - L2에 작업지시가 내려가지 않은 상태
			if ("W".equals(ydWrkProgStat)) {
				bAutoCrnWk = false;
			}
			
			sMsg = "YD_EQP_ID["+ ydEqpId +"] YD_WRK_PROG_STAT["+ ydWrkProgStat +"] YD_CRN_SCH_ID["+ ydCrnSchId +"] AutoCrnWk["+ bAutoCrnWk +"] YD_L2_RETURN_FLAG["+ ydL2ReturnFlag +"]";
			commUtils.printLog(logId, sMsg, "SL");
			
			
			if (bAutoCrnWk && "N".equals(ydL2ReturnFlag)) {
				
				/*********************************************************
				 * 일시정지 - 스케줄 취소
				 * --소재크레인, 소재스케줄인 경우에만 적용
				 *********************************************************/
				String sAPP814_YN = coilDao.ApplyYn(logId, mthdNm, "APP814", "H", "SD");
				
				if ("Y".equals(sAPP814_YN) && "H".equals(ydLocGp) && ydSchCd.endsWith("H")) {
					jrParam.setField("YD_CRN_SCH_RMD_CNT", "SD"  ); //S5 일시정지 후 스케줄 취소
				} 
				
				/**********************************************************
				* 무인크레인 작업 이고 스케쥴 취소에 대한 응답이 아닌 경우 
				**********************************************************/
				else if (!"4".equals(sEqpAutoCrnMode) && !"B".equals(ydEqpStat)) { //4: 일시정지 B:고장
					rtnMsg = "무인크레인 [" + ydEqpId + "]이 일시정지이거나 고장상태가 아니면 취소할 수 없습니다.";
					jrRtn.setField("RTN_CD"  , "0");	
					jrRtn.setField("RTN_MSG" , rtnMsg);	
					commUtils.printLog(logId, rtnMsg, "S-");
					return jrRtn;
				}
				
				/**********************************************************
				* 크레인작업지시요구 전문 조회 - 일시정지-스케줄취소
				**********************************************************/
				jrParam.setField("MSG_GP"          , "D");
				
				if ("YD99MH".equals(ydSchCd.substring(2, 8))) { 
					//분동코일 취소 전문은 별도
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockIdByCrnSchId 
					SELECT CM.STL_NO
					  FROM TB_YD_CRNSCH    CS
					     , TB_YD_CRNWRKMTL CM
					 WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
					   AND CS.DEL_YN = 'N'
					   AND CM.DEL_YN = 'N'
					   AND CS.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID 
					 ORDER BY CM.YD_STK_LYR_NO
					 */
					JDTORecordSet jsStlInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockIdByCrnSchId", logId, mthdNm, "분동코일ID 조회");
					if (jsStlInfo.size() > 0) {
						
						jrParam.setField("STL_NO", jsStlInfo.getRecord(0).getFieldString("STL_NO"));
						jrRtn = commUtils.addSndData(coilDao.getMsgL2("YDY5L004WC", jrParam));
					}
				} else {
					jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrParam));
				}
				
				commUtils.printLog(logId, "스케줄["+ydCrnSchId+"]을 스케쥴 취소 요청 전송", "SL");
	        	
				// 작업대기상태 update : 작업취소와 구분되게 D 로 상태 없데이트 함...
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnSchProgStat01
				UPDATE TB_YD_CRNSCH  
				   SET YD_L2_REQUEST_STAT = :V_YD_L2_REQUEST_STAT
				     , MODIFIER           = :V_MODIFIER
				     , MOD_DDTT           = SYSDATE
				 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
				*/
				jrParam.setField("YD_L2_REQUEST_STAT", "D"); // 취소후 응답대기중
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnSchProgStat01", logId, mthdNm, "작업대기상태 스케줄 취소(D) UPDATE");
				
				jrRtn.setField("RTN_CD"  , "1");	
				jrRtn.setField("RTN_MSG" , rtnMsg);	
				return jrRtn;
				
				/**********************************************************
				* 무인크레인 작업 이고 스케쥴 취소에 대한 응답이 아닌 경우 종료
				**********************************************************/
				
			} else if("1".equals(ydWrkProgStat) && "N".equals(ydL2ReturnFlag) ) {

				jrParam.setField("MSG_GP", "D");
				jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L004", jrParam));
				
				sMsg = "** 스케쥴 취소 전문 생성 완료 **";
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			//파라미터 레코드 편집
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);	
			jrParam.setField("YD_CRN_SCH_ID", ydCrnSchId);
			jrParam.setField("YD_SCH_CD",     ydSchCd);
			
			//스케줄코드가 동일하고 크레인스케줄 ID이상인 크레인스케줄ID를 SELECT ( 추가 : 스케줄 ID에 포함된 같은 작업예약정보에서만 추출)
			
			rtnMsg = "스케줄코드가 동일하고 크레인스케줄 ID이상인 크레인스케줄ID를 SELECT";
			commUtils.printLog(logId, rtnMsg, "SL");
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschCrnIdOVERID 
			SELECT YD_CRN_SCH_ID                 AS YD_CRN_SCH_ID
			     , YD_WBOOK_ID                   AS YD_WBOOK_ID
			     , YD_EQP_ID                     AS YD_EQP_ID
			     -------------TAKE OUT 인경우 트레킹 위치로 권상위치를 가져옴-------------------
			--     , (CASE WHEN YD_UP_WO_LOC LIKE '%00' AND YD_SCH_CD LIKE 'H__E03LM' 
			--             THEN SUBSTR(YD_UP_WO_LOC,1,6)||
			--                  NVL((SELECT SUBSTR(EQP_GP,4) 
			--                         FROM USRHRA.TB_HR_D_TRK 
			--                        WHERE PTOP_PLNT_GP='HC' 
			--                          AND COIL_NO =(SELECT STL_NO FROM USRYDA.TB_YD_CRNWRKMTL D
			--                                         WHERE D.YD_CRN_SCH_ID=A.YD_CRN_SCH_ID
			--                                           AND ROWNUM<=1)
			--                   ),'00')
			--             ELSE YD_UP_WO_LOC
			--       END)                          AS YD_UP_WO_LOC     
			     , YD_UP_WO_LOC                  AS YD_UP_WO_LOC  
			     , YD_UP_WO_LAYER                AS YD_UP_WO_LAYER
			     , YD_DN_WO_LOC                  AS YD_DN_WO_LOC
			     , YD_DN_WO_LAYER                AS YD_DN_WO_LAYER   
			  FROM TB_YD_CRNSCH A
			 WHERE YD_CRN_SCH_ID >= :V_YD_CRN_SCH_ID
			   AND YD_SCH_CD     =  :V_YD_SCH_CD     
			   AND DEL_YN = 'N'
			   ---------스케줄에 포함된 동일 작업예약 ID만 선택
			   AND YD_WBOOK_ID = (SELECT YD_WBOOK_ID 
			                        FROM TB_YD_CRNSCH 
			                       WHERE YD_CRN_SCH_ID =:V_YD_CRN_SCH_ID)  
			*/
			jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschCrnIdOVERID", logId, mthdNm, "");
			if(jsCrnSch.size() < 1){			
			//더 이상 삭제 작업이 없는경우
				rtnMsg = "삭제 작업이 완료되었습니다";
				commUtils.printLog(logId, rtnMsg, "SL");
				jrRtn.setField("RTN_CD" 	, "1");	
				jrRtn.setField("RTN_MSG" 	, rtnMsg);	
				return jrRtn;
			}
			
			
			String ydUpWoLoc 	= "";
			String ydUpWoLayer 	= "";
//			String ydDnWoLoc 	= "";
			String ydDnWoLayer 	= "";
			String ydWbookId    = "";
			String sStlNo       = "";
			String sEqpCd       = "";
			String sEqpCd1      = "";

			JDTORecordSet jsCrnSchInfo= JDTORecordFactory.getInstance().createRecordSet("Tmp");
			JDTORecordSet jsCrnSchMtl = JDTORecordFactory.getInstance().createRecordSet("Tmp");
			JDTORecordSet jsCrnSchEqp = JDTORecordFactory.getInstance().createRecordSet("Tmp");
			
			boolean bEqpUpdYn    = false; //설비 table 갱신여부
			boolean bCrnWrkSndYn = false; //작업지시 재 전송	
			
			jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			
			for (int Loop_i = 0; Loop_i < jsCrnSch.size(); Loop_i++) {
				
				//크레인스케줄 데이터의 레코드를 추출(작업상태 체크를 위해 미리 추출)
				jrCrnSch = jsCrnSch.getRecord(Loop_i);
				
			    ydWbookId   = commUtils.trim(jrCrnSch.getFieldString("YD_WBOOK_ID"));
				ydCrnSchId  = commUtils.trim(jrCrnSch.getFieldString("YD_CRN_SCH_ID"));
				ydEqpId     = commUtils.trim(jrCrnSch.getFieldString("YD_EQP_ID"));
				ydUpWoLoc  	= commUtils.trim(jrCrnSch.getFieldString("YD_UP_WO_LOC"));
				ydUpWoLayer	= commUtils.trim(jrCrnSch.getFieldString("YD_UP_WO_LAYER"));
				ydDnWoLoc  	= commUtils.trim(jrCrnSch.getFieldString("YD_DN_WO_LOC"));
				ydDnWoLayer	= commUtils.trim(jrCrnSch.getFieldString("YD_DN_WO_LAYER"));
				 
				
				jrParam.setField("YD_CRN_SCH_ID" , ydCrnSchId);
				
				rtnMsg = "스케줄에 편성된 설비번호: " + ydEqpId  ;
				commUtils.printLog(logId, rtnMsg, "SL");
	
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockIdByCrnSchId 
				SELECT CM.STL_NO
				  FROM TB_YD_CRNSCH    CS
				     , TB_YD_CRNWRKMTL CM
				 WHERE CS.YD_CRN_SCH_ID = CM.YD_CRN_SCH_ID
				   AND CS.DEL_YN = 'N'
				   AND CM.DEL_YN = 'N'
				   AND CS.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID 
				 ORDER BY CM.YD_STK_LYR_NO
				 */
				jsCrnSchMtl = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockIdByCrnSchId", logId, mthdNm, "작업재료");
				if(jsCrnSchMtl.size() < 1){	
//					rtnMsg = "실패! 해당 작업재료 조회 ERROR :" +  jsGetCrnMtl.size();
//					commUtils.printLog(logId, rtnMsg, "SL");
//					jrRtn.setField("RTN_CD" 	, "0");	
//					jrRtn.setField("RTN_MSG" 	, rtnMsg);	
//					return jrRtn;
					continue;
				} else {
					sStlNo = commUtils.trim(jsCrnSchMtl.getRecord(0).getFieldString("STL_NO"));
				}
				
				rtnMsg="권상지시위치 "+ydUpWoLoc+"\n"+"권상 지시단 "+ydUpWoLayer+"\n" + "권하 지시위치 "+ydDnWoLoc+"\n" + "권하 지시단 "+ydDnWoLayer+"\n";
				commUtils.printLog(logId, rtnMsg, "SL");

				/**********************************************************
				*   권하위치 원복
				**********************************************************/				
				if (!( "".equals(ydDnWoLoc) || "".equals(ydDnWoLayer)  || "XX010101".equals(ydDnWoLoc) )  ){
	
					if(!"00".equals(ydDnWoLoc.substring(6, 8))){		
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_STK_COL_GP"		, ydDnWoLoc.substring(0, 6));
						jrParam.setField("YD_STK_BED_NO"		, ydDnWoLoc.substring(6, 8));
						jrParam.setField("YD_STK_LYR_NO"		, ydDnWoLayer);
						jrParam.setField("STL_NO"				, "");
						jrParam.setField("YD_STK_LYR_MTL_STAT"	, "E");
						
						rtnMsg = "권하지시위치원복 " + ydDnWoLoc + "-" + ydDnWoLayer ;
						commUtils.printLog(logId, rtnMsg, "SL");
						/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStklyr 
						UPDATE TB_YD_STKLYR
						   SET MODIFIER = :V_MODIFIER
						     , MOD_DDTT = SYSDATE
						     , DEL_YN = 'N'
						     , STL_NO = :V_STL_NO 
						     , YD_STK_LYR_MTL_STAT = :V_YD_STK_LYR_MTL_STAT 
						 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP
						   AND YD_STK_BED_NO = :V_YD_STK_BED_NO
						   AND YD_STK_LYR_NO = :V_YD_STK_LYR_NO
						   AND YD_STK_LYR_MTL_STAT != 'C'
						 */
						commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStklyrDnWo", logId, mthdNm, "적치단 테이블에 권하지시 CLEAR 업데이트");
					}	
				} else {
					//권하위치가 올바르게 잡혀있지 않을때 에러처리를 원한다면 RollBack 을 시킬수 있다.				
					rtnMsg = ": 권하위치가 올바른형식이 아니라 원복시킬수 없습니다.";
					commUtils.printLog(logId, rtnMsg, "SL");				
				}
				
				/**********************************************************
				*   권상위치 원복
				**********************************************************/						
				JDTORecord jrEqpPara = JDTORecordFactory.getInstance().create();
				
				if (!( "".equals(ydUpWoLoc) || "".equals(ydUpWoLayer) )){
	
					//레코드의 커서를 처음으로					
					rtnMsg = ": 권상지시 정보  :" + ydUpWoLoc + "-" + ydUpWoLayer;
					commUtils.printLog(logId, rtnMsg, "SL");					
					
					//------------------------------------------------------------------------------------------------
					//	크레인스케줄의 작업 재료 만큼 루프를 돌아 권상대기 정보를 초기화한다. 
					//------------------------------------------------------------------------------------------------
					
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_STK_COL_GP"		, ydUpWoLoc.substring(0, 6));
					jrParam.setField("YD_STK_BED_NO"		, ydUpWoLoc.substring(6, 8));
					jrParam.setField("YD_STK_LYR_NO"		, ydUpWoLayer);
					jrParam.setField("STL_NO"				, sStlNo);
					
					rtnMsg = ": 권상지시 정보  복원하기 전에 재료번호 저장위치 CLEAR:" +sStlNo ;
					commUtils.printLog(logId, rtnMsg, "SL");

					//적치단 테이블에 권상지시 CLEAR 업데이트 
					/*
					UPDATE TB_YD_STKLYR
					   SET MODIFIER = :V_MODIFIER
					     , MOD_DDTT = SYSDATE
					     , STL_NO   = NULL
					     , YD_STK_LYR_MTL_STAT = 'E' 
					 WHERE STL_NO = :V_STL_NO
					   AND YD_STK_LYR_MTL_STAT IN ('U', 'D')					 
					 */
					commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStkLyrClearByStlNoUD", logId, mthdNm, "적치단 테이블에 권상지시 CLEAR 업데이트");

					
					rtnMsg = ": ydCrnSchCd:" + ydSchCd;
					commUtils.printLog(logId, rtnMsg, "SL");

					sEqpCd  = ydUpWoLoc.substring(2, 4);
					sEqpCd1 = ydUpWoLoc.substring(2, 6);

					/*take out 일 경우*/
					if ("E03LH".equals(ydSchCd.substring(3, 8)))  {
						jrParam.setField("STL_NO"				, sStlNo);
						jrParam.setField("YD_STK_LYR_MTL_STAT"	, "C");
					} else {									
						// 설비일때..
						if ("KD".equals(sEqpCd)    || "KE".equals(sEqpCd) || 
						    "FD".equals(sEqpCd)    || "CV".equals(sEqpCd) || //|| "DD".equals(eqpCd) || "DE".equals(eqpCd) 
						    "FE01".equals(sEqpCd1) || "FE04".equals(sEqpCd1)) { 
							
							jrParam.setField("STL_NO"				, ""); 
							jrParam.setField("YD_STK_LYR_MTL_STAT"	, "E");
							
						} else {								
							jrParam.setField("STL_NO"				, sStlNo);
							jrParam.setField("YD_STK_LYR_MTL_STAT"	, "C");
						}							
					}

 
					//적치단 테이블에 권상지시  업데이트 
					/* 
					UPDATE TB_YD_STKLYR
					   SET MODIFIER            = :V_MODIFIER
					     , MOD_DDTT            = SYSDATE
					     , DEL_YN              = 'N'
					     , STL_NO              = :V_STL_NO --설비일때 null 로 저장
					     , YD_STK_LYR_MTL_STAT = :V_YD_STK_LYR_MTL_STAT 
					 WHERE YD_STK_COL_GP = :V_YD_STK_COL_GP 
					   AND YD_STK_BED_NO = :V_YD_STK_BED_NO 
					   AND YD_STK_LYR_NO = :V_YD_STK_LYR_NO 
					 */
					int iRtnVal1 = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updDetailYdStklyr", logId, mthdNm, "적치단 테이블에 권상지시 업데이트");
					//에러리턴
					if (iRtnVal1 < 1) {
						rtnMsg = ": 적치단 테이블에 권상지시  업데이트 실패" ;
						commUtils.printLog(logId, rtnMsg, "SL");
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, rtnMsg);	
						//return jrRtnParam;
					}else{						
						rtnMsg = ": 적치단 테이블에 권상지시  업데이트 성공" ;
						commUtils.printLog(logId, rtnMsg, "SL");
					}				
					
					/**********************************************************
					*   스케줄 재료를 삭제
					**********************************************************/							
					
					//다음 스케줄 작업 재료 레코드로가기 전 작업한 스케줄 재료를 삭제 처리 해준다.											
					rtnMsg = ": 크레인스케줄 작업 재료 삭제처리" ;						
					commUtils.printLog(logId, rtnMsg, "SL");
					
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
					jrParam.setField("DEL_YN"			, "Y");
					jrParam.setField("STL_NO"			, sStlNo);	
					
					/* 
					UPDATE TB_YD_CRNWRKMTL
					   SET MODIFIER = :V_MODIFIER
					     , MOD_DDTT = SYSDATE
					     , DEL_YN   = :V_DEL_YN
					 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
					   AND STL_NO = :V_STL_NO 
					 */
					int iRtnVal2 = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnwrkmtl01", logId, mthdNm, "적치단 테이블에 권상지시 업데이트");
					
					if (iRtnVal2 < 0){
						rtnMsg = ": 크레인스케줄 작업 재료 삭제처리시 ERROR" ;
						commUtils.printLog(logId, rtnMsg, "SL");
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, rtnMsg);	
						return jrRtn;

					} else if(iRtnVal2 == 0 ){
						rtnMsg = ": 크레인스케줄 작업 재료 삭제처리 대상 없음" ;
						commUtils.printLog(logId, rtnMsg, "SL");
					} else {
						rtnMsg = ": 크레인스케줄 작업 재료 삭제처리 성공" ;
						commUtils.printLog(logId, rtnMsg, "SL");
					}
					
					
					/**********************************************************
					*   저장품 삭제
					**********************************************************/	
					
					rtnMsg = ": 저장품  작업예약 ID, 스케줄코드 CLEAR" ;
					commUtils.printLog(logId, rtnMsg, "SL");
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);					
					jrParam.setField("STL_NO"		, sStlNo);	
					jrParam.setField("YD_WBOOK_ID"	, "" );
					jrParam.setField("YD_SCH_CD"	, "" );		
					
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockClear
					UPDATE TB_YD_STOCK 
					   SET MODIFIER    = :V_MODIFIER
						 , MOD_DDTT    = SYSDATE
						 , YD_WBOOK_ID = :V_YD_WBOOK_ID
						 , YD_SCH_CD   = :V_YD_SCH_CD
					 WHERE STL_NO = :V_STL_NO
					*/
					int iRtnVal3 = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockClear", logId, mthdNm, "저장품에 등록된 작업예약 ID, 스케줄 CD Clear");
					
					if(iRtnVal3 < 0){
						rtnMsg = ": 저장품  작업예약 ID, 스케줄코드 CLEAR ERROR" ;
						commUtils.printLog(logId, rtnMsg, "SL");
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, rtnMsg);	
						return jrRtn;
					}else if(iRtnVal3 == 0 ){
						rtnMsg = ": 저장품  작업예약 ID, 스케줄코드 CLEAR 대상 없음" ;
						commUtils.printLog(logId, rtnMsg, "SL");
					}else{
						rtnMsg = ": 저장품  작업예약 ID, 스케줄코드 CLEAR 성공" ;
						commUtils.printLog(logId, rtnMsg, "SL");
					}
	
					/**********************************************************
					*   크레인스케줄 삭제처리 
					**********************************************************/	
					rtnMsg = ": 크레인스케줄  삭제처리" ;
					commUtils.printLog(logId, rtnMsg, "SL");
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
					jrParam.setField("DEL_YN"			, "Y");
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch
					UPDATE TB_YD_CRNSCH
					   SET MODIFIER = :V_MODIFIER
					     , MOD_DDTT = SYSDATE
					     , DEL_YN   = :V_DEL_YN
					 WHERE YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID   
                    */
					int iRtnVal4 = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdCrnsch", logId, mthdNm, "크레인스케줄 삭제처리");
					
					if (iRtnVal4 > 0) {
						rtnMsg = ": 크레인스케줄  삭제처리 완료" ;
						commUtils.printLog(logId, rtnMsg, "SL");
						
					} else {					
						rtnMsg = ": 크레인스케줄  삭제처리 실패" ;
						commUtils.printLog(logId, rtnMsg, "SL");
						jrRtn.setField("RTN_CD" 	, "0");	
						jrRtn.setField("RTN_MSG" 	, rtnMsg);	
						return jrRtn;
					}
					
					/*******************************************************
					 * 스케줄 취소시 작업예약테이블에 스케줄취소 컬럼 UPDATE
					 *******************************************************/
					String sAPP815_YN_J = coilDao.ApplyYn(logId, mthdNm, "APP815", "J", "J");// 스케줄 취소여부(제품)
					String sAPP815_YN_H = coilDao.ApplyYn(logId, mthdNm, "APP815", "J", "H");// 스케줄 취소여부(소재)
					
					if (("Y".equals(sAPP815_YN_J) && !ydSchCd.endsWith("H"))  //제품
					  || "Y".equals(sAPP815_YN_H) && ydSchCd.endsWith("H")) { //소재
						/*
						UPDATE TB_YD_WRKBOOK
						   SET SCH_CNCL_YN = 'Y'
						     , MODIFIER    = :V_MODIFIER
						     , MOD_DDTT    = SYSDATE
						 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
						 */
						jrParam.setField("YD_WBOOK_ID", ydWbookId);
						jrParam.setField("SCH_CNCL_YN", "Y");
						commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updSchAutoStYn", logId, mthdNm, "TB_YD_WRKBOOK >> SCH_CNCL_YN");
					}
					
					/**********************************************************
					// 설비 상태를 진행상태에 맞도록 변경 시킨다. 
					// 해당 작업 예약 ID으로 스케줄 정보 조회시에 하나도 존재 하지 않을경우에
					// - 해당 스케줄 코드로 전체 스케줄 조회시 남은스케줄 첫번째 진행상태 정보로 UPDATE 
					// - 해당 스케줄 코드로 전체 스케줄 조회시 남아있는것이 없을경우는 대기상태로 UPDAT 해준다.
					**********************************************************/						
					
					jrParam   = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_WBOOK_ID", ydWbookId);
					
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschByWrkId 
					SELECT *
					  FROM TB_YD_CRNSCH
					 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
					   AND DEL_YN='N'
					 ORDER BY YD_CRN_SCH_ID
					*/ 
					jsCrnSchInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschByWrkId", logId, mthdNm, "");
					
					//설비 상태 UPDATE 유무 체크 FLAG 
					bEqpUpdYn    = false; //설비 table 갱신여부
					bCrnWrkSndYn = false; //작업지시 재 전송	
					String sUpdEqpstat 		= "";
					
					
					if (jsCrnSchInfo.size() == 0){
						
						rtnMsg = ": 해당 작업예약 정보에  남은 스케줄 정보가 없으므로 작업대기 상태로 UPDATE 합니다." ;
						commUtils.printLog(logId, rtnMsg, "SL");
						
						//해당 설비로 같은 편성된 스케줄이 없는지 확인한다.(다른작업예약 ID가 편성되었을경우)
						jrEqpPara   = commUtils.getParam(logId, mthdNm, sModifier);
						jrEqpPara.setField("YD_EQP_ID", ydEqpId);
						
						rtnMsg = ": 해당 설비로 작업중인 스케줄이 있는지 확인한다." ;
						commUtils.printLog(logId, rtnMsg, "SL");
						
						/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqpIdWrkProgStat 
						SELECT *
						  FROM (
						        SELECT YD_CRN_SCH_ID           AS YD_CRN_SCH_ID          
						             , YD_EQP_WRK_STAT         AS YD_EQP_WRK_STAT       
						             , YD_WRK_PROG_STAT        AS YD_WRK_PROG_STAT        
						             , YD_WBOOK_DT             AS YD_WBOOK_DT        
						          FROM TB_YD_CRNSCH                                      
						         WHERE YD_EQP_ID =  :V_YD_EQP_ID            
						           AND YD_WRK_PROG_STAT IN('1','2','3')
						           AND DEL_YN='N'
						         ORDER BY YD_WRK_PROG_STAT DESC
						       ) 
						 WHERE ROWNUM<=1
						*/
						jsCrnSchEqp = commDao.select(jrEqpPara, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnSchEqpIdWrkProgStat", logId, mthdNm, "");
						
						if (jsCrnSchEqp.size() == 0){
							rtnMsg=":남은 스케줄 정보가 없으므로 작업대기 상태로 UPDATE 합니다.";
							commUtils.printLog(logId, rtnMsg, "SL");

							sUpdEqpstat     = "W";
							
						} else {
							rtnMsg=":해당 스케줄 코드에 스케줄 정보가 남아 있어 설비정보는 남은스케줄 첫번째 진행상태 정보로 UPDATE 합니다.";
							commUtils.printLog(logId, rtnMsg, "SL");
							
							jsCrnSchEqp.first();
							JDTORecord jrCrnSchEqp = jsCrnSchEqp.getRecord();
							
							sUpdEqpstat = commUtils.trim(jrCrnSchEqp.getFieldString("YD_WRK_PROG_STAT"));
							
						}
					
						bEqpUpdYn     = true;  //설비 table 갱신
						bCrnWrkSndYn  = true;  //작업지시 재 전송	
					
					} else {						
						rtnMsg="해당 작업예약 정보에 스케줄 정보가 남아 있어 설비정보는 UPDATE 하지 않습니다.";
						commUtils.printLog(logId, rtnMsg, "SL");						
					}
					
					/************************************
					 * 설비 table update
					 ************************************/
					if (bEqpUpdYn) {						
						jrParam   = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_EQP_ID"	, ydEqpId);
						jrParam.setField("YD_EQP_STAT"	, sUpdEqpstat);					
						
						String szRtnMsg = coilDao.chkCrnStat(logId , mthdNm ,ydEqpId);
						commUtils.printLog(logId, "szRtnMsg:" + szRtnMsg, "SL");
						
						if(CConstant.RETN_CD_SUCCESS.equals(szRtnMsg)){
							rtnMsg="해당 스케줄 크레인("+ ydEqpId +") 설비상태 [" + sUpdEqpstat +"]로 변경 ";
							commUtils.printLog(logId, rtnMsg, "SL");	
							/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02
							UPDATE TB_YD_EQP
							   SET YD_EQP_STAT = :V_YD_EQP_STAT
							     , MODIFIER    = :V_MODIFIER
							     , MOD_DDTT    = SYSDATE
							WHERE YD_EQP_ID    = :V_YD_EQP_ID
							*/
							int iRtnVal5 = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdEqpNew02", logId, mthdNm, "크레인스케줄 삭제처리");
							
							if (iRtnVal5 < 0 ){
								rtnMsg="해당 스케줄 크레인("+ ydEqpId +") 설비상태 [" + sUpdEqpstat +"]로 변경시 ERROR ";
								commUtils.printLog(logId, rtnMsg, "SL");
								jrRtn.setField("RTN_CD" 	, "0");	
								jrRtn.setField("RTN_MSG" 	, rtnMsg);	
								return jrRtn;								
							}
						}
						
						if (bCrnWrkSndYn && !"W".equals(ydWrkProgStat)) {
							// 취소처리 후 작업지시 재 전송	
							// 스케쥴 여러건 삭제시 작업지시는 마지막 한건만 나가게 수정 IS_LAST_SELECTED 값은 Fa에서 넘겨줌
							// 고장이 아닌 경우
							if(("1".equals(sIsLastSelected)) && ("W".equals(sUpdEqpstat)) && (!"B".equals(szRtnMsg)) ) {
								jrEqpPara   = commUtils.getParam(logId, mthdNm, sModifier);
								jrEqpPara.setField("YD_EQP_ID"			, ydEqpId);
								jrEqpPara.setField("YD_WRK_PROG_STAT"	, sUpdEqpstat);
								
								EJBConnector ejbConn = new EJBConnector("default", "CCoilL2RcvSeEJB", this);
								JDTORecord jrRtn1 = (JDTORecord)ejbConn.trx("rcvY5YDL007", new Class[] { JDTORecord.class }, new Object[] { jrEqpPara });
								
								rtnCd   = commUtils.nvl(jrRtn1.getFieldString("RTN_CD"), "0");
								rtnMsg	= commUtils.nvl(jrRtn1.getFieldString("RTN_MSG"), "");
					            commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMsg, "SL");
					            
								//내부송신
								jrRtn = commUtils.addSndData(jrRtn, jrRtn1);
								
							}
						}
					}
				}
			}
			
	        //작업 예약 /재료 삭제
			// 크레인 작업 재지시를 위하여  설비 아이디 , 스케줄 코드를 넘겨준다.
			rtnMsg=":크레인 스케쥴 삭제 호출완료";
			
			jrRtn.setField("RTN_CD" 		, "1");	
			jrRtn.setField("RTN_MSG" 		, rtnMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;

		} catch(DAOException e) {
				throw e;
		} catch(Exception e) {
				throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	
	/**
	 * 대차 권상가능 Check
	 * 강정선  2019.11.04
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord getStkColTCarUpChk3(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "대차권상가능Check[CCoilJspSeEJB.getStkColTCarUpChk3] < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";

			String ydSchCd			= rcvMsg.getFieldString("YD_SCH_CD");
			String ydWbookId		= rcvMsg.getFieldString("YD_WBOOK_ID");

			JDTORecord jrParam  = JDTORecordFactory.getInstance().create();
			jrParam.setField("YD_WBOOK_ID"	, ydWbookId);	// 작업예약ID
			jrParam.setField("YD_SCH_CD"	, ydSchCd);		// 스케쥴코드

			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStkColTCarUpChk3 
			SELECT SUM(CNT)              AS STL_CNT
			     , SUM(COIL_WT)          AS SUM_WGT
			     , MAX(CURR_PROG_CD)     AS CURR_PROG_CD
			     , MAX(TRANS_ORD_SEQNO)  AS TRANS_ORD_SEQNO
			     , MAX(STK_BED_MAX_QNTY) AS STK_BED_MAX_QNTY
			     , MAX(STK_BED_MAX_WT)   AS STK_BED_MAX_WT
			  FROM
			        (
			            SELECT COUNT(*)                AS CNT
			                 , SUM(Z2.COIL_WT)         AS COIL_WT
			                 , MAX(Z2.CURR_PROG_CD)    AS CURR_PROG_CD
			                 , MAX(C.TRANS_ORD_SEQNO)  AS TRANS_ORD_SEQNO
			                 , MAX(D.STK_BED_MAX_QNTY) AS STK_BED_MAX_QNTY
			                 , MAX(D.STK_BED_MAX_WT)   AS STK_BED_MAX_WT
			              FROM
			                   (
			                    SELECT B.STL_NO
			                         , A.YD_WRK_PLAN_TCAR 
			                      FROM TB_YD_WRKBOOK    A
			                         , TB_YD_WRKBOOKMTL B
			                     WHERE B.YD_WBOOK_ID =:V_YD_WBOOK_ID
			                       AND B.DEL_YN = 'N'
			                   ) Z1
			                 , USRPTA.TB_PT_COILCOMM Z2
			                 , TB_YD_STOCK C
			                 , TB_YD_EQP   D
			             WHERE Z1.STL_NO = Z2.COIL_NO
			               AND Z1.STL_NO = C.STL_NO
			               AND Z1.YD_WRK_PLAN_TCAR = D.YD_EQP_ID 
			            UNION ALL
			            SELECT COUNT(*)         CNT
			                 , NVL(SUM(Z2.COIL_WT),0) COIL_WT
			                 , ''
			                 , 0
			                 , 0
			                 , 0 
			              FROM
			                   (
			                    SELECT A.STL_NO
			                      FROM TB_YD_STKLYR A
			                     WHERE A.YD_STK_COL_GP  = SUBSTR(:V_YD_SCH_CD,1,2)|| (SELECT SUBSTR(YD_WRK_PLAN_TCAR,3,4) FROM TB_YD_WRKBOOK WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID)
			                       AND A.YD_STK_LYR_MTL_STAT = 'C'
			                       AND A.DEL_YN = 'N'
			                   ) Z1
			                 , USRPTA.TB_PT_COILCOMM Z2
			             WHERE Z1.STL_NO = Z2.COIL_NO
			        )
			*/
			JDTORecordSet jsTCar = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStkColTCarUpChk3", logId, mthdNm, "대차권상가능CHECK");
			intRtnVal = jsTCar.size();
			
			if( intRtnVal < 1 ) {
				sMsg = "작업예약ID["+ ydWbookId +"] 스케쥴코드["+ ydSchCd +"] 해당정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				jrRtn.setField("RTN_CD"		, "0");
				jrRtn.setField("RTN_MSG"	, sMsg);
				return jrRtn;
			}
			
			jrRtn.setField("RTN_CD"			  , "1");
			jrRtn.setField("RTN_MSG"		  , "대차권상위치 CHECK 완료");
			jrRtn.setField("STL_CNT"		  , jsTCar.getRecord(0).getFieldString("STL_CNT"));
			jrRtn.setField("SUM_WGT"		  , jsTCar.getRecord(0).getFieldString("SUM_WGT"));
			jrRtn.setField("CURR_PROG_CD"	  , jsTCar.getRecord(0).getFieldString("CURR_PROG_CD"));
			jrRtn.setField("TRANS_ORD_SEQNO"  , jsTCar.getRecord(0).getFieldString("TRANS_ORD_SEQNO"));
			jrRtn.setField("STK_BED_MAX_QNTY" , jsTCar.getRecord(0).getFieldString("STK_BED_MAX_QNTY")); // 기준매수
			jrRtn.setField("STK_BED_MAX_WT"   , jsTCar.getRecord(0).getFieldString("STK_BED_MAX_WT"));   // 기준중량 
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	
	/**
	 * 제품 통합이적지시 - 이적지시 : 기존 - updColUnitMvstkReg 소재/제품 EJB 에서 분기되었기에 Method 중복으로 Method 명에 Gds 추가 
	 * 강정선  2019.11.04
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updGdsColUnitMvstkReg(GridData gdReq) throws DAOException {
		String mthdNm = "이적지시[CCoilJspSeEJB.updGdsColUnitMvstkReg] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			String sFromYdStkColGp	= commUtils.getValue(gdReq, "FROMLOC", 0); 
			
			String sModifier     = commUtils.trim(gdReq.getParam("userid"));
			String ydSchCd		 = commUtils.trim(gdReq.getParam("FRM_YD_SCH_CD"));
			String sToYdStkColGp = commUtils.trim(gdReq.getParam("YD_GP"))
			                     + commUtils.trim(gdReq.getParam("TO_YD_BAY_GP"))
			                     + commUtils.trim(gdReq.getParam("TO_YD_EQP_GP"))
			                     + commUtils.trim(gdReq.getParam("TO_YD_STK_COL_NO"));
			String sTCar         = commUtils.trim(gdReq.getParam("T_CAR"));

			String sMsg				= "";
			String rtnCd			= "";
			String rtnMsg			= "";
			String firstYdWbookId	= ""; // 첫 작업예약이 대차작업이 아니면 스케쥴 기동
			String sSndFlag			= "N";
			String sCurrProgCd		= "0";
			String sTransOrdSeqNo	= "0";
			String ydAimBayGp	    = "";
			
			int intRtnVal			= 0;
			int iStlCnt				= 0;

			// 현재적치위치 체크
			if( "".equals(sFromYdStkColGp)) {
				sMsg = "FROM 적치정보 없음";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn.setField("RTN_CD"		, "0");
				jrRtn.setField("RTN_MSG"	, sMsg);
				return jrRtn;
			}
			
			/*******************************
			 * 1. CHECK : 대차 유무, 사용가능
			 *******************************/
			// 현재위치 : 야드구분+동+스판+열
			sFromYdStkColGp   = sFromYdStkColGp.substring(0, 6);
			String sFromBayGp = sFromYdStkColGp.substring(1, 2);
			String sToBayGp   = sToYdStkColGp.substring(1, 2);
			commUtils.printLog(logId, "현재동["+ sFromBayGp +"] 이적동["+ sToBayGp +"]", "SL");
			
			JDTORecord jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_EQP_ID", sTCar);	// 대차 설비ID

			// 동일동은 대차 체크 
			if( !sFromBayGp.equals(sToBayGp) ) {
				
				// 대차정보 체크
				
				/*
				 * SELECT YD_EQP_ID        -- 설비ID
				      ,YD_GP            -- 야드구분
				      ,YD_BAY_GP        -- 동구분
				      ,YD_EQP_GP        -- 야드설비구분
				      ,YD_EQP_NO        -- 야드설비번호
				      ,YD_CURR_BAY_GP   -- 현재동 
				      ,YD_TCAR_WRK_ABLE_BAY1 ||DECODE(YD_TCAR_WRK_ABLE_BAY1,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY2 ||DECODE(YD_TCAR_WRK_ABLE_BAY2,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY3 ||DECODE(YD_TCAR_WRK_ABLE_BAY3,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY4 ||DECODE(YD_TCAR_WRK_ABLE_BAY4,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY5 ||DECODE(YD_TCAR_WRK_ABLE_BAY5,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY6 ||DECODE(YD_TCAR_WRK_ABLE_BAY6,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY7 ||DECODE(YD_TCAR_WRK_ABLE_BAY7,'','',', ')
				      || YD_TCAR_WRK_ABLE_BAY8 
					  AS YD_TCAR_WRK_ABLE_BAY
				  FROM USRYDA.TB_YD_EQP
				 WHERE YD_EQP_ID =:V_YD_EQP_ID
				   AND DEL_YN = 'N'
				 */
				JDTORecordSet jsTcInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarInfo", logId, mthdNm, "대차정보조회");
				intRtnVal = jsTcInfo.size();
				
				if( intRtnVal < 1 ) {
					sMsg = "["+ sTCar +"] 대차상태정보 조회에 실패 하였습니다. ";
					commUtils.printLog(logId, sMsg, "SL");
					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, sMsg);
					return jrRtn;
				}
				
				// 대차 이동 가능 동 인지 체크
				int iFromBayChk = jsTcInfo.getRecord(0).getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sFromBayGp);
				int iToBayChk   = jsTcInfo.getRecord(0).getFieldString("YD_TCAR_WRK_ABLE_BAY").indexOf(sFromBayGp);
				
				if( iFromBayChk < 0 || iToBayChk < 0 ) {
					sMsg = "설정된 대차 이동구간이 일치하지 않습니다.<br>이동가능구간 : "+ jsTcInfo.getRecord(0).getFieldString("YD_TCAR_WRK_ABLE_BAY");
					commUtils.printLog(logId, sMsg, "SL");
					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, sMsg);
					return jrRtn;
				}
			}
			
			
			/*******************************
			 * 2. 2단 작업예약 등록
			 *******************************/
			String sStlNo = "";
			String sUpPos = "";
			String ydWbookId = "";
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {
				
				// 현 저장위치 ex)C0202203 (동)+(스판)+(열)+(단)+(번지)
				sUpPos = commUtils.getValue(gdReq, "UP_POS", i);
				sStlNo = commUtils.getValue(gdReq, "STL_NO", i);
				
				if( !"2".equals(sUpPos.substring(5, 6)) ) {
					continue;
				}
				
				jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd);	// 스케쥴코드
				jrParam.setField("STL_SH"				, "1");		// LINE IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo);	// 코일번호
				jrParam.setField("YD_AIM_YD_GP"			, ydSchCd.substring(0, 1));
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
				jrParam.setField("TO_YD_STK_BED_NO"		, sToYdStkColGp);	// TO 저장위치
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1");		// 권상모음 순서
				jrParam.setField("YD_WRK_PLAN_TCAR"		, sTCar);	// 대차
				jrParam.setField("YD_USER_ID"			, sModifier);
				
				//---------------------------//
				// 작업예약호출 insWrkBook
				//---------------------------//
				EJBConnector ejbConn	= new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook	= (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				rtnCd	 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg	 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId= commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
				
				if( !"1".equals(rtnCd) ) {
					
					commUtils.printLog(logId, rtnMsg, "SL");
					
					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, rtnMsg);
					return jrRtn;
				}
				
				// 등록된 작업예약 ID
				iStlCnt++;
				
				//--------------------------------------------//
				// 처음 등록된 작업예약이 대차이적이 아니면 스케쥴 기동
				//--------------------------------------------//
				if( (iStlCnt == 1) && (!"TC".equals(ydSchCd.substring(2, 4))) ) {
					
					firstYdWbookId = ydWbookId;
				}

				sMsg = i + "/"+ rowCnt +" 작업예약ID["+ ydWbookId +"] 등록하였습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
				//--------------------------------------------//
				// 대차 작업지시 생성
				//--------------------------------------------//
				if( ("N".equals(sSndFlag)) && ("TC".equals(ydSchCd.substring(2, 4))) ) {

					jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD"	, ydSchCd);		// 스케쥴코드
					jrParam.setField("YD_WBOOK_ID"	, ydWbookId);	// 작업예약 ID
					
					JDTORecord jrTCarCheck = this.getStkColTCarUpChk3(jrParam);
					
					// RTN_CD 체크하지 않음
					sCurrProgCd		= commUtils.nvl(jrTCarCheck.getFieldString("CURR_PROG_CD"), "0");
					sTransOrdSeqNo	= commUtils.nvl(jrTCarCheck.getFieldString("TRANS_ORD_SEQNO"), "0");
					
//					iMaxCnt	= Integer.parseInt(commUtils.nvl(jrTCarCheck.getFieldString("STK_BED_MAX_QNTY"), "0"));  // 기준매수
//					iMaxWt	= Integer.parseInt(commUtils.nvl(jrTCarCheck.getFieldString("STK_BED_MAX_WT"), "0"));    // 기준중량 
					
					// CURR_PROG_CD : M(출하완료)
					// TRANS_ORD_SEQNO : 운송지시순번
					// 출하완료 이거나 LOT 편성이 된 보관매출재는 동간이적 불가능
					if( "M".equals(sCurrProgCd) && !"0".equals(sTransOrdSeqNo) ) {
						sMsg = "LOT 편성된 보관매출재는 동간 이적이 불가능 합니다.";
						commUtils.printLog(logId, sMsg, "SL");
						jrRtn.setField("RTN_CD"		, "0");
						jrRtn.setField("RTN_MSG"	, sMsg);
						return jrRtn;
					}
					
					//--------------------------------------------//
					// 대차 이동지시 CHECK 및 스케쥴 UPDATE
					//--------------------------------------------//
					jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_WBOOK_ID", ydWbookId);	// 작업예약 ID
					
					JDTORecord jrWrkBookChk = this.chkTCarMoveWrkBook(jrParam);
					rtnCd		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_CD"), "0");
					rtnMsg		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_MSG"), "");
					ydAimBayGp	= commUtils.nvl(jrWrkBookChk.getFieldString("YD_AIM_BAY_GP"), "");
					sSndFlag	= commUtils.nvl(jrWrkBookChk.getFieldString("SND_FLAG"), "");
					
					if( !"1".equals(rtnCd) ) {

						commUtils.printLog(logId, sMsg, "SL");
						jrRtn.setField("RTN_CD"		, "0");
						jrRtn.setField("RTN_MSG"	, sMsg);
						return jrRtn;
					}
					
					sMsg = "대차작업 송신 여부 : "+ sSndFlag;
					commUtils.printLog(logId, sMsg, "SL");
					
					if( "Y".equals(sSndFlag) ) {
						jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_EQP_ID"   , sTCar); //야드설비ID(대차)
						jrParam.setField("YD_TO_BAY"   , ydAimBayGp  ); //야드동구분(상차동)
						jrParam.setField("YD_WBOOK_ID" , ydWbookId);

						jrRtn = this.procTcarSchLevWo(jrParam);		
						
					}
				}
			}
			
			/*******************************
			 * 3. 1단 작업예약 등록
			 *******************************/
			sStlNo = "";
			sUpPos = "";
			ydWbookId = "";
			for (int i = 0; i < rowCnt; i++) {
				
				// 현 저장위치 ex)C0202203 (동)+(스판)+(열)+(단)+(번지)
				sUpPos = commUtils.getValue(gdReq, "UP_POS", i);
				sStlNo = commUtils.getValue(gdReq, "STL_NO", i);
				if( !"1".equals(sUpPos.substring(5, 6)) ) {
					continue;
				}
				
				jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd);	// 스케쥴코드
				jrParam.setField("STL_SH"				, "1");		// LINE IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo);	// 코일번호
				jrParam.setField("YD_AIM_YD_GP"			, ydSchCd.substring(0, 1));
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
				jrParam.setField("TO_YD_STK_BED_NO"		, sToYdStkColGp);	// TO 저장위치
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1");		// 권상모음 순서
				jrParam.setField("YD_WRK_PLAN_TCAR"		, sTCar);	// 대차
				jrParam.setField("YD_USER_ID"			, sModifier);
				
				//---------------------------//
				// 작업예약호출 insWrkBook
				//---------------------------//
				EJBConnector ejbConn	= new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook	= (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				rtnCd	 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg	 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId= commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
				
				if( !"1".equals(rtnCd) ) {
					
					commUtils.printLog(logId, rtnMsg, "SL");
					
					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, sMsg);
					return jrRtn;
				}
				
				// 등록된 작업예약 ID
				iStlCnt++;
				//--------------------------------------------//
				// 처음 등록된 작업예약이 대차이적이 아니면 스케쥴 기동
				//--------------------------------------------//
				if( (iStlCnt == 1) && (!"TC".equals(ydSchCd.substring(2, 4))) ) {
					
					firstYdWbookId = ydWbookId;
				}

				sMsg = i + "/"+ rowCnt +" 작업예약ID["+ ydWbookId +"] 등록하였습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
				//--------------------------------------------//
				// 대차 작업지시 생성
				//--------------------------------------------//
				if( ("N".equals(sSndFlag)) && ("TC".equals(ydSchCd.substring(2, 4))) ) {

					//--------------------------------------------//
					// 대차 이동지시 CHECK 및 스케쥴 UPDATE
					//--------------------------------------------//
					jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_WBOOK_ID", ydWbookId);	// 작업예약 ID
					
					JDTORecord jrWrkBookChk = this.chkTCarMoveWrkBook(jrParam);
					
					rtnCd		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_CD"), "0");
					rtnMsg		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_MSG"), "");
					ydAimBayGp	= commUtils.nvl(jrWrkBookChk.getFieldString("YD_AIM_BAY_GP"), "");
					sSndFlag	= commUtils.nvl(jrWrkBookChk.getFieldString("SND_FLAG"), "");
					
					
					commUtils.printLog(logId, "작업예약:" +ydWbookId, "SL");
					
					if( !"1".equals(rtnCd) ) {

						commUtils.printLog(logId, rtnMsg, "SL");
						jrRtn.setField("RTN_CD"		, "0");
						jrRtn.setField("RTN_MSG"	, sMsg);
						return jrRtn;
					}
					
					
					sMsg = "대차작업 송신 여부 : "+ sSndFlag;
					commUtils.printLog(logId, sMsg, "SL");
					
					if( "Y".equals(sSndFlag) ) {
						
						jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_EQP_ID"   , sTCar); //야드설비ID(대차)
						jrParam.setField("YD_TO_BAY"   , ydAimBayGp); //야드동구분(상차동)
						jrParam.setField("YD_WBOOK_ID" , ydWbookId);

						jrRtn = this.procTcarSchLevWo(jrParam);	
					}
				}
			}
			
			sMsg = "이적 작업예약 완료!";
			/****************************************************
			 * 4. 처음 등록된 작업예약이 대차이적이 아니면 크레인 스케쥴 기동
			 ****************************************************/
			if( !"".equals(firstYdWbookId) ) {
				
				jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD", ydSchCd);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd */
				/*
				SELECT YD_WBOOK_ID
				     , YD_SCH_CD
				  FROM TB_YD_CRNSCH
				 WHERE DEL_YN='N'
				   AND YD_SCH_CD = :V_YD_SCH_CD
				*/
				JDTORecordSet jsYdCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "스케쥴기동체크");
				intRtnVal = jsYdCrnSch.size();

				if( intRtnVal < 1 ) {
					
		    		JDTORecord jrRecordarr = commUtils.getParam(logId, mthdNm, sModifier);
		    		jrRecordarr.setField("YD_SCH_CD"		, ydSchCd); 
		    		jrRecordarr.setField("YD_WBOOK_ID"	    , firstYdWbookId); 
					
					JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrRecordarr);
					
					rtnCd	= commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
					commUtils.printLog(logId, "//" + rtnMsg, "SL");	
					
					if (!("1".equals(rtnCd))) {
						jrRtn.setField("RTN_CD" 			, "0");	
						jrRtn.setField("RTN_MSG"			, rtnMsg);	
						
						return jrRtn;
					} else {
						jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						jrRtn.setField("RTN_MSG"			, rtnMsg + " <br> 정상적으로 스케쥴까지 등록했습니다.");	
					} 	
				}
			}
			
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg );
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 결로ON/OFF  버튼 클릭시 실행
	 * 염용선 2019-11-5
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord updConOffResultList(GridData gdReq) throws DAOException {
	    String mthdNm = "결로재 보급 ON/OFF[CCoilJspSeEJB.updConOffResultList] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();	
		
		try {
			
			int intRtnVal	= 0;
			String userid	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String sMode	= commUtils.trim(gdReq.getParam("MODE"));
			String sYdBayGp	= commUtils.trim(gdReq.getParam("YD_BAY_GP2"));
			
			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, userid);
			jrParam.setField("MODE_GP", commUtils.trim(gdReq.getParam("MODE")));
			jrParam.setField("YD_BAY_GP", commUtils.trim(gdReq.getParam("YD_BAY_GP2")));
			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updConOffResultYN2
			 UPDATE TB_YD_RULE
			    SET ITEM1      = :V_MODE_GP
			      , MODIFIER   = :V_MODIFIER
			      , MOD_DDTT   = SYSDATE
			  WHERE REPR_CD_GP ='H00032'
			    AND CD_GP = :V_YD_BAY_GP
			*/
			intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updConOffResultYN2", logId, mthdNm, "결로재보급 ON/OFF 수정");
			if (intRtnVal < 0) {
				
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", "결로ON/OFF 처리중 에러 발생");
				return jrRtn;
			}
			
			// 결로ON 이면 자동이적지시 생성
			if( "Y".equals(sMode) ) {
				jrParam	= commUtils.getParam(logId, mthdNm, userid);
				this.procHotCoilRetnMove(jrParam);
			}
			
			jrRtn.setField("RTN_CD", "1");
			
			return jrRtn;	
			
		} catch(DAOException e) {
			throw e;
		}catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 차량작업관리 - 차량POINT SPAN 범위 설정
	 * 야드관리 > 2열연 코일야드[신] > 출하이송관리 > 차량작업관리
	 * 강정선 2019.11.08
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCarSpanRng(GridData gdReq) throws DAOException {
		String mthdNm	= "차량포인트SPAN범위설정[CCoilJspSeEJ.updCarSpanRng] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";
			
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= null;
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

	    		/**************************************************
	    		 * SPAN 입력값 문자열 및 길이[VARCHAR2(2)] 화면에서 체크
	    		 * 1. 차량POINT SPAN 범위 UPDATE  
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_CARPNT_CD",	commUtils.getValue(gdReq, "YD_CARPNT_CD",	i));
				jrParam.setField("YD_SPAN_FROM",	commUtils.getValue(gdReq, "YD_SPAN_FROM",	i));
				jrParam.setField("YD_SPAN_TO",		commUtils.getValue(gdReq, "YD_SPAN_TO",		i));

				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarSpanRng */
				/*
				UPDATE TB_YD_CARPOINT
				   SET YD_SPAN_FROM = LPAD(:V_YD_SPAN_FROM, 2, '0')
				     , YD_SPAN_TO   = LPAD(:V_YD_SPAN_TO,   2, '0')
				     , MODIFIER     = :V_MODIFIER
				     , MOD_DDTT     = SYSDATE
				 WHERE YD_CARPNT_CD = :V_YD_CARPNT_CD
				*/
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarSpanRng", logId, mthdNm, "차량POINT SPAN 업데이트");
				 
				if( intRtnVal < 1 ) {
					
					sMsg = "차량POINT SPAN 범위설정 수정 실패! "+ intRtnVal;
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}
			
			sMsg = "SPAN 범위를 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 검수이상제품조회 - 출고검수 완료
	 * 야드관리 > 2열연 코일야드[신] > 출하이송관리 > 검수이상제품조회
	 * 강정선 2019.11.18
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 * 기존 : updateCarExamination
	 */
	public JDTORecord procCarExamination(GridData gdReq) throws DAOException {
		String mthdNm	= "출고검수완료[CCoilJspSeEJ.procCarExamination] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= JDTORecordFactory.getInstance().create();
			
			String sTransOrdDate	= "";
			String sTransOrdSeqNo	= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

	    		/**************************************************
	    		 * 1. 검수완료 UPDATE
	    		 **************************************************/
				sTransOrdDate  = commUtils.getValue(gdReq, "TRANS_ORD_DATE",  i);
				sTransOrdSeqNo = commUtils.getValue(gdReq, "TRANS_ORD_SEQNO", i);
				
				sMsg = "===== 검수 출고 처리 시작 ===== TRANS_ORD_DATE["+ sTransOrdDate +"] TRANS_ORD_SEQNO["+ sTransOrdSeqNo +"]";
	    		commUtils.printLog(logId, sMsg, "SL");

				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("TRANS_ORD_DATE"	, sTransOrdDate);
				jrParam.setField("TRANS_ORD_SEQNO"	, sTransOrdSeqNo);
				jrParam.setField("LABEL_YN"			, "N");
				jrParam.setField("CHECKING_YN"		, "Y");
				
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationChecking */
				/*
				UPDATE TB_YD_EXAMINATIONCHKLIST
				   SET LABEL_YN        = :V_LABEL_YN
				     , CHECKING_YN     = :V_CHECKING_YN
				     , MODIFIER        = :V_MODIFIER
				     , MOD_DDTT        = SYSDATE
				 WHERE TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
				   AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
				*/
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationChecking", logId, mthdNm, "검수완료UPDATE");
				 
				if( intRtnVal < 1 ) {
					
					sMsg = "검수완료 수정 실패! "+ intRtnVal;
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				sMsg = "검수 처리 완료! TRANS_ORD_DATE["+ sTransOrdDate +"] TRANS_ORD_SEQNO["+ sTransOrdSeqNo +"]";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		
	    		/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationChk */
	    		/*
	    		SELECT CNT
	    		     , CNT - CHECKING AS CHK
	    		     , CAR_NO
	    		     , (SELECT TRANS_EQUIPMENT_TYPE
	    		          FROM TB_YD_CARSCH B
	    		         WHERE B.TRANS_ORD_DATE  = A.TRANS_ORD_DATE
	    		           AND B.TRANS_ORD_SEQNO = A.TRANS_ORD_SEQNO
	    		           AND B.CAR_NO          = A.CAR_NO
	    		           AND ROWNUM           <= 1
	    		       ) AS TRANS_EQUIPMENT_TYPE
	    		  FROM (
	    		    SELECT COUNT(*) AS CNT
	    		         , SUM(DECODE(A.CHECKING_YN, 'Y', 1, 0)) AS CHECKING
	    		         , CAR_NO
	    		         , TRANS_ORD_DATE
	    		         , TRANS_ORD_SEQNO
	    		      FROM TB_YD_EXAMINATIONCHKLIST A
	    		     WHERE TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
	    		       AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
	    		       AND A.DEL_YN        = 'N'
	    		     GROUP BY CAR_NO, TRANS_ORD_DATE, TRANS_ORD_SEQNO
	    		    ) A
	    		*/
	    		
				JDTORecordSet jsCarExaminationChk = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationChk", logId, mthdNm, "검수완료체크");
				if( jsCarExaminationChk.size() > 0 ) {
		    		/**************************************************
		    		 * 2. 검수완료 전문 송신 여부 체크
		    		 *    PDA 출하 = YDDMR074, 그 외 = YDDMR036 
		    		 **************************************************/
					String sCnt       = commUtils.trim(jsCarExaminationChk.getRecord(0).getFieldString("CNT"));
					String sChk       = commUtils.trim(jsCarExaminationChk.getRecord(0).getFieldString("CHK"));
					String sCarNo     = commUtils.trim(jsCarExaminationChk.getRecord(0).getFieldString("CAR_NO"));
					String sTransType = commUtils.trim(jsCarExaminationChk.getRecord(0).getFieldString("TRANS_EQUIPMENT_TYPE"));
					
					String sJmsTcCd = "YDDMR036";
					if( "P".equals(sTransType) ) {
						sJmsTcCd = "YDDMR074";
					}
					
					
					if( "0".equals(sChk) && !"0".equals(sCnt) ) {
						sMsg = "===== 검수완료 전문 생성 =====";
			    		commUtils.printLog(logId, sMsg, "SL");
			    		
			    		/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationTcInfo */
			    		/*
			    		SELECT A.TRANS_ORD_DATE             AS TRANS_WORD_DATE
			    		     , A.TRANS_ORD_SEQNO            AS TRANS_WORD_SEQNO
			    		     , TO_CHAR(SYSDATE, 'YYYYMMDD') AS CARLD_CHK_DONE_DATE
			    		     , TO_CHAR(SYSDATE, 'HH24MISS') AS CARLD_CHK_DONE_TIME
			    		     , COUNT(*) OVER (PARTITION BY A.TRANS_ORD_DATE, A.TRANS_ORD_SEQNO) AS  GOODS_NO_CNT
			    		     , A.STL_NO                     AS GOODS_NO
			    		     , A.YD_AB_CD                   AS GOODS_CHK_AB_CD
			    		     , A.LABEL_YN                   AS LABEL_REISSUE_YN
			    		     , A.YD_CAR_UPP_LOC_CD
			    		     , B.CR_FRTOMOVE_GP
			    		 FROM TB_YD_EXAMINATIONCHKLIST A
			    		    , TB_YD_STOCK B
			    		 WHERE A.STL_NO          = B.STL_NO
			    		   AND A.TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
			    		   AND A.TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
			    		   AND A.DEL_YN          = 'N'
			    		 ORDER BY A.MOD_DDTT
			    		*/
						JDTORecordSet jsTcList = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationTcInfo", logId, mthdNm, "검수완료전문데이터");
						
			    		/**************************************************
			    		 * 3. 검수완료 전문 생성
			    		 *    PDA 출하 = YDDMR074, 그 외 = YDDMR036 
			    		 **************************************************/
						JDTORecord jrTcInfo = JDTORecordFactory.getInstance().create();
						
						//PIDEV
//						String sApplyYnPI = ydPICommDAO.ApplyYnPI("", "CCoilJspSeEJBBean => 열연코일검수완료실적수신", "APPPI0", "J", "*");
						
//						if("Y".equals(sApplyYnPI)) {							
			    			jrTcInfo.setField("MQ_TC_CD"			, "M10YDLMJ1101");
			    			jrTcInfo.setField("MQ_TC_CREATE_DDTT"	, commUtils.getDateTime14());
			    			jrTcInfo.setField("TRN_REQ_DATE"		, sTransOrdDate);
			    			jrTcInfo.setField("TRN_REQ_SEQ"			, sTransOrdSeqNo);
			    			jrTcInfo.setField("CAR_NO"				, sCarNo);
			    			jrTcInfo.setField("YD_GP"				, "J");
			    			jrTcInfo.setField("DIST_GOODS_GP"		, "H");
							if( "P".equals(sTransType) ) {
								jrTcInfo.setField("SCH_YN"			, "Y");
							} else {
								jrTcInfo.setField("SCH_YN"			, "N");
							}
			    			jrTcInfo.setField("CARLD_CHK_DONE_DATE"	, commUtils.getDate8()); // yyyyMMdd
			    			jrTcInfo.setField("CARLD_CHK_DONE_TIME"	, commUtils.getTime6()); // HHmmss
							
//						} else {
//			    			jrTcInfo.setField("JMS_TC_CD"			, sJmsTcCd);
//			    			jrTcInfo.setField("JMS_TC_CREATE_DDTT"	, commUtils.getDateTime14());
//			    			jrTcInfo.setField("TC_CODE"			    , sJmsTcCd);
//			    			jrTcInfo.setField("TC_CREATE_DDTT"	    , commUtils.getDateTime14());
//			    			jrTcInfo.setField("TRANS_WORD_DATE"		, sTransOrdDate);
//			    			jrTcInfo.setField("TRANS_WORD_SEQNO"	, sTransOrdSeqNo);
//			    			jrTcInfo.setField("CARLD_CHK_DONE_DATE"	, commUtils.getDate8()); // yyyyMMdd
//			    			jrTcInfo.setField("CARLD_CHK_DONE_TIME"	, commUtils.getTime6()); // HHmmss
//			    			jrTcInfo.setField("CAR_NO"				, sCarNo);
//						}

						JDTORecord jrTcList = JDTORecordFactory.getInstance().create();
						for (int Loop_i = 1; Loop_i <= jsTcList.size(); Loop_i++) {
			    			jsTcList.absolute(Loop_i);
			    			jrTcList = jsTcList.getRecord();
			    			
			    			if( Loop_i == 1 )
			    				jrTcInfo.setField("GOODS_NO_CNT", commUtils.nvl(jrTcList.getFieldString("GOODS_NO_CNT"), "0"));
			    			
			    			jrTcInfo.setField("GOODS_NO"		+ Loop_i, commUtils.trim(jrTcList.getFieldString("GOODS_NO")));
			    			jrTcInfo.setField("GOODS_CHK_AB_CD"	+ Loop_i, commUtils.trim(jrTcList.getFieldString("GOODS_CHK_AB_CD")));
			    			jrTcInfo.setField("LABEL_REISSUE_YN"+ Loop_i, commUtils.trim(jrTcList.getFieldString("LABEL_REISSUE_YN")));
			    			jrTcInfo.setField("GDS_CARLD_LOC"	+ Loop_i, commUtils.trim(jrTcList.getFieldString("YD_CAR_UPP_LOC_CD")));
						}

						// 마지막 CR_FRTOMOVE_GP 값
						jrTcInfo.setField("CR_FRTOMOVE_GP", commUtils.trim(jrTcList.getFieldString("CR_FRTOMOVE_GP")));
						jrRtn = commUtils.addSndData(jrRtn, jrTcInfo);

						sMsg = "===== 검수완료 전문 생성 완료! =====";
			    		commUtils.printLog(logId, sMsg, "SL");
			    		
			    		/**************************************************
			    		 * 4. 검수 데이터 종료 처리
			    		 **************************************************/
						jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
						jrParam.setField("TRANS_ORD_DATE"	, sTransOrdDate);
						jrParam.setField("TRANS_ORD_SEQNO"	, sTransOrdSeqNo);
						jrParam.setField("DEL_YN"			, "Y");

			    		/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationDelYn */
			    		/*
			    		UPDATE TB_YD_EXAMINATIONCHKLIST
			    		   SET DEL_YN          = :V_DEL_YN
			    		     , MODIFIER        = :V_MODIFIER
			    		     , MOD_DDTT        = SYSDATE
			    		 WHERE TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
			    		   AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
			    		*/
						intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationDelYn", logId, mthdNm, "검수데이터종료UPDATE");
						 
						if( intRtnVal < 1 ) {
							
							sMsg = "검수데이터 종료 처리 실패! "+ intRtnVal;
				    		commUtils.printLog(logId, sMsg, "SL");
				    		jrRtn.setField("RTN_CD"	, "0");	
				    		jrRtn.setField("RTN_MSG", sMsg);
							return jrRtn;
						}
					}
				}
			}
			
			sMsg = "검수출고를 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 검수이상제품조회 - 차상위치수정
	 * 야드관리 > 2열연 코일야드[신] > 출하이송관리 > 검수이상제품조회
	 * 강정선 2019.11.18
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 * 기존 : updateCarExamination
	 */
	public JDTORecord updCarExaminationCarUppLocCd(GridData gdReq) throws DAOException {
		String mthdNm	= "차상위치수정[CCoilJspSeEJ.updCarExaminationCarUppLocCd] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int intRtnVal			= 0;
			String sMsg				= "";
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= JDTORecordFactory.getInstance().create();
			
			String sTransOrdDate	= "";
			String sTransOrdSeqNo	= "";
			String sStlNo			= "";
			String ydCarUppLocCd	= "";
			String ydCarUppLocCdTmp	= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

	    		/**************************************************
	    		 * 1. 차상위치 수정 대상 코일 정보 체크
	    		 **************************************************/
				sTransOrdDate  = commUtils.getValue(gdReq, "TRANS_ORD_DATE"		, i);
				sTransOrdSeqNo = commUtils.getValue(gdReq, "TRANS_ORD_SEQNO"	, i);
				sStlNo		   = commUtils.getValue(gdReq, "STL_NO"				, i);
				ydCarUppLocCd  = commUtils.getValue(gdReq, "YD_CAR_UPP_LOC_CD"	, i);
				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("TRANS_ORD_DATE"	, sTransOrdDate);
				jrParam.setField("TRANS_ORD_SEQNO"	, sTransOrdSeqNo);
				jrParam.setField("STL_NO"			, sStlNo);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationUpdChk */
				/*
				SELECT STL_NO
				     , YD_CAR_UPP_LOC_CD
				     , YD_AB_CD
				  FROM TB_YD_EXAMINATIONCHKLIST
				 WHERE TRANS_ORD_DATE  = :V_TRANS_ORD_DATE
				   AND TRANS_ORD_SEQNO = :V_TRANS_ORD_SEQNO
				   AND STL_NO          = :V_STL_NO
				*/
				JDTORecordSet jsCarExInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCarExaminationUpdChk", logId, mthdNm, "코일정보조회");
				
				if( jsCarExInfo.size() < 1 ) {
					sMsg = "코일번호 ["+ sStlNo +"] 검수대상정보가 없습니다. 재조회 후 다시 진행하십시요.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				ydCarUppLocCdTmp = jsCarExInfo.getRecord(0).getFieldString("YD_CAR_UPP_LOC_CD");
				
				if( ydCarUppLocCd.equals(ydCarUppLocCdTmp) ) {
					sMsg = "코일번호 ["+ sStlNo +"] 차상위치 ["+ ydCarUppLocCdTmp +"] 가  변경하려는 위치와 동일합니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		return jrRtn;
				}
	    		/**************************************************
	    		 * 2. 차상위치 UPDATE
	    		 **************************************************/
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationCarUppLocCd */
				/*
				UPDATE TB_YD_EXAMINATIONCHKLIST
				   SET YD_CAR_UPP_LOC_CD = :V_YD_CAR_UPP_LOC_CD
				     , MODIFIER          = :V_MODIFIER
				     , MOD_DDTT          = SYSDATE
				 WHERE TRANS_ORD_DATE    = :V_TRANS_ORD_DATE
				   AND TRANS_ORD_SEQNO   = :V_TRANS_ORD_SEQNO
				   AND STL_NO            = :V_STL_NO
				*/
				jrParam.setField("YD_CAR_UPP_LOC_CD", ydCarUppLocCd);
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updCarExaminationCarUppLocCd", logId, mthdNm, "차상위치UPDATE");
				
				if( intRtnVal < 1 ) {
					sMsg = "코일번호 ["+ sStlNo +"] 차상위치 수정실패! " + intRtnVal;
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		return jrRtn;
				}
			}
			
			sMsg = "차상위치 수정을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
