	/**
	 * 준비스케줄과 준비재료삭제
	 * 김환진
	 * 2019.11.22
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
	public JDTORecord delYdPrepSch(GridData gdReq) throws DAOException {
		String mthdNm = "준비스케줄과 준비재료삭제 [CCoilJspSeEJB.delYdPrepSch]<" + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();
		
		/*
		 * 업무기준 : 1. 그리드로 넘겨진 준비스케줄/준비재료 삭제
		 */

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			
			String sMsg   = "";
			int intRtnVal = 0;

			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam	= JDTORecordFactory.getInstance().create();
			String sModifier 	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String ydPrepSchId  = "";

			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			for(int i = 0; i < rowCnt; i++ ) {
				
				ydPrepSchId = commUtils.trim(commUtils.getValue(gdReq, "YD_PREP_SCH_ID", i));

//				sMsg = "준비스케줄["+ydPrepSchId+"] 삭제 시작";
//				commUtils.printLog(logId, sMsg, "SL");
				
				jrParam.setField("YD_PREP_SCH_ID" , ydPrepSchId);
				jrParam.setField("MODIFIER"       , sModifier);
				jrParam.setField("DEL_YN"         , "Y");
				
				//준비재료 삭제처리
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delYdPrepmtlByPrepSchId1
				UPDATE TB_YD_PREPMTL
				   SET MODIFIER       = :V_MODIFIER
				     , MOD_DDTT       = SYSDATE
				     , DEL_YN         = :V_DEL_YN
				 WHERE YD_PREP_SCH_ID = :V_YD_PREP_SCH_ID
				*/
				
				intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delYdPrepmtlByPrepSchId1", logId, mthdNm, "준비재료 삭제처리");
				
				sMsg = "준비재료["+ydPrepSchId+"] 삭제 성공 - 반환값 : " + intRtnVal;
				commUtils.printLog(logId, sMsg, "SL");
				
				//준비스케줄 삭제처리
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delYdPrepsch1
				
				UPDATE TB_YD_PREPSCH
				   SET DEL_YN         = :V_DEL_YN
				     , YD_WBOOK_ID    = :V_YD_WBOOK_ID
				     , MODIFIER       = :V_MODIFIER
				     , MOD_DDTT       = SYSDATE
				 WHERE YD_PREP_SCH_ID = :V_YD_PREP_SCH_ID
				 
				 */
					
				sMsg = "준비스케줄["+ydPrepSchId+"] 삭제 성공 - 반환값 : " + intRtnVal;
				commUtils.printLog(logId, sMsg, "SL");
			}
			
			sMsg = "이상코드 수정을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn ;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	

	
	/**
	 * (제품)지포장재 반입관리 - 재반입
	 * 야드관리 > 2열연 코일야드[신] > 산적LOT관리 > 제품지포장재 반입관리
	 * 강정선 2019.11.22
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 * 기존 : updCoilGdsYdReSendGF
	 */
	public JDTORecord updCoilReSendGF(GridData gdReq) throws DAOException {
		String mthdNm	= "지포장재 재반입[CCoilJspSeEJ.updCoilReSendGF] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sMsg				= "";
			String rtnCd			= "";
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= JDTORecordFactory.getInstance().create();
			String ydGp				= "";
			String ydBayGp			= "";
			String ydSchCd			= "";
			String sStlNo			= "";
			String ydWbookId		= "";
			String sRunWbookId		= "";
			String sRunSchCD		= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

	    		/**************************************************
	    		 * 1. 지포장 동 체크
	    		 **************************************************/
				ydBayGp = commUtils.getValue(gdReq, "YD_STK_COL_GP", i).substring(1, 2);
				
				if( "B".equals(ydBayGp) || "C".equals(ydBayGp) || "E".equals(ydBayGp) || "H".equals(ydBayGp) ) {
					ydSchCd = gdReq.getParam("YD_GP") + ydBayGp + "GF01LH"; // 스케쥴코드 변경 : GF01LM -> GF01LH
				} else {
					
					sMsg = "B, C, E, H동 이외의 동은 동간이적 후 지포장을 선택해 주시기 바랍니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

				ydGp	= commUtils.trim(gdReq.getParam("YD_GP"));
				sStlNo	= commUtils.getValue(gdReq, "STL_NO", i);
				sStlNo	= commUtils.getValue(gdReq, "STL_NO", i);
				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_SCH_CD"			, ydSchCd);
				jrParam.setField("STL_SH"				, "1");
				jrParam.setField("TO_YD_STK_BED_NO"		, "");
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "S");
				jrParam.setField("YD_AIM_YD_GP"			, ydGp);
				jrParam.setField("YD_AIM_BAY_GP"		, "");
				jrParam.setField("STL_NO1"				, sStlNo);
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1");
				
	    		/**************************************************
	    		 * 2. 작업예약 호출
	    		 **************************************************/
				EJBConnector ejbConn	= new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkInsProc	= (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				rtnCd = commUtils.trim(jrWrkInsProc.getFieldString("RTN_CD"));
				if( !"1".equals(rtnCd) ) {
					
					sMsg = commUtils.trim(jrWrkInsProc.getFieldString("RTN_MSG"));
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				ydWbookId = commUtils.trim(jrWrkInsProc.getFieldString("YD_WBOOK_ID"));
				
				sMsg = "작업예약 등록 완료!! YD_WBOOK_ID["+ ydWbookId +"] YD_SCH_CD["+ ydSchCd +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				// 첫 작업예약 ID 는 스케쥴 기동 처리함.
				if( i == 0 ) {
					sRunWbookId	= ydWbookId;
					sRunSchCD	= ydSchCd;
				}
			}
			
    		/**************************************************
    		 * 3. 작업예약 스케쥴 기동
    		 **************************************************/
			if( !"".equals(sRunWbookId) ) {
				
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_WBOOK_ID"	, sRunWbookId);
				jrParam.setField("YD_SCH_CD"	, sRunSchCD);
				
				JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);
				
				rtnCd = commUtils.trim(jrRunSch.getFieldString("RTN_CD"));
				if( !"1".equals(rtnCd) ) {
					sMsg = commUtils.trim(jrRunSch.getFieldString("RTN_MSG"));
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				sMsg = "스케쥴 기동 성공!! YD_WBOOK_ID["+ sRunWbookId +"] YD_SCH_CD["+ sRunSchCD +"]";
				commUtils.printLog(logId, sMsg, "SL");
				
				jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
			}
			
			sMsg = "재반입 등록을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
