	/**
	 * 대차상태변경 수정(설비 고장/정상 설정)
	 * 야드관리 > 2열연 코일야드[신] > 대차작업관리 > 대차작업현황조회 > 대차작업 BackUp
	 * 강정선 2019.11.28
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdTcarStsSet(GridData gdReq) throws DAOException {
		String mthdNm	= "대차상태변경[CCoilJspSeEJ.updCoilYdTcarStsSet] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String rtnCd			= "";
			String sMsg				= "";
			JDTORecord jrRtn		= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam		= JDTORecordFactory.getInstance().create();
			String ydEqpId			= "";
			String ydEqpStat		= "";
			String ydEqpStatCode	= "";
			String ydEqpPauseCode	= "";
			String ydEqpStatDB		= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

				ydEqpId		= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID"	, i));
				ydEqpStat	= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_STAT", i));
				
				if( "".equals(ydEqpId) ) {
					sMsg = "설비ID 값이 없습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				if( "".equals(ydEqpStat) ) {
					sMsg = "설비상태 값이 없습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
	    		/**************************************************
	    		 * W(IDLE), B(고장), N(정상)
	    		 **************************************************/
				ydEqpStatCode	= "N";
				ydEqpPauseCode	= "0000";
				
				if( "B".equals(ydEqpStat) ) {
					ydEqpStatCode	= "B";
					ydEqpPauseCode	= "STOP";
				}

				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_EQP_ID", ydEqpId);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarEqpInfo */
				/*
				SELECT YD_EQP_ID
				     , YD_LOC_GP
				     , YD_CURR_BAY_GP
				     , YD_EQP_STAT
				     , RCPT_TCAR_USE_YN       -- 입고대차 지정
				     , RCPT_TCAR_BAY          -- 입고동
				     , RCPT_TCAR_AIM_BAY_GP   -- 목적동
				     , YD_TCAR_WRK_ABLE_BAY1
				     , YD_TCAR_WRK_ABLE_BAY2
				     , YD_TCAR_WRK_ABLE_BAY3
				     , YD_TCAR_WRK_ABLE_BAY4
				     , YD_TCAR_WRK_ABLE_BAY5
				     , YD_TCAR_WRK_ABLE_BAY6
				     , YD_TCAR_WRK_ABLE_BAY7
				     , YD_TCAR_WRK_ABLE_BAY8
				     , (SELECT MAX(YD_TCAR_SCH_ID)
				          FROM TB_YD_TCARSCH
				         WHERE YD_EQP_ID = A.YD_EQP_ID
				           AND DEL_YN    = 'N'
				           AND ROWNUM    <=1
				       ) AS YD_TCAR_SCH_ID
				  FROM TB_YD_EQP A
				 WHERE YD_EQP_ID = :V_YD_EQP_ID
				   AND DEL_YN    = 'N'
				*/
					   
				JDTORecordSet jsTCarInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarEqpInfo", logId, mthdNm, "대차정보조회");
				if( jsTCarInfo.size() < 1 ) {
					sMsg = "설비ID["+ ydEqpId +"] 설비정보 조회 Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

	    		/**************************************************
	    		 * 1. 입력값 DB값 비교
	    		 **************************************************/
				ydEqpStatDB = commUtils.trim(jsTCarInfo.getRecord(0).getFieldString("YD_EQP_STAT"));
				
				if( ydEqpStatDB.equals(ydEqpStatCode) ) {
					sMsg = "설비ID["+ ydEqpId +"] 변경된 내용이 없습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				
	    		/**************************************************
	    		 * 2. 고장/복구 Process 호출 (Y5YDL004 설비고장복구실적)
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_EQP_ID"			, ydEqpId);
				jrParam.setField("YD_EQP_STAT"			, ydEqpStatCode);
				jrParam.setField("YD_EQP_PAUSE_CODE"	, ydEqpPauseCode);
				jrParam.setField("YD_EQP_TRBL_RCVR_DT"	, commUtils.getDateTime14()); // yyyyMMddHHmmss
				
				commUtils.printLog(logId, "##### EJB Call", "SL");
				
				// return 전문 없음
				EJBConnector ejbConn= new EJBConnector("default", "CCoilL2RcvSeEJB", this);
				JDTORecord jrTcRtn	= (JDTORecord)ejbConn.trx("rcvY5YDL004", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				commUtils.printLog(logId, "##### EJB Call end", "SL");
				
				rtnCd           = commUtils.nvl(jrTcRtn.getFieldString("RTN_CD"), "0");
				String rtnMsg	= commUtils.nvl(jrTcRtn.getFieldString("RTN_MSG"), "");
	            commUtils.printLog(logId, "##### rtnCd:"+ rtnCd+"]] [[rtnMg : "+rtnMsg, "SL");
	            if (!("1".equals(rtnCd))) {
					jrRtn.setField("RTN_CD" 	, "0");	
					jrRtn.setField("RTN_MSG" 	, rtnMsg);	
					return jrRtn;
				}
				
				sMsg = "설비ID["+ ydEqpId +"] 상태["+ ydEqpStatCode +"] Y5YDL004 설비고장복구실적 호출 완료.";
	    		commUtils.printLog(logId, sMsg, "SL");
			}

			sMsg = "대차상태 설정을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

	/**
	 * 대차운전모드변경
	 * 야드관리 > 2열연 코일야드[신] > 대차작업관리 > 대차작업현황조회 > 대차작업 BackUp
	 * 강정선 2019.11.28
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdTcarStsSetCrnMode(GridData gdReq) throws DAOException {
		String mthdNm	= "대차운전모드변경[CCoilJspSeEJ.updCoilYdTcarStsSetCrnMode] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int iRtnVal			= 0;
			String rtnCd		= "";
			String sMsg			= "";
			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam	= JDTORecordFactory.getInstance().create();
			String ydEqpId		= "";
			String ydEqpWrkMode	= "";
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

				ydEqpId		= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID"		, i));
				ydEqpWrkMode= commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_WRK_MODE", i));
				
				if( "".equals(ydEqpId) ) {
					sMsg = "설비ID 값이 없습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
	    		/**************************************************
	    		 * 1. 설비운전모드 Process 호출 안함. DB UPDATE 처리..
	    		 *    사유 : YD_EQP_WRK_MODE 크레인과 대차 상태값 다름.
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_EQP_ID"		, ydEqpId);
				jrParam.setField("YD_EQP_WRK_MODE"	, ydEqpWrkMode);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarWrkMode */
				/*
				UPDATE TB_YD_EQP
				   SET YD_EQP_WRK_MODE = :V_YD_EQP_WRK_MODE
				     , MOD_DDTT        = SYSDATE
				     , MODIFIER        = :V_MODIFIER
				 WHERE YD_EQP_ID       = :V_YD_EQP_ID
				*/
				iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarWrkMode", logId, mthdNm, "대차운전모드UPDATE");
				if ( iRtnVal < 1 ) {
					
					sMsg = "대차ID["+ ydEqpId +"] 운전모드["+ ydEqpWrkMode +"] UPDATE Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");	
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}

			sMsg = "대차 운전모드 설정을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 대차상태초기화
	 * 야드관리 > 2열연 코일야드[신] > 대차작업관리 > 대차작업현황조회 > 대차작업 BackUp
	 * 강정선 2019.11.28
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCoilYdTcarClear(GridData gdReq) throws DAOException {
		String mthdNm	= "대차상태초기화[CCoilJspSeEJ.updCoilYdTcarClear] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			int iRtnVal			= 0;
			String sMsg			= "";
			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();
			JDTORecord jrParam	= JDTORecordFactory.getInstance().create();
			String ydGp			= commUtils.trim(gdReq.getParam("YD_GP"));
			String ydCurrBayGp	= "";
			String ydEqpId		= "";
			String ydTCarSchId	= "";
			String sStlNo		= "";
			String ydStopLoc	= "";

			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for (int i = 0; i < rowCnt; i++) {

				ydEqpId = commUtils.trim(commUtils.getValue(gdReq, "YD_EQP_ID", i));

				if( "".equals(ydEqpId) ) {
					sMsg = "설비ID 값이 없습니다.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

	    		/**************************************************
	    		 * 1. 대차 정보, 스케쥴 체크
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_EQP_ID"		, ydEqpId);
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarEqpInfo */
				/*
				SELECT YD_EQP_ID
				     , YD_LOC_GP
				     , YD_CURR_BAY_GP
				     , YD_EQP_STAT
				     , RCPT_TCAR_USE_YN       -- 입고대차 지정
				     , RCPT_TCAR_BAY          -- 입고동
				     , RCPT_TCAR_AIM_BAY_GP   -- 목적동
				     , YD_TCAR_WRK_ABLE_BAY1
				     , YD_TCAR_WRK_ABLE_BAY2
				     , YD_TCAR_WRK_ABLE_BAY3
				     , YD_TCAR_WRK_ABLE_BAY4
				     , YD_TCAR_WRK_ABLE_BAY5
				     , YD_TCAR_WRK_ABLE_BAY6
				     , YD_TCAR_WRK_ABLE_BAY7
				     , YD_TCAR_WRK_ABLE_BAY8
				     , (SELECT MAX(YD_TCAR_SCH_ID)
				          FROM TB_YD_TCARSCH
				         WHERE YD_EQP_ID = A.YD_EQP_ID
				           AND DEL_YN    = 'N'
				           AND ROWNUM    <=1
				       ) AS YD_TCAR_SCH_ID
				  FROM TB_YD_EQP A
				 WHERE YD_EQP_ID = :V_YD_EQP_ID
				   AND DEL_YN    = 'N'
				*/
				JDTORecordSet jsTCarInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTCarEqpInfo", logId, mthdNm, "대차정보조회");
				if( jsTCarInfo.size() < 1 ) {
					sMsg = "설비ID["+ ydEqpId +"] 설비정보 조회 Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}

				ydTCarSchId = commUtils.trim(jsTCarInfo.getRecord(0).getFieldString("YD_TCAR_SCH_ID"));

				// 현재동 BED, LYR 초기화
				ydCurrBayGp = commUtils.trim(jsTCarInfo.getRecord(0).getFieldString("YD_CURR_BAY_GP"));

	    		/**************************************************
	    		 * 2. 대차 스케쥴 취소
	    		 **************************************************/
				if( !"".equals(ydTCarSchId) ) {

					jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
					jrParam.setField("YD_TCAR_SCH_ID"		, ydTCarSchId);

					/*com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTEqpInfo*/
					/*
					SELECT A.YD_TCAR_SCH_ID
					     , B.STL_NO
					     , (SELECT COUNT(*)
						      FROM TB_YD_CRNSCH A1
							     , TB_YD_CRNWRKMTL B1
					  	     WHERE A1.YD_CRN_SCH_ID = B1.YD_CRN_SCH_ID
							   AND A1.DEL_YN = 'N'
							   AND B1.DEL_YN = 'N'
							   AND B1.STL_NO = B.STL_NO ) SCH_CNT
					  FROM TB_YD_TCARSCH A
					     , TB_YD_TCARFTMVMTL B
					 WHERE A.YD_TCAR_SCH_ID = B.YD_TCAR_SCH_ID(+)
					   AND A.YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
					*/
					JDTORecordSet jsTCarSchInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getTEqpInfo", logId, mthdNm, "대차스케쥴재료조회");
					if( jsTCarSchInfo.size() < 1 ) {
						sMsg = "설비ID["+ ydEqpId +"] 스케쥴ID["+ ydTCarSchId +"] 조회 Error.";
			    		commUtils.printLog(logId, sMsg, "SL");
			    		jrRtn.setField("RTN_CD"	, "0");
			    		jrRtn.setField("RTN_MSG", sMsg);
						return jrRtn;
					}

					/**************************************************
		    		 * 2-1. 스케쥴 재료 취소
		    		 **************************************************/
					for(int x=0; x<jsTCarSchInfo.size(); x++) {

						sStlNo = commUtils.trim(jsTCarSchInfo.getRecord(x).getFieldString("STL_NO"));

						jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
						jrParam.setField("YD_TCAR_SCH_ID"	, ydTCarSchId);
						jrParam.setField("STL_NO"			, sStlNo);
						/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delTCarFtmvMtlByStlNo */
						/*
						UPDATE TB_YD_TCARFTMVMTL
						   SET DEL_YN         = 'Y'
						     , MOD_DDTT       = SYSDATE
						     , MODIFIER       = :V_MODIFIER
						 WHERE YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
						   AND STL_NO         = :V_STL_NO
						*/
						iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delTCarFtmvMtlByStlNo", logId, mthdNm, "대차스케쥴재료삭제");
						if ( iRtnVal > 1 ) {

							sMsg = "[대차 정보 삭제시 이상 발생 Error!! Code : " + iRtnVal;
				    		commUtils.printLog(logId, sMsg, "SL");
				    		jrRtn.setField("RTN_CD"	, "0");
				    		jrRtn.setField("RTN_MSG", sMsg);
							return jrRtn;
						}
					}

		    		/**************************************************
		    		 * 2-2. 대차 스케쥴 초기화
		    		 * 20.01.20 강정선 : 기존 TB_YD_TCARSCH 스케줄 종료처리 후
		    		 *                 신규 YD_TCAR_SCH_ID 생성
		    		 **************************************************/
					jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
					jrParam.setField("YD_TCAR_SCH_ID"	, ydTCarSchId);
					jrParam.setField("DEL_YN"			, "Y");

					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarSchDelYnByTCarSchId */
					/*
					UPDATE TB_YD_TCARSCH
					   SET DEL_YN         = :V_DEL_YN
					     , MOD_DDTT       = SYSDATE
					     , MODIFIER       = :V_MODIFIER
					 WHERE YD_TCAR_SCH_ID = :V_YD_TCAR_SCH_ID
					*/
					iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarSchDelYnByTCarSchId", logId, mthdNm, "대차스케쥴종료처리");
					if ( iRtnVal < 1 ) {

						sMsg = "대차스케쥴 종료 UPDATE Error!! Code : " + iRtnVal;
			    		commUtils.printLog(logId, sMsg, "SL");
			    		jrRtn.setField("RTN_CD"	, "0");
			    		jrRtn.setField("RTN_MSG", sMsg);
						return jrRtn;
					}

					// 신규대차 스케줄 생성
					String sNewTCarShcId = coilDao.getSeqId(logId, mthdNm, "TcarSch");
					ydStopLoc = ydGp + ydCurrBayGp + ydEqpId.substring(2, 6);

					jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
					jrParam.setField("YD_TCAR_SCH_ID"		, sNewTCarShcId);
					jrParam.setField("YD_EQP_ID"			, ydEqpId);
					jrParam.setField("YD_EQP_WRK_STAT"		, "U");
					jrParam.setField("YD_CARLD_SCH_REQ_GP"	, "6");
					jrParam.setField("YD_CARLD_STOP_LOC"	, ydStopLoc);
					jrParam.setField("YD_CARUD_SCH_REQ_GP"	, "3");
					jrParam.setField("YD_CARUD_STOP_LOC"	, ydStopLoc);
					jrParam.setField("YD_CAR_PROG_STAT"		, "0");
					jrParam.setField("DEL_YN"				, "N");

					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insClearTCarSch */
					/*
					INSERT INTO TB_YD_TCARSCH
					    ( YD_TCAR_SCH_ID
					    , YD_EQP_ID
					    , YD_EQP_WRK_STAT
					    , YD_CARLD_SCH_REQ_GP
					    , YD_CARLD_STOP_LOC
					    , YD_CARUD_SCH_REQ_GP
					    , YD_CARUD_STOP_LOC
					    , YD_CAR_PROG_STAT
					    , DEL_YN
					    , REGISTER
					    , REG_DDTT
					    , MODIFIER
					    , MOD_DDTT
					    )
					VALUE
					    ( :V_YD_TCAR_SCH_ID
					    , :V_YD_EQP_ID
					    , :V_YD_EQP_WRK_STAT
					    , :V_YD_CARLD_SCH_REQ_GP
					    , :V_YD_CARLD_STOP_LOC
					    , :V_YD_CARUD_SCH_REQ_GP
					    , :V_YD_CARUD_STOP_LOC
					    , :V_YD_CAR_PROG_STAT
					    , :V_DEL_YN
					    , :V_MODIFIER
					    , SYSDATE
					    , :V_MODIFIER
					    , SYSDATE
					    )
					*/
					iRtnVal = commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insClearTCarSch", logId, mthdNm, "신규대차스케줄생성");

					if ( iRtnVal < 1 ) {

						sMsg = "신규대차스케줄 생성 Error!! Code : " + iRtnVal;
			    		commUtils.printLog(logId, sMsg, "SL");
			    		jrRtn.setField("RTN_CD"	, "0");
			    		jrRtn.setField("RTN_MSG", sMsg);
						return jrRtn;
					}
				}

	    		/**************************************************
	    		 * 3. 대차 BED 상태값 초기화
	    		 *    현재동 L(활성화) 이 외 C(비활성화)
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_GP"			, ydGp);				// 대차 저장위치 BED 는 J 로 동일
				jrParam.setField("YD_CURR_BAY_GP"	, ydCurrBayGp);			// 현재동
				jrParam.setField("YD_EQP_ID"		, ydEqpId.substring(2));// JXTC01 -> TC01
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarMgtBedActStat */
				/*
				UPDATE TB_YD_STKBED
				   SET YD_STK_BED_ACT_STAT = DECODE(SubSTR(YD_STK_COL_GP, 0, 6)
				                                  , :V_YD_GP || :V_YD_CURR_BAY_GP || :V_YD_EQP_ID, 'L'
				                                  , 'C')
				     , MOD_DDTT = SYSDATE
				     , MODIFIER = :V_MODIFIER
				 WHERE SubSTR(YD_STK_COL_GP, 1, 1) = 'J'
				   AND SubSTR(YD_STK_COL_GP, 3, 4) = :V_YD_EQP_ID
				   AND DEL_YN = 'N'
				*/
				iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarMgtBedActStat", logId, mthdNm, "대차BED상태UPDATE");
				if ( iRtnVal < 1 ) {

					sMsg = "대차ID["+ ydEqpId +"] BED 활성상태 UPDATE Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
	    		/**************************************************
	    		 * 4. 대차 LYR 상태값 초기화
	    		 *    제품대차 #1, #2 코일있으면 현상태 그대로
                 *    소재대차 코일번호, 적치상태, 재료상태 초기화
	    		 **************************************************/
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarMgtLyrActStat
				UPDATE TB_YD_STKLYR
				   SET YD_STK_LYR_ACT_STAT = CASE WHEN STL_NO IS NOT NULL AND SUBSTR(YD_STK_COL_GP, 3, 4) IN ('TC01', 'TC02')
				                                  THEN YD_STK_LYR_ACT_STAT
				                                  WHEN SUBSTR(YD_STK_COL_GP, 0, 6) = :V_YD_GP || :V_YD_CURR_BAY_GP || :V_YD_EQP_ID
				                                  THEN 'E'
				                                  ELSE 'C'
				       END
				     , YD_STK_LYR_MTL_STAT = CASE WHEN STL_NO IS NOT NULL AND SUBSTR(YD_STK_COL_GP, 3, 4) IN ('TC01', 'TC02')
				                                  THEN YD_STK_LYR_MTL_STAT
				                                  ELSE 'E'
				       END
				     , STL_NO              = CASE WHEN STL_NO IS NOT NULL AND SUBSTR(YD_STK_COL_GP, 3, 4) IN ('TC01', 'TC02')
				                                  THEN STL_NO
				                                  ELSE NULL
				       END
				     , MOD_DDTT = SYSDATE
				     , MODIFIER = :V_MODIFIER
				 WHERE SubSTR(YD_STK_COL_GP, 1, 1) = 'J'
				   AND SubSTR(YD_STK_COL_GP, 3, 4) = :V_YD_EQP_ID
				   AND DEL_YN = 'N'
				*/
				iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarMgtLyrActStat", logId, mthdNm, "대차적치단상태UPDATE");
				if ( iRtnVal < 1 ) {

					sMsg = "대차ID["+ ydEqpId +"] 적치단 활성상태 UPDATE Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
	    		/**************************************************
	    		 * 5. 대차 도착상태(A)로 UPDATE
	    		 **************************************************/
				jrParam = commUtils.getParam(logId, mthdNm, gdReq.getParam("userid"));
				jrParam.setField("YD_EQP_ID"	, ydEqpId);
				jrParam.setField("YD_EQP_STAT"	, "A");

				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarYdEqpStat */
				/*
				UPDATE TB_YD_EQP
				   SET YD_EQP_STAT = :V_YD_EQP_STAT
				     , MOD_DDTT    = SYSDATE
				     , MODIFIER    = :V_MODIFIER
				 WHERE YD_EQP_ID   = :V_YD_EQP_ID
				*/
				iRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updTCarYdEqpStat", logId, mthdNm, "대차설비상태UPDATE");
				if ( iRtnVal < 1 ) {

					sMsg = "대차ID["+ ydEqpId +"] 설비상태 UPDATE Error.";
		    		commUtils.printLog(logId, sMsg, "SL");
		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			}

			sMsg = "대차 초기화를 설정을 정상적으로 처리하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

