				commUtils.printLog(logId, "★  야드저장위치좌표관리 체크 szToYRule="  +sToYRule  , "SL");
				commUtils.printLog(logId, "★  야드저장위치좌표관리 체크 szToZRule="  +sToZRule  , "SL");
