					JDTORecordSet jsOutSet1 = commDao.select(jrRtnParam2, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdStkbedLyr", logId, mthdNm, "신규권하위치 좌표 조회");
					
