			String rtnMsg		= "";
			String crnSnd	   	= "";
			String ydCrnSchId	= "";
			String ydWrkProgStat= "";
			String ydCrnSchCd	= "";
			
			String ydWbookId   	= "";
			String ydDong      	= "";
