	/**
	 * 입동지시 SMS 전송
	 * 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  jrParam
	 * @return JDTORecordSet
	 * @throws DAOException
	 */
	public JDTORecord procBayInWoSmsSend(GridData gdReq) throws DAOException {
		String mthdNm = "입동지시 SMS 전송[CCoilJspSeEJB.procBayInWoSmsSend]  < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			
			String sTelNo      = ""; //전화번호
			String sCarNo      = ""; //차량번호
			String ydCarpntCd  = ""; //포인트코드
			String sMsg        = "";
			
			String sModifier   = gdReq.getParam("userid"); //수정자(Backup Only)
			String sFlag       = gdReq.getParam("SMS_FLAG"); //BAYIN, DELAY
			String sDelyRsn    = gdReq.getParam("DELY_RSN"); //작업지연사유
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			
			JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			//입동sms전송
			if ("BAYIN".equals(sFlag)) {
				for (int i = 0; i < rowCnt; i++ ) {
					
					sTelNo      = commUtils.trim(commUtils.getValue(gdReq, "TEL_NUMBER"  , i)); //전화번호  
					sCarNo      = commUtils.trim(commUtils.getValue(gdReq, "CAR_NO"      , i)); //차량번호  
					ydCarpntCd  = commUtils.trim(commUtils.getValue(gdReq, "YD_CARPNT_CD", i)); //포인트코드 
					 
					sMsg        = "["+ sCarNo + "]차량 [" + ydCarpntCd + "]포인트로 입동하세요!!";
					
					if ("".equals(sTelNo)) {
						continue;
					}
					
					JDTORecord recPara1 = JDTORecordFactory.getInstance().create();
					//recPara1.setField("FROM_PHONE_NO", "0416804879"); //2열연 출하반 연락처
					//recPara1.setField("TO_PHONE_NO"  , sTelNo      ); // 010-XXXX-XXXX
					//recPara1.setField("TO_CONTENT"   , sMsg        );
					//CCommUtils.updSmsMsgSend(recPara1); // SMS 송신 
					
					// 2025.09.29 SMS송신 -> 카카오톡 전환
                    MessageSenderTalk    sender = new MessageSenderTalk();		
                    String subJect = "입동지시";
                    recPara1.setField("PHONE_NUM", sTelNo);
                    recPara1.setField("TMPL_CD", new String("CM1"));
                    recPara1.setField("SND_MSG", new String("[현대제철 공지사항]\n" + sMsg));
                    recPara1.setField("SUBJECT", new String(subJect));
                    recPara1.setField("SMS_SND_NUM", new String("0416804879"));
                    recPara1.setField("RECV_ID","1525771");
                    recPara1.setField("GROUP_ID","KaKao");
                    recPara1.setField("PROGRAM_ID","udttalk");
					sender.sendTalk(recPara1);
					
					jrParam.setField("CAR_NO"		, sCarNo);
					jrParam.setField("YD_MSG_NM"	, sMsg  );

					/*
					UPDATE TB_YD_CARSCH
					   SET YD_MSG_NM = '['||TO_CHAR(SYSDATE, 'HH24:MI:SS') || ']' ||:V_YD_MSG_NM ||' ['||:V_MODIFIER||']'
					 WHERE CAR_NO = :V_CAR_NO
					   AND DEL_YN = 'N'
					 */
					commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilCarMvSeEJB.updYdMsgNm", logId, mthdNm, "SMS전송시각 저장");
					sMsg = "입동지시SMS 정상적으로 전송하였습니다.";
				}
			}

			//크레인작업지연 sms 전송
			String sSeq        = "";
			String ydStkColGp  = "";
			String ydBayGp     = "";
			String sPassGp     = "";
			String sDelyRsnDtl = "";
			
			if ("A".equals(sDelyRsn)) {
				sDelyRsnDtl = "설비고장";
			} else if ("B".equals(sDelyRsn)) {
				sDelyRsnDtl = "비계획 긴급보수";
			} else {
				sDelyRsnDtl = "시스템 오류";
			}
			
			if ("DELAY".equals(sFlag)) {
				for (int i = 0; i < rowCnt; i++ ) {
					ydStkColGp = commUtils.trim(commUtils.getValue(gdReq, "YD_STK_COL_GP", i)); //상차도
					ydBayGp    = ydStkColGp.substring(1, 2);
					
					if ("4".equals(ydStkColGp.substring(5, 6)) || "5".equals(ydStkColGp.substring(5, 6))) {
						sPassGp = "2";
					} else if ("3".equals(ydStkColGp.substring(5, 6))) {
						sPassGp = "3";
					} else {
						sPassGp = "1";
					}
					
					for (int j = 0; j < 21; j++ ) {
						
						sSeq = j + "";
						if (j == 0) {
							sSeq = "";
						}
						
						sTelNo      = commUtils.trim(commUtils.getValue(gdReq, "TEL_NUMBER" + sSeq  , i)); //전화번호  

						sMsg        = "현재 2열연 " + ydBayGp + "동 " + sPassGp + "통로 (" + sDelyRsnDtl + ")로 인하여 지연 발생중입니다. ";
						
						commUtils.printLog(logId, sSeq+"★★★★"+sTelNo, "SL");
						
						if ("".equals(sTelNo)) {
							continue;
						}
						
						JDTORecord recPara1 = JDTORecordFactory.getInstance().create();
						//recPara1.setField("FROM_PHONE_NO", "0416804879"); //2열연 출하반 연락처
						//recPara1.setField("TO_PHONE_NO"  , sTelNo      ); // 010-XXXX-XXXX
						//recPara1.setField("TO_CONTENT"   , sMsg        );
						//CCommUtils.updSmsMsgSend(recPara1); // SMS 송신 
						
						// 2025.09.29 SMS송신 -> 카카오톡 전환
	                    MessageSenderTalk    sender = new MessageSenderTalk();		
	                    String subJect = "크레인작업지연";
	                    recPara1.setField("PHONE_NUM", sTelNo);
	                    recPara1.setField("TMPL_CD", new String("CM1"));
	                    recPara1.setField("SND_MSG", new String("[현대제철 공지사항]\n" + sMsg));
	                    recPara1.setField("SUBJECT", new String(subJect));
	                    recPara1.setField("SMS_SND_NUM", new String("0416804879"));
	                    recPara1.setField("RECV_ID","1525771");
	                    recPara1.setField("GROUP_ID","KaKao");
	                    recPara1.setField("PROGRAM_ID","udttalk");
						sender.sendTalk(recPara1);

						sMsg = "작업지연SMS 정상적으로 전송하였습니다.";
					}
				} //end for
			}
			
			commUtils.printLog(logId, sMsg, "SL");
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");
			
			return jrRtn;
			
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	
	/**
	 * GridData -  권하위치변경가능 위치 =============진행중
	 * 염용선
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return JDTORecordSet
	 * @throws DAOException
	 */
	public GridData getDownLocChange(GridData gdReq) throws DAOException {
		String mthdNm = "조회[CCoilJspSeEJB.getDownLocChange] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm ,"S+");

			GridData gdRet = new GridData();
			JDTORecordSet	jsRtn = JDTORecordFactory.getInstance().createRecordSet("Temp");

			JDTORecord jrParam	= JDTORecordFactory.getInstance().create();

			String ydCrnSchId	= commUtils.trim(gdReq.getParam("YD_CRN_SCH_ID"));
			String ydLocGp		= commUtils.trim(gdReq.getParam("YD_LOC_GP"));
			String sStlNo		= commUtils.trim(gdReq.getParam("STL_NO"));			//크레인작업재료
			String ydSchCd		= commUtils.trim(gdReq.getParam("YD_SCH_CD"));		    //스케쥴 코드
			String ydStkColGp	= commUtils.trim(gdReq.getParam("YD_STK_COL_GP"));		//열
			String ydStkBedNo	= commUtils.trim(gdReq.getParam("YD_STK_BED_NO"));		//BED
			String ydStkLyrNo	= commUtils.trim(gdReq.getParam("YD_STK_LYR_NO"));		//단
			String ydMainChk	= commUtils.trim(gdReq.getParam("MAIN_CHK"));
			String sSpanCol		= commUtils.trim(gdReq.getParam("SPAN_COL"));
			String sRtnBedDan	= "";  //TO위치
	    	String sMsg			= "";

			jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
			jrParam.setField("YD_LOC_GP"		, ydLocGp);

			if ("".equals(sSpanCol)) {
				sMsg = "입력된 스판/열 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
				gdRet.setStatus("false");
				gdRet.setMessage(sMsg);
				return gdRet;
			}

			if (sSpanCol.length() >= 4) {
				sSpanCol = sSpanCol.substring(0, 4);
			}

			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYmCrnSchDel
			SELECT A.YD_CRN_SCH_ID
			     , A.YD_WBOOK_ID
			     , B.STL_NO
			     , A.YD_EQP_ID
			     , A.YD_SCH_CD AS SEARCH_YD
			  FROM TB_YD_CRNSCH A
			     , TB_YD_CRNWRKMTL B
			 WHERE A.DEL_YN = 'N'
			   AND B.DEL_YN = 'N'
			   AND A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID
			   AND A.YD_CRN_SCH_ID = :V_YD_CRN_SCH_ID
			*/
			JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYmCrnSchDel", logId, mthdNm, "크레인 스케쥴 조회");

			if(jsCrnSch.size() < 1 ) {
				sMsg = "크레인 스케쥴 정보가 없습니다.";
				commUtils.printLog(logId, sMsg, "SL");
				
				gdRet.setStatus("false");
				gdRet.setMessage(sMsg);
				return gdRet;
			}

			String ydEqpId = commUtils.trim(jsCrnSch.getRecord(0).getFieldString("YD_EQP_ID"));

			commUtils.printLog(logId, "STL_NO["+ sStlNo +"] YD_SCH_CD_ID["+ ydCrnSchId +"] YD_SCH_CD["+ ydSchCd +"] SPAN_COL["+ sSpanCol +"] YD_EQP_ID["+ ydEqpId +"]", "SL");
			
        	jrParam = commUtils.getParam(logId, mthdNm, logId);
			jrParam.setField("STL_NO"			, sStlNo);
			jrParam.setField("YD_SCH_CD"		, ydSchCd);
			jrParam.setField("YD_TO_LOC_GUIDE"	, ydSchCd.substring(0, 2)+sSpanCol);
			jrParam.setField("YD_CRN_SCH_ID"	, ydCrnSchId);
			jrParam.setField("YD_EQP_ID"	    , ydEqpId);

			JDTORecordSet jsUserRslt = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getYdToLocUser", logId, mthdNm, "사용자TOSQL 베드 조회");
			if (jsUserRslt.size() <= 0) {
				sMsg = "적치가능한 베드 검색 실패 ";
				commUtils.printLog(logId, sMsg, "SL");

				gdRet.setStatus("false");
				gdRet.setMessage(sMsg);
				return gdRet;
			}

			//----------------------------------------------------------------------------------------------------------------------
			//	적재가능 위치 SCH RULL 검색
			//----------------------------------------------------------------------------------------------------------------------

			EJBConnector sndConnD = new EJBConnector("default", "CCoilSchSeEJB", this);
			JDTORecord jrRuleConst = (JDTORecord)sndConnD.trx("toLocRuleConst", new Class[] { String.class,String.class }, new Object[] { logId, mthdNm });

			//----------------------------------------------------------------------------------------------------------------------
			//	적재가능 위치 LOGIC 적용여부 검색
			//----------------------------------------------------------------------------------------------------------------------

			sndConnD = new EJBConnector("default", "CCoilSchSeEJB", this);
			JDTORecord jrLocRuleApply = (JDTORecord)sndConnD.trx("toLocRuleApply", new Class[] { String.class,String.class }, new Object[] { logId, mthdNm });

			commUtils.printParam(logId, jrLocRuleApply);

			// 적치 가능 check
			JDTORecord jrLocAbleRtn = JDTORecordFactory.getInstance().create();
			JDTORecord jrUserRslt   = JDTORecordFactory.getInstance().create();
			String sLocAbleRtn 	 = "";
			String sLocAbleRtnMsg 	 = "";
			String sLocAbleRtnChk 	 = "";
			String sLocAbleRtnMath 	 = "";
			String sGrade 		 = "9";

			for (int i = 1; i <= jsUserRslt.size(); i++) {

				jsUserRslt.absolute(i);
				jrUserRslt  = jsUserRslt.getRecord();

				sGrade 		= commUtils.nvl (jrUserRslt.getFieldString("GRADE"),"9");
				ydStkColGp 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_COL_GP"  ));
				ydStkBedNo 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_BED_NO"  ));
				ydStkLyrNo 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_LYR_NO"  ));

				/**************************************
				 *         적치 가능 check
		   		 **************************************/

				sndConnD = new EJBConnector("default", "CCoilSchSeEJB", this);
				jrLocAbleRtn = (JDTORecord)sndConnD.trx("toLocAbleCheck", new Class[] { String.class,String.class,JDTORecord.class ,JDTORecord.class,JDTORecord.class }, new Object[] { logId, mthdNm, jrUserRslt, jrRuleConst, jrLocRuleApply });

				sLocAbleRtn    = commUtils.trim(jrLocAbleRtn.getFieldString("LOC_ABLE_RTN")) ;
				sLocAbleRtnMsg  = commUtils.trim(jrLocAbleRtn.getFieldString("LOC_ABLE_CONTENTS")) ;
				sLocAbleRtnMath = commUtils.trim(jrLocAbleRtn.getFieldString("LOC_CHK_MATH")) ;
				sLocAbleRtnChk  = commUtils.trim(jrLocAbleRtn.getFieldString("LOC_ABLE_CHK")) ;
			    
			    /*
				 * AT0000_HOT코일 체크 안함 수입 권하위치선정 일때  YYS 202202
				 * */
//				String sAPP004_YN = coilDao.ApplyYn(logId, mthdNm, "APP001", "J", "004");
//				if("Y".equals(sAPP004_YN)){
//					sLocAbleRtnChk = "Y";
//				}else{
//					sLocAbleRtnChk = "N";
//				}
				//적치가능
				JDTORecord 		jrRtn = JDTORecordFactory.getInstance().create();
				if ("1".equals(sLocAbleRtn)) {
					sMsg = ydStkColGp + ydStkBedNo + ydStkLyrNo+"  적치가능 위치평점:"+ sGrade;
					commUtils.printLog(logId, sMsg, "SL");
				    //적치가능
					sRtnBedDan = ydStkColGp.substring(1) +ydStkLyrNo.substring(2)+ ydStkBedNo ;
					
					jrRtn.setField("SEARCH"		, ydMainChk);
					jrRtn.setField("GRADE"		, sGrade);
					jrRtn.setField("SEARCH_LOC"	, sRtnBedDan);
					jrRtn.setField("SEARCH_MSG"	, "변경가능");
					jsRtn.addRecord(jrRtn);
				}else{
					sMsg = ydStkColGp + ydStkBedNo + ydStkLyrNo+"  적치가능 위치평점:"+ sGrade;
					
					commUtils.printLog(logId, sMsg, "SL");
					if ("Y".equals(sLocAbleRtnChk)) { // 화면에서 보여질지 판단하는 플래그
						//적치가능
						sRtnBedDan = ydStkColGp.substring(1) +ydStkLyrNo.substring(2)+ ydStkBedNo ;
						jrRtn.setField("SEARCH"		, ydMainChk);
						jrRtn.setField("GRADE"		, sGrade);
						jrRtn.setField("SEARCH_LOC"	, sRtnBedDan);
						jrRtn.setField("SEARCH_MSG"	, sLocAbleRtnMath);
						
						jsRtn.addRecord(jrRtn);

					}
				}
			}

			/********************************************
			 * 소재 1단 재검색 :
			 ********************************************/
			String sAPP901 = coilDao.ApplyYn(logId, mthdNm, "APP901", "J", "*");
			commUtils.printLog(logId, "TO위치 RULE상수[신sAPP901] : " + sAPP901, "SL");

    		if ("Y".equals(sAPP901)) {
    			commUtils.printLog(logId, "jsRtn.size() : "+ jsRtn.size() +" ydSchCd:"+ ydSchCd.substring(7, 8), "SL");

    			if( jsRtn.size() < 1 && "H".equals(ydSchCd.substring(7, 8)) ) {
    				commUtils.printLog(logId, "▼▼▼▼▼▼▼▼▼▼ 소재 1단  재검색 ▼▼▼▼▼▼▼▼▼▼", "SL");

					//소재 1단일 경우 재검색
					jrLocRuleApply.setField("WID_DIA_CHK_YN", "N");

    				for (int i = 1; i <= jsUserRslt.size(); i++) {

    					jsUserRslt.absolute(i);
    					jrUserRslt  = jsUserRslt.getRecord();

    					sGrade 		= commUtils.nvl (jrUserRslt.getFieldString("GRADE"),"9");
    					ydStkColGp 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_COL_GP"  ));
    					ydStkBedNo 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_BED_NO"  ));
    					ydStkLyrNo 	= commUtils.trim(jrUserRslt.getFieldString("TAG_YD_STK_LYR_NO"  ));

    					// 1단만 재검색
    					if( !"001".equals(ydStkLyrNo) ) continue;

    					/**************************************
    					 *         적치 가능 check
    			   		 **************************************/
    					sndConnD = new EJBConnector("default", "CCoilSchSeEJB", this);
    					jrLocAbleRtn = (JDTORecord)sndConnD.trx("toLocAbleCheck", new Class[] { String.class,String.class,JDTORecord.class ,JDTORecord.class,JDTORecord.class }, new Object[] { logId, mthdNm, jrUserRslt, jrRuleConst, jrLocRuleApply });

    					sLocAbleRtn    = commUtils.trim(jrLocAbleRtn.getFieldString("LOC_ABLE_RTN")) ;

    					if ("1".equals(sLocAbleRtn)) {
    						sMsg = ydStkColGp + ydStkBedNo + ydStkLyrNo+"  적치가능 위치평점:"+ sGrade;
    						commUtils.printLog(logId, sMsg, "SL");
    					    //적치가능
    						sRtnBedDan = ydStkColGp.substring(1) +ydStkLyrNo.substring(2)+ ydStkBedNo ;
    						//적치가능
    						JDTORecord 		jrRtn = JDTORecordFactory.getInstance().create();
    						jrRtn.setField("SEARCH"		, ydMainChk);
    						jrRtn.setField("GRADE"		, sGrade);
    						jrRtn.setField("SEARCH_LOC"	, sRtnBedDan);
    						jsRtn.addRecord(jrRtn);
    					}
    				}
    				commUtils.printLog(logId, "▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲", "SL");
    			}
    		}

			gdRet = CmUtil.genGridData(gdReq, jsRtn);

			commUtils.printLog(logId, gdRet.toString(), "S-");

			gdRet.addParam("RESULT", "ok");	// 이 값으로 화면에서 상태판단
			gdRet.setStatus("true");
			gdRet.setMessage("정상 처리 됐습니다.");
			return gdRet;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}

    /**
     * 설비보급스케쥴 기동/금지
     * 야드관리 > 2열연 소재 코일야드[신] > 설비입측관리 > SPM/HFL입측관리
     * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
     * @param  GridData
     * @return JDTORecord
     * @throws DAOException
     */
    public JDTORecord updLineInSchProhExn(GridData gdReq) throws DAOException {
        String mthdNm   = "설비보급스케쥴 기동/금지[CCoilJspSeEJB.updLineInSchProhExn]" + gdReq.getNavigateValue();
        String logId    = gdReq.getIPAddress();

        try {
            commUtils.printLog(logId, mthdNm, "S+");

            JDTORecord jrRtn    = JDTORecordFactory.getInstance().create();

            int intRtnVal       = 0;
            String sMsg         = "";
            String userid       = commUtils.trim(gdReq.getParam("YD_USER_ID"));
            String ydSchCd      = commUtils.trim(gdReq.getParam("YD_SCH_CD"));
            String ydSchProhExn = commUtils.trim(gdReq.getParam("YD_SCH_PROH_EXN"));
            String sParamMsg    = commUtils.trim(gdReq.getParam("PARAM_MSG"));

            JDTORecord jrParam = commUtils.getParam(logId, mthdNm, userid);
            jrParam.setField("YD_SCH_CD"		, ydSchCd);
            jrParam.setField("YD_SCH_PROH_EXN"	, ydSchProhExn);

            sMsg = "스케쥴코드["+ ydSchCd +"] 스케쥴금지유무["+ ydSchProhExn +"]";
            commUtils.printLog(logId, sMsg, "SL");

			/*******************************************************
			 * F동 #2HFL <-> 결사장 사용 전환시 저장위치 코일 적치유무 체크
			 *******************************************************/
            if( "JFFE01UH".equals(ydSchCd) ) {
            	JDTORecord jrChkParam = commUtils.getParam(logId, mthdNm, userid);
            	
            	/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStrLocCoilCntByYdStkColGp
            	SELECT COUNT(*) AS CNT
            	  FROM TB_YD_STKLYR
            	 WHERE YD_STK_COL_GP  = :V_YD_STK_COL_GP
            	   AND YD_STK_BED_NO <> '00'
            	   AND STL_NO IS NOT NULL
            	   AND DEL_YN         = 'N'
            	*/
            	jrChkParam.setField("YD_STK_COL_GP", "JFFE02");
            	JDTORecordSet jsCheck = commDao.select(jrChkParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStrLocCoilCntByYdStkColGp", logId, mthdNm, "적치코일 체크");

            	String cnt = jsCheck.getRecord(0).getFieldString("CNT");
            	if( !"0".equals(cnt) ) {

            		sMsg = "적치코일 갯수 ["+ cnt +"]";
            		commUtils.printLog(logId, sMsg, "SL");

                    sMsg = "HFL2 저장위치에 적치 및 권하예정 코일이 없어야 가능합니다.";
                    commUtils.printLog(logId, sMsg, "SL");

                    jrRtn.setField("RTN_CD" , "0");
                    jrRtn.setField("RTN_MSG", sMsg);
                    commUtils.printLog(logId, mthdNm, "S-");
                    return jrRtn;
            	}
            }

            /***************************************
             * 1. 스케쥴 기동/금지 UPDATE
             ***************************************/
            /* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updSchProhExn
            UPDATE TB_YD_SCHRULE
               SET YD_SCH_PROH_EXN = :V_YD_SCH_PROH_EXN
                 , MODIFIER        = :V_MODIFIER
                 , MOD_DDTT        = SYSDATE
             WHERE YD_SCH_CD       = :V_YD_SCH_CD
               AND DEL_YN          = 'N'
            */
            intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updSchProhExn", logId, mthdNm, "스케쥴 기동/금지 UPDATE");
            if( intRtnVal < 1 ) {

                sMsg = "스케쥴 금지유무 업데이트 실패! YD_SCH_CD["+ ydSchCd +"] YD_SCH_PROH_EXN["+ ydSchProhExn +"]";
                commUtils.printLog(logId, sMsg, "SL");

                jrRtn.setField("RTN_CD" , "0");
                jrRtn.setField("RTN_MSG", sMsg);
                commUtils.printLog(logId, mthdNm, "S-");
                return jrRtn;
            }

            sMsg = sParamMsg +" 처리되었습니다.";
            commUtils.printLog(logId, sMsg, "SL");

            jrRtn.setField("RTN_CD" , "1");
            jrRtn.setField("RTN_MSG", sMsg);
            commUtils.printLog(logId, mthdNm, "S-");

            return jrRtn;

        } catch(DAOException e) {
            throw e;
        } catch(Exception e) {
            throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
        }
    }

    /**
     * 지포장 이적등록
	 * 야드관리 > 2열연 소재 코일야드[신] > 설비입측관리 > 지포장보급관리
     * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
     * @param  GridData
     * @return JDTORecord
     * @throws DAOException
     */
    public JDTORecord regGFUnitMvStkH(GridData gdReq) throws DAOException {
        String mthdNm   = "지포장 이적등록[CCoilJspSeEJB.regGFUnitMvStkH]" + gdReq.getNavigateValue();
        String logId    = gdReq.getIPAddress();

        try {
            commUtils.printLog(logId, mthdNm, "S+");

            JDTORecord jrRtn    = JDTORecordFactory.getInstance().create();
            JDTORecord jrParam	= JDTORecordFactory.getInstance().create();

            String sMsg         = "";

            String rtnCd		= "";
            String rtnMsg       = "";

            String userid       = commUtils.trim(gdReq.getParam("YD_USER_ID"));

            String sFromBay		= commUtils.getValue(gdReq, "YD_STK_COL_GP", 0).substring(0, 2);	// ex)JA, JB, JC...
            String ydSchCd      = sFromBay + "YD01MH"; // 동내 이적 스케쥴코드
            String sTCar		= commUtils.trim(gdReq.getParam("T_CAR"));
            String sndFlag		= "N";

            String sStlNo		= "";
            String ydWbookId	= "";
            String runWbookId	= "";
            String runWbookIdTC	= "";
            String ydAimBayGp	= "";

            String ydStkLyrNo	= "";
            String ydToLocGuide	= commUtils.trim(gdReq.getParam("YD_GP"))
            					+ commUtils.trim(gdReq.getParam("TO_YD_BAY_GP"))
            					+ commUtils.trim(gdReq.getParam("TO_YD_EQP_GP"))
            					+ commUtils.trim(gdReq.getParam("TO_YD_STK_COL_NO"));

            // 동간이적 스케쥴코드 생성
            if( !"".equals(sTCar) ) {
            	// ex) JBTC03UH, JHTC06UH...
            	ydSchCd = sFromBay + sTCar.substring(2, 6) + "UH";
            }

            commUtils.printLog(logId, "YD_SCH_CD       : "+ ydSchCd		, "SL");
            commUtils.printLog(logId, "YD_TO_LOC_GUIDE : "+ ydToLocGuide, "SL");
            commUtils.printLog(logId, "T_CAR           : "+ sTCar		, "SL");

            int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			/************************************
			 * 1. 2단 우선 이적지시 처리
			 ************************************/
            commUtils.printLog(logId, "> 2단 이적지시 처리", "SL");
			for( int i=0; i<rowCnt; i++ ) {

				ydStkLyrNo = commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO", i));
				if( !"002".equals(ydStkLyrNo) ) continue;

				sStlNo = commUtils.trim(commUtils.getValue(gdReq, "STL_NO", i));
				/************************************
				 * 1.1 작업예약 생성
				 ************************************/
	            jrParam = commUtils.getParam(logId, mthdNm, userid);
	            jrParam.setField("YD_SCH_CD"			, ydSchCd);
	            jrParam.setField("STL_SH"				, "1");
	            jrParam.setField("STL_NO1"				, sStlNo);
	            jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
	            jrParam.setField("TO_YD_STK_BED_NO"		, ydToLocGuide);
	            jrParam.setField("YD_UP_COLL_SEQ1"		, "1");
	            jrParam.setField("YD_WRK_PLAN_TCAR"		, sTCar);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		= commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	= commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if ("0".equals(rtnCd)) {
					sMsg = "코일번호["+ sStlNo +"] 작업예약 등록 ERROR";
					commUtils.printLog(logId, sMsg, "SL");
					commUtils.printLog(logId, rtnMsg, "SL");

					jrRtn.setField("RTN_CD"  , "0");
					jrRtn.setField("RTN_MSG" , rtnMsg);

					return jrRtn;
				}

				// 일반이적/동간이적 구분 처리
				if( !"TC".equals(ydSchCd.substring(2, 4)) && "".equals(runWbookId) ) {
					runWbookId = ydWbookId;
				} else if( "TC".equals(ydSchCd.substring(2, 4)) && "".equals(runWbookIdTC) ) {
					runWbookIdTC = ydWbookId;
				}

				/************************************
				 * 1.2 대차 이동지시 송신 처리
				 ************************************/
				if( "TC".equals(ydSchCd.substring(2, 4)) && "N".equals(sndFlag) ) {

		            jrParam = commUtils.getParam(logId, mthdNm, userid);
		            jrParam.setField("YD_WBOOK_ID", ydWbookId);

					// 설비 check 하여 대차작업 송신 여부
					JDTORecord jrWrkBookChk = this.chkTCarMoveWrkBook(jrParam);

					rtnCd		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_CD"), "0");
					rtnMsg		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_MSG"), "");
					ydAimBayGp	= commUtils.nvl(jrWrkBookChk.getFieldString("YD_AIM_BAY_GP"), "");
					sndFlag		= commUtils.nvl(jrWrkBookChk.getFieldString("SND_FLAG"), "");

					if( rtnCd.equals("0")) {

						jrRtn.setField("RTN_CD"  , "0");
						jrRtn.setField("RTN_MSG" , rtnMsg);
						return jrRtn;
					} else {

						commUtils.printLog(logId, "대차작업 송신 여부:" +sndFlag, "SL");
						if( sndFlag.equals("Y")) {

							jrParam = commUtils.getParam(logId, mthdNm, userid);
							jrParam.setField("YD_EQP_ID"	, sTCar		); // 대차설비코드
							jrParam.setField("YD_TO_BAY"	, ydAimBayGp); // 상차동
							jrParam.setField("YD_WBOOK_ID"	, ydWbookId	);

							// 대차이동지시 전문 생성
							jrRtn = this.procTcarSchLevWo(jrParam);
						}
					}
				}
			}

			/************************************
			 * 2. 1단 이적지시 처리
			 ************************************/
			commUtils.printLog(logId, "> 1단 이적지시 처리", "SL");
			for( int i=0; i<rowCnt; i++ ) {

				ydStkLyrNo = commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO", i));
				commUtils.printLog(logId, "ydStkLyrNo:" +ydStkLyrNo, "SL");
				if( !"001".equals(ydStkLyrNo) ) continue;

				sStlNo = commUtils.trim(commUtils.getValue(gdReq, "STL_NO", i));
				/************************************
				 * 2.1 작업예약 생성
				 ************************************/
	            jrParam = commUtils.getParam(logId, mthdNm, userid);
	            jrParam.setField("YD_SCH_CD"			, ydSchCd);
	            jrParam.setField("STL_SH"				, "1");
	            jrParam.setField("STL_NO1"				, sStlNo);
	            jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
	            jrParam.setField("TO_YD_STK_BED_NO"		, ydToLocGuide);
	            jrParam.setField("YD_UP_COLL_SEQ1"		, "1");
	            jrParam.setField("YD_WRK_PLAN_TCAR"		, sTCar);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		= commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	= commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if ("0".equals(rtnCd)) {
					sMsg = "코일번호["+ sStlNo +"] 작업예약 등록 ERROR";
					commUtils.printLog(logId, sMsg, "SL");
					commUtils.printLog(logId, rtnMsg, "SL");

					jrRtn.setField("RTN_CD"  , "0");
					jrRtn.setField("RTN_MSG" , rtnMsg);

					return jrRtn;
				}

				// 일반이적/동간이적 구분 처리
				if( !"TC".equals(ydSchCd.substring(2, 4)) && "".equals(runWbookId) ) {
					runWbookId = ydWbookId;
				} else if( "TC".equals(ydSchCd.substring(2, 4)) && "".equals(runWbookIdTC) ) {
					runWbookIdTC = ydWbookId;
				}

				/************************************
				 * 2.2 대차 이동지시 송신 처리
				 ************************************/
				if( "TC".equals(ydSchCd.substring(2, 4)) && "N".equals(sndFlag) ) {

		            jrParam = commUtils.getParam(logId, mthdNm, userid);
		            jrParam.setField("YD_WBOOK_ID", ydWbookId);

					// 설비 check 하여 대차작업 송신 여부
					JDTORecord jrWrkBookChk = this.chkTCarMoveWrkBook(jrParam);

					rtnCd		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_CD"), "0");
					rtnMsg		= commUtils.nvl(jrWrkBookChk.getFieldString("RTN_MSG"), "");
					ydAimBayGp	= commUtils.nvl(jrWrkBookChk.getFieldString("YD_AIM_BAY_GP"), "");
					sndFlag		= commUtils.nvl(jrWrkBookChk.getFieldString("SND_FLAG"), "");

					if( rtnCd.equals("0")) {

						jrRtn.setField("RTN_CD"  , "0");
						jrRtn.setField("RTN_MSG" , rtnMsg);
						return jrRtn;
					} else {

						commUtils.printLog(logId, "대차작업 송신 여부:"+ sndFlag, "SL");
						if( sndFlag.equals("Y")) {

							jrParam = commUtils.getParam(logId, mthdNm, userid);
							jrParam.setField("YD_EQP_ID"	, sTCar		); // 대차설비코드
							jrParam.setField("YD_TO_BAY"	, ydAimBayGp); // 상차동
							jrParam.setField("YD_WBOOK_ID"	, ydWbookId	);

							// 대차이동지시 전문 생성
							jrRtn = this.procTcarSchLevWo(jrParam);
						}
					}
				}
			}

			/************************************
			 * 3. 동내이적지시 스케쥴 기동
			 ************************************/
			if( !"".equals(runWbookId) ) {

				jrParam = commUtils.getParam(logId, mthdNm, userid);
				jrParam.setField("YD_SCH_CD", ydSchCd);

				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd
				SELECT YD_WBOOK_ID
				     , YD_SCH_CD
				  FROM TB_YD_CRNSCH
				 WHERE DEL_YN    = 'N'
				   AND YD_SCH_CD = :V_YD_SCH_CD
				*/
				JDTORecordSet jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "생성된스케쥴조회");

		    	if(jsResult == null || jsResult.size() < 1) {
		    		jrParam = commUtils.getParam(logId, mthdNm, userid);
		    		jrParam.setField("YD_SCH_CD"	, ydSchCd);
		    		jrParam.setField("YD_WBOOK_ID"	, runWbookId);

					JDTORecord jrRunSchedule = (JDTORecord)this.trxRunSchedule(jrParam);

					rtnCd	= commUtils.nvl(jrRunSchedule.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRunSchedule.getFieldString("RTN_MSG"), "");
					commUtils.printLog(logId, ">> " + rtnMsg, "SL");

					if (!("1".equals(rtnCd))) {
						jrRtn.setField("RTN_CD" 			, "0");
						jrRtn.setField("RTN_MSG"			, rtnMsg);

						return jrRtn;
					} else {
						jrRtn = commUtils.addSndData(jrRtn, jrRunSchedule);
						jrRtn.setField("RTN_MSG"			, rtnMsg + " <br> 정상적으로 스케쥴까지 등록했습니다.");
					}
		    	}
			}

			/************************************
			 * 4. 동간이적 스케쥴 대차이동지시 미송신시
			 ************************************/
			if( "TC".equals(ydSchCd.substring(2, 4)) && "N".equals(sndFlag) ) {

				jrParam = commUtils.getParam(logId, mthdNm, userid);
				jrParam.setField("YD_SCH_CD"   , ydSchCd);
		        jrParam.setField("YD_EQP_ID"   , sTCar);
		        jrParam.setField("YD_WBOOK_ID" , runWbookIdTC);

		        /* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRunScheduleYn
		        SELECT CASE WHEN A.YD_CURR_BAY_GP = SUBSTR(:V_YD_SCH_CD,2,1)
		                         AND 0 = (SELECT COUNT(*)
		                                    FROM TB_YD_WRKBOOK
		                                   WHERE DEL_YN = 'N'
		                                     AND YD_WRK_PLAN_TCAR = A.YD_EQP_ID
		                                     AND TO_NUMBER(YD_WBOOK_ID) < TO_NUMBER(:V_YD_WBOOK_ID)
		                                     AND YD_GP = 'J')
		                    THEN 'Y'
		                    ELSE 'N' END TC_SCH_YN
		             , (SELECT COUNT(*)
		                  FROM TB_YD_WRKBOOK
		                 WHERE DEL_YN = 'N'
		                   AND YD_WRK_PLAN_TCAR = A.YD_EQP_ID
		                   AND TO_NUMBER(YD_WBOOK_ID) < TO_NUMBER(:V_YD_WBOOK_ID)
		                   AND YD_GP = 'J'
		               )  AS WBOOK_CHK
		             , A.YD_CURR_BAY_GP
		          FROM TB_YD_EQP A
		         WHERE A.YD_EQP_ID = :V_YD_EQP_ID
		           AND A.YD_EQP_STAT <> 'B'
		       */
				JDTORecordSet jsWbookChk = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRunScheduleYn", logId, mthdNm, "");
				if (jsWbookChk.size() > 0) {
					jsWbookChk.absolute(1);
					JDTORecord jrWbookChk = jsWbookChk.getRecord();

					commUtils.printLog(logId, "대차현재위치 " + commUtils.nvl(jrWbookChk.getFieldString("A.YD_CURR_BAY_GP"),""), "SL");
					String sTcSchYn	= commUtils.nvl(jrWbookChk.getFieldString("TC_SCH_YN"),"");
					commUtils.printLog(logId, "현위치 대차 스케쥴 기동 여부 " + sTcSchYn, "S+");
					if ("Y".equals(sTcSchYn)) {

						//도착동 우선순위 빠른 작업예약 조회
						/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdWrkbookYdWrkPlanTcar
						WITH TEMP_TBL AS
						(
						-- 대상재중 첫번재 작업예약
						SELECT *
						  FROM (SELECT A.YD_WBOOK_ID
						             , A.YD_AIM_BAY_GP
						          FROM TB_YD_WRKBOOK A
						             , TB_YD_EQP  D
						         WHERE A.YD_WRK_PLAN_TCAR = D.YD_EQP_ID
						           AND A.YD_WRK_PLAN_TCAR = :V_YD_WRK_PLAN_TCAR
						           AND ( A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY1,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY2,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY3,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY4,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY5,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY6,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY7,'*')
						                  OR A.YD_AIM_BAY_GP = NVL(D.YD_TCAR_WRK_ABLE_BAY8,'*')
						               )
						           AND A.YD_WBOOK_ID NOT IN (
						                                     SELECT A.YD_WBOOK_ID
						                                       FROM (
						                                            SELECT YD_CARLD_WRK_BOOK_ID AS YD_WBOOK_ID
						                                              FROM TB_YD_TCARSCH
						                                             WHERE YD_CARLD_WRK_BOOK_ID IS NOT NULL
						                                               AND DEL_YN = 'N'
						                                            UNION ALL
						                                            SELECT YD_CARUD_WRK_BOOK_ID AS YD_WBOOK_ID
						                                              FROM TB_YD_TCARSCH
						                                             WHERE YD_CARUD_WRK_BOOK_ID IS NOT NULL
						                                               AND DEL_YN = 'N'
						                                            UNION ALL
						                                            SELECT YD_WBOOK_ID
						                                              FROM TB_YD_CRNSCH
						                                             WHERE YD_GP IN ('J')
						                                               AND DEL_YN = 'N'
						                                            ) A
						                                          , USRYDA.TB_YD_WRKBOOKMTL B
						                                          , USRYDA.TB_YD_CRNWRKMTL C
						                                      WHERE A.YD_WBOOK_ID=B.YD_WBOOK_ID
						                                        AND B.STL_NO= C.STL_NO(+)
						                                        AND B.DEL_YN='N'
						                                        AND C.DEL_YN='N'
						                                      GROUP BY A.YD_WBOOK_ID
						                                    )
						           AND A.YD_SCH_CD LIKE 'J' || nvl(:V_YD_BAY_GP,'_') || 'TC%'
						           AND A.DEL_YN = 'N'
						           AND SUBSTR(A.YD_SCH_CD,7,2) NOT IN ('LM','LH')
						--         ORDER BY A.YD_SCH_PRIOR ASC, A.YD_WBOOK_ID ASC 
						         ORDER BY A.YD_WBOOK_ID, A.YD_SCH_PRIOR ASC
						       )
						 WHERE ROWNUM = 1
						)
						SELECT *
						  FROM (SELECT *
						          FROM (SELECT A.*
						                     , SUM(A.COIL_WT)   OVER(ORDER BY A.YD_SCH_PRIOR ASC, A.YD_WBOOK_ID ASC) LOW_SUM
						                     , COUNT(A.STL_NO)  OVER(ORDER BY A.YD_SCH_PRIOR ASC, A.YD_WBOOK_ID ASC) LOW_CNT
						                  FROM (SELECT A.YD_WBOOK_ID
						                             , A.YD_GP
						                             , A.YD_BAY_GP
						                             , A.YD_SCH_CD
						                             , A.YD_SCH_PRIOR
						                             , A.YD_SCH_PROG_STAT
						                             , A.YD_SCH_ST_GP
						                             , A.YD_SCH_REQ_GP
						                             , A.YD_AIM_YD_GP
						                             , A.YD_AIM_BAY_GP
						                             , A.YD_CTS_RELAY_YN
						                             , A.YD_CTS_RELAY_BAY_GP
						                             , A.YD_TO_LOC_DCSN_MTD
						                             , A.YD_TO_LOC_GUIDE
						                             , A.YD_WRK_PLAN_TCAR
						                             , A.YD_CAR_USE_GP
						                             , A.TRN_EQP_CD
						                             , A.CAR_NO
						                             , A.CARD_NO
						                             , B.STL_NO
						                             , C.COIL_WT
						                             , D.STK_BED_MAX_QNTY
						                             , D.STK_BED_MAX_WT
						                          FROM TB_YD_WRKBOOK    A
						                             , TB_YD_WRKBOOKMTL B
						                             , TB_PT_COILCOMM   C
						                             , TB_YD_EQP        D
						                         WHERE A.YD_WBOOK_ID  = B.YD_WBOOK_ID
						                           AND B.STL_NO = C.COIL_NO
						                           AND A.YD_WRK_PLAN_TCAR = :V_YD_WRK_PLAN_TCAR
						                           AND A.YD_WRK_PLAN_TCAR = D.YD_EQP_ID
						                           AND A.YD_WBOOK_ID NOT IN (
						                                                     SELECT A.YD_WBOOK_ID
						                                                       FROM (
						                                                             SELECT YD_CARLD_WRK_BOOK_ID AS YD_WBOOK_ID
						                                                               FROM TB_YD_TCARSCH
						                                                              WHERE YD_CARLD_WRK_BOOK_ID IS NOT NULL
						                                                                AND DEL_YN = 'N'
						                                                             UNION ALL
						                                                             SELECT YD_CARUD_WRK_BOOK_ID AS YD_WBOOK_ID
						                                                               FROM TB_YD_TCARSCH
						                                                              WHERE YD_CARUD_WRK_BOOK_ID IS NOT NULL
						                                                                AND DEL_YN = 'N'
						                                                             UNION ALL
						                                                             SELECT YD_WBOOK_ID
						                                                               FROM TB_YD_CRNSCH
						                                                               WHERE YD_GP IN ('J')
						                                                                 AND DEL_YN = 'N'
						                                                            ) A
						                                                          , USRYDA.TB_YD_WRKBOOKMTL B
						                                                          , USRYDA.TB_YD_CRNWRKMTL  C
						                                                      WHERE A.YD_WBOOK_ID=B.YD_WBOOK_ID
						                                                        AND B.STL_NO= C.STL_NO(+)
						                                                        AND B.DEL_YN='N'
						                                                        AND C.DEL_YN='N'
						                                                      GROUP BY A.YD_WBOOK_ID
						                                                    )
						                           AND A.YD_SCH_CD LIKE 'J' || nvl(:V_YD_BAY_GP,'_') || 'TC%'
						                           AND A.DEL_YN = 'N'
						                           AND B.DEL_YN = 'N'
						                           AND SUBSTR(A.YD_SCH_CD,7,2) NOT IN ('LM','LH')
						                       ) A
						                     , TEMP_TBL B
						                 WHERE 1 = 1
						                   -- 첫선택된 대상재와 동일 목적동
						                   AND A.YD_AIM_BAY_GP = B.YD_AIM_BAY_GP
						                 ORDER BY A.YD_SCH_PRIOR ASC, A.YD_WBOOK_ID ASC
						               ) A
						           WHERE 1 = 1
						             AND LOW_SUM           < STK_BED_MAX_WT -- 중량
						             AND STK_BED_MAX_QNTY >= LOW_CNT -- 매수
						             AND NOT EXISTS(SELECT 1
						                              FROM USRYDA.TB_YD_CRNSCH C
						                             WHERE C.DEL_YN='N'
						                               AND C.YD_GP     = A.YD_GP
						                               AND C.YD_BAY_GP = A.YD_BAY_GP
						                               AND C.YD_DN_WO_LOC LIKE 'J'||'_TC%'
						                               AND SUBSTR(C.YD_SCH_CD,2,5) = SUBSTR(A.YD_WRK_PLAN_TCAR,2,5)
						                           )
						           ORDER BY YD_WBOOK_ID
						       )
						 WHERE ROWNUM = 1
						*/

						jrParam.setField("YD_WRK_PLAN_TCAR", sTCar); //작업계획 대차
						jrParam.setField("YD_BAY_GP"       , ydSchCd.substring(1, 2));
						JDTORecordSet jsTcarWbook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdWrkbookYdWrkPlanTcar", logId, mthdNm, "작업예약조회");

						if (jsTcarWbook.size() > 0) {
							JDTORecord jrYdMsg = commUtils.getParam(logId, mthdNm, userid);
							jrYdMsg.setField("JMS_TC_CD"		 , "YDYDJ552"); //
							jrYdMsg.setField("JMS_TC_CREATE_DDTT", commUtils.getDateTime14()  ); //JMSTC생성일시

							for (int i = 1; i <= jsTcarWbook.size(); i++) {
								jsTcarWbook.absolute(i);
								jrYdMsg.setField("YD_WBOOK_ID"+i     , jsTcarWbook.getRecord().getFieldString("YD_WBOOK_ID"    )); //야드작업예약ID
								jrYdMsg.setField("SCH_CNT" , ""+i); //작업예약 개수
							}

							jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);
						}
					}
				}
			}

            sMsg = "이적지시등록을 정상적으로 처리하였습니다.";
            commUtils.printLog(logId, sMsg, "SL");

            jrRtn.setField("RTN_CD" , "1");
            jrRtn.setField("RTN_MSG", sMsg);

            commUtils.printLog(logId, mthdNm, "S-");

            return jrRtn;

        } catch(DAOException e) {
            throw e;
        } catch(Exception e) {
            throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
        }
    }
    
	/**
	 * 입고스케줄 변경
	 * 이현진
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procChgRcptSch(GridData gdReq) throws DAOException {
		String mthdNm	= "입고스케줄 변경[CCoilJspSeEJB.procChgRcptSch] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			
			JDTORecord jrRtn   = JDTORecordFactory.getInstance().create();

			String userid      = commUtils.trim(gdReq.getParam("userid"));
			String sMsg        = "";
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, userid);
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			String ydSchCd   = "";
			String ydWbookId = "";
			String ydBayGp   = ""; 
			
			for (int i = 0; i < rowCnt; i++) {
				
				ydSchCd   = commUtils.trim(gdReq.getHeader("YD_SCH_CD"  ).getValue(i));
				ydWbookId = commUtils.trim(gdReq.getHeader("YD_WBOOK_ID").getValue(i));
				ydBayGp   = commUtils.trim(gdReq.getHeader("YD_BAY_GP"  ).getValue(i));
				
				jrParam.setField("YD_SCH_CD"  , ydSchCd  );
				jrParam.setField("YD_WBOOK_ID", ydWbookId);
				jrParam.setField("YD_BAY_GP"  , ydBayGp  );
				/*
				SELECT *
				  FROM TB_YD_CRNSCH
				 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID
				   AND DEL_YN='N'
				 ORDER BY YD_CRN_SCH_ID
				*/
				JDTORecordSet jsCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdCrnschByWrkId", logId, mthdNm, "크레인스케쥴 조회");
				if (jsCrnSch.size() > 0) {
					sMsg = "["+ ydWbookId +"] 작업예약은 크레인스케줄이 존재합니다.";
					commUtils.printLog(logId, sMsg, "S-");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				/*
				WITH PARAM AS (
				SELECT :V_YD_BAY_GP AS P_YD_BAY_GP
				  FROM DUAL
				)
				SELECT EQ.*
				  FROM TB_YD_EQP  EQ
				     , PARAM
				 WHERE YD_EQP_ID LIKE 'JXTC%'
				   AND DEL_YN    = 'N'
				   AND YD_LOC_GP = 'J'
				   AND RCPT_TCAR_USE_YN = 'Y' --입고대차 여부
				   AND RCPT_TCAR_BAY    = P_YD_BAY_GP
				   AND P_YD_BAY_GP = CASE P_YD_BAY_GP WHEN 'A' THEN YD_TCAR_WRK_ABLE_BAY1
				                                      WHEN 'B' THEN YD_TCAR_WRK_ABLE_BAY2
				                                      WHEN 'C' THEN YD_TCAR_WRK_ABLE_BAY3
				                                      WHEN 'D' THEN YD_TCAR_WRK_ABLE_BAY4
				                                      WHEN 'E' THEN YD_TCAR_WRK_ABLE_BAY5
				                                      WHEN 'F' THEN YD_TCAR_WRK_ABLE_BAY6
				                                      WHEN 'G' THEN YD_TCAR_WRK_ABLE_BAY7
				                                      WHEN 'H' THEN YD_TCAR_WRK_ABLE_BAY8
				                     ELSE 'XX' END
				   AND RCPT_TCAR_USE_YN = 'Y'
				   AND RCPT_TCAR_BAY    = P_YD_BAY_GP
				 */
				JDTORecordSet jsTcar = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRcptTcar", logId, mthdNm, "대차정보 조회");
				if (jsTcar.size() <= 0) {
					sMsg = "입고대차 지정 및 동이 잘못되었습니다.";
					commUtils.printLog(logId, sMsg, "SL");
					commUtils.printLog(logId, mthdNm, "S-");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				String ydEqpId        = jsTcar.getRecord(0).getFieldString("YD_EQP_ID"); //대차번호
				String ydWrkCrnPrior  = ""; //스케줄 우선 순위
				
				jrParam.setField("YD_EQP_ID", ydEqpId);
				/*
				SELECT SR.*
				  FROM TB_YD_SCHRULE SR
				     , (SELECT :V_YD_EQP_ID AS P_YD_EQP_ID
				             , :V_YD_BAY_GP AS P_YD_BAY_GP
				          FROM DUAL
				       )
				 WHERE SR.DEL_YN = 'N'
				   AND SR.YD_SCH_CD = 'J'||P_YD_BAY_GP||SUBSTR(P_YD_EQP_ID, 3, 6)||'MM'
				 */
				JDTORecordSet jsRcptSchCd = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getRcptTcarSchCd", logId, mthdNm, "입고대차 스케줄코드 조회");
				if (jsRcptSchCd.size() <= 0) {
					sMsg = "입고대차 스케줄코드 변환 실패";
					commUtils.printLog(logId, sMsg, "SL");
					commUtils.printLog(logId, mthdNm, "S-");
					
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
				
				ydSchCd       = jsRcptSchCd.getRecord(0).getFieldString("YD_SCH_CD");
				ydWrkCrnPrior = jsRcptSchCd.getRecord(0).getFieldString("YD_WRK_CRN_PRIOR");
				
				jrParam.setField("YD_SCH_CD"       , ydSchCd      );
				jrParam.setField("YD_SCH_PRIOR"    , ydWrkCrnPrior);
				jrParam.setField("YD_WRK_PLAN_TCAR", ydEqpId      );
				/*
				UPDATE TB_YD_WRKBOOK
				   SET MODIFIER     = :V_MODIFIER
				     , MOD_DDTT     = SYSDATE
				     , YD_SCH_CD        = :V_YD_SCH_CD
				     , YD_SCH_PRIOR     = :V_YD_SCH_PRIOR
				     , YD_WRK_PLAN_TCAR = :V_YD_WRK_PLAN_TCAR
				     , YD_AIM_BAY_GP    = (SELECT RCPT_TCAR_AIM_BAY_GP FROM TB_YD_EQP WHERE YD_EQP_ID = :V_YD_WRK_PLAN_TCAR AND ROWNUM = 1)
				 WHERE YD_WBOOK_ID = :V_YD_WBOOK_ID   
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updWbRcptTcarSch", logId, mthdNm, "작업예약 수정");
			} //END FOR
			
			sMsg = "입고스케줄 변경작업을 정상적으로 처리하였습니다.";

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);
			
			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}    
	
    /**
     * 결속장 기동/금지
     * 야드관리 > 2열연 소재 코일야드[신] > 설비입측관리 > SPM/HFL입측관리
     * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
     * @param  GridData
     * @return JDTORecord
     * @throws DAOException
     */
    public JDTORecord updLineInSupMtdGp(GridData gdReq) throws DAOException {
        String mthdNm   = "결속장 기동/금지[CCoilJspSeEJB.updLineInSupMtdGp]" + gdReq.getNavigateValue();
        String logId    = gdReq.getIPAddress();

        try {
            commUtils.printLog(logId, mthdNm, "S+");

            JDTORecord jrRtn    = JDTORecordFactory.getInstance().create();

            int intRtnVal       = 0;
            String sMsg         = "";
            String userid       = commUtils.trim(gdReq.getParam("YD_USER_ID"));
            String ydSchCd      = commUtils.trim(gdReq.getParam("YD_SCH_CD"));
            String matlSupMtdGp = commUtils.trim(gdReq.getParam("MATL_SUP_MTD_GP"));
            String sParamMsg    = commUtils.trim(gdReq.getParam("PARAM_MSG"));

            JDTORecord jrParam = commUtils.getParam(logId, mthdNm, userid);
            jrParam.setField("YD_SCH_CD"        , ydSchCd);
            jrParam.setField("MATL_SUP_MTD_GP"  , matlSupMtdGp);

            /***************************************
             * 1. 스케쥴 기동/금지 UPDATE
             ***************************************/
            /* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updSupMtdGp
              
				 UPDATE TB_YD_STKCOL
				    SET MATL_SUP_MTD_GP = :V_MATL_SUP_MTD_GP
				  WHERE SUBSTR(YD_STK_COL_GP,0,4) IN (
				             SELECT SUBSTR(YD_SCH_CD,0,4) AS YD_SCH_CD
				               FROM TB_YD_SCHRULE
				             WHERE YD_SCH_CD IN ('JFFE01UH','JDFE01UH','JBFE01UH')
				               AND DEL_YN = 'N' 
				        	)
				    AND DEL_YN = 'N'
				    AND RL.YD_SCH_CD = :V_YD_SCH_CD
            */
            intRtnVal = commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updSupMtdGp", logId, mthdNm, "결속장 기동/금지 UPDATE");
            if( intRtnVal < 1 ) {

                sMsg = "결속장 금지유무 업데이트 실패! YD_SCH_CD["+ ydSchCd +"] MATL_SUP_MTD_GP["+ matlSupMtdGp +"]";
                commUtils.printLog(logId, sMsg, "SL");

                jrRtn.setField("RTN_CD" , "0");
                jrRtn.setField("RTN_MSG", sMsg);
                return jrRtn;
            }

            sMsg = sParamMsg +" 처리되었습니다.";

            commUtils.printLog(logId, sMsg, "SL");

            jrRtn.setField("RTN_CD" , "1");
            jrRtn.setField("RTN_MSG", sMsg);

            commUtils.printLog(logId, mthdNm, "S-");

            return jrRtn;

        } catch(DAOException e) {
            throw e;
        } catch(Exception e) {
            throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
        }
    }
    
	/**
	 * 야드관리 > 2열연 소재 코일야드[신] > 산적LOT관리  > 결로HOT코일이적
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updCondenMvStkReg(GridData gdReq) throws DAOException {
		String mthdNm = "결로HOT코일이적[CCoilJspSeEJB.updCondenMvStkReg] < " + gdReq.getNavigateValue();
		String logId  = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sModifier	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String ydSchCd		= commUtils.trim(gdReq.getParam("YD_SCH_CD"));
			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
			
			String rtnCd		= "";
	        String sMsg         = "";
			String ydWbookId 	= "";
			String runYdWbookId	= "";
			String ydStkLyrNo	= "";
			String sStlNo		= "";

			/*******************************
			 * 1. 2단 적치 코일 부터 작업예약 생성
			 *******************************/
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			for( int i=0; i<rowCnt; i++ ) {

				ydStkLyrNo	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO", i));
				sStlNo		= commUtils.trim(commUtils.getValue(gdReq, "STL_NO", i));
				
				commUtils.printLog(logId, i +".2단 CHECK >> LYR_NO:"+ ydStkLyrNo, "SL");

				if( !"002".equals(ydStkLyrNo) ) continue;

				jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd);//스케줄코드
				jrParam.setField("STL_SH"				, "1");  //LINE_IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1");

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				sMsg		= commUtils.trim(jrWrkBook.getFieldString("RTN_MSG"));
				ydWbookId	= commUtils.trim(jrWrkBook.getFieldString("YD_WBOOK_ID"));

				if( "0".equals(rtnCd) ) {
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD"		, "0");
					jrRtn.setField("RTN_MSG"	, sMsg);

					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				} else {

					if( "".equals(runYdWbookId) ) {
						runYdWbookId = ydWbookId;
					}

					sMsg = "STL_NO["+ sStlNo +"] YD_WBOOK_ID["+ ydWbookId +"] 작업예약 등록.";
					commUtils.printLog(logId, sMsg, "SL");
				}
			}

			/*******************************
			 * 2. 1단 적치 코일 부터 작업예약 생성
			 *******************************/
			for( int i=0; i<rowCnt; i++ ) {

				ydStkLyrNo	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO", i));
				sStlNo		= commUtils.trim(commUtils.getValue(gdReq, "STL_NO", i));

				commUtils.printLog(logId, i +".1단 CHECK >> LYR_NO:"+ ydStkLyrNo, "SL");

				if( !"001".equals(ydStkLyrNo) ) continue;

				jrParam  = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd);//스케줄코드
				jrParam.setField("STL_SH"				, "1");  //LINE_IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F");
				jrParam.setField("YD_UP_COLL_SEQ1"		, "1");

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				sMsg		= commUtils.trim(jrWrkBook.getFieldString("RTN_MSG"));
				ydWbookId	= commUtils.trim(jrWrkBook.getFieldString("YD_WBOOK_ID"));

				if( "0".equals(rtnCd) ) {
					commUtils.printLog(logId, sMsg, "SL");

					jrRtn.setField("RTN_CD"  , "0");
					jrRtn.setField("RTN_MSG" , sMsg);

					commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				} else {

					if( "".equals(runYdWbookId) ) {
						runYdWbookId = ydWbookId;
					}

					sMsg = "STL_NO["+ sStlNo +"] YD_WBOOK_ID["+ ydWbookId +"] 작업예약 등록.";
					commUtils.printLog(logId, sMsg, "SL");
				}
			}

			/****************************************************
			 * 3. 스케쥴 기동(결로HOT코일 이적 스케쥴 확인하여 없으면..)
			 ****************************************************/
			if( !"".equals(runYdWbookId) ) {

				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
				/*
				 * SELECT YD_WBOOK_ID
				     , YD_SCH_CD
				  FROM TB_YD_CRNSCH
				 WHERE DEL_YN='N'
				   AND YD_SCH_CD = :V_YD_SCH_CD
				 */
				JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "스케쥴기동 작업예약 조회");

				if( jsWrkBook.size() < 1 ) {

		    		JDTORecord jrSchParam = commUtils.getParam(logId, mthdNm, sModifier);
		    		jrSchParam.setField("YD_SCH_CD"		, ydSchCd);
		    		jrSchParam.setField("YD_WBOOK_ID"	, runYdWbookId);

					JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrSchParam);

					rtnCd	= commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
					sMsg	= commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

					commUtils.printLog(logId, "trxRunSchedule : RTN_CD["+ rtnCd +"] RTN_MSG["+ sMsg +"]", "SL");

					if( !"1".equals(rtnCd) ) {
						commUtils.printLog(logId, sMsg, "SL");

						jrRtn.setField("RTN_CD"		, rtnCd);
						jrRtn.setField("RTN_MSG"	, sMsg);

						commUtils.printLog(logId, mthdNm, "S-");
						return jrRtn;
					}
					
					jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
		    	}
			}

			sMsg = "작업예약을 생성 하였습니다.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"		, "1");
			jrRtn.setField("RTN_MSG"	, sMsg);

			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;

		}catch(DAOException e) {
			throw e;
		}catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 장기공냉재자동이적처리
	 * jsp에서 호출
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procHotCoilMove(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "장기공냉재자동이적처리[CCoilJspSeEJ.procHotCoilMove] < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			
			if (logId == null ) {
				logId = commUtils.getLogId();
			}
			
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);

			String sModifier = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydBayGp	 = commUtils.trim(rcvMsg.getFieldString("YD_BAY_GP"));
			String sMsg      = "";
			String rtnCd	 = "";
			String rtnMsg	 = "";
			String ydWbookId = "";

			if ("".equals(ydBayGp) ) {
				
				sMsg = "동구분이 없습니다.";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		jrRtn.setField("RTN_CD"	, "0");
	    		jrRtn.setField("RTN_MSG", sMsg);
	    		
	    		commUtils.printLog(logId, mthdNm, "S-");
				return jrRtn;
			}

			String sAPP301 = coilDao.ApplyYn(logId, mthdNm, "APP301", "J", "*");
			commUtils.printLog(logId, "공냉재자동이적ON/OFF : " + sAPP301, "SL");
			if( !"Y".equals(sAPP301) ) {
				sMsg = "공냉재자동이적 OFF 입니다.";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		jrRtn.setField("RTN_CD"	, "0");
	    		jrRtn.setField("RTN_MSG", sMsg);

	    		commUtils.printLog(logId, mthdNm, "S-");
	    		return jrRtn;
			}
			
			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_BAY_GP", ydBayGp);
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdHotCoilMove 
				WITH TEMP_TBL AS 
				(
				SELECT A.YD_STK_COL_GP
				     , A.YD_STK_BED_NO
				     , A.YD_STK_LYR_NO
				     , A.STL_NO
				     , CASE WHEN SUBSTR(A.YD_STK_COL_GP,2,1) = 'D' AND  SUBSTR(A.YD_STK_COL_GP,3,2) > 34 THEN '6'
				            --WHEN SUBSTR(A.YD_STK_COL_GP,2,1) = 'A'  THEN '3'
				            ELSE '5' END  AS SCH_GP
				     , (
				          SELECT DTL_ITEM1 
				          FROM 
				          TB_YD_RULE 
				               WHERE REPR_CD_GP LIKE 'APP033%'
				                 AND DEL_YN  = 'N'
				       ) AS TM_AIR
				     , C.CURR_PROG_CD
				     , C.NEXT_PROC
				     , C.HRMILL_CMPL_DT
				     , C.COIL_CREATE_DDTT
				     , TO_NUMBER(TRUNC((SYSDATE - NVL(HRMILL_CMPL_DT,COIL_CREATE_DDTT)) * 24)) AS TM
				     , NVL((SELECT TO_NUMBER(ITEM_VALUE1) * 0.1 
				              FROM TB_YD_RULE 
				             WHERE REPR_CD_GP LIKE 'APP033%'
				               AND DEL_YN  = 'N' ),0.3) AS PER 
				     , D.SNDBK_GP
				     , D.YD_ABMTL_REM -- 판정내용 탈레스 짱구 
				     , D.YD_AIM_RT_GP 
				  FROM TB_YD_STKLYR   A
				     , TB_YD_STKCOL   B
				     , TB_PT_COILCOMM C
				     , TB_YD_STOCK    D
				 WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
				   AND A.STL_NO        = C.COIL_NO
				   AND D.STL_NO        = C.COIL_NO
				   AND A.YD_STK_LYR_MTL_STAT = 'C'
				   AND B.YD_GP         = 'J'
				   AND B.YD_LOC_GP     = 'H'
				   AND B.YD_BAY_GP     = :V_YD_BAY_GP
				   AND A.DEL_YN        = 'N'
				   AND B.DEL_YN        = 'N'
				   AND (D.SNDBK_GP IS NULL OR D.SNDBK_GP NOT IN ('1') )
				   AND (D.SNDBK_RSN_CD IS NULL OR D.SNDBK_RSN_CD NOT IN ('1', '3') )-- 반품/부분하차
				   --직송
				   AND 'Y' =  CASE WHEN SUBSTR(C.NEXT_PROC,2,1) IN ('A')  
				                OR EXISTS (SELECT 1
				                             FROM TB_HR_C_SHEARWOWR SR
				                            WHERE SR.HR_PLNT_GP = 'C'
				                              AND SR.WORK_STAT  = '*'
				                              AND SR.WORD_PROC  LIKE '%A'
				                              AND SR.COIL_NO = C.COIL_NO
				                              AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP IN ('I','B')
				                              AND SR.STEP_NO = (SELECT MAX(STEP_NO)
				                                                  FROM TB_HR_C_SHEARWOWR
				                                                  WHERE COIL_NO = SR.COIL_NO) 
				                          ) THEN 'Y'
				              ELSE 'N' END
				                  
				   AND 'Y' =  CASE WHEN TO_NUMBER(TRUNC((SYSDATE - NVL(C.HRMILL_CMPL_DT,COIL_CREATE_DDTT)) * 24)) >= TO_NUMBER(NVL((
				                                                                                                                      SELECT DTL_ITEM1 
				                                                                                                                      FROM 
				                                                                                                                      TB_YD_RULE 
				                                                                                                                           WHERE REPR_CD_GP LIKE 'APP033%'
				                                                                                                                             AND DEL_YN  = 'N'
				                                                                                                                   ),'168')) --7일
				                   THEN 'Y'
				                   ELSE 'N'
				              END
				   AND A.STL_NO NOT IN ( SELECT B1.STL_NO 
				                           FROM TB_YD_CRNSCH A1
				                              , TB_YD_CRNWRKMTL B1
				                          WHERE A1.YD_CRN_SCH_ID = B1.YD_CRN_SCH_ID
				                            AND A1.DEL_YN = 'N'
				                            AND B1.DEL_YN = 'N'
				                            AND A1.YD_GP  = 'J'
				                       ) 
				   AND A.STL_NO NOT IN ( SELECT B1.STL_NO 
				                           FROM TB_YD_WRKBOOK A1
				                              , TB_YD_WRKBOOKMTL B1
				                          WHERE A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
				                            AND A1.DEL_YN = 'N'
				                            AND B1.DEL_YN = 'N'
				                            AND A1.YD_GP  = 'J'
				                       ) 
				   AND C.CURR_PROG_CD IN ('3','H','F','Y') -- 진도코드 >> F:판정보류 Y:재공충당대기 3:소재이송지시대기 H:입고대기
				   AND SUBSTR(B.YD_STK_COL_GP,3,2) BETWEEN '01' AND '99'
				   -- 이강일주임요청 : C동 45스판, D동 43스판, B동 45 46 스판으로만 이적 20230525 YYS   
				   -- 20231108 이강일 주임 요청 전체동 확장
				   AND 'Y' = CASE WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JH32' ,'JH33','JH34','JH35','JH36','JH37','JH38') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JG34' ,'JG35','JG36','JG37','JG40','JG41') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JE32' ,'JE33','JE34','JE35','JE36','JE37') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JD32' ,'JD33','JD34','JD35','JD36','JD37') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JC29','JC31' ,'JC32','JC33','JC35','JC36') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JB29','JB31' ,'JB32','JB33') THEN 'Y'
				                  WHEN SUBSTR(B.YD_STK_COL_GP,0,4) IN ('JA31' ,'JA32') THEN 'Y'
				                  ELSE 'N'
				             END
				 ORDER BY YD_STK_LYR_NO DESC 
				        , YD_STK_COL_GP DESC                 
				)
				SELECT BB.* 
				  FROM ( 
				  --- 168 시간 이상
				        SELECT A.*
				          FROM TEMP_TBL A            
				      ) BB
				      WHERE 1=1
				        
				ORDER BY BB.TM DESC
				       , BB.SCH_GP
				       , BB.YD_STK_LYR_NO DESC 
				       , BB.YD_STK_COL_GP DESC
			*/
			JDTORecordSet jsStlMove = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdHotCoilMove", logId, mthdNm, "공냉재이적대상건수 검색");
			if( jsStlMove.size() < 1 ) {
				sMsg = "공냉재자동이적대상재 없음.";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		jrRtn.setField("RTN_CD"	, "1"); // 정상처리
	    		jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			JDTORecord jrStlMove = JDTORecordFactory.getInstance().create();
			String sStlNo        = "";
			String ydSchCd       = "";
			String sFirstWrkBook = "N";
			
			String sSchGp        = "";
			String sFirstSchCd   = "";
			
			for (int Loop_i = 1; Loop_i <= jsStlMove.size(); Loop_i++) {
				
				jsStlMove.absolute(Loop_i);
				jrStlMove = JDTORecordFactory.getInstance().create();
				jrStlMove = jsStlMove.getRecord();
			    
				sStlNo  = commUtils.trim(jrStlMove.getFieldString("STL_NO"));

				//ydSchCd = "J" + ydBayGp + "YD05MH";
				
				sSchGp  = commUtils.trim(jrStlMove.getFieldString("SCH_GP"));
				ydSchCd = "J" + ydBayGp + "YD0" + sSchGp + "MH";
				/*********************************
	    		 * 1.2 작업예약 등록
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

				jrParam.setField("YD_SCH_CD"			, ydSchCd				 );
				jrParam.setField("STL_SH"				, "1"					 ); // LINE_IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo				 );
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"					 );
				jrParam.setField("YD_AIM_YD_GP"			, "J"   				 );
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp				 );
				
				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				rtnCd		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	 = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
				
				/*********************************
				 * 첫번째 작업예약 스케쥴 기동
				 *********************************/
				if( Loop_i == 1 ) {
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
					/*
					SELECT YD_WBOOK_ID
					     , YD_SCH_CD
					  FROM TB_YD_CRNSCH
					 WHERE DEL_YN = 'N'
					   AND YD_SCH_CD = :V_YD_SCH_CD
					*/
					JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

					if( jsWrkBook.size() < 1 ) {
						
						// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
						/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
						SELECT A.YD_WBOOK_ID
						  FROM (SELECT WB.YD_WBOOK_ID
						             , SR.YD_SCH_DIV_GP
						          FROM TB_YD_SCHRULE SR
						              ,TB_YD_WRKBOOK WB
						         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
						           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
						           AND SR.YD_SCH_PROH_EXN = 'N'
						           AND SR.DEL_YN          = 'N'
						           AND WB.DEL_YN          = 'N'
						           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
						                                        FROM TB_YD_CRNSCH
						                                       WHERE DEL_YN = 'N')
						         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
						 WHERE ROWNUM = 1
						*/ 
						jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
						
						if (jsWrkBook != null && jsWrkBook.size() > 0) {
							ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
						} 
						//----------------------------------------------------------------------
					
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);							
						
						jrParam.setField("YD_SCH_CD"	, ydSchCd  ); 
						jrParam.setField("YD_WBOOK_ID"	, ydWbookId); 
						
						JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);
						
						rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
						rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
						
						if (!"1".equals(rtnCd)) {
							commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
							jrRtn.setField("RTN_CD"	, "0");	
				    		jrRtn.setField("RTN_MSG", sMsg);
							return jrRtn;
						} else {
							jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						}
						
		    			sMsg = "스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
			    		commUtils.printLog(logId, sMsg, "SL");
			    		sFirstWrkBook = "Y";
			    		sFirstSchCd = ydSchCd;
					}
				} else {
					//다른 스케쥴도 기동처리 할수있도록
					//D동을 스케쥴 2개임
					if( !ydSchCd.equals(sFirstSchCd)) {
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
						/*
						SELECT YD_WBOOK_ID
						     , YD_SCH_CD
						  FROM TB_YD_CRNSCH
						 WHERE DEL_YN = 'N'
						   AND YD_SCH_CD = :V_YD_SCH_CD
						*/
						JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

						if( jsWrkBook.size() < 1 ) {
							// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
							/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
							SELECT A.YD_WBOOK_ID
							  FROM (SELECT WB.YD_WBOOK_ID
							             , SR.YD_SCH_DIV_GP
							          FROM TB_YD_SCHRULE SR
							              ,TB_YD_WRKBOOK WB
							         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
							           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
							           AND SR.YD_SCH_PROH_EXN = 'N'
							           AND SR.DEL_YN          = 'N'
							           AND WB.DEL_YN          = 'N'
							           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
							                                        FROM TB_YD_CRNSCH
							                                       WHERE DEL_YN = 'N')
							         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
							 WHERE ROWNUM = 1
							*/ 
							jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
							
							if (jsWrkBook != null && jsWrkBook.size() > 0) {
								ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
							} 
							//----------------------------------------------------------------------
							
							jrParam = commUtils.getParam(logId, mthdNm, sModifier);							
							
							jrParam.setField("YD_SCH_CD"	, ydSchCd  ); 
							jrParam.setField("YD_WBOOK_ID"	, ydWbookId); 
							
							JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);
							
							rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
							rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
							
							if (!"1".equals(rtnCd)) {
								commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
								jrRtn.setField("RTN_CD"	, "0");	
					    		jrRtn.setField("RTN_MSG", sMsg);
								return jrRtn;
							} else {
								jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
							}
							
			    			sMsg = "스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
				    		commUtils.printLog(logId, sMsg, "SL");
				    		sFirstWrkBook = "Y";
				    		sFirstSchCd = ydSchCd;
						}
					}
				}
			}
				
			if( "Y".equals(sFirstWrkBook) ) {
				commUtils.printLog(logId, "명령선택기동 처리", "SL");
				EJBConnector sndConn = new EJBConnector("default", "CCommSeEJB", this);
				sndConn.trx("sndInterface", new Class[] { JDTORecord.class }, new Object[] { jrRtn });
			}
		
				
			sMsg = "공냉재자동이적 처리 완료.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}	
	
	
	/**
	 * 공냉재자동입고처리
	 * jsp에서 호출
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procJicMove(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "공냉재자동입고처리[CCoilJspSeEJ.procJicMove] < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			if (logId == null ) {
				logId = commUtils.getLogId();
			}
			
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);
			
			String sAppYn = coilDao.ApplyYn(logId, mthdNm, "APP302", "J", "*");
			commUtils.printLog(logId,  "==========[[[ APP302 공냉재 직송장 제품야드 입고 : "+ sAppYn +" ]]]============", "SL");
			if( "N".equals(sAppYn) ) {
				
				commUtils.printLog(logId, mthdNm, "S-");
	    		jrRtn.setField("RTN_CD", "0");
				return jrRtn;
			}
			
			String sModifier = commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String ydBayGp	 = commUtils.trim(rcvMsg.getFieldString("YD_BAY_GP"));
			String sMsg      = "";
			String rtnCd	 = "";
			String rtnMsg	 = "";
			String ydWbookId = "";

			if ("".equals(ydBayGp) ) {
				
				sMsg = "동구분이 없습니다.";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		jrRtn.setField("RTN_CD"	, "0");
	    		jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
						
			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_BAY_GP", ydBayGp);
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdJicMove
			SELECT A.YD_STK_COL_GP
			     , A.YD_STK_BED_NO
			     , A.YD_STK_LYR_NO
			     , A.STL_NO
			     , C.CURR_PROG_CD
			     , C.NEXT_PROC
			     , C.HRMILL_CMPL_DT
			  FROM TB_YD_STKLYR   A
			     , TB_YD_STKCOL   B
			     , TB_PT_COILCOMM C
			     , (SELECT ITEM_VALUE1 AS YD_STK_COL_GP
			          FROM TB_YD_RULE 
			         WHERE REPR_CD_GP LIKE 'APP032%'
			           AND DEL_YN  = 'N'
			       ) D 
			     , TB_YD_STOCK E
			 WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
			   AND A.YD_STK_COL_GP = D.YD_STK_COL_GP
			   AND A.STL_NO        = C.COIL_NO
			   AND A.STL_NO        = E.STL_NO
			   AND A.YD_STK_LYR_MTL_STAT = 'C'
			   AND B.YD_GP         = 'J'
			   AND B.YD_LOC_GP     = 'H'
			   AND B.YD_BAY_GP     = :V_YD_BAY_GP
			   AND A.DEL_YN        = 'N'
			   AND B.DEL_YN        = 'N'
			   AND C.CURR_PROG_CD  IN ( '3', 'H')
			   --직송장
			   AND 'Y' = CASE WHEN SUBSTR(C.NEXT_PROC,2,1) IN ('A')  
			              OR EXISTS (SELECT 1
			                           FROM TB_HR_C_SHEARWOWR SR
			                          WHERE SR.HR_PLNT_GP = 'C'
			                            AND SR.WORK_STAT  = '*'
			                            AND SR.WORD_PROC  LIKE '%A'
			                            AND SR.COIL_NO = C.COIL_NO
			                            AND SR.RECEIPT_HOLD_SCRAP_CAUSE_GP IN ('I','B')
			                            AND SR.STEP_NO = (SELECT MAX(STEP_NO)
			                                                FROM TB_HR_C_SHEARWOWR
			                                               WHERE COIL_NO = SR.COIL_NO) 
			                        ) THEN 'Y'
			             ELSE 'N' END
			                  
			   AND 'Y' = CASE WHEN TO_NUMBER(TRUNC((SYSDATE - NVL(HRMILL_CMPL_DT,COIL_CREATE_DDTT)) * 24)) < 72
			                  THEN 'N'
			                  ELSE 'Y'
			              END
			   AND A.STL_NO NOT IN ( SELECT B1.STL_NO 
			                           FROM TB_YD_CRNSCH A1
			                              , TB_YD_CRNWRKMTL B1
			                          WHERE A1.YD_CRN_SCH_ID = B1.YD_CRN_SCH_ID
			                            AND A1.DEL_YN = 'N'
			                            AND B1.DEL_YN = 'N'
			                       ) 
			   AND A.STL_NO NOT IN ( SELECT B1.STL_NO 
			                           FROM TB_YD_WRKBOOK A1
			                              , TB_YD_WRKBOOKMTL B1
			                          WHERE A1.YD_WBOOK_ID = B1.YD_WBOOK_ID
			                            AND A1.DEL_YN = 'N'
			                            AND B1.DEL_YN = 'N'
			                       ) 
			  -- 1단일 경우 상단에 코일이 작업을 하는 코일인지 CHECK                       
			   AND 'Y' =  CASE WHEN A.YD_STK_LYR_NO = '001' THEN 
			                   CASE WHEN NVL((SELECT STL_NO
			                                    FROM TB_YD_STKLYR
			                                   WHERE YD_STK_COL_GP = A.YD_STK_COL_GP 
			                                     AND YD_STK_BED_NO = LPAD(TO_NUMBER(A.YD_STK_BED_NO) - SF_YD_SKID_INTERVAL_GAP(A.YD_STK_COL_GP), 2, '0')   
			                                     AND YD_STK_LYR_NO = '002'
			                                 ),'E') IN ('E')
			                            
			                         AND  
			                             NVL((SELECT STL_NO
			                                    FROM TB_YD_STKLYR
			                                   WHERE YD_STK_COL_GP = A.YD_STK_COL_GP 
			                                     AND YD_STK_BED_NO = A.YD_STK_BED_NO  
			                                     AND YD_STK_LYR_NO = '002'
			                                 ),'E') IN ('E')
			                         THEN 'Y'         
			                         ELSE 'N' 
			                   END   
			              ELSE 'Y'
			              END
			ORDER BY A.YD_STK_LYR_NO DESC 
			*/
			JDTORecordSet jsStlMove = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdJicMove", logId, mthdNm, "공냉재자동입고 검색");
			if( jsStlMove.size() < 1 ) {
				sMsg = "공냉재자동입고 없음 .";
	    		commUtils.printLog(logId, sMsg, "SL");
	    		jrRtn.setField("RTN_CD"	, "1"); // 정상처리
	    		jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			JDTORecord jrStlMove = JDTORecordFactory.getInstance().create();
			String sStlNo        = "";
			String ydSchCd       = "";
			String sFirstWrkBook = "";
			for (int Loop_i = 1; Loop_i <= jsStlMove.size(); Loop_i++) {
				
				jsStlMove.absolute(Loop_i);
				jrStlMove = JDTORecordFactory.getInstance().create();
				jrStlMove = jsStlMove.getRecord();
			    
			    sStlNo  = commUtils.trim(jrStlMove.getFieldString("STL_NO"));

				ydSchCd = "J" + ydBayGp + "YD04MM"; 
				/*********************************
	    		 * 1.2 작업예약 등록
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

				jrParam.setField("YD_SCH_CD"			, ydSchCd				 );
				jrParam.setField("STL_SH"				, "1"					 ); // LINE_IN 재료매수
				jrParam.setField("STL_NO1"				, sStlNo				 );
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"					 );
				jrParam.setField("YD_AIM_YD_GP"			, "J"   				 );
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp				 );
				
				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });
				
				rtnCd		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	 = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
				
				/*********************************
				 * 첫번째 작업예약 스케쥴 기동
				 *********************************/
				if( Loop_i == 1 ) {
					
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
					/*
					SELECT YD_WBOOK_ID
					     , YD_SCH_CD
					  FROM TB_YD_CRNSCH
					 WHERE DEL_YN = 'N'
					   AND YD_SCH_CD = :V_YD_SCH_CD
					*/
					JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

					if( jsWrkBook.size() < 1 ) {
						
						// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
						/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
						SELECT A.YD_WBOOK_ID
						  FROM (SELECT WB.YD_WBOOK_ID
						             , SR.YD_SCH_DIV_GP
						          FROM TB_YD_SCHRULE SR
						              ,TB_YD_WRKBOOK WB
						         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
						           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
						           AND SR.YD_SCH_PROH_EXN = 'N'
						           AND SR.DEL_YN          = 'N'
						           AND WB.DEL_YN          = 'N'
						           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
						                                        FROM TB_YD_CRNSCH
						                                       WHERE DEL_YN = 'N')
						         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
						 WHERE ROWNUM = 1
						*/ 
						jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
						
						if (jsWrkBook != null && jsWrkBook.size() > 0) {
							ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
						} 
						//----------------------------------------------------------------------
					
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);							
						
						jrParam.setField("YD_SCH_CD"	, ydSchCd  ); 
						jrParam.setField("YD_WBOOK_ID"	, ydWbookId); 
						
						JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);
						
						rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
						rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
						
						if (!"1".equals(rtnCd)) {
							commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
							jrRtn.setField("RTN_CD"	, "0");	
				    		jrRtn.setField("RTN_MSG", sMsg);
							return jrRtn;
						} else {
							jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						}
						
		    			sMsg = "스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
			    		commUtils.printLog(logId, sMsg, "SL");
			    		sFirstWrkBook = "Y";
					}
				}
			}
			
			
			if( "Y".equals(sFirstWrkBook) ) {
				commUtils.printLog(logId, "명령선택기동 처리", "SL");
				EJBConnector sndConn = new EJBConnector("default", "CCommSeEJB", this);
				sndConn.trx("sndInterface", new Class[] { JDTORecord.class }, new Object[] { jrRtn });
			}
			
			sMsg = "직송재이적 처리 완료.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}		
	
	/**
	 * 수입 냉각제 정정보급존 자동이적
	 * jsp에서 호출
	 * /yd/hr2CoilYd/CCoilHotCoilSupMove.jsp
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 * @ejb.transaction type="RequiresNew"
	 */
	public JDTORecord procSupplyZoneMove(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "정정보급존 자동이적[CCoilJspSeEJ.procSupplyZoneMove] < " + rcvMsg.getResultMsg();

		String logId  = rcvMsg.getResultCode();
		
		if( logId == null ) {
			logId  = commUtils.getLogId();
		}
		
		commUtils.printParam(logId, rcvMsg);
		
		String sIfSnd     = commUtils.nvl(rcvMsg.getFieldString("IF_SEND"), "Y");
		String singleSend = commUtils.nvl(rcvMsg.getFieldString("SINGLE_SEND"), "N");
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);
			
			String sAPP103 = coilDao.ApplyYn(logId, mthdNm, "APP103", "J", "*");
			commUtils.printLog(logId, "정정보급존 자동이적 : "+ sAPP103, "SL");
			if( "N".equals(sAPP103) ) {
				jrRtn.setField("RTN_CD"	, "1");
				jrRtn.setField("RTN_MSG", "APP103 : "+ sAPP103);

				commUtils.printLog(logId, mthdNm, "S-");
				return jrRtn;
			}

			String sModifier	= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));

			String sMsg			= "";
			String rtnCd		= "";
			String rtnMsg		= "";
			String ydWbookId	= "";
			String ydBayGp		= "";
			String ydBayGpChk	= "";
			boolean bIfSendYn	= false;

			String sMaxMillWrkDt	= "";
			String ydStkColGp		= "";
			String ydStkBedNo		= "";
			String ydStkLyrNo		= "";
			String sStlNo			= "";
			String ydSchCd			= "";


			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMove
			WITH TB_COOLER AS (
			    -- 보급존 자동이적 적용 동, 냉각시간
			    SELECT CD_GP     AS YD_BAY_GP
			         , DTL_ITEM1 AS COOLTIME
			      FROM TB_YD_RULE
			     WHERE REPR_CD_GP = 'APP103'
			       AND ITEM  <> '*'
			       AND ITEM1  = 'Y'
			       AND DEL_YN = 'N'
			       AND LPAD(ITEM, 2, '0') = TO_CHAR(SYSDATE, 'MM')
			)
			, TB_COOLING_LOC AS (
			    -- 수입 저장영역별검색순서 정보
			    SELECT DISTINCT B.YD_STK_COL_GP
			         , COOLTIME
			      FROM TB_YD_LOCSRCHRNG A
			         , TB_YD_LOCSRCHBED B
			         , TB_COOLER        F
			     WHERE A.YD_LOC_SRCH_RNG_REG_SNO     = B.YD_LOC_SRCH_RNG_REG_SNO
			       AND SUBSTR(A.YD_SCH_CD, 2, 1)     = F.YD_BAY_GP
			       AND SUBSTR(B.YD_STK_COL_GP, 0, 1) = 'J'
			       AND A.YD_SCH_CD                LIKE 'J_CV01LH'
			       AND A.DEL_YN                      = 'N'
			       AND B.DEL_YN                      = 'N'
			       ----- SPM/HFL 수입위치
			       AND SUBSTR(A.YD_ROUTE_GP, 2, 1)  IN ('K', 'H') -- SPM/HFL 수입위치
			       ----- B,C동 HFL/공냉재 자동이적 없음
			       AND A.YD_ROUTE_GP            NOT IN ('BH', 'CH')
			       ----- G동 자동이적 없음
			       AND SUBSTR(A.YD_SCH_CD, 2, 1)    <> 'G'
			)
			, TB_COIL_INFO AS (
			    ----- 보급존 자동이적 대상재 -----
			    SELECT X1.*
			      FROM (
			            SELECT B.YD_BAY_GP
			                 , TRUNC( (SYSDATE - B.MAX_MILL_WRK_DT) * 24)          AS ELAPSED_TIME
			                 , TO_CHAR(B.MAX_MILL_WRK_DT, 'YYYY-MM-DD HH24:MI:SS') AS MAX_MILL_WRK_DT
			                 , ROW_NUMBER() OVER (PARTITION BY B.YD_BAY_GP
			                                          ORDER BY B.STK_SEQ
			--                                                 , A.YD_STK_LYR_NO DESC
			                                                 -- 1단인데 상단 코일 없을때
			                                                 , CASE WHEN A.YD_STK_LYR_NO = '002' THEN 1
			                                                        ELSE CASE WHEN (
			                                                                        SELECT COUNT(*) AS CNT
			                                                                          FROM TB_YD_STKLYR SL
			                                                                         WHERE SL.DEL_YN = 'N'
			                                                                           AND SL.YD_STK_COL_GP = A.YD_STK_COL_GP
			                                                                           AND 'Y' = CASE WHEN SL.YD_STK_BED_NO = LPAD(TO_NUMBER(A.YD_STK_BED_NO)-1, 2, '0')
			                                                                                           AND SL.YD_STK_LYR_NO = '002'
			                                                                                           AND SL.YD_STK_LYR_MTL_STAT IN ('C', 'D')
			                                                                                               THEN 'Y'
			                                                                                          WHEN SL.YD_STK_BED_NO = A.YD_STK_BED_NO
			                                                                                           AND SL.YD_STK_LYR_NO = '002'
			                                                                                           AND SL.YD_STK_LYR_MTL_STAT IN ('C', 'D')
			                                                                                               THEN 'Y'
			                                                                                          ELSE 'N'
			                                                                                     END
			                                                                       ) < 1 THEN 1
			                                                                  ELSE 2
			                                                             END
			                                                   END
			                                                 , C.COIL_W
			                                                 , A.YD_STK_BED_NO) AS WRK_SEQ
			                 , STK_SEQ
			                 , (SELECT YD_WBOOK_ID FROM TB_YD_WRKBOOKMTL WHERE STL_NO = A.STL_NO AND DEL_YN = 'N') AS YD_WBOOK_ID
			                 , A.YD_STK_COL_GP
			                 , A.YD_STK_BED_NO
			                 , A.YD_STK_LYR_NO
			                 , A.STL_NO
			                 , C.COIL_W
			                 ----- YD_SCH_CD 생성 -----------------------------------------
			                 , SUBSTR(A.YD_STK_COL_GP, 0, 2) ||
			                   CASE WHEN SUBSTR(A.YD_STK_COL_GP, 2, 1) IN ('B', 'C')
			                         AND TO_NUMBER(SUBSTR(A.YD_STK_COL_GP, 3, 2)) < 40
			                             THEN 'YD54MH' -- 2통로
			                        ELSE      'YD04MH' -- 1통로
			                   END AS YD_SCH_CD
			                 ----- YD_ROUTE_GP --------------------------------------------
			                 , CASE WHEN SUBSTR(C.NEXT_PROC,1,1) = SUBSTR(A.YD_STK_COL_GP, 2, 1)
			                         AND SUBSTR(C.NEXT_PROC,2,1) IN ('H','K','R','A')
			                             THEN C.NEXT_PROC -- 차공정
			                        -- 공냉재 ROUTE 처리 : 동별 SPM/HFL재와 같은 위치에 적치
			                        WHEN SUBSTR(C.PLAN_PROC1,1,1) = SUBSTR(A.YD_STK_COL_GP, 2, 1)
			                         AND SUBSTR(C.PLAN_PROC1,2,1) = 'A'
			                             THEN PLAN_PROC1
			                        ELSE SUBSTR(A.YD_STK_COL_GP, 2, 1) || 'Z'
			                   END AS YD_ROUTE_GP
			                 --------------------------------------------------------------
			              FROM TB_YD_STKLYR A
			                 , (-- 열단위 마지막 압연시간 체크
			                    SELECT A.YD_BAY_GP
			                         , MAX(C.HRMILL_CMPL_DT) AS MAX_MILL_WRK_DT
			                         , A.YD_STK_COL_GP
			                         , ROW_NUMBER() OVER(PARTITION BY A.YD_BAY_GP ORDER BY MAX(C.HRMILL_CMPL_DT)) AS STK_SEQ
			                      FROM (SELECT SUBSTR(AA.YD_STK_COL_GP, 2, 1) AS YD_BAY_GP
			                                 , AA.*
			                              FROM TB_YD_STKLYR AA
			                             WHERE YD_STK_COL_GP LIKE 'J%'
			                               AND STL_NO IS NOT NULL
			                               AND DEL_YN = 'N'
			                           ) A
			                         , USRPTA.TB_PT_COILCOMM C
			                         , TB_COOLING_LOC        F
			                     WHERE A.YD_STK_COL_GP = F.YD_STK_COL_GP
			                       AND A.STL_NO        = C.COIL_NO
			                       AND A.DEL_YN        = 'N'
			                     GROUP BY A.YD_BAY_GP, A.YD_STK_COL_GP
			                   ) B
			                 , USRPTA.TB_PT_COILCOMM C
			                 , TB_COOLER             F
			             WHERE A.YD_STK_COL_GP   = B.YD_STK_COL_GP
			               AND F.YD_BAY_GP       = SUBSTR(A.YD_STK_COL_GP, 2, 1)
			               AND A.STL_NO          = C.COIL_NO
			               AND C.CURR_PROG_CD   IN ('B', 'C')
			               AND A.DEL_YN          = 'N'
			               AND B.MAX_MILL_WRK_DT < (SYSDATE - (1 / 24 * F.COOLTIME))
			               ----- 수입받은 코일 이외 자동이적 금지.. 정규섭기사 요청
			--               AND C.YD_STR_LOC_HIS1 IS NULL
			               ----- 자동이적 외 작업예약 제외 ---------
			               AND NOT EXISTS (SELECT 1
			                                 FROM TB_YD_WRKBOOK    WB
			                                    , TB_YD_WRKBOOKMTL WM
			                                WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
			                                  AND WB.YD_SCH_CD NOT LIKE 'J_YD_4MH'
			                                  AND WB.YD_GP       = 'J'
			                                  AND WB.DEL_YN      = 'N'
			                                  AND WM.DEL_YN      = 'N'
			                                  AND WM.STL_NO      = A.STL_NO
			                              )
			               ----- 보급요구 예정 대상재 제외 ---------
			               AND A.STL_NO NOT IN (
			                                    SELECT H.COIL_NO
			--                                         , H.WORD_UNIT_NAME
			                                      FROM (
			                                            SELECT 
			                                                   ROW_NUMBER() OVER (PARTITION BY SUBSTR(HA.WORD_UNIT_NAME, 0, 2) ORDER BY HB.PUT_PRIOR, HA.WORD_UNIT_SEQNO) AS HR_SEQ
			                                                 , HB.PUT_PRIOR
			                                                 , HA.COIL_NO
			                                              FROM USRHRA.TB_HR_C_SHEARWOWR   HA
			                                                 , USRHRA.TB_HR_C_SHEARWOUNIT HB
			                                                 , TB_COOLER                  F
			                                                 , TB_YD_STKLYR               SL
			                                             WHERE 1=1
			                                               AND HA.WORD_UNIT_NAME = HB.WORD_UNIT_NAME(+)
			                                               AND HA.COIL_NO        = SL.STL_NO
			                                               AND SL.STL_NO IS NOT NULL
			                                               AND SL.DEL_YN         = 'N'
			                                               AND SUBSTR(SL.YD_STK_COL_GP,1,1) =  'J'
			                                               AND SL.YD_STK_COL_GP  LIKE 'J'|| F.YD_BAY_GP ||'%'
			                                               AND HA.PTOP_PLNT_GP   = 'HC'
			                                               AND HA.WORK_STAT      = '2'
			                                               AND HA.WORD_UNIT_NAME LIKE DECODE(F.YD_BAY_GP, 'A', 'AK'
			                                                                                            , 'B', 'BK'
			                                                                                            , 'C', 'CK'
			                                                                                            , 'D', 'DH'
			                                                                                            , 'E', 'EK'
			                                                                                            , 'H', 'HK'
			                                                                                            , 'XX') ||'%'
			                                               AND HA.STEP_NO      = (SELECT MAX(Y.STEP_NO)
			                                                                       FROM TB_HR_C_SHEARWOWR Y
			                                                                       WHERE Y.COIL_NO = HA.COIL_NO)
			                                           ) H
			                                     WHERE H.HR_SEQ <= 3
			                                   )
			               ----- 권상한 코일 제외 ---------
			               AND 'Y' = CASE WHEN (SELECT 1
			                                      FROM TB_YD_CRNSCH    AA
			                                         , TB_YD_CRNWRKMTL BB
			                                     WHERE AA.YD_GP         = 'J'
			                                       AND AA.YD_CRN_SCH_ID = BB.YD_CRN_SCH_ID
			                                       AND BB.STL_NO        = A.STL_NO
			                                       AND YD_WRK_PROG_STAT<> 'W'
			                                       AND AA.DEL_YN        = 'N') = 1 THEN 'N'
			                              ELSE 'Y'
			                         END
			           ) X1
			     WHERE 1=1
			       AND X1.YD_WBOOK_ID IS NULL
			       -- 작업예약 생성 갯수
			       AND X1.WRK_SEQ <= (SELECT MAX(DTL_ITEM1) FROM TB_YD_RULE WHERE REPR_CD_GP = 'APP103' AND CD_GP = 'J' AND ITEM = '*' AND DEL_YN = 'N')
			)
			, TB_TO_LOC AS (
			    -- 보급존 권하가능 위치 정보
			    SELECT A.YD_SCH_CD
			         , A.YD_ROUTE_GP
			         , COUNT(*) AS EMPTY_CNT
			         -- 버퍼 공간
			         , (SELECT TO_NUMBER(MAX(DTL_ITEM2))
			              FROM TB_YD_RULE
			             WHERE REPR_CD_GP = 'APP103'
			               AND CD_GP = 'J'
			               AND ITEM = '*'
			               AND DEL_YN = 'N'
			           ) AS DUMMY_CNT
			      FROM (
			            -- 정정보급존 자동이적 검색순서등록 위치
			            SELECT DISTINCT
			                   A.YD_SCH_CD
			                 , A.YD_ROUTE_GP
			                 , B.YD_STK_COL_GP
			              FROM TB_YD_LOCSRCHRNG A
			                 , TB_YD_LOCSRCHBED B
			                 , TB_COOLER        F
			             WHERE A.YD_LOC_SRCH_RNG_REG_SNO     = B.YD_LOC_SRCH_RNG_REG_SNO
			               AND SUBSTR(A.YD_SCH_CD, 2, 1)     = F.YD_BAY_GP
			               AND SUBSTR(B.YD_STK_COL_GP, 0, 1) = 'J'
			               AND A.YD_SCH_CD                LIKE 'J_YD_4MH'
			               AND A.DEL_YN                      = 'N'
			               AND B.DEL_YN                      = 'N'
			           ) A
			         , TB_YD_STKLYR B
			     WHERE A.YD_STK_COL_GP       = B.YD_STK_COL_GP
			       AND B.YD_STK_COL_GP    LIKE 'J%'
			       AND B.DEL_YN              = 'N'
			       AND B.YD_STK_LYR_ACT_STAT = 'E'
			       AND B.YD_STK_LYR_MTL_STAT = 'E'
			       AND B.YD_STK_LYR_NO       = '001'
			     GROUP BY A.YD_SCH_CD, A.YD_ROUTE_GP
			)
			SELECT A.YD_SCH_CD
			     , A.YD_ROUTE_GP
			     , A.YD_BAY_GP
			     , B.EMPTY_CNT
			     , B.DUMMY_CNT
			     , B.EMPTY_CNT - B.DUMMY_CNT AS LOC_CNT
			     , A.STK_SEQ
			     , A.WRK_SEQ
			     , A.ELAPSED_TIME
			     , A.MAX_MILL_WRK_DT
			     , A.YD_STK_COL_GP
			     , A.YD_STK_BED_NO
			     , A.YD_STK_LYR_NO
			     , A.STL_NO
			     , A.YD_WBOOK_ID
			  FROM TB_COIL_INFO A
			     , TB_TO_LOC    B
			 WHERE A.YD_SCH_CD   = B.YD_SCH_CD
			   AND A.YD_ROUTE_GP = B.YD_ROUTE_GP
			   AND A.WRK_SEQ    <= (B.EMPTY_CNT - B.DUMMY_CNT)
			 ORDER BY A.YD_SCH_CD, A.WRK_SEQ
			*/
			JDTORecordSet jsSupMvInfo = null;
			if("Y".equals(singleSend)){
				 jsSupMvInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMoveSingle", logId, mthdNm, "보급존 자동이적 대상재 조회");
                /*코일 적치갯수가 4개 이하 인 열에서 대상재 검색 기존 조건 유지*/
			}else{
				 jsSupMvInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMove", logId, mthdNm, "보급존 자동이적 대상재 조회");

			}
			
			int rowCnt = jsSupMvInfo.size();
			if( rowCnt < 1 ) {
				sMsg = "정정보급존 자동이적 대상재 ["+ rowCnt +"]건";
	    		commUtils.printLog(logId, sMsg, "SL");

	    		/****************************
				 *  log용
				 *****************************/
	    		
	    		JDTORecordSet jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMoveRetentionRate", logId, mthdNm, "보급존 자동이적 적치율조회");

				JDTORecord jrResult1 = JDTORecordFactory.getInstance().create();
				String  ydDong = "";
				String  ydDongRate = "";
				String  schLogContents = "";
				for (int i = 1; i <= jsResult.size(); i++) {
					jsResult.absolute(i);
					jrResult1  = jsResult.getRecord();
								
					ydDong 	= commUtils.trim(jrResult1.getFieldString("DONG"  ));
					ydDongRate 	= commUtils.trim(jrResult1.getFieldString("DONG_RATE"  ));
					
					schLogContents  = schLogContents + "[getYdSupplyZoneMoveRetentionRate] 정정보급존 자동이적 적치가능대상스판 적치율 = "+" 동:"+ ydDong+" 적치율:"+ydDongRate+"\r\n";
				}
				schLogContents = schLogContents+sMsg;
				
	    		JDTORecord jrLog  				= commUtils.getParam(logId, mthdNm, ""); 
				jrLog.setField("STL_NO"			, "");
				jrLog.setField("YD_CRN_SCH_ID"	, "");
				jrLog.setField("YD_GP"			, "J");
				jrLog.setField("YD_SCH_CD"		, "DongRate");
				jrLog.setField("SCH_CONTENTS"	, schLogContents );
				
	    		EJBConnector SchLog = new EJBConnector("default", "CCoilSchSeEJB", this);
				SchLog.trx( "insSchLog" , new Class[] { JDTORecord.class }, new Object[] { jrLog });

				
	    		//jrRtn.setField("RTN_CD"	, "0");
	    		//jrRtn.setField("RTN_MSG", sMsg);
	    		//commUtils.printLog(logId, mthdNm, "S-");
				//return jrRtn;
			}

			for( int i=0; i<rowCnt; i++ ) {
				sMaxMillWrkDt	= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("MAX_MILL_WRK_DT"));
				ydStkColGp		= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("YD_STK_COL_GP"));
				ydStkBedNo		= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("YD_STK_BED_NO"));
				ydStkLyrNo		= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("YD_STK_LYR_NO"));
				sStlNo			= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("STL_NO"));
				ydSchCd			= commUtils.trim(jsSupMvInfo.getRecord(i).getFieldString("YD_SCH_CD"));
				String ydStkLoc	= ydStkColGp+ydStkBedNo+"-"+ydStkLyrNo;

				sMsg = "["+ (i+1) +"/"+ rowCnt +"] 열마지막 압연시간["+ sMaxMillWrkDt +"] 저장위치["+ ydStkLoc +"] 코일번호["+ sStlNo +"] 스케쥴코드["+ ydSchCd +"]";
				commUtils.printLog(logId, sMsg, "SL");

				ydBayGp = ydStkColGp.substring(1, 2);

				/*********************************
	    		 * 1. 작업예약 등록
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

				jrParam.setField("YD_SCH_CD"			, ydSchCd	);
				jrParam.setField("STL_SH"				, "1"		);
				jrParam.setField("STL_NO1"				, sStlNo	);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"		);
				jrParam.setField("YD_AIM_YD_GP"			, "J"		);
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp	);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	 = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if( !"1".equals(rtnCd) ) {
					sMsg = "작업예약생성 실패 : YD_STK_COL_GP["+ ydStkLoc +"] STL_NO["+ sStlNo +"] RTN_MSG:"+ rtnMsg;
		    		commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);

		    		m_ctx.setRollbackOnly(); // ROLLBACK
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				sMsg = " >> ["+ (i+1) +"/"+ rowCnt +"] 동별 스케쥴기동 체크 ["+ ydBayGpChk +"/"+ ydBayGp +"] 작업에약ID["+ ydWbookId +"]";
				commUtils.printLog(logId, sMsg, "SL");
				/*********************************
	    		 * 2. 동별 스케쥴 1개 기동처리
	    		 *********************************/
				if( !ydBayGpChk.equals(ydBayGp) ) {
					ydBayGpChk = ydBayGp;
					
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
					/*
					SELECT YD_WBOOK_ID
					     , YD_SCH_CD
					  FROM TB_YD_CRNSCH
					 WHERE DEL_YN = 'N'
					   AND YD_SCH_CD = :V_YD_SCH_CD
					*/
					JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

					if( jsWrkBook.size() < 1 ) {
						
						// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
						/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
						SELECT A.YD_WBOOK_ID
						  FROM (SELECT WB.YD_WBOOK_ID
						             , SR.YD_SCH_DIV_GP
						          FROM TB_YD_SCHRULE SR
						              ,TB_YD_WRKBOOK WB
						         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
						           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
						           AND SR.YD_SCH_PROH_EXN = 'N'
						           AND SR.DEL_YN          = 'N'
						           AND WB.DEL_YN          = 'N'
						           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
						                                        FROM TB_YD_CRNSCH
						                                       WHERE DEL_YN = 'N')
						         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
						 WHERE ROWNUM = 1
						*/ 
						jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
						
						if (jsWrkBook != null && jsWrkBook.size() > 0) {
							ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
						} 
						//----------------------------------------------------------------------
						
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_SCH_CD"	, ydSchCd  );
						jrParam.setField("YD_WBOOK_ID"	, ydWbookId);

						JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);

						rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
						rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

						if (!"1".equals(rtnCd)) {
							commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
							jrRtn.setField("RTN_CD"	, "0");
				    		jrRtn.setField("RTN_MSG", sMsg);

				    		m_ctx.setRollbackOnly(); // ROLLBACK
				    		commUtils.printLog(logId, mthdNm, "S-");
							return jrRtn;

						} else {

							bIfSendYn = true;
							jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						}

		    			sMsg = " >> 스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
			    		commUtils.printLog(logId, sMsg, "SL");
			    	}
				}
			}
			
			if( "Y".equals(sIfSnd) ) {
	
				if( bIfSendYn ) {
					commUtils.printLog(logId, "명령선택기동 처리", "SL");
					EJBConnector sndConn = new EJBConnector("default", "CCommSeEJB", this);
					sndConn.trx("sndInterface", new Class[] { JDTORecord.class }, new Object[] { jrRtn });
				}
			}

			sMsg = "정정보급존 자동이적 처리완료.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	/**
	 * 보급존 적치율 75 이상 이고
	 * 트레킹 여유없음 이면 보급예정재 더미 이적
	 * YYS 20230814
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 * @ejb.transaction type="RequiresNew"
	 */
	public JDTORecord procSupplyZoneMoveDummy(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "보급예정재 더미 이적[CCoilJspSeEJ.procSupplyZoneMoveDummy] < " + rcvMsg.getResultMsg();

		String logId  = rcvMsg.getResultCode();
		
		if( logId == null ) {
			logId  = commUtils.getLogId();
		}
		
		commUtils.printParam(logId, rcvMsg);
		
		String sIfSnd       = commUtils.nvl(rcvMsg.getFieldString("IF_SEND"), "Y");
		String supZoneDummy = commUtils.nvl(rcvMsg.getFieldString("SUPZONE_DUMMY"), "N");
		String ydBayGp      = commUtils.nvl(rcvMsg.getFieldString("YD_BAY_GP"), "");
		
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);
			
			

			String sModifier	= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));

			String sMsg			= "";
			String rtnCd		= "";
			String rtnMsg		= "";
			String ydWbookId	= "";
			String ydBayGpChk	= "";
			boolean bIfSendYn	= false;

			String sMaxMillWrkDt	= "";
			String ydStkColGp		= "";
			String ydFromStkColGp	= "";
			String ydToStkColGp		= "";
			String ydStkBedNo		= "";
			String ydStkLyrNo		= "";
			String sStlNo			= "";
			String ydSchCd			= "";


			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
			           jrParam.setField("YD_BAY_GP",	  ydBayGp);
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMoveDummy
			    WITH TEMP_PARAM AS (
				SELECT  :V_YD_BAY_GP AS V_YD_BAY_GP
				 FROM DUAL 
				),
				TEMP_TO_LOC AS ( -- 영역별검색순서  
				
				SELECT BB.YD_STK_COL_GP
				           FROM (
				             SELECT  B.YD_STK_COL_GP ,B.YD_STK_BED_SRCH_SEQ                
				               FROM TB_YD_LOCSRCHRNG A
				                  , TB_YD_LOCSRCHBED B
				              WHERE A.YD_LOC_SRCH_RNG_REG_SNO = B.YD_LOC_SRCH_RNG_REG_SNO
				                AND (A.YD_SCH_CD  LIKE  'J_YD_4MH' OR A.YD_SCH_CD LIKE  'J_YD_8MH' )
				                AND B.YD_STK_COL_GP LIKE 'J%'
				                AND A.DEL_YN = 'N'
				                AND B.DEL_YN = 'N'            
				              ORDER BY B.YD_STK_BED_SRCH_SEQ
				              ) BB
				            WHERE 1=1             
				              GROUP BY BB.YD_STK_COL_GP
				)
				SELECT ----- YD_SCH_CD 생성 -----------------------------------------
				      SUBSTR(SR.YD_STK_COL_GP, 0, 2) || 'YD01MH' AS YD_SCH_CD    
				     ,SR.* 
				 FROM 
				  TB_YD_STKLYR SR
				  ,(
				   SELECT SL.YD_STK_COL_GP
				      ,SL.YD_STK_BED_NO
				      ,SL.YD_STK_LYR_NO
				          FROM TB_YD_STKLYR SL
				             , TB_YD_STKCOL SC
				             , TB_PT_COILCOMM  CC
				             , TEMP_PARAM TP
				         WHERE SC.YD_STK_COL_GP = SL.YD_STK_COL_GP 
				           AND SL.STL_NO        = CC.COIL_NO 
				           AND SC.YD_GP = 'J'
				           AND SC.YD_BAY_GP =  TP.V_YD_BAY_GP
				           AND SL.YD_STK_LYR_ACT_STAT = 'E'           
				           ----- 보급요구 예정 대상재 제외 ---------
				           AND SL.STL_NO IN (   
				                                 SELECT WM.STL_NO
				                                     FROM TB_YD_WRKBOOK    WB
				                                        , TB_YD_WRKBOOKMTL WM
				                                        , TB_YD_CRNSCH     AA
				                                    WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
				                                      AND WB.YD_WBOOK_ID = AA.YD_WBOOK_ID(+)
				                                      AND (WB.YD_SCH_CD LIKE 'J_KE01UH' OR WB.YD_SCH_CD LIKE 'J_FE01UH')
				                                      AND AA.YD_CRN_SCH_ID IS NULL
				                                      AND WB.YD_GP       = 'J'
				                                      AND WB.DEL_YN      = 'N'
				                                      AND WM.DEL_YN      = 'N'
				                               )
				           ----- 권상한 코일 제외 ---------
				           AND 'Y' = CASE WHEN (SELECT 1
				                                  FROM TB_YD_CRNSCH    AA
				                                     , TB_YD_CRNWRKMTL BB
				                                 WHERE AA.YD_GP         = 'J'
				                                   AND AA.YD_CRN_SCH_ID = BB.YD_CRN_SCH_ID
				                                   AND BB.STL_NO        = SL.STL_NO
				                                   AND YD_WRK_PROG_STAT<> 'W'
				                                   AND AA.DEL_YN        = 'N') = 1 THEN 'N'
				                          ELSE 'Y'
				                     END  
				  ) SA
				  WHERE SR.YD_STK_COL_GP = SA.YD_STK_COL_GP
				    AND SR.YD_STK_BED_NO IN (SA.YD_STK_BED_NO , SA.YD_STK_BED_NO-1)
				    AND SR.YD_STK_LYR_ACT_STAT = 'E'
				    AND SR.YD_STK_LYR_MTL_STAT = 'C'
				    AND SR.YD_STK_LYR_NO = '002'
				      ----- 작업예약 제외 ---------
				    AND NOT EXISTS (SELECT 1
				                     FROM TB_YD_WRKBOOK    WB
				                        , TB_YD_WRKBOOKMTL WM
				                    WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
				                      AND WB.YD_GP       = 'J'
				                      AND WB.DEL_YN      = 'N'
				                      AND WM.DEL_YN      = 'N'
				                      AND WM.STL_NO      = SR.STL_NO
				                  )
				    AND SR.STL_NO IS NOT NULL
			*/
			JDTORecordSet jsSupMvDummy  = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getYdSupplyZoneMoveDummy", logId, mthdNm, "보급예정재 더미 이적 조회");

			int rowCnt = jsSupMvDummy.size();

			for( int i=0; i<rowCnt; i++ ) {
				//sMaxMillWrkDt	= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("MAX_MILL_WRK_DT"));
				ydStkColGp		= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("YD_STK_COL_GP"));
				ydStkBedNo		= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("YD_STK_BED_NO"));
				ydStkLyrNo		= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("YD_STK_LYR_NO"));
				sStlNo			= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("STL_NO"));
				ydSchCd			= commUtils.trim(jsSupMvDummy.getRecord(i).getFieldString("YD_SCH_CD"));
				String ydStkLoc	= ydStkColGp+ydStkBedNo+"-"+ydStkLyrNo;

				sMsg = "["+ (i+1) +"/"+ rowCnt +"] 저장위치["+ ydStkLoc +"] 코일번호["+ sStlNo +"] 스케쥴코드["+ ydSchCd +"]";
				commUtils.printLog(logId, sMsg, "SL");

				ydBayGp = ydStkColGp.substring(1, 2);

				/*********************************
	    		 * 1. 작업예약 등록
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

				jrParam.setField("YD_SCH_CD"			, ydSchCd	);
				jrParam.setField("STL_SH"				, "1"		);
				jrParam.setField("STL_NO1"				, sStlNo	);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"		);
				jrParam.setField("YD_AIM_YD_GP"			, "J"		);
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp	);
				jrParam.setField("YD_SCH_PRIOR"	        , "0");
				jrParam.setField("SUPZONE_DUMMY"	    , supZoneDummy);
				jrParam.setField("TO_YD_STK_BED_NO"	    , ydStkColGp.substring(0, 4));				
				
				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				ydWbookId	 = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if( !"1".equals(rtnCd) ) {
					sMsg = "작업예약생성 실패 : YD_STK_COL_GP["+ ydStkLoc +"] STL_NO["+ sStlNo +"] RTN_MSG:"+ rtnMsg;
		    		commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);

		    		m_ctx.setRollbackOnly(); // ROLLBACK
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				sMsg = " >> ["+ (i+1) +"/"+ rowCnt +"] 동별 스케쥴기동 체크 ["+ ydBayGpChk +"/"+ ydBayGp +"] 작업에약ID["+ ydWbookId +"]";
				commUtils.printLog(logId, sMsg, "SL");
				/*********************************
	    		 * 2. 1개 기동처리
	    		 *********************************/
					
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
					/*
					SELECT YD_WBOOK_ID                       
						     , YD_SCH_CD   
						  FROM TB_YD_CRNSCH                    
						 WHERE DEL_YN='N'
						   AND YD_SCH_CD = :V_YD_SCH_CD
						   AND YD_WRK_PROG_STAT IN('W','S','1')
					*/
					JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

					if( jsWrkBook.size() < 1 ) {

						// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
						/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
						SELECT A.YD_WBOOK_ID
						  FROM (SELECT WB.YD_WBOOK_ID
						             , SR.YD_SCH_DIV_GP
						          FROM TB_YD_SCHRULE SR
						              ,TB_YD_WRKBOOK WB
						         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
						           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
						           AND SR.YD_SCH_PROH_EXN = 'N'
						           AND SR.DEL_YN          = 'N'
						           AND WB.DEL_YN          = 'N'
						           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
						                                        FROM TB_YD_CRNSCH
						                                       WHERE DEL_YN = 'N')
						         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
						 WHERE ROWNUM = 1
						*/ 
						jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
						
						if (jsWrkBook != null && jsWrkBook.size() > 0) {
							ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
						} 
						//----------------------------------------------------------------------
						
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_SCH_CD"	, ydSchCd  );
						jrParam.setField("YD_WBOOK_ID"	, ydWbookId);
						jrParam.setField("YD_SCH_PRIOR"	, "0");
						jrParam.setField("SUPZONE_DUMMY", supZoneDummy);
						
						JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);

						rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
						rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

						if (!"1".equals(rtnCd)) {
							commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
							jrRtn.setField("RTN_CD"	, "0");
				    		jrRtn.setField("RTN_MSG", sMsg);

				    		m_ctx.setRollbackOnly(); // ROLLBACK
				    		commUtils.printLog(logId, mthdNm, "S-");
							return jrRtn;

						} else {

							bIfSendYn = true;
							jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						}

		    			sMsg = " >> 스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
			    		commUtils.printLog(logId, sMsg, "SL");
			    	}
				}
			

			sMsg = "보급예정재 더미이적 처리완료.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 결로방지용 HOT COIL 반납장으로 자동이적
	 * jsp에서 호출
	 * /yd/hr2CoilYd/CCoilHotCoilCallLOC.jsp
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procHotCoilRetnMove(JDTORecord rcvMsg) throws DAOException {
		String mthdNm = "결로재HOTCOIL 반납장 자동이적[CCoilJspSeEJ.procHotCoilRetnMove] < " + rcvMsg.getResultMsg();

		String logId  = commUtils.getLogId();

		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

		try {
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId, rcvMsg);

			String sModifier	= commUtils.trim(rcvMsg.getFieldString("MODIFIER"));
			String sydBayGp		= commUtils.trim(rcvMsg.getFieldString("YD_BAY_GP"));
			
			if("".equals(sydBayGp)){
				sydBayGp = "*";
			}
			
			String sMsg			= "";
			String rtnCd		= "";
			String rtnMsg		= "";
			String ydBayGpChk	= "";
			boolean bIfSendYn	= false;
			
    		String sH00032_YN = coilDao.ApplyYn(logId, mthdNm, "H00032", sydBayGp , "*");
			commUtils.printLog(logId,  "==========[[[ H00032 2열연 결로ON/OFF : "+sydBayGp +"동, "+ sH00032_YN +" ]]]============", "SL");
			if( "N".equals(sH00032_YN) ) {

	    		jrRtn.setField("RTN_CD"	, "0");
	    		jrRtn.setField("RTN_MSG", sMsg);
	    		commUtils.printLog(logId, mthdNm, "S-");
				return jrRtn;
			}

			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getHotCoilRetnMove
			WITH TB_WAIT_COIL AS (
			    SELECT A.YD_BAY_GP
			         , SUM(WAIT_HOTCOIL) AS WAIT_HOTCOIL
			      FROM (
			            -- HOTCOIL 반납장으로 보급 크레인 작업예약 갯수
			            SELECT AA.YD_BAY_GP
			                 , COUNT(*) AS WAIT_HOTCOIL
			              FROM TB_YD_WRKBOOK AA
			             WHERE AA.YD_GP = 'J'
			               AND AA.DEL_YN = 'N'
			               AND AA.YD_BAY_GP IN ('B', 'C')
			               AND AA.YD_SCH_CD LIKE 'J_HC02LH'
			             GROUP BY AA.YD_BAY_GP
			            -- 반납장에서 결로존 보급 대기중인 코일 갯수
			            UNION ALL
			           SELECT BB.YD_BAY_GP
			                , COUNT(*) AS WAIT_HOTCOIL
			             FROM TB_YD_STKLYR          AA
			                , TB_YD_STKCOL          BB
			                , USRPTA.TB_PT_COILCOMM CC
			            WHERE AA.YD_STK_COL_GP = BB.YD_STK_COL_GP
			              AND AA.STL_NO        = CC.COIL_NO
			              AND BB.YD_GP         = 'J'
			              AND BB.YD_LOC_GP     = 'H'
			              AND BB.YD_BAY_GP    IN ('B', 'C')
			              AND AA.YD_STK_LYR_MTL_STAT = 'C'
			              AND CC.CURR_PROG_CD        = 'B'                   -- 지시대기
			              AND CC.COIL_W             <= 1400                  -- 압연실적폭 1400 이하
			              AND CC.HRMILL_CMPL_DT     >= SYSDATE - 1 / 24 * 10 -- 압연후 5시간 이내
			              AND CC.NEXT_PROC        LIKE '_K'                  -- 차공정 SPM
			              AND 'Y' = (SELECT ITEM1 FROM TB_YD_RULE WHERE REPR_CD_GP ='H00032') -- 결로재보급 ON
			              AND NOT EXISTS (SELECT 1 FROM TB_YD_CRNWRKMTL CC WHERE CC.STL_NO = AA.STL_NO AND CC.DEL_YN = 'N') -- 결로존보급 스케쥴 여부
			              AND BB.YD_EQP_GP BETWEEN '15' AND '17' --// 반납장 위치
			              AND AA.DEL_YN = 'N'
			              AND BB.DEL_YN = 'N'
			            GROUP BY BB.YD_BAY_GP
			           ) A
			     GROUP BY A.YD_BAY_GP
			)
			, TO_HOTCOIL_ZONE AS (
			    -- 결로보급존 비어있는 갯수에서 HOTCOIL 반납장 보급 작업 갯수 제외
			    SELECT A.YD_BAY_GP
			         , CASE WHEN A.IN_LOC_CNT < NVL(B.WAIT_HOTCOIL, 0) THEN 0
			                ELSE A.IN_LOC_CNT - NVL(B.WAIT_HOTCOIL, 0)
			           END AS IN_LOC_CNT
			      FROM (
			            SELECT BB.YD_BAY_GP
			                 , COUNT(*) AS IN_LOC_CNT
			              FROM TB_YD_STKLYR AA
			                 , TB_YD_STKCOL BB
			             WHERE AA.YD_STK_COL_GP = BB.YD_STK_COL_GP
			               AND BB.YD_GP         = 'J'
			               AND BB.YD_LOC_GP     = 'J'
			               AND BB.YD_BAY_GP    IN ('B', 'C')
			               AND SUBSTR(AA.YD_STK_COL_GP, 3, 2) BETWEEN '00' AND '17' -- 2통로
			               AND AA.YD_STK_LYR_ACT_STAT = 'S'
			               AND AA.YD_STK_LYR_MTL_STAT = 'E'
			               AND AA.STL_NO IS NULL
			               AND AA.DEL_YN = 'N'
			               AND BB.DEL_YN = 'N'
			             GROUP BY BB.YD_BAY_GP
			           ) A
			         , TB_WAIT_COIL B
			     WHERE A.YD_BAY_GP = B.YD_BAY_GP(+)
			     ORDER BY A.YD_BAY_GP
			)
			, TO_EMPTY_LOC AS (
			    SELECT A.YD_BAY_GP
			         , B.IN_LOC_CNT
			         , A.RETN_LOC_CNT
			         , CASE WHEN A.RETN_LOC_CNT < B.IN_LOC_CNT THEN A.RETN_LOC_CNT
			                ELSE B.IN_LOC_CNT
			           END AS MOVE_CNT
			      FROM (
			            SELECT SUBSTR(AA.YD_STK_COL_GP, 2, 1) AS YD_BAY_GP
			                 --*--*--*--*--*--*--*--*--*--
			                 --최소 이적위치 확보 3자리
			                 --*--*--*--*--*--*--*--*--*--
			                 , CASE WHEN COUNT(*) - 3 < 0 THEN 0
			                        ELSE COUNT(*) - 3
			                   END AS RETN_LOC_CNT
			--                 , COUNT(*) AS RETN_LOC_CNT
			              FROM TB_YD_STKLYR AA
			                 , (SELECT DISTINCT FF.YD_STK_COL_GP
			                         , FF.YD_STK_BED_NO
			                      FROM TB_YD_LOCSRCHRNG EE
			                         , TB_YD_LOCSRCHBED FF
			                     WHERE EE.YD_LOC_SRCH_RNG_REG_SNO = FF.YD_LOC_SRCH_RNG_REG_SNO
			                       AND EE.YD_SCH_CD LIKE 'J_HC02LH'
			                       AND SUBSTR(EE.YD_SCH_CD, 2, 1) IN ('B', 'C')
			                       AND EE.DEL_YN = 'N'
			                       AND FF.DEL_YN = 'N'
			                   ) BB
			             WHERE AA.YD_STK_COL_GP = BB.YD_STK_COL_GP
			               AND AA.YD_STK_BED_NO = BB.YD_STK_BED_NO
			               AND AA.YD_STK_LYR_ACT_STAT = 'E'
			               AND AA.YD_STK_LYR_MTL_STAT = 'E'
			               AND AA.DEL_YN = 'N'
			             GROUP BY SUBSTR(AA.YD_STK_COL_GP, 2, 1)
			           ) A
			         , TO_HOTCOIL_ZONE B
			     WHERE A.YD_BAY_GP = B.YD_BAY_GP
			)
			, TO_COIL_INFO AS (
			SELECT ROW_NUMBER() OVER (PARTITION BY YD_BAY_GP ORDER BY RANK, HRMILL_CMPL_DT DESC) AS SEQ -- 2단코일 우선, 최근 압연시간 정렬
			     , K.*
			  FROM (
			        SELECT B.YD_BAY_GP
			             , C.HRMILL_CMPL_DT
			             , A.STL_NO
			             , C.NEXT_PROC
			             , A.YD_STK_COL_GP
			             , A.YD_STK_BED_NO
			             , A.YD_STK_LYR_NO
			             , CASE WHEN A.YD_STK_LYR_NO = '002'
			                    THEN 1 -- 2단 우선
			                    WHEN A.YD_STK_LYR_NO = '001'
			                     AND 0 = (SELECT COUNT(*)
			                                FROM TB_YD_STKLYR AA
			                               WHERE AA.YD_STK_COL_GP = A.YD_STK_COL_GP
			                                 AND AA.YD_STK_LYR_NO = '002'
			                                 AND AA.STL_NO IS NOT NULL
			                                 AND 'Y' = CASE WHEN AA.YD_STK_BED_NO = LPAD(TO_NUMBER(A.YD_STK_BED_NO) - SF_YD_SKID_INTERVAL_GAP(A.YD_STK_COL_GP), 2, '0')
			                                                     THEN 'Y'
			                                                WHEN AA.YD_STK_BED_NO = A.YD_STK_BED_NO
			                                                     THEN 'Y'
			                                                ELSE 'N'
			                                           END)
			                    THEN 2 -- 1단 적치 중 상단 코일없음
			                    ELSE 9
			               END AS RANK
			          FROM TB_YD_STKLYR          A
			             , TB_YD_STKCOL          B
			             , USRPTA.TB_PT_COILCOMM C
			         WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
			           AND A.STL_NO        = C.COIL_NO
			           AND B.YD_GP         = 'J'
			           AND B.YD_LOC_GP     = 'H'
			           AND B.YD_BAY_GP    IN ('B', 'C')
			           AND B.YD_EQP_GP BETWEEN '01' AND '99'
			           -- 반납장 이적 코일 제외
			           AND 'Y' = CASE WHEN B.YD_BAY_GP = 'B' AND B.YD_EQP_GP IN ('15', '16') THEN 'N'
			                          WHEN B.YD_BAY_GP = 'C' AND B.YD_EQP_GP IN ('16', '17') THEN 'N'
			                          ELSE 'Y'
			                     END
			           AND A.YD_STK_LYR_MTL_STAT = 'C'
			           AND C.CURR_PROG_CD        = 'B'                   -- 지시대기
			           AND C.COIL_W             <= 1400                  -- 압연실적폭 1400 이하
			           AND C.HRMILL_CMPL_DT     >= SYSDATE - 1 / 24 * 5  -- 압연후 5시간 이내
			           AND (C.NEXT_PROC LIKE '%K' OR C.NEXT_PROC LIKE '%A')                -- 차공정 SPM
			           AND 'Y' = (SELECT ITEM1 FROM TB_YD_RULE WHERE REPR_CD_GP ='H00032') -- 결로재보급 ON
			           AND NOT EXISTS (SELECT 1 FROM TB_YD_WRKBOOKMTL CC WHERE CC.STL_NO = A.STL_NO AND CC.DEL_YN = 'N')
			           AND C.HR_SPEC_ABBSYM <> 'SPFH590Y'                                  -- 강종590Y 제외
			           AND A.DEL_YN = 'N'
			           AND B.DEL_YN = 'N'
			         ORDER BY RANK, C.HRMILL_CMPL_DT DESC
			    ) K
			)
			SELECT 'J'|| B.YD_BAY_GP || 'HC02LH' AS YD_SCH_CD
			     , A.SEQ
			     , A.YD_BAY_GP
			     , TO_CHAR(A.HRMILL_CMPL_DT, 'YYYY-MM-DD HH24:MI:SS') AS HRMILL_CMPL_DT
			     , A.STL_NO
			     , A.NEXT_PROC
			     , A.YD_STK_COL_GP
			     , A.YD_STK_BED_NO
			     , A.YD_STK_LYR_NO
			     , A.RANK
			     , B.MOVE_CNT
			     , B.IN_LOC_CNT   -- (HOTCOIL 결로존-반납장HOT코일-반납장이적작업예약)
			     , B.RETN_LOC_CNT -- (반납장 적치가능 갯수-3)
			  FROM TO_COIL_INFO A
			     , TO_EMPTY_LOC B
			 WHERE A.YD_BAY_GP = B.YD_BAY_GP
			   AND A.SEQ      <= B.MOVE_CNT
			 ORDER BY A.YD_BAY_GP, A.SEQ
			*/
			JDTORecordSet jsHotCoilMvInfo = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getHotCoilRetnMove", logId, mthdNm, "결로HOTCOIL 반납장 자동이적 대상재 조회");

			int rowCnt = jsHotCoilMvInfo.size();
			if( rowCnt < 1 ) {
				sMsg = "결로HOTCOIL 대상재 ["+ rowCnt +"]건";
	    		commUtils.printLog(logId, sMsg, "SL");

	    		jrRtn.setField("RTN_CD"	, "0");
	    		jrRtn.setField("RTN_MSG", sMsg);
	    		commUtils.printLog(logId, mthdNm, "S-");
				return jrRtn;
			}

			for( int i=0; i<rowCnt; i++ ) {
				String ydSchCd		= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("YD_SCH_CD"));
				String sSeq			= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("SEQ"));
				String ydBayGp		= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("YD_BAY_GP"));
				String sHrMillCmplDt= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("HRMILL_CMPL_DT"));

				String sStlNo		= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("STL_NO"));
				String ydStkColGp	= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("YD_STK_COL_GP"));
				String ydStkBedNo	= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("YD_STK_BED_NO"));
				String ydStkLyrNo	= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("YD_STK_LYR_NO"));

				String sRank		= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("RANK"));
				String sMoveCnt		= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("MOVE_CNT"));
				String sInLocCnt	= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("IN_LOC_CNT"));
				String sRetnLocCnt	= commUtils.trim(jsHotCoilMvInfo.getRecord(i).getFieldString("RETN_LOC_CNT"));


				String ydStkLoc	= ydStkColGp+ydStkBedNo+"-"+ydStkLyrNo;

				sMsg = "["+ (i+1) +"/"+ rowCnt +"] SEQ["+ sSeq +"] 압연시간["+ sHrMillCmplDt +"] 저장위치["+ ydStkLoc +"] 코일번호["+ sStlNo +"] 스케쥴코드["+ ydSchCd +"]";
				commUtils.printLog(logId, sMsg, "SL");
				sMsg = "  >> RANK["+ sRank +"] MOVE_CNT["+ sMoveCnt +"] IN_LOC_CNT["+ sInLocCnt +"] RETN_LOC_CNT["+ sRetnLocCnt +"]";
				commUtils.printLog(logId, sMsg, "SL");

				/*********************************
	    		 * 1. 작업예약 등록
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);

				jrParam.setField("YD_SCH_CD"			, ydSchCd	);
				jrParam.setField("STL_SH"				, "1"		);
				jrParam.setField("STL_NO1"				, sStlNo	);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"		);
				jrParam.setField("YD_AIM_YD_GP"			, "J"		);
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp	);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				String ydWbookId	 = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if( !"1".equals(rtnCd) ) {
					sMsg = "작업예약생성 실패 : YD_STK_COL_GP["+ ydStkLoc +"] STL_NO["+ sStlNo +"] RTN_MSG:"+ rtnMsg;
		    		commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);

		    		m_ctx.setRollbackOnly(); // ROLLBACK
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				sMsg = " >> ["+ (i+1) +"/"+ rowCnt +"] 동별 스케쥴기동 체크 ["+ ydBayGpChk +"/"+ ydBayGp +"] 작업에약ID["+ ydWbookId +"]";
				commUtils.printLog(logId, sMsg, "SL");
				/*********************************
	    		 * 2. 동별 스케쥴 1개 기동처리
	    		 *********************************/
				if( !ydBayGpChk.equals(ydBayGp) ) {
					ydBayGpChk = ydBayGp;

					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD", ydSchCd);//스케줄코드
					/*
					SELECT YD_WBOOK_ID
					     , YD_SCH_CD
					  FROM TB_YD_CRNSCH
					 WHERE DEL_YN = 'N'
					   AND YD_SCH_CD = :V_YD_SCH_CD
					*/
					JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "기동된 크레인스케쥴 조회");

					if( jsWrkBook.size() < 1 ) {

						// 2023.10.24 가장 최근 작업 예약 호출-------------------------------------------
						/* com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd 
						SELECT A.YD_WBOOK_ID
						  FROM (SELECT WB.YD_WBOOK_ID
						             , SR.YD_SCH_DIV_GP
						          FROM TB_YD_SCHRULE SR
						              ,TB_YD_WRKBOOK WB
						         WHERE SR.YD_SCH_CD       = WB.YD_SCH_CD
						           AND WB.YD_SCH_CD      = :V_YD_SCH_CD
						           AND SR.YD_SCH_PROH_EXN = 'N'
						           AND SR.DEL_YN          = 'N'
						           AND WB.DEL_YN          = 'N'
						           AND WB.YD_WBOOK_ID NOT IN (SELECT YD_WBOOK_ID
						                                        FROM TB_YD_CRNSCH
						                                       WHERE DEL_YN = 'N')
						         ORDER BY WB.YD_SCH_PRIOR, WB.YD_WBOOK_ID) A
						 WHERE ROWNUM = 1
						*/ 
						jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilSchSeEJB.getCrnSchWbookSchCd", logId, mthdNm, "작업예약 조회");
						
						if (jsWrkBook != null && jsWrkBook.size() > 0) {
							ydWbookId	= commUtils.trim(jsWrkBook.getRecord(0).getFieldString("YD_WBOOK_ID"));
						} 
						//----------------------------------------------------------------------
						
						jrParam = commUtils.getParam(logId, mthdNm, sModifier);
						jrParam.setField("YD_SCH_CD"	, ydSchCd  );
						jrParam.setField("YD_WBOOK_ID"	, ydWbookId);

						JDTORecord jrRunSch = (JDTORecord) this.trxRunSchedule(jrParam);

						rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
						rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

						if (!"1".equals(rtnCd)) {
							commUtils.printLog(logId, "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId, "SL");
							jrRtn.setField("RTN_CD"	, "0");
				    		jrRtn.setField("RTN_MSG", sMsg);

				    		m_ctx.setRollbackOnly(); // ROLLBACK
				    		commUtils.printLog(logId, mthdNm, "S-");
							return jrRtn;

						} else {

							bIfSendYn = true;
							jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						}

		    			sMsg = " >> 스케쥴 기동처리 - rtnCd["+ rtnCd +"] rtnMsg["+ rtnMsg +"] 작업예약ID["+ ydWbookId +"]";
			    		commUtils.printLog(logId, sMsg, "SL");
			    	}
				}
			}

			if( bIfSendYn ) {
				commUtils.printLog(logId, "명령선택기동 처리", "SL");
				EJBConnector sndConn = new EJBConnector("default", "CCommSeEJB", this);
				sndConn.trx("sndInterface", new Class[] { JDTORecord.class }, new Object[] { jrRtn });
			}

			sMsg = "결로재HOTCOIL 반납장 자동이적 처리완료.";
			commUtils.printLog(logId, sMsg, "SL");

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 공냉재자동이적 ON/OFF
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param inDto
	 * @return
	 * @throws DAOException
	 */
