	/**
	 *      [A] 오퍼레이션명 : 스크랩현황조회- 스크랩비우기
	 *
	 * 		@ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 *      @param GridData gdReq
	 *      @return JDTORecord
	 *      @throws DAOException
	*/
	public JDTORecord procClearScrap(GridData gdReq) throws DAOException {
		String mthdNm = "스크랩현황조회-스크랩비우기[CCoilJspSeEJB.procClearScrap] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sCOL_GP		   = commUtils.trim(gdReq.getParam("COL_GP"		   )); //삭제 동구분
			String sSCRAP_CLEAR_GP = commUtils.trim(gdReq.getParam("SCRAP_CLEAR_GP")); //삭제할 열 %: 전체삭제
			String sCOL_NO         = commUtils.trim(gdReq.getParam("COL_NO"        )); //삭제할 열 %: 전체삭제
			String sAREA_GP        = commUtils.trim(gdReq.getParam("AREA_GP"       )); //삭제할 지역
			String sARR_STL_NO     = commUtils.trim(gdReq.getParam("ARR_STOCK_ID"  )); //재료번호들
			
			
			commUtils.printLog(logId, "sCOL_GP:" + sCOL_GP, "SL");
			commUtils.printLog(logId, "sSCRAP_CLEAR_GP:" + sSCRAP_CLEAR_GP, "SL");
			commUtils.printLog(logId, "sCOL_NO:" + sCOL_NO, "SL");
			commUtils.printLog(logId, "sAREA_GP:" + sAREA_GP, "SL");
			commUtils.printLog(logId, "sARR_STL_NO:" + sARR_STL_NO, "SL");
			
			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));
			jrParam.setField("ARR_STL_NO"   , sARR_STL_NO  ); //재료번호들
			jrParam.setField("COL_NO"       , sCOL_NO      ); //열
			jrParam.setField("AREA_GP"      , sAREA_GP     ); //지역구분
			jrParam.setField("COL_GP"       , sCOL_GP      ); //동구분
			
			/*****************************************************
			 * 저장품제원 : 코일야드L2로 송신(YDY5L002)
			 ******************************************************/
			commUtils.printLog(logId, "YDY5L002 JMS전송", "SL");
			
			JDTORecordSet arrStock = null;
			if ("COL".equals(sSCRAP_CLEAR_GP)) {
				jrParam.setField("COL_GP"         , sCOL_GP+sCOL_NO      ); //동구분
				jrParam.setField("YD_STK_BED_NO"  , ""                   ); //bed구분
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getScrapStockByCol
				WITH DATA_TEMP AS (
				    SELECT A.YD_STK_COL_GP
				         , A.YD_STK_BED_NO
				         , A.YD_STK_LYR_NO
				      FROM TB_YD_STKLYR A
				         , TB_YD_RULE B
				     WHERE A.YD_STK_COL_GP = B.CD_GP
				       AND A.YD_STK_BED_NO = B.ITEM
				       AND B.REPR_CD_GP = 'SCRAP'
				       AND B.ITEM1     IN ('A', 'B', 'C', 'D')
				       AND B.CD_GP   LIKE :V_COL_GP
				       AND B.ITEM1   LIKE :V_AREA_GP
				     UNION ALL
				     --B구역일경우 전BED 2단 스크랩 삭제
				    SELECT MIN(CD_GP) AS YD_STK_COL_GP
				         , LPAD(TO_NUMBER(MIN(ITEM))-1, 2, '0') AS YD_STK_BED_NO
				         , '002' AS YD_STK_LYR_NO
				      FROM TB_YD_RULE 
				     WHERE REPR_CD_GP = 'SCRAP'
				       AND CD_GP   LIKE :V_COL_GP
				       AND ITEM1      = :V_AREA_GP
				       AND :V_AREA_GP IN ('B','C','D')
				)
				SELECT A.STL_NO
				  FROM TB_YD_STKLYR A
				     , DATA_TEMP    B
				 WHERE A.YD_STK_COL_GP = B.YD_STK_COL_GP
				   AND A.YD_STK_BED_NO = B.YD_STK_BED_NO
				   AND A.YD_STK_LYR_NO = B.YD_STK_LYR_NO
				   AND A.DEL_YN        = 'N'
				   AND A.STL_NO IS NOT NULL
				*/
				arrStock = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getScrapStockByCol", logId, mthdNm, "");
			} else {
				//작업예약과 스케줄대상재료는 제외하고 삭제 처리 진행
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockListByArrList 
				WITH DATA_TBL AS (
				  SELECT REGEXP_SUBSTR(SSTL_NOS, '[^,]+', 1, LEVEL) AS STL_NO
				    FROM (SELECT :V_ARR_STL_NO AS SSTL_NOS FROM DUAL)
				 CONNECT BY REGEXP_SUBSTR(SSTL_NOS, '[^,]+', 1, LEVEL) IS NOT NULL
				)
				SELECT STL_NO 
				  FROM DATA_TBL
				 WHERE STL_NO NOT IN (
				           SELECT B.STL_NO 
				             FROM TB_YD_WRKBOOK A,
				                  TB_YD_WRKBOOKMTL B,
				                  DATA_TBL C
				            WHERE A.YD_WBOOK_ID = B.YD_WBOOK_ID
				              AND B.STL_NO = C.STL_NO 
				              AND A.DEL_YN = 'N'
				              AND B.DEL_YN = 'N'
				            UNION ALL
				           SELECT B.STL_NO 
				             FROM TB_YD_CRNSCH A, 
				                  TB_YD_CRNWRKMTL B,
				                  DATA_TBL C
				            WHERE A.YD_CRN_SCH_ID = B.YD_CRN_SCH_ID 
				              AND B.STL_NO = C.STL_NO
				              AND A.DEL_YN = 'N'
				              AND B.DEL_YN = 'N'
				        )
				 */
				arrStock = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getStockListByArrList", logId, mthdNm, "");
			}
			
			for (int idx = 0; idx < arrStock.size(); ++idx) {
				JDTORecord jrYdMsg = JDTORecordFactory.getInstance().create();
				jrYdMsg.setField("JMS_TC_CD"      , "YDY5L002");
				jrYdMsg.setField("MSG_GP"         , "D"); 
				jrYdMsg.setField("YD_INFO_SYNC_CD", "5");
				jrYdMsg.setField("STL_NO"         , arrStock.getRecord(idx).getFieldString("STL_NO"));

				jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L002", jrYdMsg));			
			}
			
			/***************************
			 * 스크랩 비우기
			 ***************************/
			// 열단위 스크랩 삭제
			if ("COL".equals(sSCRAP_CLEAR_GP)) {
				for (int idx = 0; idx < arrStock.size(); ++idx) {
					JDTORecord jrScrList = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));
					jrScrList.setField("COL_GP"   , sCOL_GP+sCOL_NO      ); //동구분
					jrScrList.setField("STL_NO"   , arrStock.getRecord(idx).getFieldString("STL_NO"));	
					jrScrList.setField("DEL_YN"   , "Y");
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockDel
					UPDATE TB_YD_STOCK
					   SET DEL_YN   = :V_DEL_YN
					     , MODIFIER = :V_MODIFIER
					     , MOD_DDTT = SYSDATE
					 WHERE STL_NO   = :V_STL_NO
					 */
					commDao.update(jrScrList, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockDel", logId, mthdNm, "");
					
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapLyrByCol1
					UPDATE TB_YD_STKLYR
					   SET STL_NO              = NULL
					     , YD_STK_LYR_MTL_STAT = 'E'
					     , MODIFIER            = :V_MODIFIER
					     , MOD_DDTT            = SYSDATE
					 WHERE YD_STK_COL_GP    LIKE :V_COL_GP
					   AND STL_NO              = :V_STL_NO
					   AND YD_STK_LYR_MTL_STAT = 'C'
					*/
					commDao.update(jrScrList, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapLyrByCol1", logId, mthdNm, "");
				}
			}
			
			// 코일 단위 스크랩 삭제
			if ("STOCK".equals(sSCRAP_CLEAR_GP)) {
				for (int idx = 0; idx < arrStock.size(); ++idx) {
					
					JDTORecord jrScrList = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));
					jrScrList.setField("STL_NO"  , arrStock.getRecord(idx).getFieldString("STL_NO"));		
					jrScrList.setField("COL_GP"  , sCOL_GP);

					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapLyrByArrStockId                   
					UPDATE TB_YD_STKLYR
					   SET STL_NO           = NULL
					     , YD_STK_LYR_MTL_STAT = 'E'
					     , MODIFIER         = :V_MODIFIER
					     , MOD_DDTT         = SYSDATE
					 WHERE YD_STK_COL_GP LIKE :V_COL_GP||'%'
					   AND STL_NO           = :V_STL_NO
					 */
					commDao.update(jrScrList, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapLyrByArrStockId", logId, mthdNm, "");
					
					/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapStockByArrStockId          
					UPDATE TB_YD_STOCK
					   SET DEL_YN   = 'Y'
					     , MODIFIER = :V_MODIFIER
					     , MOD_DDTT = SYSDATE
					 WHERE STL_NO   = :V_STL_NO
					 */
					commDao.update(jrScrList, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updClearScrapStockByArrStockId", logId, mthdNm, "");
				}
			}
			
			commUtils.printLog(logId, mthdNm, "S-");
			
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "");
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}	
	/**
	 *      [A] 오퍼레이션명 : 스크랩현황조회- 스크랩생성
	 *
	 * 		@ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 *      @param GridData gdReq
	 *      @return JDTORecord
	 *      @throws DAOException
	*/
	public JDTORecord procCreateScrap(GridData gdReq) throws DAOException {
		String mthdNm = "스크랩현황조회-스크랩생성[CCoilJspSeEJB.procCreateScrap] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sARR_STL_NO   = commUtils.trim(gdReq.getParam("ARR_STOCK_ID"  )); //재료번호들
			String sCOL_GP		 = commUtils.trim(gdReq.getParam("COL_GP"		 )); //동구분
		
			commUtils.printLog(logId, "sARR_STL_NO:" + sARR_STL_NO, "SL");
			commUtils.printLog(logId, "sCOL_GP:" + sCOL_GP, "SL");
			
			String arrYdLoc[] = sARR_STL_NO.split(","); // ex)JHSC0209001,JHSC0210001
			int iRowCnt = arrYdLoc.length;
			
			for( int i=0; i<iRowCnt; i++ ) {
				commUtils.printLog(logId, "arrYdLoc["+ i +"]:"+ arrYdLoc[i] , "SL");
			}
			
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));
			jrParam.setField("ROWCNT", ""+iRowCnt);
			
			/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCrScrLyrByLoc
			SELECT A.STL_NO
			  FROM TB_YD_WRKHIST A
			     , TB_YD_STOCK   B
			 WHERE A.STL_NO       = B.STL_NO
			   AND A.YD_GP        = 'J'
			   AND A.YD_SCH_CD LIKE 'J_KD05LH'
			   AND A.YD_WRK_HDS_DD BETWEEN TO_CHAR(SYSDATE - 7,'YYYYMMDD') AND TO_CHAR(SYSDATE - 5,'YYYYMMDD')
			   AND A.DEL_YN       = 'N'
			   AND B.DEL_YN       = 'Y'
			   AND ROWNUM        <= :V_ROWCNT
			*/   
			JDTORecordSet jsLocList = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getCrScrLyrByLoc", logId, mthdNm, "대상재 조회");
			
			for( int i=0; i<jsLocList.size(); i++ ) {
				
				jrParam.setField("STL_NO", jsLocList.getRecord(i).getField("STL_NO"));
				jrParam.setField("COL_GP", sCOL_GP); //동구분
				jrParam.setField("YD_LOC", arrYdLoc[i]);
				
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insCrScrLyrByLoc
				UPDATE TB_YD_STKLYR
				   SET STL_NO           = :V_STL_NO
				     , YD_STK_LYR_MTL_STAT = 'C'
				     , MODIFIER         = :V_MODIFIER
				     , MOD_DDTT         = SYSDATE
				 WHERE YD_STK_COL_GP LIKE :V_COL_GP||'%'
				   AND YD_STK_COL_GP||YD_STK_BED_NO||YD_STK_LYR_NO = :V_YD_LOC
				   AND YD_STK_LYR_MTL_STAT = 'E'
				*/
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.insCrScrLyrByLoc", logId, mthdNm, "TB_YD_STKLYR 스크랩 생성");
				
				jrParam.setField("DEL_YN", "N");
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockDel
				UPDATE TB_YD_STOCK
				   SET DEL_YN   = :V_DEL_YN
				     , MODIFIER = :V_MODIFIER
				     , MOD_DDTT = SYSDATE
				 WHERE STL_NO   = :V_STL_NO
				*/
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdStockDel", logId, mthdNm, "TB_YD_STOCK 스크랩코일");
			}

			/*****************************************************
			 * 저장품제원 : 코일야드L2로 송신(YDY5L002)
			 ******************************************************/
			commUtils.printLog(logId, "YDY5L002 JMS전송", "[INFO]");
			
			for (int idx = 0; idx < jsLocList.size(); ++idx) {
				JDTORecord jrYdMsg = JDTORecordFactory.getInstance().create();
				jrYdMsg.setField("JMS_TC_CD"      , "YDY5L002");
				jrYdMsg.setField("MSG_GP"         , "I"); 
				jrYdMsg.setField("YD_INFO_SYNC_CD", "5");
				jrYdMsg.setField("STL_NO"       , jsLocList.getRecord(idx).getFieldString("STL_NO"));

				jrRtn = commUtils.addSndData(jrRtn, coilDao.getMsgL2("YDY5L002", jrYdMsg));			
			}

			commUtils.printLog(logId, mthdNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "");
			
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}	
	/**
	 * 스크랩 관련 RULE 수정
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord updYdRuleScrap(GridData gdReq) throws DAOException {
		String mthdNm = "스크랩 관련 RULE 수정[CCoilJspSeEJB.updYdRuleScrap] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));
	
			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();

			for (int ii = 0; ii < rowCnt; ii++) {
				//세부항목수정
				if(!commUtils.getValue(gdReq, "ITEM1", ii).equals("")){
					jrParam.setField("ITEM1"		, commUtils.getValue(gdReq, "ITEM1", ii) );
				}
				jrParam.setField("MODIFIER"		, gdReq.getParam("userid"));
				jrParam.setField("REPR_CD_GP"	, commUtils.getValue(gdReq, "REPR_CD_GP", ii) );
				jrParam.setField("CD_GP"		, commUtils.getValue(gdReq, "CD_GP", ii) );
				jrParam.setField("ITEM"			, commUtils.getValue(gdReq, "ITEM", ii));
				
				commUtils.printLog(logId, "REPR_CD_GP:" + commUtils.getValue(gdReq, "REPR_CD_GP", ii), "SL");
				commUtils.printLog(logId, "CD_GP:" + commUtils.getValue(gdReq, "CD_GP", ii), "SL");
				commUtils.printLog(logId, "ITEM:" + commUtils.getValue(gdReq, "ITEM", ii), "SL");
				
				/* com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdRuleScrap 
				UPDATE TB_YD_RULE
				   SET ITEM1 = NVL(:V_ITEM1, ITEM1)
				      ,MODIFIER = :V_MODIFIER
				      ,MOD_DDTT = SYSDATE
				 WHERE REPR_CD_GP = :V_REPR_CD_GP
				   AND CD_GP = :V_CD_GP
				   AND ITEM = :V_ITEM
			*/	   
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdRuleScrap", logId, mthdNm, "기준관리 수정");
			}
		
			commUtils.printLog(logId, mthdNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "");

			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	} 
	
