	/**
	 *      [A] 오퍼레이션명 : Scrap이적작업 예약 등록
	 *
	 * 		@ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 *      @param GridData gdReq
	 *      @return JDTORecord
	 *      @throws DAOException
	*/
	public JDTORecord updScrapMvStkWrkBook(GridData gdReq) throws DAOException {
		String mthdNm = "Scrap이적작업 예약 등록[CCoilJspSeEJB.updScrapMvStkWrkBook] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();
		JDTORecord jrRtn = JDTORecordFactory.getInstance().create();
		
		try {
			commUtils.printLog(logId, mthdNm, "S+");

			String sModifier    = commUtils.trim(gdReq.getParam("YD_USER_ID"));
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			String stlNos       = commUtils.trim(gdReq.getParam("ARR_STOCK_ID"    )); //재료번호들
			String ydStkColGp   = commUtils.trim(gdReq.getParam("YD_STK_COL_GP"   )); //야드적치열구분(4자리 이상)
			String ydToLocGuide = commUtils.trim(gdReq.getParam("YD_TO_LOC_GUIDE" )); //야드To위치Guide
			String ydWrkPlanCrn = commUtils.trim(gdReq.getParam("YD_WRK_PLAN_CRN" )); //야드지정크레인
			
			commUtils.printLog(logId, "stlNos:"+stlNos, "SL");
			commUtils.printLog(logId, "ydStkColGp:"+ydStkColGp, "SL");
			commUtils.printLog(logId, "ydToLocGuide:"+ydToLocGuide, "SL");
			commUtils.printLog(logId, "ydWrkPlanCrn:"+ydWrkPlanCrn, "SL");
			
			if (ydWrkPlanCrn.length() != 6) {
				ydWrkPlanCrn = "";
			}
			
			if (ydStkColGp.length() < 4) {
				//혹시 이적 적치열구분 값이 잘못되어 있으면 무조건 01 Span 으로 처리
				ydStkColGp = ydStkColGp.substring(0, 2) + "001";
			} else if (ydStkColGp.length() > 6) {
				ydStkColGp = ydStkColGp.substring(0, 6);
			}

			if ("".equals(stlNos)) {
				throw new Exception("이적 재료번호가 없습니다.");
			} else if ("".equals(ydStkColGp) || ydStkColGp.length() < 4) {
				throw new Exception("Span[" + ydStkColGp + "] 정보가 없습니다.");
			}
			
			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
			
			int    intStlCnt        = 0;
			int    intStlSchCnt     = 0;	
			String rtnCd            = "";
			String rtnMsg           = "";
			String ydWbookId        = "";
			String firstYdWbookId   = "";
			String sMsg             = "";
			
			/**********************************************************
			* 1. 스케줄코드 설정
			**********************************************************/
			String ydSchCd    = ""; //야드스케쥴코드
			String ydAimBayGp = ""; //야드목표동구분

			ydAimBayGp = ydStkColGp.substring(1, 2);
			
			if ("".equals(ydToLocGuide)) {
				//위치검색Bed기준 적용
			} else {
				//To위치가 동까지만 있으면 위치검색Bed 기준 적용
				if (ydToLocGuide.length() < 4) {
					ydToLocGuide = "";
				}
			}

			ydSchCd = ydStkColGp.substring(0, 2) + "SC01MH"; // 스크랩 이적
			
			//작업예약등록
			String sUpPos = "";
	        //2단  처리		
			for (int Loopi = 0; Loopi < rowCnt; Loopi++) {	
			
				sUpPos =  commUtils.nvl(commUtils.getValue(gdReq, "YD_STK_LYR_NO", Loopi),"");
				commUtils.printLog(logId, "sUpPos:"+sUpPos, "SL");
				
				if(sUpPos.substring(2, 3).equals("2")) {
					intStlCnt++;
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD"          , ydSchCd);//스케줄코드
					jrParam.setField("YD_AIM_BAY_GP"      , ydAimBayGp   ); //야드목표동구분
					jrParam.setField("STL_SH"             , "1");          
					jrParam.setField("STL_NO1"            , commUtils.nvl(commUtils.getValue(gdReq, "STL_NO", Loopi),""));
					jrParam.setField("YD_TO_LOC_DCSN_MTD" , "F");
							
					jrParam.setField("TO_YD_STK_BED_NO"   , ydToLocGuide);
					jrParam.setField("YD_UP_COLL_SEQ1"    , "1"); 
					jrParam.setField("YD_WRK_PLAN_TCAR"   , "");  
					jrParam.setField("YD_USER_ID"         , sModifier);  //권상모음순서
					jrParam.setField("YD_WRK_PLAN_CRN"    , ydWrkPlanCrn);  //작업 크레인
	
	
//					EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
//					JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBook", new Class[] { JDTORecord.class }, new Object[] { jrParam });
					
					JDTORecord jrWrkBook = this.insWrkBookSc(jrParam);
					rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
					rtnMsg	    = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
					ydWbookId   = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
					
					commUtils.printLog(logId, "작업예약:" +ydWbookId, "SL");
					
					if ("0".equals(rtnCd)) {
						sMsg = "작업예약 등록시 ERROR";
						commUtils.printLog(logId, sMsg, "SL");
						jrRtn.setField("RTN_CD"  , "0");	
						jrRtn.setField("RTN_MSG" , rtnMsg);	
						
						return jrRtn;
					} else {
						intStlSchCnt++;
						
						if (intStlSchCnt == 1) {
							firstYdWbookId = ydWbookId;
						}
						jrRtn.setField("RTN_CD"  , "1");	
						jrRtn.setField("RTN_MSG" , rtnMsg + " <br> 정상적으로 작업예약까지 등록했습니다.");	
								
					}
				}	
			}
	
	//1단  처리		
			for (int Loopi = 0; Loopi < rowCnt; Loopi++) {	
				//재료번호
				//STL_NO []
				sUpPos =  commUtils.nvl(commUtils.getValue(gdReq, "YD_STK_LYR_NO", Loopi),"");
				commUtils.printLog(logId, "sUpPos:"+sUpPos, "SL");
				if(sUpPos.substring(2, 3).equals("1")) {
					intStlCnt++;
					jrParam = commUtils.getParam(logId, mthdNm, sModifier);
					jrParam.setField("YD_SCH_CD"         , ydSchCd);//스케줄코드
					jrParam.setField("STL_SH"            , "1");  //LINE_IN 재료매수
					jrParam.setField("STL_NO1"           , commUtils.nvl(commUtils.getValue(gdReq, "STL_NO", Loopi),""));
					jrParam.setField("YD_TO_LOC_DCSN_MTD", "F");
							
					jrParam.setField("TO_YD_STK_BED_NO"  , ydToLocGuide);
					jrParam.setField("YD_UP_COLL_SEQ1"   , "1");  //권상모음순서
					jrParam.setField("YD_WRK_PLAN_TCAR"  , "");  //권상모음순서
					jrParam.setField("YD_USER_ID"        , sModifier);  //권상모음순서
					jrParam.setField("YD_WRK_PLAN_CRN"    , ydWrkPlanCrn);  //작업 크레인
	
//					EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
//					JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBook", new Class[] { JDTORecord.class }, new Object[] { jrParam });
					JDTORecord jrWrkBook = this.insWrkBookSc(jrParam);
					
					rtnCd		= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
					rtnMsg	    = commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
					ydWbookId   = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");
					
					commUtils.printLog(logId, "첫작업예약:" +ydWbookId, "SL");
					if ("0".equals(rtnCd)) {
						sMsg = "작업예약 등록시 ERROR";
						commUtils.printLog(logId, sMsg, "SL");
						jrRtn.setField("RTN_CD"  , "0");	
						jrRtn.setField("RTN_MSG" , rtnMsg);	
						
						return jrRtn;
					} else {
						intStlSchCnt++;
						
						if (intStlSchCnt == 1) {
							firstYdWbookId = ydWbookId;
						}
						jrRtn.setField("RTN_CD"  , "1");	
						jrRtn.setField("RTN_MSG" , rtnMsg + " <br> 정상적으로 작업예약까지 등록했습니다.");	
								
					}
					
					commUtils.printLog(logId, "첫작업예약:" +firstYdWbookId, "SL");
					
				}	
			}
		
				
			if(!firstYdWbookId.equals("")) {
				//재료번호
				jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD",  ydSchCd);//스케줄코드
				/*
				 * SELECT YD_WBOOK_ID                       
				     , YD_SCH_CD   
				  FROM TB_YD_CRNSCH                    
				 WHERE DEL_YN='N'
				   AND YD_SCH_CD = :V_YD_SCH_CD
				 */
				JDTORecordSet jsYdCrnSch = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.getWorkTbRefNONESchCd", logId, mthdNm, "크레인 작업지시");
	
		    	if(jsYdCrnSch == null || jsYdCrnSch.size() < 1) {
		    		
		    		JDTORecord jrRecordarr = commUtils.getParam(logId, mthdNm, sModifier);
		    		jrRecordarr.setField("YD_SCH_CD"		, ydSchCd); 
		    		jrRecordarr.setField("YD_WBOOK_ID"	    , firstYdWbookId); 
					
					JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrRecordarr);
					rtnCd	= commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
					rtnMsg	= commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");
					commUtils.printLog(logId, ">>>>>>>>>:" +rtnMsg, "SL");
					
					if (!("1".equals(rtnCd))) {
						jrRtn.setField("RTN_CD" 			, "0");	
						jrRtn.setField("RTN_MSG"			, rtnMsg );	
						
						return jrRtn;
					} else {
		
						jrRtn = commUtils.addSndData(jrRtn, jrRunSch);
						jrRtn.setField("RTN_CD" 			, "1");	
						jrRtn.setField("RTN_MSG"			, rtnMsg + " <br> 정상적으로 스케쥴까지 등록했습니다." );	
					} 	
		    	}	
			}
				
			
			commUtils.printLog(logId, mthdNm, "S-");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "");
			
			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	}
	
	/**
	 * 오퍼레이션명 : C열연 작업예약 생성 모든 소스는 여기로 호출하도록 WrkBookInsertProc
	 * 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @p aram JDTORecord rcvMsg
	 * @return JDTORecord
	 * @throws DAOException
	 * 
	 */
	public JDTORecord insWrkBookSc(JDTORecord rcvMsg) throws DAOException  {
		String mthdNm = "작업예약생성[CCoilJspSeEJB.insWrkBookSc] < " + rcvMsg.getResultMsg();
		String logId  = rcvMsg.getResultCode();
		
		JDTORecord	  jrRtn	   = JDTORecordFactory.getInstance().create(); //
		JDTORecordSet jsResult = JDTORecordFactory.getInstance().createRecordSet("");

		String sMsg	= "";

		try	{
			commUtils.printLog(logId, mthdNm, "S+");
			commUtils.printParam(logId,	rcvMsg);

			String ydSchCd			 	= commUtils.trim(rcvMsg.getFieldString("YD_SCH_CD"		   )); //스케줄	코드
			String sStlSh				= commUtils.nvl	(rcvMsg.getFieldString("STL_SH"			   ), "0");	//재료매수
			int	iStlSh					= Integer.parseInt(sStlSh);

			String sToYdStkBedNo	 	= commUtils.trim(rcvMsg.getFieldString("TO_YD_STK_BED_NO"  ));
			String ydToLocDcsnMtd 		= commUtils.trim(rcvMsg.getFieldString("YD_TO_LOC_DCSN_MTD"));
			String ydAimGp 				= commUtils.trim(rcvMsg.getFieldString("YD_AIM_YD_GP"	   ));
			String ydAimBayGp	 		= commUtils.trim(rcvMsg.getFieldString("YD_AIM_BAY_GP"	   ));
			String ydWrkPlanTcar	 	= commUtils.trim(rcvMsg.getFieldString("YD_WRK_PLAN_TCAR"  ));
			String sCardNo				= commUtils.trim(rcvMsg.getFieldString("CARD_NO"		   ));
			String ydCarUseGp			= commUtils.trim(rcvMsg.getFieldString("YD_CAR_USE_GP"	   ));
			String sDistShipassignGp	= commUtils.trim(rcvMsg.getFieldString("DIST_SHIPASSIGN_GP"));
			String sCarNo				= commUtils.trim(rcvMsg.getFieldString("CAR_NO"			   ));
			String sTrnEqpCd			= commUtils.trim(rcvMsg.getFieldString("TRN_EQP_CD"		   ));
			String sIsptor				= commUtils.trim(rcvMsg.getFieldString("ISPTOR"			   ));
			String sTakeOutDt			= commUtils.trim(rcvMsg.getFieldString("TAKE_OUT_DT"	   ));
			String stakeOutCd			= commUtils.trim(rcvMsg.getFieldString("TAKE_OUT_CD"	   ));
			String ydWrkPlanCrn			= commUtils.trim(rcvMsg.getFieldString("YD_WRK_PLAN_CRN"	   ));
			String sModifier   			= commUtils.trim(rcvMsg.getFieldString("MODIFIER" )); //수정자(Backup Only)
			if ("".equals(sModifier)) {	sModifier =	"";	}

			String[] sStlNo			   	= new String[100]; //재료번호
			String[] ydUpCollSeq		= new String[100]; //권상모음순서

			String sWrkCrn	   	= "";//야드작업크레인
			String ydSchPrior	= "";//야드작업크레인우선순위
			String ydWbookId 	= "";//작업예약ID

//			DAO	Parameter -	Log	ID,	Method,	수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, commUtils.trim(sModifier));

			/**********************************************************
			* 0. 항목 값 Check
			**********************************************************/
			//스케줄 코드
			if ("".equals(ydSchCd))	{
				sMsg = "스케줄코드가 없습니다.";
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}
			//재료매수
			if (iStlSh == 0) {
				sMsg = "재료매수가 없습니다.";
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			/**********************************************************
			* 1. 스케줄코드	Check
			**********************************************************/
			//스케줄코드
			jrParam.setField("YD_SCH_CD", ydSchCd);
			/*
			SELECT YD_SCH_CD
				 , DEL_YN
				 , YD_GP
				 , YD_BAY_GP
				 , YD_SCH_RNG_CD
				 , YD_SCH_WHIO_GP
				 , YD_SCH_DIV_GP
				 , YD_SCH_RULE_ACT_STAT
				 , YD_WRK_CRN
				 , YD_WRK_CRN_PRIOR
				 , YD_ALT_CRN_YN
				 , YD_ALT_CRN
				 , YD_ALT_CRN_PRIOR
				 , CD_CONTENTS
				 , YD_SCH_PROH_EXN
			  FROM TB_YD_SCHRULE
			 WHERE 1 = 1
			   AND YD_GP IN	('H','J')
			   AND YD_SCH_CD = :V_YD_SCH_CD
			   AND DEL_YN	 = 'N'
			 */
			jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdSchRule", logId, mthdNm, "스케줄기준 조회");

			//리턴값 메세지처리
			if (jsResult.size()	<= 0) {
				sMsg = "스케줄코드(" + ydSchCd + ")에 대한 스케줄기준 데이터가 이상합니다.";
				commUtils.printLog(logId, sMsg,	"SL");
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			//레코드 추출
			jsResult.absolute(1);

			String ydGp			   	= commUtils.trim(jsResult.getRecord().getFieldString("YD_GP"		   )); //야드구분
			String ydBayGp		  	= commUtils.trim(jsResult.getRecord().getFieldString("YD_BAY_GP"	   )); //동구분
			String ydSchProhExn	  	= commUtils.trim(jsResult.getRecord().getFieldString("YD_SCH_PROH_EXN" )); //스케줄	금지 유무
			String ydWrkCrn		  	= commUtils.trim(jsResult.getRecord().getFieldString("YD_WRK_CRN"	   )); //작업크레인
			String ydWrkCrnPrior 	= commUtils.trim(jsResult.getRecord().getFieldString("YD_WRK_CRN_PRIOR")); //작업크레인우선순위
			String ydAltCrnYn	 	= commUtils.trim(jsResult.getRecord().getFieldString("YD_ALT_CRN_YN"   )); //대체크레인유무
			String ydAltCrn		  	= commUtils.trim(jsResult.getRecord().getFieldString("YD_ALT_CRN"	   )); //대체크레인
			String ydAltCrnPrior	= commUtils.trim(jsResult.getRecord().getFieldString("YD_ALT_CRN_PRIOR")); //대체크레인우선순위

			//스케줄 금지 유무가 "Y"이면 처리를	중지
			if ("Y".equals(ydSchProhExn)) {
				sMsg = "스케줄 금지 유무가 [Y] 입니다";
				commUtils.printLog(logId, sMsg,	"SL");
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			//야드 목적동
			if ("".equals(ydAimBayGp)) {
				if (!"".equals(sToYdStkBedNo)) {
					if (sToYdStkBedNo.length() ==  6) {
						ydAimBayGp = sToYdStkBedNo.substring(1,	2);
					} else if (sToYdStkBedNo.length() ==  8) {
						ydAimBayGp = sToYdStkBedNo.substring(1,	2);
					}
				}
			}

			if (!"".equals(ydWrkPlanCrn))	{
				ydWrkCrn = ydWrkPlanCrn;
			}

			/**********************************************************
			* 2. 작업크레인	체크
			**********************************************************/
			//작업크레인 설비 상태 체크
			boolean	blnRtnVal =	coilDao.chkEqpStat(logId, mthdNm, ydWrkCrn);

			commUtils.printLog(logId, "blnRtnVal:"+ blnRtnVal, "SL");

			// 스케쥴 작업크레인 Default
			sWrkCrn	   = ydWrkCrn;
			ydSchPrior = ydWrkCrnPrior;
			
			//작업크레인이 사용불가이면 대체크레인의 상태를 체크한다.
			if (!blnRtnVal)	{

				sMsg = "작업크레인("+ ydWrkCrn +")이 사용 불가 상태입니다.";
				commUtils.printLog(logId, sMsg,	"SL");

				//대체크레인의 유무	체크
				if (!"Y".equals(ydAltCrnYn)) {
					sMsg = "대체크레인유무("+ ydAltCrnYn +"), 대체크레인이 없습니다.";
					commUtils.printLog(logId, sMsg,	"SL");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
				}

				//대체크레인이 있으면 대체크레인 설비 상태 체크
				blnRtnVal =	coilDao.chkEqpStat(logId, mthdNm, ydAltCrn);

				//대체크레인 사용여부
				if (!blnRtnVal)	{
					sMsg = "대체크레인("+ ydAltCrn +")이 사용 불가 상태입니다.";
					commUtils.printLog(logId, sMsg,	"SL");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
				} else {
					//대체크레인이 사용가능하면	설비사양 파라미터에	대체크레인의 설비ID를 세팅한다.
					sWrkCrn	   = ydAltCrn;
					ydSchPrior = ydAltCrnPrior;
				}
			}

			/**********************************************************
			* 3. 작업재료 check
			**********************************************************/
			//다른 작업예약에 재료가 등록되어있는지	체크한다.
			for	(int ii	= 1; ii	<= iStlSh; ii++) {

				sStlNo[ii] 			= commUtils.trim(rcvMsg.getFieldString("STL_NO"		   +ii));
				ydUpCollSeq[ii]		= commUtils.trim(rcvMsg.getFieldString("YD_UP_COLL_SEQ"+ii));

				/*
				SELECT A.YD_WBOOK_ID		 AS	YD_WBOOK_ID
					  ,A.DEL_YN				 AS	DEL_YN
					  ,A.YD_GP				 AS	YD_GP
					  ,A.YD_BAY_GP			 AS	YD_BAY_GP
					  ,A.YD_SCH_CD			 AS	YD_SCH_CD
					  ,A.YD_SCH_PRIOR		 AS	YD_SCH_PRIOR
					  ,A.YD_SCH_PROG_STAT	 AS	YD_SCH_PROG_STAT
					  ,A.YD_SCH_ST_GP		 AS	YD_SCH_ST_GP
					  ,A.YD_SCH_REQ_GP		 AS	YD_SCH_REQ_GP
					  ,A.YD_AIM_YD_GP		 AS	YD_AIM_YD_GP
					  ,A.YD_AIM_BAY_GP		 AS	YD_AIM_BAY_GP
					  ,A.YD_CTS_RELAY_YN	 AS	YD_CTS_RELAY_YN
					  ,A.YD_CTS_RELAY_BAY_GP AS	YD_CTS_RELAY_BAY_GP
					  ,A.YD_TO_LOC_DCSN_MTD	 AS	YD_TO_LOC_DCSN_MTD
					  ,A.YD_TO_LOC_GUIDE	 AS	YD_TO_LOC_GUIDE
					  ,B.STL_NO				 AS	STL_NO
					  ,B.YD_STK_COL_GP		 AS	YD_STK_COL_GP
					  ,B.YD_STK_BED_NO		 AS	YD_STK_BED_NO
					  ,B.YD_STK_LYR_NO		 AS	YD_STK_LYR_NO
					  ,B.YD_UP_COLL_SEQ		 AS	YD_UP_COLL_SEQ
				  FROM TB_YD_WRKBOOK	A
					  ,TB_YD_WRKBOOKMTL	B
				 WHERE A.YD_WBOOK_ID = B.YD_WBOOK_ID
				   AND A.DEL_YN	= 'N'
				   AND B.DEL_YN	= 'N'
				   AND B.STL_NO	= :V_STL_NO
				 */
				jrParam.setField("STL_NO", sStlNo[ii]);
				jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdWrkbookmtlSTLNO", logId, mthdNm, "작업예약조회");

				//리턴값 메세지처리
				if (jsResult.size()	> 0) {
					sMsg = "재료번호("+ sStlNo[ii] +")로 작업예약재료 등록되어 있습니다.!";
					commUtils.printLog(logId, sMsg,	"SL");
					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", sMsg);
					return jrRtn;
				}
			} //END	FOR


			/**********************************************************
			* 4. 작업예약 생성
			**********************************************************/
			//작업예약 Id생성
			ydWbookId =	coilDao.getSeqId(logId,	mthdNm,	"WrkBook");

			if ("".equals(ydWbookId)) {
				throw new Exception("작업예약ID 생성 실패");
			}


			//저장품 조회 (목표동 및 목표야드 조회)
			jrParam.setField("STL_NO", sStlNo[1]); // 일단첫코일 기준으로

			JDTORecordSet rsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdStock", logId, mthdNm, "저장품 조회");

			if (rsResult.size()	<= 0) {
				sMsg="getYdStock : data	not	found";
				jrRtn.setField("RTN_CD"	, "0");
				jrRtn.setField("RTN_MSG", sMsg);
				return jrRtn;
			}

			if ("".equals(ydAimGp))	{
				ydAimGp		= commUtils.trim(rsResult.getRecord(0).getFieldString("YD_AIM_YD_GP"));
			}
			if ("".equals(ydAimBayGp)) {
				ydAimBayGp 	= commUtils.trim(rsResult.getRecord(0).getFieldString("YD_AIM_BAY_GP"));
			}

			//INSERT 항목 record 생성
			jrParam	= commUtils.getParam(logId,	mthdNm,	sModifier);

			//INSERT할 항목	SET
			jrParam.setField("YD_WBOOK_ID"			,ydWbookId);
			jrParam.setField("YD_GP"				,ydGp);
			jrParam.setField("YD_BAY_GP"			,ydBayGp);
			jrParam.setField("YD_SCH_CD"			,ydSchCd);
			jrParam.setField("YD_SCH_PRIOR"			,ydSchPrior);
			jrParam.setField("YD_AIM_YD_GP"			,ydAimGp);
			jrParam.setField("YD_AIM_BAY_GP"		,ydAimBayGp);
			jrParam.setField("YD_TO_LOC_DCSN_MTD"	,ydToLocDcsnMtd);
			jrParam.setField("YD_TO_LOC_GUIDE"		,sToYdStkBedNo);	//야드To위치Guide
			jrParam.setField("YD_WRK_PLAN_TCAR"		,ydWrkPlanTcar);
			jrParam.setField("YD_CAR_USE_GP"		,ydCarUseGp);
			jrParam.setField("DIST_SHIPASSIGN_GP"	,sDistShipassignGp); //차량동간이적	방향 1:1통로로
			jrParam.setField("CARD_NO"				,sCardNo);
			jrParam.setField("TRN_EQP_CD"			,sTrnEqpCd);
			jrParam.setField("CAR_NO"				,sCarNo);
			jrParam.setField("YD_WRK_PLAN_CRN"		,sWrkCrn);

			//작업예약 INSERT
			commDao.insert(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilWrkBookSeEJB.insYdWrkbook",	logId, mthdNm, "작업예약 생성");

			commUtils.printLog(logId, "작업예약 생성 완료", "SL");

			/*****************************************
			 * 5. 작업예약 재료(TB_YD_WRKBOOKMTL) 생성
			 *****************************************/
			commUtils.printLog(logId, "작업예약 재료 생성", "SL");
			//조회항목 record 생성
//			jrParam	=commUtils.getParam(logId, mthdNm, sModifier);
			jrParam.setField("YD_WBOOK_ID",	  ydWbookId);

			for	(int ii	= 1; ii	<= iStlSh; ii++) {

				/* com.inisteel.cim.yd.ccoil.dao.CCoilWrkBookSeEJB.getWrkBookMtlSc
				-- 작업예약 재료조회 
				SELECT SL.YD_STK_COL_GP AS YD_STK_COL_GP
				     , SL.YD_STK_BED_NO AS YD_STK_COL_GP
				     , SL.YD_STK_LYR_NO AS YD_STK_COL_GP
				  FROM TB_YD_STOCK      ST
				     , TB_YD_STKLYR     SL
				     , TB_PT_COILCOMM   PT
				 WHERE 1 = 1
				   AND ST.STL_NO  = SL.STL_NO
				   AND ST.STL_NO  = PT.COIL_NO(+)
				   AND ST.STL_NO = :V_STL_NO
				   AND NOT EXISTS (SELECT  1
				                     FROM TB_YD_WRKBOOK    WB
				                        , TB_YD_WRKBOOKMTL WM
				                    WHERE WB.YD_WBOOK_ID = WM.YD_WBOOK_ID
				                      AND WB.DEL_YN = 'N'
				                      AND WM.DEL_YN = 'N'
				                      AND WM.STL_NO = PT.COIL_NO
				                  )
				*/
				jrParam.setField("STL_NO" ,	sStlNo[ii]);
				jsResult = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilWrkBookSeEJB.getWrkBookMtlSc",	logId, mthdNm, "작업예약재료 조회");
				if (jsResult.size()	<= 0) {

					sMsg = "재료번호에 해당하는	적치 확인 중 에러";
					commUtils.printLog(logId, sMsg,	"SL");

					jrRtn.setField("RTN_CD"	, "0");
					jrRtn.setField("RTN_MSG", "재료번호에 해당하는 적치 확인 중 에러");
					return jrRtn;
				}

	 			//레코드추출
				jrParam.setField("YD_STK_COL_GP",  jsResult.getRecord(0).getFieldString("YD_STK_COL_GP")); //적치열구분
				jrParam.setField("YD_STK_BED_NO",  jsResult.getRecord(0).getFieldString("YD_STK_BED_NO")); //적치BED번호
				jrParam.setField("YD_STK_LYR_NO",  jsResult.getRecord(0).getFieldString("YD_STK_LYR_NO")); //적치단번호
				jrParam.setField("YD_UP_COLL_SEQ", ydUpCollSeq[ii]);  //권상모음순서

				jrParam.setField("YD_ISPTOR"	 , sIsptor);
				jrParam.setField("YD_TAKE_OUT_DT", sTakeOutDt);
				jrParam.setField("YD_TAKE_OUT_CD", stakeOutCd);

				// 작업예약재료	테이블에 등록한다.
				commDao.insert(jrParam,	"com.inisteel.cim.yd.ccoil.dao.CCoilWrkBookSeEJB.insYdWrkbookMtl", logId, mthdNm, "작업예약재료 등록");
			}

			jrRtn.setField("RTN_CD"		, "1");
			jrRtn.setField("RTN_MSG"	, "작업예약 등록 완료");

			jrRtn.setField("YD_WBOOK_ID", ydWbookId);
			jrRtn.setField("YD_SCH_CD"	, ydSchCd);
			jrRtn.setField("YD_WRK_CRN"	, sWrkCrn);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	} 
	
	
	/**
	 * 제품이송하차 입동제한 기준관리
	 * 
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord updGdsFtmvCarudStdMgt(GridData gdReq) throws DAOException {
		String mthdNm	= "제품이송하차 입동제한 기준관리-수정[CCoilJspSeEJ.updGdsFtmvCarudStdMgt] < " + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();
			
			String sMsg			= "";
			String userid		= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			
			JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, userid);
			
			// Key Value
			String ydBayGp      = "";
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
			//입동제한
			jrParam.setField("REPR_CD_GP"	, "J00007"	);
			jrParam.setField("ITEM1"		, "N"	   	);
			/*
			UPDATE TB_YD_RULE
			   SET ITEM1       = :V_ITEM1
			     , ITEM_VALUE1 = :V_ITEM_VALUE1
			     , ITEM2       = :V_ITEM2
			     , ITEM_VALUE2 = :V_ITEM_VALUE2
			     , DTL_ITEM1   = :V_DTL_ITEM1
			     , DTL_ITEM2   = :V_DTL_ITEM2
			     , DTL_ITEM3   = :V_DTL_ITEM3
			     , DTL_ITEM4   = :V_DTL_ITEM4
			     , DTL_ITEM5   = :V_DTL_ITEM5
			     , DTL_ITEM6   = :V_DTL_ITEM6
			     , DTL_ITEM7   = :V_DTL_ITEM7
			     , DTL_ITEM8   = :V_DTL_ITEM8
			     , DTL_ITEM9   = :V_DTL_ITEM9
			     , DTL_ITEM10  = :V_DTL_ITEM10
			     , MOD_DDTT    = SYSDATE
			     , MODIFIER    = :V_MODIFIER
			 WHERE REPR_CD_GP  = :V_REPR_CD_GP
			   AND CD_GP       LIKE :V_CD_GP || '%'
			   AND ITEM        LIKE :V_ITEM  || '%'
			 */
			commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdRuleMgtLIKE", logId, mthdNm, "입동제한기준 초기화");
			
			
			for (int i = 0; i < rowCnt; i++) {
				
				// Key Value
				ydBayGp     = commUtils.trim(commUtils.getValue(gdReq, "YD_BAY_GP"  , i));
				
				/**************************
				 * 1. 2열연 기준관리 UPDATE
				 **************************/
				// Key Value
				jrParam.setField("REPR_CD_GP"	, "J00007"	);
				jrParam.setField("CD_GP"		, ydBayGp	);
				jrParam.setField("ITEM"			, "*"		);
				// Update Value
				jrParam.setField("ITEM1"		, "Y"	   	);

				/*
				UPDATE TB_YD_RULE
				   SET ITEM1       = :V_ITEM1
				     , ITEM_VALUE1 = :V_ITEM_VALUE1
				     , ITEM2       = :V_ITEM2
				     , ITEM_VALUE2 = :V_ITEM_VALUE2
				     , DTL_ITEM1   = :V_DTL_ITEM1
				     , DTL_ITEM2   = :V_DTL_ITEM2
				     , DTL_ITEM3   = :V_DTL_ITEM3
				     , DTL_ITEM4   = :V_DTL_ITEM4
				     , DTL_ITEM5   = :V_DTL_ITEM5
				     , DTL_ITEM6   = :V_DTL_ITEM6
				     , DTL_ITEM7   = :V_DTL_ITEM7
				     , DTL_ITEM8   = :V_DTL_ITEM8
				     , DTL_ITEM9   = :V_DTL_ITEM9
				     , DTL_ITEM10  = :V_DTL_ITEM10
				     , MOD_DDTT    = SYSDATE
				     , MODIFIER    = :V_MODIFIER
				 WHERE REPR_CD_GP  = :V_REPR_CD_GP
				   AND CD_GP       = :V_CD_GP
				   AND ITEM        = :V_ITEM
				*/
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.updYdRuleMgt", logId, mthdNm, "2열연기준 UPDATE");
			}
			
			sMsg = "기준관리 수정 처리 완료.";
			commUtils.printLog(logId, sMsg, "SL");
			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", sMsg);

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
	/**
	 * 공냉재 HFL재 변경 이적지시
	 * 야드관리 > 2열연 소재 코일야드[신] > 산적LOT관리 > 공냉재이적대상재조회
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  GridData
	 * @return JDTORecord
	 * @throws DAOException
	 */
	public JDTORecord procAirClHflMoveReg(GridData gdReq) throws DAOException {
		String mthdNm	= "공냉재 HFL재 변경 이적지시[CCoilJspSeEJB.procAirClHflMoveReg]" + gdReq.getNavigateValue();
		String logId	= gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			JDTORecord jrRtn	= JDTORecordFactory.getInstance().create();

			String rtnCd		= "";
			String rtnMsg		= "";
			String sMsg			= "";
			String sModifier	= commUtils.trim(gdReq.getParam("YD_USER_ID"));
			String workGp		= commUtils.trim(gdReq.getParam("WORK_GP"));
			
			commUtils.printLog(logId, ">> WORK_GP:"+ workGp, "SL");
			
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			/***************************************
			 * 정합성 체크
			 ***************************************/
			for(int i=0; i<rowCnt; i++) {
				String sStlNo = commUtils.trim(commUtils.getValue(gdReq, "STL_NO", i));

				/**********************************************************
				* 1. 작업예약 조회
				**********************************************************/
				JDTORecord jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("STL_NO", sStlNo);

				/* com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdWrkbookmtlSTLNO
				SELECT A.YD_WBOOK_ID         AS YD_WBOOK_ID
				     , A.DEL_YN              AS DEL_YN
				     , A.YD_GP               AS YD_GP
				     , A.YD_BAY_GP           AS YD_BAY_GP
				     , A.YD_SCH_CD           AS YD_SCH_CD
				     , A.YD_SCH_PRIOR        AS YD_SCH_PRIOR
				     , A.YD_SCH_PROG_STAT    AS YD_SCH_PROG_STAT
				     , A.YD_SCH_ST_GP        AS YD_SCH_ST_GP
				     , A.YD_SCH_REQ_GP       AS YD_SCH_REQ_GP
				     , A.YD_AIM_YD_GP        AS YD_AIM_YD_GP
				     , A.YD_AIM_BAY_GP       AS YD_AIM_BAY_GP
				     , A.YD_CTS_RELAY_YN     AS YD_CTS_RELAY_YN
				     , A.YD_CTS_RELAY_BAY_GP AS YD_CTS_RELAY_BAY_GP
				     , A.YD_TO_LOC_DCSN_MTD  AS YD_TO_LOC_DCSN_MTD
				     , A.YD_TO_LOC_GUIDE     AS YD_TO_LOC_GUIDE
				     , B.STL_NO              AS STL_NO
				     , B.YD_STK_COL_GP       AS YD_STK_COL_GP
				     , B.YD_STK_BED_NO       AS YD_STK_BED_NO
				     , B.YD_STK_LYR_NO       AS YD_STK_LYR_NO
				     , B.YD_UP_COLL_SEQ      AS YD_UP_COLL_SEQ
				  FROM TB_YD_WRKBOOK    A
				     , TB_YD_WRKBOOKMTL B
				 WHERE A.YD_WBOOK_ID = B.YD_WBOOK_ID
				   AND B.STL_NO = :V_STL_NO
				   AND A.DEL_YN = 'N'
				   AND B.DEL_YN = 'N'
				 */
				JDTORecordSet jsWrkBook = commDao.select(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilDAO.getYdWrkbookmtlSTLNO", logId, mthdNm, "작업예약 조회");
				if (jsWrkBook.size() > 0) {
					sMsg = "["+sStlNo+"] 등록된 작업예약이 있습니다.";
					commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		commUtils.printLog(logId, mthdNm, "S-");
			        return jrRtn;
				}
			}

			/***************************************
			 * 2단 코일 작업예약
			 ***************************************/
			for(int i=0; i<rowCnt; i++) {

				String ydStkColGp	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_COL_GP"	, i));
				String ydStkBedNo	= commUtils.trim(commUtils.getValue(gdReq, "Yd_STK_BED_NO"	, i));
				String ydStkLyrNo	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO"	, i));
				String sStlNo		= commUtils.trim(commUtils.getValue(gdReq, "STL_NO"			, i));
				String ydBayGp		= ydStkColGp.substring(1,2);

				if( !"002".equals(ydStkLyrNo) ) continue;

				/*********************************
	    		 * 1. 작업예약 등록
	    		 *********************************/
				String schGp = "";
				
				if( "H".equals(workGp) ) {
					// HFL 보급
					schGp = "YD03MH";
					
					if( "D".equals(ydBayGp) ) {
						// 35스판 미만 D1, 이상 D2 크레인
						if( Integer.parseInt(ydStkColGp.substring(2,4)) > 34 ) {
							schGp = "YD13MH";
						}
					}
				} else if( "S".equals(workGp) ) {
					// SPM 직보급
					schGp = "YD53MH";
				}
				
				String ydSchCd = "J"+ ydBayGp + schGp;
				
				commUtils.printLog(logId, " >> WORK_GP["+ workGp +"] YD_STK_COL_GP["+ ydStkColGp +"] YD_SCH_CD["+ ydSchCd +"]", "SL");

				JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd	);
				jrParam.setField("STL_SH"				, "1"		);
				jrParam.setField("STL_NO1"				, sStlNo	);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"		);
				jrParam.setField("YD_AIM_YD_GP"			, "J"		);
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp	);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd	= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg	= commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				String ydWbookId = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if( !"1".equals(rtnCd) ) {
					sMsg = "작업예약생성 실패 : 저장위치["+ ydStkColGp+ydStkBedNo+ydStkLyrNo +"] STL_NO["+ sStlNo +"] RTN_MSG:"+ rtnMsg;
		    		commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************
	    		 * 2. 스케쥴 기동
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"	, ydSchCd);
				jrParam.setField("YD_WBOOK_ID"	, ydWbookId);

				JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrParam);
				rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

				if (!"1".equals(rtnCd)) {
					sMsg = "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId;
					commUtils.printLog(logId, sMsg, "SL");
					jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jrRtn = commUtils.addSndData(jrRtn, jrRunSch);

				/*********************************************
	    		 * 3. 조업L3 YDHRJ009(공냉재 HFL재 변경요구) 송신
	    		 *********************************************/
				String currDt = commUtils.getDateTime14(); //현재시각

				JDTORecord jrYdMsg	= commUtils.getParam(logId, mthdNm, sModifier);
				jrYdMsg.setField("JMS_TC_CD"			, "YDHRJ009"); // 공냉재 HFL재 변경요구
				jrYdMsg.setField("JMS_TC_CREATE_DDTT"	, currDt	); // 현재시간
    			jrYdMsg.setField("YD_GP"				, "J"		); // 야드구분
    			jrYdMsg.setField("YD_BAY_GP"			, ydBayGp	); // 동 구분
    			jrYdMsg.setField("WORK_GP"				, workGp	); // H(HFL보급), S(SPM직보급)
    			jrYdMsg.setField("STL_NO"				, sStlNo	); // 재료번호

    			//열연조업 L3 정정보급완료 실적 전송
    			jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);
    			commUtils.printLog(logId, "○○○ 열연조업 L3 공냉재 HFL재 변경요구 송신", "SL");
			}

			/***************************************
			 * 1단 코일 작업예약
			 ***************************************/
			for(int i=0; i<rowCnt; i++) {

				String ydStkColGp	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_COL_GP"	, i));
				String ydStkBedNo	= commUtils.trim(commUtils.getValue(gdReq, "Yd_STK_BED_NO"	, i));
				String ydStkLyrNo	= commUtils.trim(commUtils.getValue(gdReq, "YD_STK_LYR_NO"	, i));
				String sStlNo		= commUtils.trim(commUtils.getValue(gdReq, "STL_NO"			, i));
				String ydBayGp		= ydStkColGp.substring(1,2);

				if( !"001".equals(ydStkLyrNo) ) continue;

				/*********************************
	    		 * 1. 작업예약 등록
	    		 *********************************/
				String schGp = "";
				
				if( "H".equals(workGp) ) {
					// HFL 보급
					schGp = "YD03MH";
					
					if( "D".equals(ydBayGp) ) {
						// 35스판 미만 D1, 이상 D2 크레인
						if( Integer.parseInt(ydStkColGp.substring(2,4)) > 34 ) {
							schGp = "YD13MH";
						}
					}
				} else if( "S".equals(workGp) ) {
					// SPM 직보급
					schGp = "YD53MH";
				}
				
				String ydSchCd = "J"+ ydBayGp + schGp;
				
				commUtils.printLog(logId, " >> WORK_GP["+ workGp +"] YD_STK_COL_GP["+ ydStkColGp +"] YD_SCH_CD["+ ydSchCd +"]", "SL");

				JDTORecord jrParam = commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"			, ydSchCd	);
				jrParam.setField("STL_SH"				, "1"		);
				jrParam.setField("STL_NO1"				, sStlNo	);
				jrParam.setField("YD_TO_LOC_DCSN_MTD"	, "F"		);
				jrParam.setField("YD_AIM_YD_GP"			, "J"		);
				jrParam.setField("YD_AIM_BAY_GP"		, ydBayGp	);

				EJBConnector ejbConn = new EJBConnector("default", "CCoilWrkBookSeEJB", this);
				JDTORecord jrWrkBook = (JDTORecord)ejbConn.trx("insWrkBookTx", new Class[] { JDTORecord.class }, new Object[] { jrParam });

				rtnCd	= commUtils.nvl(jrWrkBook.getFieldString("RTN_CD"), "0");
				rtnMsg	= commUtils.nvl(jrWrkBook.getFieldString("RTN_MSG"), "");
				String ydWbookId = commUtils.nvl(jrWrkBook.getFieldString("YD_WBOOK_ID"), "");

				if( !"1".equals(rtnCd) ) {
					sMsg = "작업예약생성 실패 : 저장위치["+ ydStkColGp+ydStkBedNo+ydStkLyrNo +"] STL_NO["+ sStlNo +"] RTN_MSG:"+ rtnMsg;
		    		commUtils.printLog(logId, sMsg, "SL");

		    		jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				/*********************************
	    		 * 2. 스케쥴 기동
	    		 *********************************/
				jrParam	= commUtils.getParam(logId, mthdNm, sModifier);
				jrParam.setField("YD_SCH_CD"	, ydSchCd);
				jrParam.setField("YD_WBOOK_ID"	, ydWbookId);

				JDTORecord jrRunSch = (JDTORecord)this.trxRunSchedule(jrParam);
				rtnCd		 = commUtils.nvl(jrRunSch.getFieldString("RTN_CD"), "0");
				rtnMsg		 = commUtils.nvl(jrRunSch.getFieldString("RTN_MSG"), "");

				if (!"1".equals(rtnCd)) {
					sMsg = "스케줄 기동처리 오류 YD_WBOOK_ID:"+ydWbookId;
					commUtils.printLog(logId, sMsg, "SL");
					jrRtn.setField("RTN_CD"	, "0");
		    		jrRtn.setField("RTN_MSG", sMsg);
		    		commUtils.printLog(logId, mthdNm, "S-");
					return jrRtn;
				}

				jrRtn = commUtils.addSndData(jrRtn, jrRunSch);

				/*********************************************
	    		 * 3. 조업L3 YDHRJ009(공냉재 HFL재 변경요구) 송신
	    		 *********************************************/
				String currDt = commUtils.getDateTime14(); //현재시각

				JDTORecord jrYdMsg	= commUtils.getParam(logId, mthdNm, sModifier);
				jrYdMsg.setField("JMS_TC_CD"			, "YDHRJ009"); // 공냉재 HFL재 변경요구
				jrYdMsg.setField("JMS_TC_CREATE_DDTT"	, currDt	); // 현재시간
    			jrYdMsg.setField("YD_GP"				, "J"		); // 야드구분
    			jrYdMsg.setField("YD_BAY_GP"			, ydBayGp	); // 동 구분
    			jrYdMsg.setField("WORK_GP"				, workGp	); // H(HFL보급), S(SPM직보급)
    			jrYdMsg.setField("STL_NO"				, sStlNo	); // 재료번호

    			//열연조업 L3 정정보급완료 실적 전송
    			jrRtn = commUtils.addSndData(jrRtn, jrYdMsg);
    			commUtils.printLog(logId, "○○○ 열연조업 L3 공냉재 HFL재 변경요구 송신", "SL");
			}
			
			commUtils.printParam(logId, jrRtn);

			jrRtn.setField("RTN_CD"	, "1");
			jrRtn.setField("RTN_MSG", "공냉재 이적지시 완료 되었습니다.");
			commUtils.printLog(logId, mthdNm, "S-");
			return jrRtn;

		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}
	}
	
