	/**
	 * 화면 도움말 - 작업방법(버튼상세) 등록
	 *
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param GridData gdReq
	 * @return JDTORecord
	 * @throws DAOException
	*/
	public JDTORecord setPageHelpBtnDtlInfo(GridData gdReq) throws DAOException {
		String mthdNm = "화면 도움말 - 작업방법(버튼상세) 등록[CCoilJspSeEJB.setPageHelpBtnDtlInfo] < " + gdReq.getNavigateValue();
		String logId = gdReq.getIPAddress();

		try {
			commUtils.printLog(logId, mthdNm, "S+");

			//Return Value
			JDTORecord jrRtn = JDTORecordFactory.getInstance().create();

			//DAO Parameter - Log ID, Method, 수정자 Set
			JDTORecord jrParam = commUtils.getParam(logId, mthdNm, commUtils.trim(gdReq.getParam("userid")));

			//수정할 레코드 수
			int rowCnt = gdReq.getHeader("CHECK").getRowCount();
			
				/* 이전 버전 data 삭제
				DELETE USRYDA.TB_YD_HELP_BTNDTL B
				 WHERE B.PAGE_ID = :V_PAGE_ID
				   AND B.BTN_ID  = :V_BTN_ID
				*/
				jrParam.setField("PAGE_ID"	, gdReq.getParam("PAGE_ID"	));
				jrParam.setField("BTN_ID"	, gdReq.getParam("BTN_ID"	));
				commDao.delete(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.delPageHelpBtnDtlInfo", logId, mthdNm, "이전 버전 data 삭제");

			for (int ii = 0; ii < rowCnt; ii++) {
				
				// 파라미터 Set.
				jrParam.setField("PAGE_ID"	,commUtils.getValue(gdReq, "PAGE_ID"	, ii)	); 
				jrParam.setField("BTN_ID"	,commUtils.getValue(gdReq, "BTN_ID"		, ii)	);
				jrParam.setField("BTN_SEQ"	,commUtils.getValue(gdReq, "BTN_SEQ"	, ii)	);
				jrParam.setField("BTN_CMNT"	,commUtils.getValue(gdReq, "BTN_CMNT"	, ii)	);
				jrParam.setField("BTN_DISC"	,commUtils.getValue(gdReq, "BTN_DISC"	, ii)	);
				jrParam.setField("REGISTER"	,commUtils.getValue(gdReq, "REGISTER"	, ii)	);
				jrParam.setField("MODIFIER"	,commUtils.getValue(gdReq, "MODIFIER"	, ii)	);
				
				/*
					INSERT INTO USRYDA.TB_YD_HELP_BTNDTL B(
					      B.PAGE_ID   -- 화면ID   
					    , B.BTN_ID    -- 버튼ID   
					    , B.BTN_SEQ   -- 순번     
					    , B.BTN_CMNT  -- 버튼설명 
					    , B.DEL_YN    -- 삭제여부 
					    , B.REGISTER  -- 등록자   
					    , B.REG_DDTT  -- 등록 일시
					    , B.MODIFIER  -- 수정자   
					    , B.MOD_DDTT  -- 수정 일시
					) VALUES (
					      :V_PAGE_ID   -- 화면ID   
					    , :V_BTN_ID    -- 버튼ID   
					    , :V_BTN_SEQ   -- 순번
					    , :V_BTN_CMNT  -- 버튼설명
					    , 'N'          -- 삭제여부 
					    , :V_REGISTER  -- 등록자   
					    , SYSDATE      -- 등록 일시
					    , :V_MODIFIER  -- 수정자   
					    , SYSDATE      -- 수정 일시 
					)
				 */
				commDao.update(jrParam, "com.inisteel.cim.yd.ccoil.dao.CCoilJspSeEJB.setPageHelpBtnDtlInfo", logId, mthdNm, "작업방법(버튼상세)등록");
								
			}

			commUtils.printLog(logId, mthdNm, "S-");

			return jrRtn;
		} catch(DAOException e) {
			throw e;
		} catch(Exception e) {
			throw new DAOException(commUtils.makeErrorLog(logId, mthdNm, e));
		}	
	} // end of setPageHelpBtnInfo
	
	
